def cmd_code_engine_show(engine_name: str, session_id: str) -> None:
    """Show indexed files for one engine by name/base/root substring."""
    from agents.forge.memory import write_audit_entry
    q = (engine_name or "").strip().lower()
    if not q:
        print()
        print("  Usage: code-engine-show <engine_name>")
        print("  Example: code-engine-show phase_engine")
        print()
        return
    rows, errors = _code_engine_inventory_rows()
    q_base = _code_engine_base_name(q)
    matches = [r for r in rows if q in str(r.get("engine_name", "")).lower() or q in str(r.get("root", "")).lower() or q_base == str(r.get("engine_base", ""))]
    matches.sort(key=lambda r: (-int(r.get("canonical_score", 0)), r.get("root", "")))
    print()
    print("── Code Engine Show ─────────────────────────────────")
    print(f"  Query      : {engine_name}")
    print(f"  Matches    : {len(matches)}")
    print(f"  Read-only  : YES")
    print()
    for r in matches[:20]:
        print(f"  Engine     : {r.get('engine_name')}  base={r.get('engine_base')}")
        print(f"  Root       : {r.get('root')}")
        print(f"  Family     : {r.get('family')}")
        print(f"  Score      : {r.get('canonical_score')}")
        print(f"  Files      : {r.get('file_count')}  chunks={r.get('chunk_count')}  symbols={r.get('symbol_count')}")
        print(f"  Tags       : {', '.join(r.get('status_tags', []))}")
        print(f"  Roles      : " + ", ".join(f"{k}={v}" for k, v in sorted(r.get("roles", {}).items())))
        print("  Samples:")
        for sf in r.get("sample_files", [])[:6]:
            print(f"    - {sf}")
        print()
    if len(matches) > 20:
        print(f"  ... {len(matches) - 20} more matches hidden. Use report from code-engine-inventory for full list.")
    if errors:
        print("  Index warnings:")
        for e in errors[:5]:
            print(f"    - {e}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "CODE_ENGINE_SHOW_SHOWN", engine_name, f"matches={len(matches)}", "read-only")


