def cmd_code_engine_canonical_plan(session_id: str) -> None:
    """Write a non-destructive canonical-engine plan. Does not move, delete, or edit files."""
    from agents.forge.memory import write_audit_entry
    rows, errors = _code_engine_inventory_rows()
    groups = _code_engine_duplicate_groups(rows)
    plan_rows = []
    for g in groups:
        cand = g["canonical_candidate"]
        plan_rows.append({
            "engine_base": g["engine_base"],
            "canonical_candidate_root": cand.get("root"),
            "canonical_candidate_name": cand.get("engine_name"),
            "canonical_score": cand.get("canonical_score"),
            "variant_count": len(g["variants"]),
            "keep_candidate_reason": "highest conservative canonical score; prefer active/unfrozen aiweb/engines roots; no action performed",
            "variants": [
                {
                    "engine_name": v.get("engine_name"),
                    "root": v.get("root"),
                    "score": v.get("canonical_score"),
                    "tags": v.get("status_tags", []),
                    "file_count": v.get("file_count"),
                    "symbol_count": v.get("symbol_count"),
                }
                for v in g["variants"]
            ],
        })
    payload = {
        "report_type": "CODE_ENGINE_CANONICAL_PLAN_PATCH58_NON_DESTRUCTIVE",
        "timestamp": datetime.datetime.now().isoformat(timespec="seconds"),
        "read_only": True,
        "implemented_destructive_action": False,
        "warning": "PLAN ONLY. This command does not delete, move, rename, freeze, promote, or rewrite engine files.",
        "engine_count": len(rows),
        "duplicate_group_count": len(groups),
        "canonical_plan": plan_rows,
        "errors": errors,
    }
    report_path = _code_engine_write_report("code_engine_canonical_plan", payload)
    print()
    print("── Code Engine Canonical Plan ───────────────────────")
    print("  Mode        : PLAN ONLY")
    print("  Read-only   : YES — no files changed")
    print(f"  Engines     : {len(rows)}")
    print(f"  Groups      : {len(groups)} duplicate/version families")
    print(f"  Plan path   : {report_path}")
    print()
    for item in plan_rows[:40]:
        print(f"  - {item['engine_base']}")
        print(f"      keep candidate : {item['canonical_candidate_root']} score={item['canonical_score']}")
        print(f"      variants       : {item['variant_count']}")
    if len(plan_rows) > 40:
        print(f"  ... {len(plan_rows) - 40} more plan rows written to report")
    if errors:
        print("  Index warnings:")
        for e in errors[:5]:
            print(f"    - {e}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "CODE_ENGINE_CANONICAL_PLAN_CREATED", str(report_path), f"groups={len(groups)}", "plan-only read-only")


