# ─── PATCH 60 — PATCH SANDBOX MODE ───────────────────────────────────────────

def _patch60_sha16(text: str) -> str:
    """Return Forge-standard SHA-256/16 for text content."""
    import hashlib
    return hashlib.sha256(text.encode("utf-8")).hexdigest()[:16]


def _patch60_timestamp() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch60_safe_slug(value: str, limit: int = 80) -> str:
    slug = re.sub(r"[^A-Za-z0-9_.-]+", "_", str(value or "")).strip("._-")
    return (slug or "sandbox")[:limit]


def _patch60_latest_json(folder: Path) -> Path | None:
    if not folder.exists():
        return None
    rows = sorted(folder.glob("*.json"), key=lambda p: p.stat().st_mtime, reverse=True)
    return rows[0] if rows else None


def _patch60_resolve_apply_plan(arg: str) -> tuple[Path | None, str]:
    """Resolve an apply plan inside ~/forge/apply_plans only."""
    import os
    apply_plans_dir = FORGE_ROOT / "apply_plans"
    raw = (arg or "").strip()
    if not raw or raw == "latest":
        latest = _patch60_latest_json(apply_plans_dir) or (sorted(apply_plans_dir.glob("*.txt"), key=lambda p: p.stat().st_mtime, reverse=True)[0] if apply_plans_dir.exists() and list(apply_plans_dir.glob("*.txt")) else None)
        if latest:
            return latest, ""
        return None, f"No apply plans found in {apply_plans_dir}"
    candidate = Path(os.path.expanduser(raw))
    if not candidate.is_absolute():
        candidate = apply_plans_dir / raw
    try:
        candidate.resolve().relative_to(apply_plans_dir.resolve())
    except Exception:
        return None, f"Apply plan must be inside {apply_plans_dir}; got {candidate}"
    if not candidate.exists() or not candidate.is_file():
        return None, f"Apply plan not found: {candidate}"
    return candidate, ""


def _patch60_parse_apply_plan_text(plan_text: str) -> dict:
    """Best-effort apply-plan parser with external Forge parser fallback."""
    fields = {}
    try:
        from agents.forge.applier import _parse_apply_plan
        parsed = _parse_apply_plan(plan_text)
        if isinstance(parsed, dict):
            fields.update(parsed)
    except Exception:
        pass

    def first_regex(patterns):
        for pat in patterns:
            m = re.search(pat, plan_text, re.IGNORECASE | re.MULTILINE)
            if m:
                return m.group(1).strip()
        return ""

    fallbacks = {
        "target_file": [r"^\s*Target file\s*:\s*(.+)$", r"^\s*target_file\s*[:=]\s*(.+)$"],
        "original_sha256": [r"^\s*Original SHA(?:-256)?\s*:\s*([0-9a-fA-F]{16,64})", r"^\s*original_sha256\s*[:=]\s*([0-9a-fA-F]{16,64})"],
        "future_sha256": [r"^\s*Future SHA(?:-256)?\s*:\s*([0-9a-fA-F]{16,64})", r"^\s*future_sha256\s*[:=]\s*([0-9a-fA-F]{16,64})"],
        "rollback_path": [r"^\s*Rollback(?: saved| path| at)?\s*:\s*(.+)$", r"^\s*rollback_path\s*[:=]\s*(.+)$"],
    }
    for key, patterns in fallbacks.items():
        if not fields.get(key):
            val = first_regex(patterns)
            if val:
                fields[key] = val
    return fields


def _patch60_extract_section(plan_text: str, headers: list[str]) -> str:
    """Extract a fenced-ish section from a Forge text plan."""
    for header in headers:
        # Header line, optional separator line, then content until a strong all-caps header or EOF.
        pat = rf"(?ims)^\s*{re.escape(header)}\s*\n(?:[═=─\-]{{6,}}\s*\n)?(.*?)(?=\n\s*[A-Z][A-Z0-9 _()/-]{{5,}}\s*\n(?:[═=─\-]{{6,}}\s*\n)?|\Z)"
        m = re.search(pat, plan_text)
        if m:
            return m.group(1).rstrip("\n")
    return ""


def _patch60_compute_future_content(plan_text: str, fields: dict, current_content: str) -> tuple[str | None, str]:
    """Compute future content for sandbox write; never touches project files."""
    for key in ("future_content", "computed_future_content", "proposed_full_content", "new_content"):
        value = fields.get(key)
        if isinstance(value, str) and value:
            return value, f"parser_field:{key}"

    full = _patch60_extract_section(plan_text, [
        "COMPUTED FUTURE CONTENT",
        "FUTURE CONTENT",
        "PROPOSED FULL CONTENT",
        "FINAL CONTENT",
    ])
    if full:
        return full, "section:computed_future_content"

    original = fields.get("original_snippet") or _patch60_extract_section(plan_text, ["ORIGINAL SNIPPET", "ORIGINAL", "ORIGINAL CONTENT"])
    proposed = fields.get("proposed_snippet") or _patch60_extract_section(plan_text, ["PROPOSED SNIPPET", "PROPOSED CHANGE", "PROPOSED CONTENT"])
    if isinstance(original, str) and isinstance(proposed, str) and original and proposed:
        if original in current_content:
            return current_content.replace(original, proposed, 1), "snippet_replace:first_occurrence"
        return None, "original snippet not present in current target content"

    return None, "could not parse future content from apply plan"


def _patch60_target_relative_path(target_file: str) -> Path:
    """Preserve project-relative path inside sandbox when possible."""
    target = Path(target_file).expanduser().resolve()
    bases = []
    try:
        bases.extend(get_session_paths() or [])
    except Exception:
        pass
    try:
        bases.extend(get_approved_paths() or [])
    except Exception:
        pass
    for base in bases:
        try:
            base_p = Path(base).expanduser().resolve()
            rel = target.relative_to(base_p)
            if ".." not in rel.parts:
                return rel
        except Exception:
            continue
    return Path("_single_file") / _patch60_safe_slug(target.name or "target.txt")


def _patch60_resolve_sandbox_plan(arg: str) -> tuple[Path | None, str]:
    """Resolve a sandbox plan inside ~/forge/patch_sandbox_plans only."""
    import os
    raw = (arg or "").strip()
    if not raw or raw == "latest":
        latest = _patch60_latest_json(PATCH_SANDBOX_PLANS_DIR)
        if latest:
            return latest, ""
        return None, f"No sandbox plans found in {PATCH_SANDBOX_PLANS_DIR}"
    candidate = Path(os.path.expanduser(raw))
    if not candidate.is_absolute():
        candidate = PATCH_SANDBOX_PLANS_DIR / raw
    try:
        candidate.resolve().relative_to(PATCH_SANDBOX_PLANS_DIR.resolve())
    except Exception:
        return None, f"Sandbox plan must be inside {PATCH_SANDBOX_PLANS_DIR}; got {candidate}"
    if not candidate.exists() or not candidate.is_file():
        return None, f"Sandbox plan not found: {candidate}"
    return candidate, ""


def _patch60_load_sandbox_plan(arg: str) -> tuple[dict | None, Path | None, str]:
    path, err = _patch60_resolve_sandbox_plan(arg)
    if err:
        return None, None, err
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except Exception as e:
        return None, path, f"Cannot read sandbox plan JSON: {e}"
    return payload, path, ""


def cmd_patch_sandbox_plan(apply_plan_arg: str, session_id: str) -> None:
    """Create a Forge-owned sandbox rehearsal plan from an existing apply plan."""
    from agents.forge.memory import write_audit_entry
    from agents.forge.permissions import is_path_allowed, is_path_blocked
    apply_plan_path, err = _patch60_resolve_apply_plan(apply_plan_arg)
    print()
    print("── Patch Sandbox Plan ───────────────────────────────")
    print("  Mode      : PLAN ONLY")
    print("  Read-only : YES for project files — writes only Forge-owned sandbox plan JSON")
    if err:
        print(f"  Refused   : {err}")
        write_audit_entry(session_id, "PATCH_SANDBOX_PLAN_REFUSED", str(apply_plan_arg), "-", err[:180])
        print("──────────────────────────────────────────────────────")
        print()
        return
    plan_text = apply_plan_path.read_text(encoding="utf-8", errors="replace")
    fields = _patch60_parse_apply_plan_text(plan_text)
    target_file = str(fields.get("target_file", "")).strip()
    original_sha = str(fields.get("original_sha256", "")).strip()[:16]
    future_sha = str(fields.get("future_sha256", "")).strip()[:16]
    rollback_path = str(fields.get("rollback_path", "")).strip()

    issues = []
    if not target_file:
        issues.append("cannot parse target_file from apply plan")
    if not original_sha:
        issues.append("cannot parse original_sha256 from apply plan")
    if not future_sha:
        issues.append("cannot parse future_sha256 from apply plan")
    target_path = Path(target_file).expanduser() if target_file else None
    current_sha = ""
    target_size = 0
    if target_path:
        try:
            target_resolved = target_path.resolve()
            blocked, reason = is_path_blocked(str(target_resolved))
            if blocked:
                issues.append(f"blocked target: {reason}")
            allowed, reason = is_path_allowed(str(target_resolved))
            if not allowed:
                issues.append(f"target outside approved/session scope: {reason}")
            if target_resolved.is_symlink():
                issues.append("target is a symlink")
            if not target_resolved.exists() or not target_resolved.is_file():
                issues.append("target file does not exist or is not a regular file")
            else:
                content = target_resolved.read_text(encoding="utf-8", errors="replace")
                current_sha = _patch60_sha16(content)
                target_size = len(content.encode("utf-8"))
                if original_sha and current_sha != original_sha:
                    issues.append(f"current SHA {current_sha} does not match apply-plan original SHA {original_sha}")
        except Exception as e:
            issues.append(f"target read/check failed: {e}")

    ts = _patch60_timestamp()
    sandbox_id = f"sandbox_{ts}_{_patch60_safe_slug(Path(target_file).name if target_file else apply_plan_path.stem, 40)}"
    sandbox_root = PATCH_SANDBOXES_DIR / sandbox_id
    sandbox_rel = str(_patch60_target_relative_path(target_file)) if target_file else ""
    status = "READY" if not issues else "REFUSED_UNTIL_REVIEW"
    payload = {
        "report_type": "PATCH_SANDBOX_PLAN_PATCH60",
        "timestamp": datetime.datetime.now().isoformat(timespec="seconds"),
        "sandbox_id": sandbox_id,
        "status": status,
        "read_only_project_files": True,
        "forge_owned_writes_only": True,
        "apply_plan_path": str(apply_plan_path),
        "target_file": str(Path(target_file).expanduser().resolve()) if target_file else "",
        "target_size_bytes": target_size,
        "original_sha256": original_sha,
        "future_sha256": future_sha,
        "current_sha256": current_sha,
        "rollback_path": rollback_path,
        "sandbox_root": str(sandbox_root),
        "sandbox_relative_target": sandbox_rel,
        "issues": issues,
        "next_step": "patch-sandbox-apply " + sandbox_id + ".json" if status == "READY" else "Resolve issues before sandbox apply.",
    }
    PATCH_SANDBOX_PLANS_DIR.mkdir(parents=True, exist_ok=True)
    plan_path = PATCH_SANDBOX_PLANS_DIR / f"{sandbox_id}.json"
    plan_path.write_text(json.dumps(payload, indent=2), encoding="utf-8")
    print(f"  Apply plan : {apply_plan_path}")
    print(f"  Target     : {payload.get('target_file')}")
    print(f"  Current SHA: {current_sha or '?'}")
    print(f"  Original   : {original_sha or '?'}")
    print(f"  Future     : {future_sha or '?'}")
    print(f"  Status     : {status}")
    print(f"  Plan path  : {plan_path}")
    if issues:
        print("  Issues:")
        for issue in issues:
            print(f"    - {issue}")
    else:
        print(f"  Next       : patch-sandbox-apply {plan_path.name}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "PATCH_SANDBOX_PLAN_CREATED" if not issues else "PATCH_SANDBOX_PLAN_REFUSED", str(plan_path), f"status={status}", f"issues={len(issues)}")


def cmd_patch_sandbox_apply(plan_arg: str, session_id: str) -> None:
    """Apply an existing patch apply-plan to a Forge-owned sandbox copy only."""
    from agents.forge.memory import write_audit_entry
    payload, plan_path, err = _patch60_load_sandbox_plan(plan_arg)
    print()
    print("── Patch Sandbox Apply ──────────────────────────────")
    print("  Mode      : SANDBOX ONLY")
    print("  Writes    : YES, but only under ~/forge/patch_sandboxes and reports")
    print("  Project   : NO project files modified")
    if err:
        print(f"  Refused   : {err}")
        write_audit_entry(session_id, "PATCH_SANDBOX_APPLY_REFUSED", str(plan_arg), "-", err[:180])
        print("──────────────────────────────────────────────────────")
        print()
        return
    if payload.get("status") != "READY":
        print(f"  Refused   : sandbox plan status is {payload.get('status')}")
        for issue in payload.get("issues", [])[:8]:
            print(f"    - {issue}")
        write_audit_entry(session_id, "PATCH_SANDBOX_APPLY_REFUSED", str(plan_path), "-", f"status={payload.get('status')}")
        print("──────────────────────────────────────────────────────")
        print()
        return
    target = Path(payload.get("target_file", "")).expanduser().resolve()
    apply_plan_path = Path(payload.get("apply_plan_path", "")).expanduser().resolve()
    sandbox_root = Path(payload.get("sandbox_root", "")).expanduser().resolve()
    try:
        sandbox_root.relative_to(PATCH_SANDBOXES_DIR.resolve())
    except Exception:
        print(f"  Refused   : sandbox root outside Forge sandbox dir: {sandbox_root}")
        write_audit_entry(session_id, "PATCH_SANDBOX_APPLY_REFUSED", str(sandbox_root), "-", "sandbox root outside Forge-owned directory")
        print("──────────────────────────────────────────────────────")
        print()
        return
    current_content = target.read_text(encoding="utf-8", errors="replace")
    current_sha = _patch60_sha16(current_content)
    if payload.get("original_sha256") and current_sha != payload.get("original_sha256"):
        print(f"  Refused   : current target SHA drifted: {current_sha} != {payload.get('original_sha256')}")
        write_audit_entry(session_id, "PATCH_SANDBOX_APPLY_REFUSED", str(target), "-", "target drift before sandbox apply")
        print("──────────────────────────────────────────────────────")
        print()
        return
    plan_text = apply_plan_path.read_text(encoding="utf-8", errors="replace")
    fields = _patch60_parse_apply_plan_text(plan_text)
    future_content, mode = _patch60_compute_future_content(plan_text, fields, current_content)
    if future_content is None:
        print(f"  Refused   : {mode}")
        write_audit_entry(session_id, "PATCH_SANDBOX_APPLY_REFUSED", str(apply_plan_path), "-", mode[:180])
        print("──────────────────────────────────────────────────────")
        print()
        return
    future_sha = _patch60_sha16(future_content)
    expected_future = payload.get("future_sha256", "")
    if expected_future and future_sha != expected_future:
        print(f"  Refused   : computed future SHA {future_sha} != apply-plan future SHA {expected_future}")
        print(f"  Parse mode : {mode}")
        write_audit_entry(session_id, "PATCH_SANDBOX_APPLY_REFUSED", str(apply_plan_path), "-", "future sha mismatch in sandbox computation")
        print("──────────────────────────────────────────────────────")
        print()
        return
    sandbox_rel = Path(payload.get("sandbox_relative_target") or "target.txt")
    if ".." in sandbox_rel.parts or sandbox_rel.is_absolute():
        print("  Refused   : unsafe sandbox relative target")
        write_audit_entry(session_id, "PATCH_SANDBOX_APPLY_REFUSED", str(sandbox_rel), "-", "unsafe relative target")
        print("──────────────────────────────────────────────────────")
        print()
        return
    sandbox_target = sandbox_root / "project_copy" / sandbox_rel
    sandbox_target.parent.mkdir(parents=True, exist_ok=True)
    sandbox_target.write_text(future_content, encoding="utf-8")
    original_target = sandbox_root / "original_copy" / sandbox_rel
    original_target.parent.mkdir(parents=True, exist_ok=True)
    original_target.write_text(current_content, encoding="utf-8")
    PATCH_SANDBOX_REPORTS_DIR.mkdir(parents=True, exist_ok=True)
    report = dict(payload)
    report.update({
        "report_type": "PATCH_SANDBOX_APPLY_PATCH60",
        "sandbox_apply_timestamp": datetime.datetime.now().isoformat(timespec="seconds"),
        "status": "SANDBOX_APPLIED",
        "parse_mode": mode,
        "sandbox_target": str(sandbox_target),
        "sandbox_original": str(original_target),
        "sandbox_future_sha256": future_sha,
        "project_file_modified": False,
    })
    report_path = PATCH_SANDBOX_REPORTS_DIR / f"{payload.get('sandbox_id')}_report.json"
    report_path.write_text(json.dumps(report, indent=2), encoding="utf-8")
    (sandbox_root / "sandbox_report.json").write_text(json.dumps(report, indent=2), encoding="utf-8")
    print(f"  Sandbox   : {sandbox_root}")
    print(f"  Original  : {original_target}")
    print(f"  Patched   : {sandbox_target}")
    print(f"  Future SHA: {future_sha} ✓")
    print(f"  Report    : {report_path}")
    print("  Result    : PATCH_SANDBOX_APPLIED_PROJECT_UNCHANGED")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "PATCH_SANDBOX_APPLIED", str(report_path), f"sha={future_sha}", "project_file_modified=False")


