def cmd_patch_sandbox_clean(plan_arg: str, session_id: str) -> None:
    """Delete a Forge-owned sandbox directory after explicit CLEAN confirmation. Reports remain."""
    from agents.forge.memory import write_audit_entry
    import shutil as _shutil
    payload, plan_path, err = _patch60_load_sandbox_plan(plan_arg)
    print()
    print("── Patch Sandbox Clean ──────────────────────────────")
    print("  Deletes   : Forge-owned sandbox copy only")
    print("  Preserves : plan JSON and report JSON")
    if err:
        print(f"  Refused   : {err}")
        write_audit_entry(session_id, "PATCH_SANDBOX_CLEAN_REFUSED", str(plan_arg), "-", err[:180])
        print("──────────────────────────────────────────────────────")
        print()
        return
    sandbox_root = Path(payload.get("sandbox_root", "")).expanduser().resolve()
    try:
        sandbox_root.relative_to(PATCH_SANDBOXES_DIR.resolve())
    except Exception:
        print(f"  Refused   : sandbox root outside Forge sandbox dir: {sandbox_root}")
        write_audit_entry(session_id, "PATCH_SANDBOX_CLEAN_REFUSED", str(sandbox_root), "-", "outside Forge-owned sandbox dir")
        print("──────────────────────────────────────────────────────")
        print()
        return
    if not sandbox_root.exists():
        print(f"  Nothing to clean: {sandbox_root}")
        write_audit_entry(session_id, "PATCH_SANDBOX_CLEAN_NOOP", str(sandbox_root), "-", "sandbox missing")
        print("──────────────────────────────────────────────────────")
        print()
        return
    print(f"  Sandbox   : {sandbox_root}")
    print("  Type CLEAN to delete this Forge-owned sandbox directory:")
    try:
        confirmation = input("  > ").strip()
    except (EOFError, KeyboardInterrupt):
        print("\n[forge] Sandbox clean cancelled.")
        return
    if confirmation != "CLEAN":
        print("[forge] Sandbox clean cancelled. No files deleted.")
        return
    _shutil.rmtree(sandbox_root)
    print(f"  Deleted   : {sandbox_root}")
    print("  Result    : PATCH_SANDBOX_CLEANED")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "PATCH_SANDBOX_CLEANED", str(sandbox_root), "-", "Forge-owned sandbox removed")


# ─── PATCH 61 — SANDBOX SMOKE TEST GENERATOR ────────────────────────────────

def _patch61_latest_smoke_plan() -> Path | None:
    """Return the newest sandbox plan generated by the Patch 61 smoke-test command."""
    if not PATCH_SANDBOX_PLANS_DIR.exists():
        return None
    candidates = []
    for path in PATCH_SANDBOX_PLANS_DIR.glob("*.json"):
        try:
            data = json.loads(path.read_text(encoding="utf-8"))
        except Exception:
            continue
        if data.get("smoke_test") is True or data.get("report_type") == "PATCH_SANDBOX_SMOKE_PLAN_PATCH61":
            candidates.append(path)
    return sorted(candidates, key=lambda p: p.stat().st_mtime, reverse=True)[0] if candidates else None


def _patch61_resolve_smoke_plan(arg: str) -> tuple[Path | None, str]:
    """Resolve a smoke sandbox plan without accidentally grabbing a normal project plan."""
    import os
    raw = (arg or "").strip()
    if not raw or raw == "latest":
        latest = _patch61_latest_smoke_plan()
        if latest:
            return latest, ""
        return None, f"No Patch 61 smoke sandbox plans found in {PATCH_SANDBOX_PLANS_DIR}"
    candidate = Path(os.path.expanduser(raw))
    if not candidate.is_absolute():
        candidate = PATCH_SANDBOX_PLANS_DIR / raw
    try:
        candidate.resolve().relative_to(PATCH_SANDBOX_PLANS_DIR.resolve())
    except Exception:
        return None, f"Smoke sandbox plan must be inside {PATCH_SANDBOX_PLANS_DIR}; got {candidate}"
    if not candidate.exists() or not candidate.is_file():
        return None, f"Smoke sandbox plan not found: {candidate}"
    try:
        data = json.loads(candidate.read_text(encoding="utf-8"))
    except Exception as e:
        return None, f"Cannot read smoke sandbox plan JSON: {e}"
    if data.get("smoke_test") is not True and data.get("report_type") != "PATCH_SANDBOX_SMOKE_PLAN_PATCH61":
        return None, f"Selected plan is not a Patch 61 smoke-test plan: {candidate.name}"
    return candidate, ""


def cmd_patch_sandbox_smoke_plan(session_id: str) -> None:
    """Create a deterministic Forge-owned target plus matching apply/sandbox plan."""
    from agents.forge.memory import write_audit_entry

    ts = _patch60_timestamp()
    PATCH_SANDBOX_SMOKE_TARGETS_DIR.mkdir(parents=True, exist_ok=True)
    (FORGE_ROOT / "apply_plans").mkdir(parents=True, exist_ok=True)
    PATCH_SANDBOX_PLANS_DIR.mkdir(parents=True, exist_ok=True)

    target = PATCH_SANDBOX_SMOKE_TARGETS_DIR / "patch61_sandbox_smoke_target.txt"
    original_content = (
        "Forge Patch 61 sandbox smoke target\n"
        "state: original\n"
        "purpose: prove sandbox rehearsal without modifying AI.Web project files\n"
    )
    future_content = (
        "Forge Patch 61 sandbox smoke target\n"
        "state: sandboxed\n"
        "purpose: prove sandbox rehearsal without modifying AI.Web project files\n"
    )
    future_content = future_content.rstrip("\n")

    # Reset the Forge-owned smoke target on each run so the original SHA is deterministic.
    target.write_text(original_content, encoding="utf-8")
    original_sha = _patch60_sha16(original_content)
    future_sha = _patch60_sha16(future_content)

    apply_plan = FORGE_ROOT / "apply_plans" / f"{ts}_PATCH61_SANDBOX_SMOKE_PLAN.txt"
    apply_plan_text = (
        "PATCH 61 SANDBOX SMOKE APPLY PLAN\n"
        "=================================\n"
        f"Target file: {target}\n"
        f"Original SHA: {original_sha}\n"
        f"Future SHA: {future_sha}\n"
        "Rollback path: FORGE_OWNED_SMOKE_TARGET_NO_PROJECT_ROLLBACK_REQUIRED\n"
        "\n"
        "COMPUTED FUTURE CONTENT\n"
        "=======================\n"
        f"{future_content}"
    )
    apply_plan.write_text(apply_plan_text, encoding="utf-8")

    sandbox_id = f"sandbox_smoke_{ts}_patch61_sandbox_smoke_target.txt"
    sandbox_root = PATCH_SANDBOXES_DIR / sandbox_id
    payload = {
        "report_type": "PATCH_SANDBOX_SMOKE_PLAN_PATCH61",
        "timestamp": datetime.datetime.now().isoformat(timespec="seconds"),
        "sandbox_id": sandbox_id,
        "status": "READY",
        "smoke_test": True,
        "smoke_test_patch": 61,
        "read_only_project_files": True,
        "forge_owned_writes_only": True,
        "project_file_modified": False,
        "apply_plan_path": str(apply_plan),
        "target_file": str(target.resolve()),
        "target_size_bytes": len(original_content.encode("utf-8")),
        "original_sha256": original_sha,
        "future_sha256": future_sha,
        "current_sha256": original_sha,
        "rollback_path": "FORGE_OWNED_SMOKE_TARGET_NO_PROJECT_ROLLBACK_REQUIRED",
        "sandbox_root": str(sandbox_root),
        "sandbox_relative_target": "_forge_owned_smoke/patch61_sandbox_smoke_target.txt",
        "issues": [],
        "next_step": "patch-sandbox-smoke-apply latest",
    }
    plan_path = PATCH_SANDBOX_PLANS_DIR / f"{sandbox_id}.json"
    plan_path.write_text(json.dumps(payload, indent=2), encoding="utf-8")

    print()
    print("── Patch Sandbox Smoke Plan ─────────────────────────")
    print("  Mode      : SMOKE PLAN ONLY")
    print("  Writes    : Forge-owned smoke target, apply plan, sandbox plan JSON")
    print("  Project   : NO AI.Web project files modified")
    print(f"  Target    : {target}")
    print(f"  Apply plan: {apply_plan}")
    print(f"  Sandbox ID: {sandbox_id}")
    print(f"  Original  : {original_sha}")
    print(f"  Future    : {future_sha}")
    print("  Status    : READY")
    print(f"  Plan path : {plan_path}")
    print("  Next      : patch-sandbox-smoke-apply latest")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "PATCH_SANDBOX_SMOKE_PLAN_CREATED", str(plan_path), f"sha={original_sha}->{future_sha}", "Forge-owned smoke target only")


