# ─── PATCH 62 — SANDBOX REQUIRED APPLY GATE ─────────────────────────────────

def _patch62_report_matches_apply_plan(report: dict, report_path: Path, apply_plan_path: Path, fields: dict) -> tuple[bool, list[str]]:
    """Return whether one sandbox report proves this exact apply plan was rehearsed."""
    issues = []
    expected_apply = str(apply_plan_path.expanduser().resolve())
    expected_target = str(Path(str(fields.get("target_file", ""))).expanduser().resolve()) if fields.get("target_file") else ""
    expected_original = str(fields.get("original_sha256", "")).strip()[:16]
    expected_future = str(fields.get("future_sha256", "")).strip()[:16]

    if report.get("status") != "SANDBOX_APPLIED":
        issues.append(f"report status is {report.get('status')}, not SANDBOX_APPLIED")
    if str(report.get("apply_plan_path", "")):
        try:
            report_apply = str(Path(str(report.get("apply_plan_path"))).expanduser().resolve())
        except Exception:
            report_apply = str(report.get("apply_plan_path"))
    else:
        report_apply = ""
    if report_apply != expected_apply:
        issues.append("apply_plan_path mismatch")

    if expected_target:
        try:
            report_target = str(Path(str(report.get("target_file", ""))).expanduser().resolve())
        except Exception:
            report_target = str(report.get("target_file", ""))
        if report_target != expected_target:
            issues.append("target_file mismatch")

    if expected_original and str(report.get("original_sha256", "")).strip()[:16] != expected_original:
        issues.append("original_sha256 mismatch")
    if expected_future and str(report.get("future_sha256", "")).strip()[:16] != expected_future:
        issues.append("future_sha256 mismatch")
    if expected_future and str(report.get("sandbox_future_sha256", "")).strip()[:16] != expected_future:
        issues.append("sandbox_future_sha256 mismatch")
    if report.get("project_file_modified") is not False:
        issues.append("report does not prove project_file_modified=False")
    if report.get("read_only_project_files") is not True:
        issues.append("report does not declare read_only_project_files=True")
    if report.get("issues"):
        issues.append(f"report contains sandbox issues: {len(report.get('issues') or [])}")
    return (len(issues) == 0), issues


def _patch62_find_matching_sandbox_report(apply_plan_path: Path, fields: dict) -> dict:
    """Find a current SANDBOX_APPLIED report matching target/original/future/apply-plan."""
    if not PATCH_SANDBOX_REPORTS_DIR.exists():
        return {"ok": False, "reason": f"No sandbox report directory exists: {PATCH_SANDBOX_REPORTS_DIR}", "checked": 0, "candidates": []}

    reports = sorted(PATCH_SANDBOX_REPORTS_DIR.glob("*.json"), key=lambda p: p.stat().st_mtime, reverse=True)
    checked = 0
    near = []
    for path in reports:
        try:
            data = json.loads(path.read_text(encoding="utf-8"))
        except Exception as e:
            near.append({"path": str(path), "reason": f"unreadable JSON: {e}"})
            continue
        checked += 1
        ok, issues = _patch62_report_matches_apply_plan(data, path, apply_plan_path, fields)
        if ok:
            return {
                "ok": True,
                "report_path": str(path),
                "sandbox_id": data.get("sandbox_id", ""),
                "sandbox_root": data.get("sandbox_root", ""),
                "sandbox_future_sha256": data.get("sandbox_future_sha256", ""),
                "checked": checked,
                "report": data,
            }
        if len(near) < 8:
            near.append({"path": str(path), "reason": "; ".join(issues[:4]) or "not matching"})

    return {
        "ok": False,
        "reason": "No matching SANDBOX_APPLIED report found for this apply plan, target, original SHA, and future SHA.",
        "checked": checked,
        "candidates": near,
    }


def _patch62_apply_plan_gate_check(apply_plan_arg: str) -> dict:
    """Resolve and parse an apply plan, then verify the sandbox-required apply gate."""
    apply_plan_path, err = _patch60_resolve_apply_plan(apply_plan_arg)
    if err:
        return {"ok": False, "stage": "resolve_apply_plan", "reason": err, "apply_plan_path": str(apply_plan_arg)}
    try:
        plan_text = apply_plan_path.read_text(encoding="utf-8", errors="replace")
    except Exception as e:
        return {"ok": False, "stage": "read_apply_plan", "reason": f"Cannot read apply plan: {e}", "apply_plan_path": str(apply_plan_path)}
    fields = _patch60_parse_apply_plan_text(plan_text)
    issues = []
    if not fields.get("target_file"):
        issues.append("cannot parse target_file")
    if not str(fields.get("original_sha256", "")).strip():
        issues.append("cannot parse original_sha256")
    if not str(fields.get("future_sha256", "")).strip():
        issues.append("cannot parse future_sha256")
    if issues:
        return {"ok": False, "stage": "parse_apply_plan", "reason": "; ".join(issues), "apply_plan_path": str(apply_plan_path), "fields": fields}
    match = _patch62_find_matching_sandbox_report(apply_plan_path, fields)
    match.update({
        "apply_plan_path": str(apply_plan_path),
        "target_file": str(fields.get("target_file", "")),
        "original_sha256": str(fields.get("original_sha256", "")).strip()[:16],
        "future_sha256": str(fields.get("future_sha256", "")).strip()[:16],
        "stage": "sandbox_report_match",
    })
    return match


def cmd_patch_sandbox_gate_check(apply_plan_arg: str, session_id: str) -> None:
    """Read-only check: would patch-apply be allowed by the sandbox-required gate?"""
    from agents.forge.memory import write_audit_entry
    result = _patch62_apply_plan_gate_check(apply_plan_arg)
    print()
    print("── Patch Sandbox Gate Check ─────────────────────────")
    print("  Mode      : READ ONLY")
    print("  Rule      : patch-apply requires matching SANDBOX_APPLIED report")
    print(f"  Apply plan: {result.get('apply_plan_path')}")
    if result.get("target_file"):
        print(f"  Target    : {result.get('target_file')}")
        print(f"  Original  : {result.get('original_sha256')}")
        print(f"  Future    : {result.get('future_sha256')}")
    if result.get("ok"):
        print("  Status    : PASS")
        print(f"  Report    : {result.get('report_path')}")
        print(f"  Sandbox ID: {result.get('sandbox_id')}")
        print("  Result    : PATCH_APPLY_GATE_READY")
        write_audit_entry(session_id, "PATCH_SANDBOX_GATE_CHECK_PASS", str(result.get('apply_plan_path')), "read-only", f"report={result.get('report_path')}")
    else:
        print("  Status    : BLOCKED")
        print(f"  Reason    : {result.get('reason')}")
        if result.get("candidates"):
            print("  Nearby reports checked:")
            for row in result.get("candidates", [])[:5]:
                print(f"    - {row.get('path')} :: {row.get('reason')}")
        print("  Required  : run patch-sandbox-plan + patch-sandbox-apply for this exact apply plan")
        print("  Result    : PATCH_APPLY_GATE_BLOCKED")
        write_audit_entry(session_id, "PATCH_SANDBOX_GATE_CHECK_BLOCKED", str(result.get('apply_plan_path')), "read-only", str(result.get('reason', 'blocked'))[:180])
    print("──────────────────────────────────────────────────────")
    print()


