# ─── PATCH 63 — TEST INVENTORY (READ ONLY) ──────────────────────────────────

_TEST_POLICY_ALLOWED_FUTURE_COMMANDS = [
    "python -m py_compile <file>",
    "python -m pytest <explicit-test-file>",
    "npm test -- --runInBand  # only after package.json allowlist review",
]

_TEST_POLICY_NEVER_AUTORUN_PATTERNS = [
    "shell pipelines from model text",
    "curl | bash",
    "sudo",
    "rm -rf",
    "chmod/chown on project paths",
    "npm install / pip install during test run",
    "networked tests unless explicitly approved later",
]

_TEST_CONFIG_NAMES = {
    "pytest.ini", "pyproject.toml", "tox.ini", "setup.cfg", "setup.py", "package.json",
    "package-lock.json", "pnpm-lock.yaml", "yarn.lock", "jest.config.js", "jest.config.cjs",
    "jest.config.mjs", "vitest.config.js", "vitest.config.ts", "playwright.config.js",
    "playwright.config.ts", ".coveragerc", "noxfile.py",
}


def _patch63_is_test_file(row: dict) -> tuple[bool, list[str]]:
    """Classify one indexed file as test-related without executing anything."""
    rel = str(row.get("relative_path", ""))
    name = str(row.get("filename", ""))
    low_rel = rel.lower()
    low_name = name.lower()
    role = str(row.get("file_role", ""))
    reasons: list[str] = []
    if role == "test_file":
        reasons.append("file_role=test_file")
    if low_name.startswith("test_") or low_name.endswith("_test.py") or "/tests/" in f"/{low_rel}":
        reasons.append("python_test_pattern")
    if any(x in low_name for x in [".test.", ".spec."]) or low_name.endswith((".test.js", ".spec.js", ".test.ts", ".spec.ts", ".test.jsx", ".spec.jsx", ".test.tsx", ".spec.tsx")):
        reasons.append("js_ts_test_pattern")
    if low_name in ("test_log.txt", "pytest.log") or low_name.endswith("test_log.txt") or "test_log" in low_name:
        reasons.append("test_log_or_output")
    if low_name in _TEST_CONFIG_NAMES:
        reasons.append("test_or_package_config")
    return (len(reasons) > 0), sorted(set(reasons))


def _patch63_test_framework(row: dict, reasons: list[str]) -> str:
    rel = str(row.get("relative_path", "")).lower()
    name = str(row.get("filename", "")).lower()
    suffix = str(row.get("suffix", "")).lower()
    if name in ("pytest.ini", "tox.ini", "noxfile.py") or (suffix == ".py" and (name.startswith("test_") or name.endswith("_test.py") or "/tests/" in f"/{rel}")):
        return "python/pytest_candidate"
    if name == "pyproject.toml" or name == "setup.cfg" or name == "setup.py":
        return "python_config_candidate"
    if name == "package.json" or name.endswith((".test.js", ".spec.js", ".test.ts", ".spec.ts", ".test.jsx", ".spec.jsx", ".test.tsx", ".spec.tsx")) or "jest.config" in name or "vitest.config" in name:
        return "node_test_candidate"
    if "log" in name:
        return "test_log"
    return "unknown_test_related"


def _patch63_engine_for_test(rel: str) -> tuple[str | None, str | None]:
    name, root, family = _code_engine_root_from_relative_path(rel)
    if name and root:
        return name, root
    parts = [x for x in str(rel or "").split("/") if x]
    if len(parts) >= 2 and parts[0] in ("tests", "test"):
        return parts[1], "/".join(parts[:2])
    return None, None


def _patch63_build_test_inventory() -> tuple[dict, list[str]]:
    """Build a read-only inventory from current code index artifacts. No tests are run."""
    data, errors = _code_load_current_indexes(load_chunks=False)
    files = data.get("files", [])
    manifest = data.get("manifest", {})
    test_rows: list[dict] = []
    config_rows: list[dict] = []
    logs_rows: list[dict] = []
    framework_counts: dict[str, int] = {}
    engine_counts: dict[str, dict] = {}
    by_reason: dict[str, int] = {}

    for row in files:
        is_test, reasons = _patch63_is_test_file(row)
        if not is_test:
            continue
        rel = str(row.get("relative_path", ""))
        framework = _patch63_test_framework(row, reasons)
        engine_name, engine_root = _patch63_engine_for_test(rel)
        record = {
            "relative_path": rel,
            "absolute_path": row.get("absolute_path", ""),
            "filename": row.get("filename", ""),
            "suffix": row.get("suffix", ""),
            "sha256_16": row.get("sha256_16", ""),
            "file_role": row.get("file_role", ""),
            "line_count": row.get("line_count", 0),
            "framework": framework,
            "reasons": reasons,
            "engine_name": engine_name,
            "engine_root": engine_root,
        }
        test_rows.append(record)
        framework_counts[framework] = framework_counts.get(framework, 0) + 1
        for reason in reasons:
            by_reason[reason] = by_reason.get(reason, 0) + 1
        if "config" in framework or record["filename"] in _TEST_CONFIG_NAMES:
            config_rows.append(record)
        if framework == "test_log" or "test_log_or_output" in reasons:
            logs_rows.append(record)
        if engine_root:
            rec = engine_counts.setdefault(engine_root, {"engine_name": engine_name, "engine_root": engine_root, "test_files": 0, "frameworks": {}, "samples": []})
            rec["test_files"] += 1
            rec["frameworks"][framework] = rec["frameworks"].get(framework, 0) + 1
            if len(rec["samples"]) < 8:
                rec["samples"].append(rel)

    engine_list = sorted(engine_counts.values(), key=lambda r: (-int(r.get("test_files", 0)), str(r.get("engine_root", ""))))
    test_rows.sort(key=lambda r: (str(r.get("framework", "")), str(r.get("relative_path", ""))))

    readiness = "READY_FOR_SAFE_RUNNER_DESIGN" if test_rows else "NO_TEST_FILES_FOUND"
    payload = {
        "patch": "63",
        "name": "test_inventory",
        "mode": "read_only_no_execution",
        "timestamp": datetime.datetime.now().isoformat(timespec="seconds"),
        "index_manifest": str(_code_index_paths().get("manifest")),
        "index_stats": manifest.get("stats", {}) if isinstance(manifest, dict) else {},
        "counts": {
            "indexed_files": len(files),
            "test_related_files": len(test_rows),
            "test_configs": len(config_rows),
            "test_logs": len(logs_rows),
            "engine_roots_with_tests": len(engine_list),
            "frameworks": framework_counts,
            "reasons": by_reason,
        },
        "readiness": readiness,
        "policy": {
            "execution_allowed": False,
            "future_allowed_command_shapes": _TEST_POLICY_ALLOWED_FUTURE_COMMANDS,
            "never_autorun_patterns": _TEST_POLICY_NEVER_AUTORUN_PATTERNS,
        },
        "test_files": test_rows,
        "test_configs": config_rows,
        "test_logs": logs_rows,
        "engine_test_summary": engine_list,
        "errors": errors,
    }
    return payload, errors


def _patch63_write_report(name: str, payload: dict) -> Path:
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    ts = datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")
    p = CODE_MANIFESTS_DIR / f"{ts}_{name}.json"
    p.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    return p


def _patch63_latest_inventory_report() -> Path | None:
    if not CODE_MANIFESTS_DIR.exists():
        return None
    rows = sorted(CODE_MANIFESTS_DIR.glob("*_test_inventory.json"), key=lambda p: p.stat().st_mtime, reverse=True)
    return rows[0] if rows else None


def _patch63_load_inventory_or_build() -> tuple[dict | None, Path | None, str | None]:
    latest = _patch63_latest_inventory_report()
    if latest:
        try:
            return json.loads(latest.read_text(encoding="utf-8")), latest, None
        except Exception as e:
            return None, latest, f"Cannot read latest inventory report: {e}"
    payload, _ = _patch63_build_test_inventory()
    path = _patch63_write_report("test_inventory", payload)
    return payload, path, None


