# ─── PATCH 64: SAFE TEST RUNNER ─────────────────────────────────────────────

TEST_RUN_REPORTS_DIR = FORGE_ROOT / "memory" / "test_run_reports"
PATCH_TEST_BINDINGS_DIR = FORGE_ROOT / "memory" / "patch_test_bindings"
TEST_RUN_SMOKE_DIR = FORGE_ROOT / "test_runner_smoke"
TEST_RUN_TIMEOUT_SECONDS = 45
TEST_RUN_MAX_OUTPUT_CHARS = 120_000
TEST_RUN_MAX_FILE_BYTES = 750_000


def _patch64_now_stamp() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch64_write_report(payload: dict) -> Path:
    TEST_RUN_REPORTS_DIR.mkdir(parents=True, exist_ok=True)
    ts = _patch64_now_stamp()
    name = payload.get("report_name") or "test_run"
    path = TEST_RUN_REPORTS_DIR / f"{ts}_{name}.json"
    path.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    return path


def _patch64_latest_report() -> Path | None:
    if not TEST_RUN_REPORTS_DIR.exists():
        return None
    rows = sorted(TEST_RUN_REPORTS_DIR.glob("*_test_run*.json"), key=lambda p: p.stat().st_mtime, reverse=True)
    return rows[0] if rows else None


def _patch64_resolve_report(arg: str) -> Path | None:
    arg = (arg or "latest").strip()
    if not arg or arg == "latest":
        return _patch64_latest_report()
    p = Path(os.path.expanduser(arg))
    if not p.is_absolute():
        p = TEST_RUN_REPORTS_DIR / arg
    try:
        p = Path(os.path.realpath(str(p)))
    except Exception:
        return None
    if not str(p).startswith(str(TEST_RUN_REPORTS_DIR)):
        return None
    return p if p.exists() and p.is_file() else None


def _patch64_sha16(path: Path) -> str:
    import hashlib
    h = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()[:16]


def _patch64_is_forge_owned(path: Path) -> bool:
    try:
        return str(path).startswith(str(FORGE_ROOT))
    except Exception:
        return False


def _patch64_validate_target(raw_path: str, requested_mode: str = "auto") -> dict:
    """Validate an explicit test target. This never executes anything."""
    from agents.forge.permissions import is_path_blocked, is_path_allowed

    raw_path = (raw_path or "").strip().strip('"').strip("'")
    if not raw_path:
        return {"ok": False, "reason": "missing explicit test file path"}
    if any(x in raw_path for x in ["\n", "\r", ";", "|", "&&", "||", "`", "$(", ">", "<"]):
        return {"ok": False, "reason": "path contains shell metacharacters or pipeline syntax"}
    if raw_path.startswith("-"):
        return {"ok": False, "reason": "target path may not start with an option flag"}

    path = Path(os.path.realpath(os.path.abspath(os.path.expanduser(raw_path))))
    forge_owned = _patch64_is_forge_owned(path)

    if not forge_owned:
        blocked, reason = is_path_blocked(str(path))
        if blocked:
            return {"ok": False, "reason": f"blocked path: {reason}", "path": str(path)}
        allowed, reason = is_path_allowed(str(path))
        if not allowed:
            return {"ok": False, "reason": f"outside approved/session scope: {reason}", "path": str(path)}

    if not path.exists():
        return {"ok": False, "reason": "file does not exist", "path": str(path)}
    if not path.is_file():
        return {"ok": False, "reason": "target is not a file", "path": str(path)}
    if path.is_symlink():
        return {"ok": False, "reason": "symlink targets are refused for safe test execution", "path": str(path)}
    if path.suffix.lower() != ".py":
        return {"ok": False, "reason": "Patch 64 only allows explicit Python .py files", "path": str(path)}
    try:
        size = path.stat().st_size
    except Exception as e:
        return {"ok": False, "reason": f"cannot stat file: {e}", "path": str(path)}
    if size > TEST_RUN_MAX_FILE_BYTES:
        return {"ok": False, "reason": f"file too large for Patch 64 safe runner ({size} bytes)", "path": str(path)}

    name = path.name.lower()
    is_pytest_file = name.startswith("test_") or name.endswith("_test.py")
    if requested_mode == "pytest" and not is_pytest_file:
        return {"ok": False, "reason": "pytest mode requires explicit test_*.py or *_test.py file", "path": str(path)}

    return {
        "ok": True,
        "path": str(path),
        "forge_owned": forge_owned,
        "size_bytes": size,
        "sha256_16": _patch64_sha16(path),
        "is_pytest_file": is_pytest_file,
    }


def _patch64_parse_run_arg(arg: str) -> dict:
    import shlex
    arg = (arg or "").strip()
    if not arg:
        return {"ok": False, "reason": "Usage: test-run-safe [--compile|--pytest] <explicit .py file>"}
    try:
        parts = shlex.split(arg)
    except Exception as e:
        return {"ok": False, "reason": f"cannot parse argument safely: {e}"}
    mode = "auto"
    if parts and parts[0] in ("--compile", "--pytest"):
        mode = parts[0][2:]
        parts = parts[1:]
    if len(parts) != 1:
        return {"ok": False, "reason": "Patch 64 accepts exactly one explicit file path, not a shell command"}
    return {"ok": True, "mode": mode, "target": parts[0]}


def _patch64_build_command(target: Path, mode: str, is_pytest_file: bool) -> tuple[list[str] | None, str, str | None]:
    """Return argv, run_type, refusal_reason. No shell strings."""
    import shutil
    if mode == "auto":
        mode = "pytest" if is_pytest_file else "compile"
    if mode == "compile":
        return [sys.executable, "-m", "py_compile", str(target)], "python_py_compile", None
    if mode == "pytest":
        if shutil.which("pytest") is None:
            return None, "python_pytest_explicit_file", "pytest executable not found in current environment"
        return [sys.executable, "-m", "pytest", str(target), "-q"], "python_pytest_explicit_file", None
    return None, "unknown", f"unsupported mode: {mode}"


def _patch64_execute_safe_test(arg: str, session_id: str, source: str = "manual") -> dict:
    """Deterministic allowlisted test execution. Uses subprocess with shell=False."""
    from agents.forge.memory import write_audit_entry
    import subprocess

    parsed = _patch64_parse_run_arg(arg)
    if not parsed.get("ok"):
        payload = {
            "patch": "64",
            "report_name": "test_run_refused",
            "source": source,
            "status": "REFUSED",
            "reason": parsed.get("reason"),
            "argv": [],
            "shell": False,
            "timestamp": datetime.datetime.now().isoformat(timespec="seconds"),
        }
        report = _patch64_write_report(payload)
        payload["report_path"] = str(report)
        write_audit_entry(session_id, "TEST_RUN_REFUSED", str(report), "no execution", str(parsed.get("reason", ""))[:160])
        return payload

    mode = parsed["mode"]
    validation = _patch64_validate_target(parsed["target"], requested_mode=("pytest" if mode == "pytest" else "auto"))
    if not validation.get("ok"):
        payload = {
            "patch": "64",
            "report_name": "test_run_refused",
            "source": source,
            "status": "REFUSED",
            "reason": validation.get("reason"),
            "target": validation.get("path") or parsed["target"],
            "argv": [],
            "shell": False,
            "timestamp": datetime.datetime.now().isoformat(timespec="seconds"),
        }
        report = _patch64_write_report(payload)
        payload["report_path"] = str(report)
        write_audit_entry(session_id, "TEST_RUN_REFUSED", str(payload.get("target")), "no execution", str(validation.get("reason", ""))[:160])
        return payload

    target = Path(validation["path"])
    argv, run_type, reason = _patch64_build_command(target, mode, bool(validation.get("is_pytest_file")))
    if not argv:
        payload = {
            "patch": "64",
            "report_name": "test_run_refused",
            "source": source,
            "status": "REFUSED",
            "reason": reason,
            "target": str(target),
            "target_sha256_16": validation.get("sha256_16"),
            "argv": [],
            "shell": False,
            "timestamp": datetime.datetime.now().isoformat(timespec="seconds"),
        }
        report = _patch64_write_report(payload)
        payload["report_path"] = str(report)
        write_audit_entry(session_id, "TEST_RUN_REFUSED", str(target), "no execution", str(reason)[:160])
        return payload

    started = datetime.datetime.now()
    try:
        proc = subprocess.run(
            argv,
            cwd=str(target.parent),
            shell=False,
            capture_output=True,
            text=True,
            timeout=TEST_RUN_TIMEOUT_SECONDS,
        )
        timed_out = False
        exit_code = int(proc.returncode)
        stdout = proc.stdout or ""
        stderr = proc.stderr or ""
    except subprocess.TimeoutExpired as e:
        timed_out = True
        exit_code = 124
        stdout = e.stdout or ""
        stderr = e.stderr or f"Timed out after {TEST_RUN_TIMEOUT_SECONDS} seconds"
    ended = datetime.datetime.now()
    combined = (stdout or "") + ("\n" if stdout and stderr else "") + (stderr or "")
    if len(combined) > TEST_RUN_MAX_OUTPUT_CHARS:
        combined = combined[:TEST_RUN_MAX_OUTPUT_CHARS] + "\n...[output truncated by Forge Patch 64]"

    status = "PASS" if exit_code == 0 and not timed_out else "FAIL"
    payload = {
        "patch": "64",
        "report_name": "test_run",
        "source": source,
        "status": status,
        "run_type": run_type,
        "target": str(target),
        "target_sha256_16": validation.get("sha256_16"),
        "forge_owned_target": bool(validation.get("forge_owned")),
        "argv": argv,
        "shell": False,
        "cwd": str(target.parent),
        "timeout_seconds": TEST_RUN_TIMEOUT_SECONDS,
        "timed_out": timed_out,
        "exit_code": exit_code,
        "started_at": started.isoformat(timespec="seconds"),
        "ended_at": ended.isoformat(timespec="seconds"),
        "duration_seconds": round((ended - started).total_seconds(), 3),
        "stdout": stdout[:TEST_RUN_MAX_OUTPUT_CHARS],
        "stderr": stderr[:TEST_RUN_MAX_OUTPUT_CHARS],
        "combined_output": combined,
        "policy": {
            "no_shell": True,
            "explicit_file_only": True,
            "no_install_commands": True,
            "no_network_commands": True,
            "no_model_generated_command_execution": True,
        },
    }
    report = _patch64_write_report(payload)
    payload["report_path"] = str(report)
    audit_tool = "TEST_RUN_PASS" if status == "PASS" else "TEST_RUN_FAIL"
    write_audit_entry(session_id, audit_tool, str(target), f"exit={exit_code}", f"type={run_type} report={report}")
    return payload


