# ─── PATCH 65: SANDBOX + TEST BINDING GATE ─────────────────────────────────

_PATCH65_ALLOWED_TEST_RUN_TYPES = {"python_py_compile", "python_pytest_file"}


def _patch65_sha16(path: Path) -> str:
    import hashlib
    h = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()[:16]


def _patch65_resolve_binding(arg: str) -> Path | None:
    arg = (arg or "latest").strip()
    if not PATCH_TEST_BINDINGS_DIR.exists():
        return None
    if not arg or arg == "latest":
        rows = sorted(PATCH_TEST_BINDINGS_DIR.glob("*.json"), key=lambda p: p.stat().st_mtime, reverse=True)
        return rows[0] if rows else None
    p = Path(os.path.expanduser(arg))
    if not p.is_absolute():
        p = PATCH_TEST_BINDINGS_DIR / arg
    try:
        p = Path(os.path.realpath(str(p)))
    except Exception:
        return None
    if not str(p).startswith(str(PATCH_TEST_BINDINGS_DIR)):
        return None
    return p if p.exists() and p.is_file() else None


def _patch65_read_apply_plan_fields(apply_plan_arg: str) -> dict:
    apply_plan_path, err = _patch60_resolve_apply_plan(apply_plan_arg)
    if err:
        return {"ok": False, "stage": "resolve_apply_plan", "reason": err, "apply_plan_path": str(apply_plan_arg)}
    try:
        plan_text = apply_plan_path.read_text(encoding="utf-8", errors="replace")
    except Exception as e:
        return {"ok": False, "stage": "read_apply_plan", "reason": f"Cannot read apply plan: {e}", "apply_plan_path": str(apply_plan_path)}
    fields = _patch60_parse_apply_plan_text(plan_text)
    issues = []
    if not fields.get("target_file"):
        issues.append("cannot parse target_file")
    if not str(fields.get("original_sha256", "")).strip():
        issues.append("cannot parse original_sha256")
    if not str(fields.get("future_sha256", "")).strip():
        issues.append("cannot parse future_sha256")
    if issues:
        return {"ok": False, "stage": "parse_apply_plan", "reason": "; ".join(issues), "apply_plan_path": str(apply_plan_path), "fields": fields}
    return {
        "ok": True,
        "apply_plan_path": str(apply_plan_path.expanduser().resolve()),
        "target_file": str(fields.get("target_file", "")),
        "original_sha256": str(fields.get("original_sha256", "")).strip()[:16],
        "future_sha256": str(fields.get("future_sha256", "")).strip()[:16],
        "fields": fields,
    }


def _patch65_read_test_report(report_arg: str) -> dict:
    report_path = _patch64_resolve_report(report_arg)
    if not report_path:
        return {"ok": False, "stage": "resolve_test_report", "reason": f"Test report not found: {report_arg or 'latest'}", "test_report_path": str(report_arg)}
    try:
        data = json.loads(report_path.read_text(encoding="utf-8"))
    except Exception as e:
        return {"ok": False, "stage": "read_test_report", "reason": f"Cannot read test report: {e}", "test_report_path": str(report_path)}
    issues = []
    if data.get("status") != "PASS":
        issues.append(f"test report status is {data.get('status')}, not PASS")
    if data.get("shell") is not False:
        issues.append("test report does not prove shell=False")
    if data.get("exit_code") != 0:
        issues.append(f"test exit_code is {data.get('exit_code')}, not 0")
    if data.get("timed_out") is True:
        issues.append("test report timed out")
    if str(data.get("run_type", "")) not in _PATCH65_ALLOWED_TEST_RUN_TYPES:
        issues.append(f"run_type {data.get('run_type')} is not in Patch 65 allowlist")
    if not data.get("target"):
        issues.append("test report missing target")
    return {
        "ok": len(issues) == 0,
        "stage": "validate_test_report",
        "reason": "; ".join(issues) if issues else "PASS report is acceptable",
        "test_report_path": str(report_path.expanduser().resolve()),
        "test_report_sha16": _patch65_sha16(report_path),
        "report": data,
        "issues": issues,
    }



# ─── PATCH 66: TEST BINDING RELEVANCE GUARD ────────────────────────────────

_PATCH66_SMOKE_TARGET_ROOT = FORGE_ROOT / "patch_sandbox_smoke_tests"
_PATCH66_RELEVANCE_POLICY_VERSION = "patch66_relevance_guard_v1"


def _patch66_realpath_str(value: str) -> str:
    try:
        return str(Path(os.path.realpath(os.path.expanduser(str(value)))) )
    except Exception:
        return str(value or "")


def _patch66_is_under(path_value: str, root: Path) -> bool:
    try:
        path = Path(_patch66_realpath_str(path_value))
        root = Path(os.path.realpath(str(root)))
        path.relative_to(root)
        return True
    except Exception:
        return False


def _patch66_known_root(path_value: str) -> str:
    """Return a stable runtime root such as aiweb/engines/name or engines/name."""
    s = _patch66_realpath_str(path_value)
    marker = "/home/nic/aiweb/"
    rel = s.split(marker, 1)[1] if marker in s else None
    if rel is None:
        marker2 = "/home/nic/"
        rel = s.split(marker2, 1)[1] if marker2 in s else s
    parts = [p for p in rel.split("/") if p]
    for prefix in ("aiweb", "projects"):
        if parts and parts[0] == prefix:
            # aiweb/engines/<name>, aiweb/agents/<name>, projects/<proj>/engines/<name>
            if len(parts) >= 3 and parts[1] in {"engines", "agents", "runtime_wrappers", "symbolic_layers"}:
                return "/".join(parts[:3])
            if len(parts) >= 4 and parts[2] in {"engines", "agents", "runtime_wrappers", "symbolic_layers"}:
                return "/".join(parts[:4])
    if len(parts) >= 2 and parts[0] in {"engines", "agents", "runtime_wrappers", "symbolic_layers"}:
        return "/".join(parts[:2])
    if len(parts) >= 3 and parts[0] == "forge" and parts[1] == "patch_sandbox_smoke_tests":
        return "forge/patch_sandbox_smoke_tests"
    return ""


def _patch66_evaluate_test_relevance(apply_info: dict, report_data: dict) -> dict:
    """Deterministically decide whether a PASS safe test is relevant to this apply plan."""
    patch_target = _patch66_realpath_str(apply_info.get("target_file", ""))
    test_target = _patch66_realpath_str(report_data.get("target", ""))
    run_type = str(report_data.get("run_type", ""))
    patch_suffix = Path(patch_target).suffix.lower()
    test_suffix = Path(test_target).suffix.lower()

    if not patch_target or not test_target:
        return {"ok": False, "method": "missing_path", "reason": "apply target or test target missing"}

    # Forge-owned smoke plans are allowed to prove the gate machinery without validating AI.Web.
    if _patch66_is_under(patch_target, _PATCH66_SMOKE_TARGET_ROOT):
        if _patch66_is_under(test_target, FORGE_ROOT):
            return {
                "ok": True,
                "method": "forge_owned_smoke_exception",
                "reason": "Forge-owned smoke target may bind to a Forge-owned PASS safe test only",
                "project_file_relevance_required": False,
            }
        return {"ok": False, "method": "smoke_exception_refused", "reason": "smoke apply plan bound to non-Forge test target"}

    # Real project files require relevance.
    if patch_target == test_target:
        if run_type == "python_py_compile" and patch_suffix == ".py":
            return {"ok": True, "method": "exact_python_compile_target", "reason": "changed Python file was compiled directly", "project_file_relevance_required": True}
        if run_type == "python_pytest_file" and test_suffix == ".py":
            return {"ok": True, "method": "exact_pytest_target", "reason": "explicit pytest file is itself the patch target", "project_file_relevance_required": True}
        return {"ok": True, "method": "exact_target_match", "reason": "test target exactly matches patch target", "project_file_relevance_required": True}

    patch_root = _patch66_known_root(patch_target)
    test_root = _patch66_known_root(test_target)
    test_name = Path(test_target).name.lower()
    test_is_pytest = run_type == "python_pytest_file" or test_name.startswith("test_") or "/test" in test_target.lower()
    if patch_root and patch_root == test_root and test_is_pytest:
        return {
            "ok": True,
            "method": "same_runtime_root_pytest",
            "reason": f"test target shares runtime root {patch_root} with patch target",
            "project_file_relevance_required": True,
        }

    return {
        "ok": False,
        "method": "unrelated_test_target",
        "reason": "safe test target is not the changed file, not a same-root pytest file, and not a Forge-owned smoke exception",
        "project_file_relevance_required": True,
        "patch_root": patch_root,
        "test_root": test_root,
    }


def _patch66_binding_relevance(binding: dict, apply_info: dict, report_data: dict | None = None) -> dict:
    if report_data is None:
        report_path = Path(str(binding.get("test_report_path", ""))).expanduser()
        try:
            report_data = json.loads(report_path.read_text(encoding="utf-8"))
        except Exception as e:
            return {"ok": False, "method": "cannot_read_test_report", "reason": f"cannot read test report for relevance: {e}"}
    return _patch66_evaluate_test_relevance(apply_info, report_data)


def _patch65_binding_matches_apply(binding: dict, binding_path: Path, apply_info: dict) -> tuple[bool, list[str]]:
    issues = []
    if binding.get("status") != "TEST_BOUND":
        issues.append(f"binding status is {binding.get('status')}, not TEST_BOUND")
    expected_apply = str(Path(str(apply_info.get("apply_plan_path", ""))).expanduser().resolve())
    bind_apply = str(binding.get("apply_plan_path", ""))
    try:
        bind_apply = str(Path(bind_apply).expanduser().resolve())
    except Exception:
        pass
    if bind_apply != expected_apply:
        issues.append("apply_plan_path mismatch")
    if str(binding.get("target_file", "")) != str(apply_info.get("target_file", "")):
        issues.append("target_file mismatch")
    if str(binding.get("original_sha256", "")).strip()[:16] != str(apply_info.get("original_sha256", "")).strip()[:16]:
        issues.append("original_sha256 mismatch")
    if str(binding.get("future_sha256", "")).strip()[:16] != str(apply_info.get("future_sha256", "")).strip()[:16]:
        issues.append("future_sha256 mismatch")

    report_path = Path(str(binding.get("test_report_path", ""))).expanduser()
    if not report_path.exists():
        issues.append("bound test report no longer exists")
    else:
        try:
            current_report_sha = _patch65_sha16(report_path)
            if current_report_sha != str(binding.get("test_report_sha16", "")):
                issues.append("bound test report hash changed")
            report_data = json.loads(report_path.read_text(encoding="utf-8"))
            if report_data.get("status") != "PASS":
                issues.append("bound test report is no longer PASS")
            if report_data.get("shell") is not False:
                issues.append("bound test report does not prove shell=False")
            if report_data.get("exit_code") != 0:
                issues.append("bound test report exit_code is not 0")
            if report_data.get("timed_out") is True:
                issues.append("bound test report timed out")
            if str(report_data.get("run_type", "")) not in _PATCH65_ALLOWED_TEST_RUN_TYPES:
                issues.append("bound test report run_type is not allowlisted")
            relevance = _patch66_binding_relevance(binding, apply_info, report_data)
            if not relevance.get("ok"):
                issues.append("test relevance guard blocked: " + str(relevance.get("reason", "unrelated test")))
        except Exception as e:
            issues.append(f"cannot re-read bound test report: {e}")
    return (len(issues) == 0), issues


def _patch65_find_matching_test_binding(apply_info: dict) -> dict:
    if not PATCH_TEST_BINDINGS_DIR.exists():
        return {"ok": False, "reason": f"No patch test binding directory exists: {PATCH_TEST_BINDINGS_DIR}", "checked": 0, "candidates": []}
    rows = sorted(PATCH_TEST_BINDINGS_DIR.glob("*.json"), key=lambda p: p.stat().st_mtime, reverse=True)
    checked = 0
    near = []
    for path in rows:
        try:
            binding = json.loads(path.read_text(encoding="utf-8"))
        except Exception as e:
            near.append({"path": str(path), "reason": f"unreadable JSON: {e}"})
            continue
        checked += 1
        ok, issues = _patch65_binding_matches_apply(binding, path, apply_info)
        if ok:
            relevance = _patch66_binding_relevance(binding, apply_info)
            return {"ok": True, "binding_path": str(path), "binding": binding, "checked": checked, "test_report_path": binding.get("test_report_path"), "test_target": binding.get("test_target"), "run_type": binding.get("run_type"), "relevance": relevance, "relevance_method": relevance.get("method"), "relevance_reason": relevance.get("reason")}
        if len(near) < 8:
            near.append({"path": str(path), "reason": "; ".join(issues[:4]) or "not matching"})
    return {"ok": False, "reason": "No matching TEST_BOUND binding found for this apply plan, target, original SHA, and future SHA.", "checked": checked, "candidates": near}


def _patch65_apply_plan_test_gate_check(apply_plan_arg: str) -> dict:
    apply_info = _patch65_read_apply_plan_fields(apply_plan_arg)
    if not apply_info.get("ok"):
        return apply_info
    match = _patch65_find_matching_test_binding(apply_info)
    match.update({
        "apply_plan_path": apply_info.get("apply_plan_path"),
        "target_file": apply_info.get("target_file"),
        "original_sha256": apply_info.get("original_sha256"),
        "future_sha256": apply_info.get("future_sha256"),
        "stage": "test_binding_match",
    })
    return match


def cmd_patch_test_bind(arg: str, session_id: str) -> None:
    """Bind one apply plan to one successful safe test report. Writes only Forge-owned binding JSON."""
    from agents.forge.memory import write_audit_entry
    import shlex
    raw = (arg or "").strip()
    try:
        parts = shlex.split(raw) if raw else []
    except Exception as e:
        parts = []
        parse_error = str(e)
    else:
        parse_error = ""
    if len(parts) == 0:
        apply_arg, report_arg = "latest", "latest"
    elif len(parts) == 1:
        apply_arg, report_arg = parts[0], "latest"
    elif len(parts) == 2:
        apply_arg, report_arg = parts[0], parts[1]
    else:
        print()
        print("── Patch Test Bind ─────────────────────────────────")
        print("  Status : REFUSED")
        print("  Usage  : patch-test-bind [apply_plan|latest] [test_report|latest]")
        print("  Reason : expected at most two arguments")
        if parse_error:
            print(f"  Parse  : {parse_error}")
        print("──────────────────────────────────────────────────────")
        print()
        return

    apply_info = _patch65_read_apply_plan_fields(apply_arg)
    test_info = _patch65_read_test_report(report_arg)
    print()
    print("── Patch Test Bind ─────────────────────────────────")
    print("  Mode       : BINDING WRITE — Forge-owned JSON only")
    print("  Apply plan : %s" % apply_info.get("apply_plan_path"))
    if apply_info.get("target_file"):
        print("  Target     : %s" % apply_info.get("target_file"))
        print("  Original   : %s" % apply_info.get("original_sha256"))
        print("  Future     : %s" % apply_info.get("future_sha256"))
    print("  Test report: %s" % test_info.get("test_report_path"))

    if not apply_info.get("ok") or not test_info.get("ok"):
        reason = apply_info.get("reason") if not apply_info.get("ok") else test_info.get("reason")
        print("  Status     : REFUSED")
        print(f"  Reason     : {reason}")
        print("──────────────────────────────────────────────────────")
        print()
        write_audit_entry(session_id, "PATCH_TEST_BIND_REFUSED", str(apply_arg), "no-write", str(reason)[:180])
        return

    report = test_info.get("report") or {}
    target_match = str(report.get("target", "")) == str(apply_info.get("target_file", ""))
    relevance = _patch66_evaluate_test_relevance(apply_info, report)
    PATCH_TEST_BINDINGS_DIR.mkdir(parents=True, exist_ok=True)
    ts = datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")
    safe_name = re.sub(r"[^A-Za-z0-9_.-]+", "_", Path(str(apply_info.get("apply_plan_path"))).name)[:120]
    binding_path = PATCH_TEST_BINDINGS_DIR / f"{ts}_TEST_BINDING_{safe_name}.json"
    binding = {
        "patch": "65",
        "status": "TEST_BOUND",
        "binding_policy": "sandbox_plus_safe_test_gate_v1",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "session_id": session_id,
        "apply_plan_path": apply_info.get("apply_plan_path"),
        "target_file": apply_info.get("target_file"),
        "original_sha256": apply_info.get("original_sha256"),
        "future_sha256": apply_info.get("future_sha256"),
        "test_report_path": test_info.get("test_report_path"),
        "test_report_sha16": test_info.get("test_report_sha16"),
        "test_status": report.get("status"),
        "test_target": report.get("target"),
        "test_target_sha16": report.get("target_sha256_16"),
        "test_target_matches_patch_target": target_match,
        "test_relevance_ok": bool(relevance.get("ok")),
        "test_relevance_method": relevance.get("method"),
        "test_relevance_reason": relevance.get("reason"),
        "test_relevance_policy": _PATCH66_RELEVANCE_POLICY_VERSION,
        "project_file_relevance_required": relevance.get("project_file_relevance_required"),
        "run_type": report.get("run_type"),
        "exit_code": report.get("exit_code"),
        "shell": report.get("shell"),
        "timed_out": report.get("timed_out"),
        "argv": report.get("argv", []),
        "notes": [
            "Patch 65 does not infer test relevance from the LLM.",
            "This binding is a deterministic receipt linking an apply plan to a PASS safe test report.",
            "Future patches may require stricter target-to-test relationship rules.",
        ],
    }
    binding_path.write_text(json.dumps(binding, indent=2, ensure_ascii=False), encoding="utf-8")
    print("  Status     : TEST_BOUND")
    print("  Binding    : %s" % binding_path)
    print("  Test status: %s  exit=%s  shell=%s" % (report.get("status"), report.get("exit_code"), report.get("shell")))
    print("  Target/test match: %s" % target_match)
    print("  Relevance  : %s via %s" % ("PASS" if relevance.get("ok") else "BLOCKED", relevance.get("method")))
    print("  Relevance reason: %s" % relevance.get("reason"))
    print("  Result     : PATCH_TEST_BINDING_WRITTEN")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "PATCH_TEST_BINDING_WRITTEN", str(binding_path), "forge-owned", f"plan={Path(str(apply_info.get('apply_plan_path'))).name} report={Path(str(test_info.get('test_report_path'))).name}")


def cmd_patch_test_gate_check(apply_plan_arg: str, session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    result = _patch65_apply_plan_test_gate_check(apply_plan_arg or "latest")
    print()
    print("── Patch Test Gate Check ────────────────────────────")
    print("  Mode      : READ ONLY")
    print("  Rule      : patch-apply requires matching TEST_BOUND safe test receipt")
    print(f"  Apply plan: {result.get('apply_plan_path')}")
    if result.get("target_file"):
        print(f"  Target    : {result.get('target_file')}")
        print(f"  Original  : {result.get('original_sha256')}")
        print(f"  Future    : {result.get('future_sha256')}")
    if result.get("ok"):
        print("  Status    : PASS")
        print(f"  Binding   : {result.get('binding_path')}")
        print(f"  Test      : {result.get('test_report_path')}")
        print(f"  Run type  : {result.get('run_type')} target={result.get('test_target')}")
        print(f"  Relevance : {result.get('relevance_method')} — {result.get('relevance_reason')}")
        print("  Result    : PATCH_TEST_GATE_READY")
        write_audit_entry(session_id, "PATCH_TEST_GATE_CHECK_PASS", str(result.get('apply_plan_path')), "read-only", f"binding={result.get('binding_path')}")
    else:
        print("  Status    : BLOCKED")
        print(f"  Reason    : {result.get('reason')}")
        if result.get("candidates"):
            print("  Nearby bindings checked:")
            for row in result.get("candidates", [])[:5]:
                print(f"    - {row.get('path')} :: {row.get('reason')}")
        print("  Required  : run a safe test, then patch-test-bind for this exact apply plan")
        print("  Result    : PATCH_TEST_GATE_BLOCKED")
        write_audit_entry(session_id, "PATCH_TEST_GATE_CHECK_BLOCKED", str(result.get('apply_plan_path')), "read-only", str(result.get('reason', 'blocked'))[:180])
    print("──────────────────────────────────────────────────────")
    print()


