# ─── PATCH 67: APPLY GATE MATRIX (READ ONLY) ────────────────────────────────

_PATCH67_GATE_VERSION = "patch67_apply_gate_matrix_v1"


def _patch67_disk_truth_check(apply_info: dict) -> dict:
    """Read the target from disk and compare current SHA to the apply-plan original SHA."""
    if not apply_info.get("ok"):
        return {"ok": False, "status": "BLOCKED", "reason": apply_info.get("reason", "apply plan invalid")}
    target_raw = str(apply_info.get("target_file", ""))
    original = str(apply_info.get("original_sha256", "")).strip()[:16]
    if not target_raw:
        return {"ok": False, "status": "BLOCKED", "reason": "apply plan has no target_file"}
    try:
        target = Path(os.path.realpath(os.path.abspath(os.path.expanduser(target_raw))))
    except Exception as e:
        return {"ok": False, "status": "BLOCKED", "reason": f"cannot resolve target path: {e}", "target_file": target_raw}
    if not target.exists():
        return {"ok": False, "status": "BLOCKED", "reason": "target file does not exist", "target_file": str(target)}
    if not target.is_file():
        return {"ok": False, "status": "BLOCKED", "reason": "target is not a regular file", "target_file": str(target)}
    if target.is_symlink():
        return {"ok": False, "status": "BLOCKED", "reason": "target is a symlink", "target_file": str(target)}
    try:
        content = target.read_text(encoding="utf-8", errors="replace")
    except Exception as e:
        return {"ok": False, "status": "BLOCKED", "reason": f"cannot read target text: {e}", "target_file": str(target)}
    current = _patch60_sha16(content)
    size = len(content.encode("utf-8"))
    ok = bool(original and current == original)
    return {
        "ok": ok,
        "status": "PASS" if ok else "BLOCKED",
        "reason": "current disk SHA matches apply-plan original SHA" if ok else f"current SHA {current} does not match apply-plan original SHA {original}",
        "target_file": str(target),
        "current_sha256": current,
        "original_sha256": original,
        "size_bytes": size,
    }


def _patch67_stage_row(stage_id: str, title: str, result: dict, pass_label: str = "PASS") -> dict:
    ok = bool(result.get("ok"))
    reason = result.get("reason") or result.get("stage") or (pass_label if ok else "blocked")
    return {
        "stage_id": stage_id,
        "title": title,
        "ok": ok,
        "status": pass_label if ok else "BLOCKED",
        "reason": str(reason),
        "details": result,
    }


def _patch67_apply_gate_matrix_payload(apply_plan_arg: str = "latest") -> dict:
    """Build the full read-only apply readiness matrix for one apply plan."""
    apply_info = _patch65_read_apply_plan_fields(apply_plan_arg or "latest")
    stages = []
    stages.append(_patch67_stage_row("apply_plan_parse", "Apply plan parses", apply_info))

    disk = _patch67_disk_truth_check(apply_info)
    stages.append(_patch67_stage_row("disk_truth", "Current disk SHA matches plan", disk))

    if apply_info.get("ok"):
        sandbox = _patch62_apply_plan_gate_check(str(apply_info.get("apply_plan_path")))
    else:
        sandbox = {"ok": False, "reason": "apply plan invalid; sandbox gate not checked"}
    stages.append(_patch67_stage_row("sandbox_gate", "Matching SANDBOX_APPLIED report", sandbox))

    if apply_info.get("ok"):
        test_gate = _patch65_apply_plan_test_gate_check(str(apply_info.get("apply_plan_path")))
    else:
        test_gate = {"ok": False, "reason": "apply plan invalid; test gate not checked"}
    stages.append(_patch67_stage_row("test_gate", "Matching TEST_BOUND safe test receipt", test_gate))

    relevance = {"ok": False, "reason": "no matching TEST_BOUND binding to evaluate"}
    if test_gate.get("ok") and test_gate.get("binding_path"):
        relevance = _patch66_relevance_check_from_binding_path(str(test_gate.get("binding_path")))
    elif test_gate.get("relevance"):
        rel = test_gate.get("relevance") or {}
        relevance = {"ok": bool(rel.get("ok")), "reason": rel.get("reason"), "method": rel.get("method")}
    stages.append(_patch67_stage_row("test_relevance", "Bound safe test is relevant", relevance))

    eligible = all(row.get("ok") for row in stages)
    first_block = next((row for row in stages if not row.get("ok")), None)
    return {
        "report_type": "PATCH67_APPLY_GATE_MATRIX_READ_ONLY",
        "gate_version": _PATCH67_GATE_VERSION,
        "timestamp": datetime.datetime.now().isoformat(timespec="seconds"),
        "read_only": True,
        "eligible_for_real_apply": eligible,
        "result": "PATCH_APPLY_ELIGIBLE" if eligible else "PATCH_APPLY_BLOCKED",
        "first_blocking_stage": first_block.get("stage_id") if first_block else None,
        "first_blocking_reason": first_block.get("reason") if first_block else None,
        "apply_plan_arg": apply_plan_arg or "latest",
        "apply_plan_path": apply_info.get("apply_plan_path"),
        "target_file": apply_info.get("target_file"),
        "original_sha256": apply_info.get("original_sha256"),
        "future_sha256": apply_info.get("future_sha256"),
        "stages": stages,
    }


def _patch67_print_matrix(payload: dict, detailed: bool = False) -> None:
    print()
    print("── Patch Apply Gate Matrix ──────────────────────────")
    print("  Mode      : READ ONLY")
    print(f"  Version   : {payload.get('gate_version')}")
    print(f"  Apply plan: {payload.get('apply_plan_path')}")
    if payload.get("target_file"):
        print(f"  Target    : {payload.get('target_file')}")
        print(f"  Original  : {payload.get('original_sha256')}")
        print(f"  Future    : {payload.get('future_sha256')}")
    print(f"  Eligible  : {'YES' if payload.get('eligible_for_real_apply') else 'NO'}")
    if not payload.get("eligible_for_real_apply"):
        print(f"  Blocked at: {payload.get('first_blocking_stage')}")
        print(f"  Reason    : {payload.get('first_blocking_reason')}")
    print()
    print("  Gate checklist:")
    for row in payload.get("stages", []):
        mark = "✓" if row.get("ok") else "✗"
        print(f"    {mark} {row.get('title'):<42} {row.get('status')}")
        reason = str(row.get("reason") or "")
        if reason:
            print(f"      - {reason[:220]}")
        if detailed:
            details = row.get("details") or {}
            if row.get("stage_id") == "sandbox_gate" and details.get("report_path"):
                print(f"      report: {details.get('report_path')}")
            if row.get("stage_id") == "test_gate" and details.get("binding_path"):
                print(f"      binding: {details.get('binding_path')}")
            if row.get("stage_id") == "test_relevance" and details.get("method"):
                print(f"      method: {details.get('method')}")
    print(f"  Result    : {payload.get('result')}")
    print("──────────────────────────────────────────────────────")
    print()


