# ─── ENTRY POINT ──────────────────────────────────────────────────────────────

def cmd_add(path_arg: str, mode: str = "core", preview_only: bool = False):
    """
    forge add <path> [--mode core|docs|logs|all] [--preview]

    Scan a path, show inclusion preview, ask for approval, then index into ChromaDB.
    Uses approved_paths.json + blocked_paths.json only. Session scope is not consulted.

    --mode core    Source and high-signal files only. DEFAULT.
    --mode docs    Documentation files only.
    --mode logs    Core files plus .log, .jsonl, .trace files.
    --mode all     Broad scan. Requires extra confirmation if over 1000 files.

    --preview / --dry-run
                   Scan and show detailed report without indexing anything.
    """
    from agents.forge.knowledge_base import (
        scan_for_indexing,
        index_path,
        check_embed_model_available,
        get_kb_stats,
        EMBED_MODEL,
        KB_DIR,
        INDEXING_MODES,
        LARGE_INDEX_THRESHOLD,
    )
    from agents.forge.permissions import (
        get_approved_paths,
        is_path_blocked,
        _is_under_any,
    )
    from agents.forge.memory import write_audit_entry

    if mode not in INDEXING_MODES:
        print(f"[forge] ERROR: Unknown mode '{mode}'. Choose from: {list(INDEXING_MODES)}")
        sys.exit(1)

    path = os.path.realpath(os.path.abspath(os.path.expanduser(path_arg)))

    # Generate KB session ID
    kb_session_id = f"kb_{datetime.datetime.now().strftime('%Y_%m_%d_%H%M%S')}"

    # Check 1: approved
    approved = get_approved_paths()
    if not approved:
        print(f"[forge] ERROR: No approved paths configured.")
        print(f"[forge] Run 'python main.py approve {path}' first.")
        sys.exit(1)
    if not _is_under_any(path, approved):
        print(f"[forge] ERROR: '{path}' is not in approved_paths.json.")
        print(f"[forge] Approved: {approved}")
        print(f"[forge] Run 'python main.py approve {path}' to add it.")
        sys.exit(1)

    # Check 2: not blocked
    blocked, reason = is_path_blocked(path)
    if blocked:
        print(f"[forge] ERROR: Path is blocked. {reason}")
        sys.exit(1)

    # Check 3: exists
    if not os.path.exists(path):
        print(f"[forge] ERROR: Path does not exist: {path}")
        sys.exit(1)

    # Check embedding model (skip in preview-only mode)
    if not preview_only:
        model_ok, model_msg = check_embed_model_available()
        if not model_ok:
            print(f"[forge] ERROR: {model_msg}")
            sys.exit(1)
        print(f"[forge] Embedding model: {EMBED_MODEL} ✓")

    # AUDIT: KB_SCAN_START
    write_audit_entry(
        session_id=kb_session_id,
        tool="KB_SCAN_START",
        path=path,
        lines="-",
        reason=f"forge add | mode={mode} | preview={preview_only} | model={EMBED_MODEL}"
    )

    # Scan with session scope override
    import agents.forge.permissions as perms
    orig_session = perms.get_session_paths
    perms.get_session_paths = lambda: [path]
    print(f"[forge] Scanning {path}  [mode: {mode}] ...")
    try:
        scan = scan_for_indexing(path, mode=mode)
    finally:
        perms.get_session_paths = orig_session

    # AUDIT: KB_SCAN_PREVIEW
    write_audit_entry(
        session_id=kb_session_id,
        tool="KB_SCAN_PREVIEW",
        path=path,
        lines="-",
        reason=(
            f"mode={mode} | "
            f"to_index={len(scan.will_index)} | "
            f"already_current={len(scan.already_current)} | "
            f"excluded={len(scan.will_skip)}"
        )
    )

    # ── PREVIEW / DRY RUN MODE ──
    if preview_only:
        print(scan.detailed_preview())
        write_audit_entry(
            session_id=kb_session_id,
            tool="KB_INDEX_COMPLETE",
            path=path,
            lines="-",
            reason=f"DRY RUN — no files indexed | mode={mode}"
        )
        return

    # ── NORMAL MODE: show short summary then ask ──
    print("\n── Indexing Preview ──────────────────────────────────")
    print(scan.summary())
    print("──────────────────────────────────────────────────────")

    if scan.is_empty():
        print("\n[forge] Nothing new to index.")
        if scan.already_current:
            print(f"[forge] {len(scan.already_current)} files are already current.")
        write_audit_entry(
            session_id=kb_session_id,
            tool="KB_INDEX_COMPLETE",
            path=path,
            lines="-",
            reason="nothing_to_index | all files already current"
        )
        return

    # ── 1000-FILE GATE ──
    if len(scan.will_index) > LARGE_INDEX_THRESHOLD:
        print()
        print(f"  ⚠️  WARNING: This index contains {len(scan.will_index):,} files.")
        print(f"     That is more than {LARGE_INDEX_THRESHOLD} files.")
        print(f"     Indexing will take significant time and disk space.")
        print()
        confirm_large = input(
            f"  Type INDEX (all caps) to continue, or anything else to cancel: "
        ).strip()
        if confirm_large != "INDEX":
            write_audit_entry(
                session_id=kb_session_id,
                tool="KB_INDEX_CANCELLED",
                path=path,
                lines="-",
                reason=f"large index cancelled by user ({len(scan.will_index)} files)"
            )
            print("[forge] Indexing cancelled.")
            return
    else:
        # Normal approval
        print()
        confirm = input(
            f"  Index {len(scan.will_index)} files into the local knowledge base? [y/n]: "
        ).strip().lower()
        if confirm != "y":
            write_audit_entry(
                session_id=kb_session_id,
                tool="KB_INDEX_CANCELLED",
                path=path,
                lines="-",
                reason="user declined indexing"
            )
            print("[forge] Indexing cancelled. No files were changed.")
            return

    # AUDIT: KB_INDEX_APPROVED
    write_audit_entry(
        session_id=kb_session_id,
        tool="KB_INDEX_APPROVED",
        path=path,
        lines="-",
        reason=f"user approved | mode={mode} | files_to_index={len(scan.will_index)}"
    )

    project_name = os.path.basename(path.rstrip("/")) or "unknown"
    print(f"\n[forge] Indexing into project '{project_name}'  [mode: {mode}] ...")
    print(f"[forge] This may take a few minutes for large codebases.\n")

    files_indexed, chunks_created, empty_skipped, true_errors = index_path(
        path=path,
        project_name=project_name,
        files_to_index=scan.will_index,
        session_id=kb_session_id,
        already_current_count=len(scan.already_current),
    )

    write_audit_entry(
        session_id=kb_session_id,
        tool="KB_INDEX_COMPLETE",
        path=path,
        lines=f"{chunks_created} chunks",
        reason=(
            f"files_indexed={files_indexed} | "
            f"chunks={chunks_created} | "
            f"empty_skipped={empty_skipped} | "
            f"true_errors={true_errors} | "
            f"mode={mode} | "
            f"project={project_name}"
        )
    )

    print()
    print("── Indexing Complete ─────────────────────────────────")
    print(f"  Mode          : {mode}")
    print(f"  Files indexed : {files_indexed}")
    print(f"  Chunks created: {chunks_created}")
    if empty_skipped:
        print(f"  Empty skipped : {empty_skipped}")
    if true_errors:
        print(f"  True errors   : {true_errors}")
    print(f"  Manifest      : {MEMORY_DIR / 'forge_kb_manifest.json'}")
    print(f"  Vector DB     : {KB_DIR}")
    print()
    print(get_kb_stats())
    print("──────────────────────────────────────────────────────")
    print()
    print("[forge] No project files were modified. Only the local knowledge base was updated.")


def cmd_kb(subcommand: str = "status", query: str = "", n_results: int = 5):
    """
    forge kb             — show knowledge base stats
    forge kb search <q>  — search the knowledge base directly (no LLM)
    """
    from agents.forge.knowledge_base import get_kb_stats, search_knowledge_base

    if subcommand == "search":
        if not query:
            print("[forge] ERROR: Provide a search query. Example: python main.py kb search 'agent loop'")
            sys.exit(1)

        print(f"\n[forge] Searching knowledge base for: '{query}'  (top {n_results} results)\n")
        result = search_knowledge_base(query, n_results=n_results)

        if not result["ok"]:
            print(f"[forge] {result['error']}")
            sys.exit(1)

        print(result["data"])
        print("[forge] Direct KB search complete. No files were read. No LLM was used.")

    else:
        # Default: status
        print()
        print(get_kb_stats())
        print()



# ─── PATCH 68: CANONICAL ENGINE REVIEW LAYER (REVIEW ONLY) ──────────────────

_PATCH68_PRIMARY_ROOT_PREFIXES = (
    "aiweb/engines/",
    "aiweb/agents/",
    "aiweb/runtime_wrappers/",
    "aiweb/symbolic_layers/",
)

_PATCH68_MIRROR_ROOT_PREFIXES = (
    "engines/",
    "agents/",
    "runtime_wrappers/",
    "symbolic_layers/",
)


def _patch68_root_class(root: str) -> str:
    root_l = str(root or "").lower()
    if root_l.startswith(_PATCH68_PRIMARY_ROOT_PREFIXES):
        return "primary_aiweb_root"
    if root_l.startswith(_PATCH68_MIRROR_ROOT_PREFIXES):
        return "mirror_root"
    if root_l.startswith("projects/"):
        return "project_copy"
    if root_l.startswith("simulations/"):
        return "simulation_copy"
    if "/site-packages/" in root_l or root_l.startswith(".venv/"):
        return "external_dependency"
    return "other_indexed_root"


def _patch68_review_flags(candidate: dict, variants: list[dict]) -> tuple[list[str], str, str]:
    """Return (flags, status, confidence) for a provisional canonical candidate."""
    flags: list[str] = []
    root = str(candidate.get("root", ""))
    root_l = root.lower()
    tags = set(candidate.get("status_tags", []) or [])
    root_class = _patch68_root_class(root)
    if "frozen" in tags:
        flags.append("candidate_is_frozen")
    if "backup_or_archive" in tags:
        flags.append("candidate_is_backup_or_archive")
    if "test_only" in tags:
        flags.append("candidate_is_test_only")
    if "external_dependency" in tags:
        flags.append("candidate_is_external_dependency")
    if root_class in {"project_copy", "simulation_copy", "other_indexed_root"}:
        flags.append(f"candidate_root_class_{root_class}")
    active_variants = [v for v in variants if "active_or_unfrozen" in set(v.get("status_tags", []) or [])]
    active_roots = sorted({str(v.get("root", "")) for v in active_variants})
    if len(active_roots) > 1:
        flags.append("multiple_active_or_unfrozen_variants")
    if len(variants) >= 6:
        flags.append("high_duplicate_variant_count")
    if root_l.startswith("aiweb/runtime_wrappers/protoforge") or root_l.startswith("runtime_wrappers/protoforge"):
        flags.append("protoforge_runtime_wrapper_requires_manual_review")
    ranked = sorted(variants, key=lambda r: (-int(r.get("canonical_score", 0) or 0), str(r.get("root", ""))))
    gap = 0
    if len(ranked) > 1:
        gap = int(ranked[0].get("canonical_score", 0) or 0) - int(ranked[1].get("canonical_score", 0) or 0)
    if flags:
        status = "REVIEW_REQUIRED"
        confidence = "manual_review"
    elif root_class == "primary_aiweb_root" and gap >= 10:
        status = "PROVISIONAL_KEEP_CANDIDATE"
        confidence = "high"
    else:
        status = "PROVISIONAL_KEEP_CANDIDATE"
        confidence = "medium"
    return flags, status, confidence


def _patch68_build_canonical_review() -> dict:
    rows, errors = _code_engine_inventory_rows()
    groups = _code_engine_duplicate_groups(rows)
    review_rows: list[dict] = []
    provisional = 0
    review_required = 0
    confidence_counts: dict[str, int] = {}
    root_classes: dict[str, int] = {}
    for g in groups:
        variants = list(g.get("variants", []))
        cand = dict(g.get("canonical_candidate", {}) or (variants[0] if variants else {}))
        flags, status, confidence = _patch68_review_flags(cand, variants)
        if status == "REVIEW_REQUIRED":
            review_required += 1
        else:
            provisional += 1
        confidence_counts[confidence] = confidence_counts.get(confidence, 0) + 1
        root_class = _patch68_root_class(str(cand.get("root", "")))
        root_classes[root_class] = root_classes.get(root_class, 0) + 1
        review_rows.append({
            "engine_base": g.get("engine_base"),
            "status": status,
            "confidence": confidence,
            "review_flags": flags,
            "root_class": root_class,
            "provisional_keep": {
                "engine_name": cand.get("engine_name"),
                "root": cand.get("root"),
                "family": cand.get("family"),
                "canonical_score": cand.get("canonical_score"),
                "status_tags": cand.get("status_tags", []),
                "file_count": cand.get("file_count"),
                "symbol_count": cand.get("symbol_count"),
                "sample_files": cand.get("sample_files", [])[:6],
            },
            "variant_count": len(variants),
            "variants": [
                {
                    "engine_name": v.get("engine_name"),
                    "root": v.get("root"),
                    "family": v.get("family"),
                    "canonical_score": v.get("canonical_score"),
                    "status_tags": v.get("status_tags", []),
                    "file_count": v.get("file_count"),
                    "symbol_count": v.get("symbol_count"),
                    "root_class": _patch68_root_class(str(v.get("root", ""))),
                }
                for v in variants
            ],
            "allowed_action_patch68": "REVIEW_ONLY_NO_MOVE_NO_DELETE_NO_LOCK",
        })
    review_rows.sort(key=lambda r: (0 if r.get("status") == "REVIEW_REQUIRED" else 1, -int(r.get("variant_count", 0) or 0), str(r.get("engine_base", ""))))
    return {
        "report_type": "ENGINE_CANONICAL_REVIEW_PATCH68_REVIEW_ONLY",
        "timestamp": datetime.datetime.now().isoformat(timespec="seconds"),
        "read_only": True,
        "implemented_destructive_action": False,
        "lockfile_written": False,
        "quarantine_written": False,
        "engine_count": len(rows),
        "duplicate_group_count": len(groups),
        "provisional_keep_count": provisional,
        "review_required_count": review_required,
        "confidence_counts": confidence_counts,
        "candidate_root_classes": root_classes,
        "policy": {
            "patch68_scope": "review-only canonical engine candidates",
            "no_file_moves": True,
            "no_deletes": True,
            "no_quarantine": True,
            "no_lockfile": True,
            "next_phase": "canonical lockfile only after human review",
        },
        "errors": errors,
        "review": review_rows,
    }


def _patch68_write_review_report(name: str, payload: dict) -> Path:
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    ts = datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")
    p = CODE_MANIFESTS_DIR / f"{ts}_{name}.json"
    p.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    return p


def _patch68_latest_review_report() -> Path | None:
    candidates = sorted(CODE_MANIFESTS_DIR.glob("*engine_canonical_review*.json"), key=lambda p: p.stat().st_mtime, reverse=True)
    return candidates[0] if candidates else None


