# ─── PATCH 70: CANONICAL ENGINE DECISION REVIEW TOOLS (READ ONLY) ───────────

def _patch70_decision_payload() -> dict:
    """Build the current Patch 69 decision draft payload without writing a new report."""
    return _patch69_build_decision_draft()


def _patch70_decision_rows() -> list[dict]:
    return _patch70_decision_payload().get("decisions", [])


def _patch70_decision_matches(decision_filter: str, rows: list[dict]) -> list[dict]:
    f = (decision_filter or "").strip().upper()
    if not f or f in ("ALL", "*"):
        return rows
    if f in ("HOLD", "HOLDS", "MANUAL"):
        return [r for r in rows if str(r.get("draft_decision", "")).upper().startswith("HOLD")]
    if f in ("DRAFT", "KEEP", "KEEPS"):
        return [r for r in rows if str(r.get("draft_decision", "")).upper().startswith("DRAFT")]
    return [r for r in rows if str(r.get("draft_decision", "")).upper() == f]


def _patch70_print_decision_row(row: dict, *, verbose: bool = False) -> None:
    print(f"  - {row.get('engine_base')} [{row.get('draft_decision')}] confidence={row.get('decision_confidence')}")
    print(f"      keep draft : {row.get('recommended_keep_path')}")
    print(f"      variants   : {row.get('variant_count')}")
    if row.get("required_human_checks"):
        print(f"      checks     : {', '.join(row.get('required_human_checks')[:4])}")
    if row.get("cautions"):
        print(f"      cautions   : {', '.join(row.get('cautions')[:3])}")
    if verbose:
        print(f"      reason     : {row.get('reason')}")
        print(f"      patch68    : {row.get('patch68_keep_candidate')}")
        for v in row.get("variants", [])[:10]:
            print(f"        • {v.get('root')} score={v.get('canonical_score')} tags={','.join(v.get('status_tags', []))} class={v.get('root_class')}")
        extra = int(row.get("variant_count", 0) or 0) - 10
        if extra > 0:
            print(f"        ... {extra} more variants in decision report")


