# ─── PATCH 72 — ENGINE REVIEW LEDGER ─────────────────────────────────────────

ENGINE_REVIEW_LEDGER_FILE = CODE_MANIFESTS_DIR / "engine_review_ledger_v1.json"
ENGINE_REVIEW_ALLOWED_STATUSES = {"approved", "deferred", "rejected"}


def _patch72_now() -> str:
    return datetime.datetime.now().isoformat(timespec="seconds")


def _patch72_norm_status(status: str) -> str:
    s = (status or "").strip().lower().replace(" ", "_")
    aliases = {
        "approve": "approved",
        "approved": "approved",
        "yes": "approved",
        "ok": "approved",
        "defer": "deferred",
        "deferred": "deferred",
        "hold": "deferred",
        "later": "deferred",
        "reject": "rejected",
        "rejected": "rejected",
        "no": "rejected",
    }
    return aliases.get(s, s)


def _patch72_ledger_path() -> Path:
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    return ENGINE_REVIEW_LEDGER_FILE


def _patch72_make_entry(row: dict, source_section: str) -> dict:
    is_hold = str(row.get("draft_decision", "")).startswith("HOLD_") or row.get("status") == "EXCLUDED_HOLD"
    return {
        "engine_base": row.get("engine_base"),
        "review_status": "PENDING_REVIEW",
        "reviewed": False,
        "reviewed_at": None,
        "reviewed_by": None,
        "review_note": "",
        "source_section": source_section,
        "draft_lock_status": row.get("status"),
        "draft_decision": row.get("draft_decision"),
        "decision_confidence": row.get("decision_confidence"),
        "recommended_keep_path": row.get("recommended_keep_path"),
        "patch68_keep_candidate": row.get("patch68_keep_candidate"),
        "variant_count": row.get("variant_count"),
        "required_human_checks": list(row.get("required_human_checks", []) or []),
        "cautions": list(row.get("cautions", []) or []),
        "reason": row.get("reason"),
        "is_hold_family": bool(is_hold),
        "future_lockfile_eligible": False,
        "future_lockfile_block_reason": "pending human review" if not is_hold else "HOLD family excluded until future override/review patch",
        "no_engine_file_action": True,
        "no_quarantine_action": True,
        "canonical_authority": False,
    }


def _patch72_build_ledger_from_lockfile() -> dict:
    lock = _patch71_load_or_build_lockfile()
    rows = []
    for row in lock.get("lockfile_entries", []) or []:
        rows.append(_patch72_make_entry(row, "draft_included"))
    for row in lock.get("excluded_holds", []) or []:
        rows.append(_patch72_make_entry(row, "excluded_hold"))
    rows = sorted(rows, key=lambda r: str(r.get("engine_base", "")))
    return {
        "report_type": "engine_review_ledger",
        "policy_version": "patch72_engine_review_ledger_v1",
        "created_at": _patch72_now(),
        "updated_at": _patch72_now(),
        "mode": "HUMAN_REVIEW_LEDGER_ONLY",
        "canonical_authority": False,
        "actual_lockfile_written": False,
        "engine_files_changed": False,
        "quarantine_written": False,
        "source_lockfile_policy_version": lock.get("policy_version"),
        "source_lockfile_status": lock.get("status"),
        "total_entries": len(rows),
        "entries": rows,
        "policy": {
            "allowed_review_statuses": sorted(ENGINE_REVIEW_ALLOWED_STATUSES),
            "holds_cannot_become_final_authority_in_patch72": True,
            "approved_non_hold_rows_are_candidates_only": True,
            "destructive_actions_forbidden": ["move", "delete", "rename", "quarantine", "promote", "edit_engine_files"],
        },
    }


def _patch72_load_ledger(create_if_missing: bool = False) -> tuple[dict | None, Path, str | None]:
    path = _patch72_ledger_path()
    if not path.exists():
        if not create_if_missing:
            return None, path, "ledger not initialized"
        ledger = _patch72_build_ledger_from_lockfile()
        path.write_text(json.dumps(ledger, indent=2, ensure_ascii=False), encoding="utf-8")
        return ledger, path, None
    try:
        ledger = json.loads(path.read_text(encoding="utf-8"))
        return ledger, path, None
    except Exception as e:
        return None, path, f"ledger read failed: {e}"


def _patch72_save_ledger(ledger: dict) -> Path:
    ledger["updated_at"] = _patch72_now()
    ledger["total_entries"] = len(ledger.get("entries", []) or [])
    path = _patch72_ledger_path()
    path.write_text(json.dumps(ledger, indent=2, ensure_ascii=False), encoding="utf-8")
    return path


def _patch72_find_entry(ledger: dict, engine_base: str) -> dict | None:
    q = _code_engine_base_name((engine_base or "").strip().lower())
    for row in ledger.get("entries", []) or []:
        if str(row.get("engine_base", "")).lower() == q:
            return row
    return None


def _patch72_counts(ledger: dict) -> dict:
    entries = list(ledger.get("entries", []) or [])
    counts = {"total": len(entries), "pending": 0, "approved": 0, "deferred": 0, "rejected": 0, "holds": 0, "non_holds": 0, "eligible_candidates": 0}
    for row in entries:
        st = str(row.get("review_status", "PENDING_REVIEW")).upper()
        if st == "APPROVED":
            counts["approved"] += 1
        elif st == "DEFERRED":
            counts["deferred"] += 1
        elif st == "REJECTED":
            counts["rejected"] += 1
        else:
            counts["pending"] += 1
        if row.get("is_hold_family"):
            counts["holds"] += 1
        else:
            counts["non_holds"] += 1
        if row.get("future_lockfile_eligible"):
            counts["eligible_candidates"] += 1
    return counts


def _patch72_mark_row(row: dict, status: str, note: str) -> None:
    status = _patch72_norm_status(status)
    row["review_status"] = status.upper()
    row["reviewed"] = True
    row["reviewed_at"] = _patch72_now()
    row["reviewed_by"] = "human_operator"
    row["review_note"] = note or ""
    row["canonical_authority"] = False
    row["no_engine_file_action"] = True
    row["no_quarantine_action"] = True
    if status == "approved" and not row.get("is_hold_family"):
        row["future_lockfile_eligible"] = True
        row["future_lockfile_block_reason"] = "approved for future human-approved lockfile draft; not authoritative in Patch 72"
    elif status == "approved" and row.get("is_hold_family"):
        row["future_lockfile_eligible"] = False
        row["future_lockfile_block_reason"] = "approved note recorded, but HOLD family remains excluded until future override/review patch"
    elif status == "deferred":
        row["future_lockfile_eligible"] = False
        row["future_lockfile_block_reason"] = "deferred by human review"
    elif status == "rejected":
        row["future_lockfile_eligible"] = False
        row["future_lockfile_block_reason"] = "rejected by human review"


