def cmd_engine_review_ledger_init(session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    ledger, path, err = _patch72_load_ledger(create_if_missing=True)
    if err:
        print(f"[forge] ERROR: {err}")
        return
    counts = _patch72_counts(ledger)
    print()
    print("── Engine Review Ledger Init ───────────────────────")
    print("  Mode        : LEDGER INIT ONLY")
    print("  Engine files: unchanged")
    print("  Authority   : NO — not a final canonical lockfile")
    print(f"  Ledger path : {path}")
    print(f"  Entries     : {counts['total']}  holds={counts['holds']} non_holds={counts['non_holds']}")
    print(f"  Pending     : {counts['pending']}  approved={counts['approved']} deferred={counts['deferred']} rejected={counts['rejected']}")
    print("  Status      : LEDGER_READY")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_LEDGER_INIT", str(path), f"entries={counts['total']}", "authority=no")


def cmd_engine_review_mark(arg: str, session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    parts = (arg or "").strip().split(maxsplit=2)
    if len(parts) < 2:
        print()
        print("  Usage: engine-review-mark <engine_base> <approved|deferred|rejected> [note]")
        print("  Example: engine-review-mark phase_engine approved canonical phase runtime candidate")
        print()
        return
    engine_base, status = parts[0], _patch72_norm_status(parts[1])
    note = parts[2] if len(parts) > 2 else ""
    if status not in ENGINE_REVIEW_ALLOWED_STATUSES:
        print()
        print("── Engine Review Mark Refused ──────────────────────")
        print(f"  Status supplied : {parts[1]}")
        print("  Allowed         : approved, deferred, rejected")
        print("  Result          : ENGINE_REVIEW_MARK_REFUSED")
        print("──────────────────────────────────────────────────────")
        print()
        write_audit_entry(session_id, "ENGINE_REVIEW_MARK_REFUSED", engine_base, status, "invalid_status")
        return
    ledger, path, err = _patch72_load_ledger(create_if_missing=True)
    if err:
        print(f"[forge] ERROR: {err}")
        return
    row = _patch72_find_entry(ledger, engine_base)
    if not row:
        print()
        print("── Engine Review Mark Refused ──────────────────────")
        print(f"  Engine base : {engine_base}")
        print("  Reason      : no exact engine_base found in review ledger")
        print("  Result      : ENGINE_REVIEW_MARK_REFUSED")
        print("──────────────────────────────────────────────────────")
        print()
        write_audit_entry(session_id, "ENGINE_REVIEW_MARK_REFUSED", engine_base, status, "not_found")
        return
    _patch72_mark_row(row, status, note)
    _patch72_save_ledger(ledger)
    print()
    print("── Engine Review Mark ──────────────────────────────")
    print("  Mode        : LEDGER WRITE ONLY — no engine files changed")
    print(f"  Ledger      : {path}")
    print(f"  Engine base : {row.get('engine_base')}")
    print(f"  Review      : {row.get('review_status')}")
    print(f"  Hold family : {row.get('is_hold_family')}")
    print(f"  Eligible?   : {row.get('future_lockfile_eligible')}")
    print(f"  Reason      : {row.get('future_lockfile_block_reason')}")
    if note:
        print(f"  Note        : {note}")
    print("  Result      : ENGINE_REVIEW_MARK_RECORDED")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_MARK_RECORDED", row.get("engine_base") or engine_base, row.get("review_status") or status, f"eligible={row.get('future_lockfile_eligible')}")


