# ─── PATCH 73 — ENGINE REVIEW BATCH TOOLS ────────────────────────────────────

ENGINE_REVIEW_BATCH_PLAN_FILE = CODE_MANIFESTS_DIR / "engine_review_batch_plan_v1.json"


def _patch73_ledger_or_create() -> tuple[dict | None, Path, str | None]:
    return _patch72_load_ledger(create_if_missing=True)


def _patch73_core_rows(ledger: dict) -> list[dict]:
    bases = set(_PATCH69_CORE_KEEP_BASES)
    return sorted(
        [r for r in ledger.get("entries", []) or [] if str(r.get("engine_base", "")) in bases],
        key=lambda r: str(r.get("engine_base", "")),
    )


def _patch73_core_approvable_rows(ledger: dict) -> list[dict]:
    rows = []
    for row in _patch73_core_rows(ledger):
        status = str(row.get("review_status", "PENDING_REVIEW")).upper()
        if row.get("is_hold_family"):
            continue
        if status == "REJECTED":
            continue
        rows.append(row)
    return rows


def _patch73_hold_rows(ledger: dict) -> list[dict]:
    return sorted(
        [r for r in ledger.get("entries", []) or [] if r.get("is_hold_family")],
        key=lambda r: str(r.get("engine_base", "")),
    )


def _patch73_batch_counts(ledger: dict) -> dict:
    counts = _patch72_counts(ledger)
    core_rows = _patch73_core_rows(ledger)
    approvable_core = _patch73_core_approvable_rows(ledger)
    hold_rows = _patch73_hold_rows(ledger)
    counts.update({
        "core_total": len(core_rows),
        "core_non_hold_approvable": len(approvable_core),
        "core_approved": sum(1 for r in core_rows if str(r.get("review_status", "")).upper() == "APPROVED" and not r.get("is_hold_family")),
        "core_hold": sum(1 for r in core_rows if r.get("is_hold_family")),
        "holds_total": len(hold_rows),
        "holds_deferred": sum(1 for r in hold_rows if str(r.get("review_status", "")).upper() == "DEFERRED"),
        "holds_rejected": sum(1 for r in hold_rows if str(r.get("review_status", "")).upper() == "REJECTED"),
        "holds_pending": sum(1 for r in hold_rows if str(r.get("review_status", "PENDING_REVIEW")).upper() not in ("DEFERRED", "REJECTED")),
    })
    return counts


def _patch73_build_batch_plan(ledger: dict) -> dict:
    core_candidates = []
    for row in _patch73_core_approvable_rows(ledger):
        core_candidates.append({
            "engine_base": row.get("engine_base"),
            "recommended_keep_path": row.get("recommended_keep_path"),
            "current_review_status": row.get("review_status"),
            "decision_confidence": row.get("decision_confidence"),
            "variant_count": row.get("variant_count"),
            "required_human_checks": row.get("required_human_checks", []),
            "action": "approve_core_candidate",
        })
    hold_candidates = []
    for row in _patch73_hold_rows(ledger):
        hold_candidates.append({
            "engine_base": row.get("engine_base"),
            "recommended_keep_path": row.get("recommended_keep_path"),
            "current_review_status": row.get("review_status"),
            "draft_decision": row.get("draft_decision"),
            "required_human_checks": row.get("required_human_checks", []),
            "action": "defer_hold_family",
        })
    return {
        "report_type": "engine_review_batch_plan",
        "policy_version": "patch73_engine_review_batch_tools_v1",
        "created_at": _patch72_now(),
        "mode": "BATCH_PLAN_ONLY",
        "canonical_authority": False,
        "actual_lockfile_written": False,
        "engine_files_changed": False,
        "quarantine_written": False,
        "ledger_path": str(_patch72_ledger_path()),
        "core_approval_candidates": core_candidates,
        "hold_deferral_candidates": hold_candidates,
        "counts": _patch73_batch_counts(ledger),
        "rules": {
            "batch_approve_core_only_marks_non_hold_core_rows": True,
            "batch_defer_holds_only_marks_hold_rows_deferred": True,
            "rejected_rows_are_not_overwritten_by_batch_approve_core": True,
            "destructive_actions_forbidden": ["move", "delete", "rename", "quarantine", "promote", "edit_engine_files"],
        },
    }


def _patch73_write_batch_plan(plan: dict) -> Path:
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    path = ENGINE_REVIEW_BATCH_PLAN_FILE
    path.write_text(json.dumps(plan, indent=2, ensure_ascii=False), encoding="utf-8")
    return path


def _patch73_save_batch_export(ledger: dict) -> tuple[Path, Path, dict]:
    counts = _patch73_batch_counts(ledger)
    payload = {
        "report_type": "engine_review_batch_export",
        "policy_version": "patch73_engine_review_batch_tools_v1",
        "created_at": _patch72_now(),
        "canonical_authority": False,
        "engine_files_changed": False,
        "quarantine_written": False,
        "counts": counts,
        "core_rows": _patch73_core_rows(ledger),
        "hold_rows": _patch73_hold_rows(ledger),
        "recent_reviewed": sorted([r for r in ledger.get("entries", []) or [] if r.get("reviewed")], key=lambda r: str(r.get("reviewed_at") or ""), reverse=True)[:20],
    }
    stamp = datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")
    json_path = CODE_MANIFESTS_DIR / f"{stamp}_engine_review_batch_export.json"
    md_path = CODE_MANIFESTS_DIR / f"{stamp}_engine_review_batch_export.md"
    json_path.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = []
    lines.append("# Patch 73 Engine Review Batch Export")
    lines.append("")
    lines.append("Mode: review ledger batch tooling only. No canonical authority. No engine files moved, deleted, quarantined, promoted, renamed, or edited.")
    lines.append("")
    lines.append(f"Entries: {counts['total']}")
    lines.append(f"Approved: {counts['approved']}")
    lines.append(f"Deferred: {counts['deferred']}")
    lines.append(f"Rejected: {counts['rejected']}")
    lines.append(f"Pending: {counts['pending']}")
    lines.append(f"Eligible candidates: {counts['eligible_candidates']}")
    lines.append(f"Core approved: {counts['core_approved']} / {counts['core_non_hold_approvable']}")
    lines.append(f"Held families deferred: {counts['holds_deferred']} / {counts['holds_total']}")
    lines.append("")
    lines.append("## Core Rows")
    for row in payload["core_rows"]:
        lines.append(f"- **{row.get('engine_base')}** — {row.get('review_status')} eligible={row.get('future_lockfile_eligible')} hold={row.get('is_hold_family')}")
        lines.append(f"  - keep draft: `{row.get('recommended_keep_path')}`")
    lines.append("")
    lines.append("## Held Rows")
    for row in payload["hold_rows"]:
        lines.append(f"- **{row.get('engine_base')}** — {row.get('review_status')} eligible={row.get('future_lockfile_eligible')}")
        lines.append(f"  - reason: {row.get('future_lockfile_block_reason')}")
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    return json_path, md_path, payload


