# ─── PATCH 75 — LLM MEMORY LEDGER (RECEIPTS ONLY; NO HIDDEN CHAIN) ───────────

LLM_MEMORY_SCHEMA_VERSION = "llm_memory_v1_patch75"


def _llm_memory_dirs() -> list[Path]:
    return [
        LLM_MEMORY_DIR,
        LLM_MEMORY_CONVERSATIONS_DIR,
        LLM_MEMORY_TURNS_DIR,
        LLM_MEMORY_TOOL_REQUESTS_DIR,
        LLM_MEMORY_RECOMMENDATIONS_DIR,
        LLM_MEMORY_DECISION_SUMMARIES_DIR,
        LLM_MEMORY_CONTEXT_SNAPSHOTS_DIR,
        LLM_MEMORY_CORRECTIONS_DIR,
        LLM_MEMORY_INDEXES_DIR,
        LLM_MEMORY_EXPORTS_DIR,
    ]


def _llm_memory_ensure_dirs() -> None:
    for folder in _llm_memory_dirs():
        folder.mkdir(parents=True, exist_ok=True)


def _llm_memory_ts() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _llm_memory_iso() -> str:
    return datetime.datetime.now().isoformat(timespec="seconds")


def _llm_memory_slug(value: str, limit: int = 64) -> str:
    slug = re.sub(r"[^A-Za-z0-9_.-]+", "_", str(value or "")).strip("._-")
    return (slug or "receipt")[:limit]


def _llm_memory_sha16(text: str) -> str:
    import hashlib
    return hashlib.sha256(text.encode("utf-8")).hexdigest()[:16]


def _llm_memory_write_json(path: Path, payload: dict) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, indent=2, sort_keys=True), encoding="utf-8")


def _llm_memory_append_session_line(session_id: str, payload: dict) -> None:
    LLM_MEMORY_CONVERSATIONS_DIR.mkdir(parents=True, exist_ok=True)
    line = {
        "timestamp": payload.get("timestamp"),
        "receipt_id": payload.get("receipt_id"),
        "receipt_type": payload.get("receipt_type"),
        "summary": payload.get("final_answer_summary") or payload.get("correction_summary") or payload.get("summary") or "",
        "path": payload.get("receipt_path", ""),
    }
    session_file = LLM_MEMORY_CONVERSATIONS_DIR / f"{_llm_memory_slug(session_id)}.jsonl"
    with session_file.open("a", encoding="utf-8") as f:
        f.write(json.dumps(line, sort_keys=True) + "\n")


def _llm_memory_update_latest(payload: dict) -> None:
    latest = {
        "schema_version": LLM_MEMORY_SCHEMA_VERSION,
        "updated_at": _llm_memory_iso(),
        "latest_receipt_id": payload.get("receipt_id"),
        "latest_receipt_type": payload.get("receipt_type"),
        "latest_receipt_path": payload.get("receipt_path"),
    }
    _llm_memory_write_json(LLM_MEMORY_INDEXES_DIR / "latest_receipt.json", latest)


def _llm_memory_all_receipts() -> list[Path]:
    if not LLM_MEMORY_DIR.exists():
        return []
    ignored_names = {"policy.json", "latest_receipt.json", "session_index.json"}
    rows = []
    for path in LLM_MEMORY_DIR.rglob("*.json"):
        if path.name in ignored_names:
            continue
        if path.is_file():
            rows.append(path)
    return sorted(rows, key=lambda p: p.stat().st_mtime, reverse=True)


def _llm_memory_load_latest() -> tuple[Path | None, dict | None, str]:
    latest_index = LLM_MEMORY_INDEXES_DIR / "latest_receipt.json"
    if latest_index.exists():
        try:
            idx = json.loads(latest_index.read_text(encoding="utf-8"))
            path = Path(idx.get("latest_receipt_path", ""))
            if path.exists() and path.is_file():
                return path, json.loads(path.read_text(encoding="utf-8")), ""
        except Exception as e:
            return None, None, f"latest index unreadable: {e}"
    rows = _llm_memory_all_receipts()
    if not rows:
        return None, None, "no llm memory receipts found"
    try:
        return rows[0], json.loads(rows[0].read_text(encoding="utf-8")), ""
    except Exception as e:
        return None, None, f"latest receipt unreadable: {e}"


def _llm_memory_resolve_receipt(arg: str) -> tuple[Path | None, dict | None, str]:
    raw = (arg or "latest").strip()
    if not raw or raw == "latest":
        return _llm_memory_load_latest()
    candidate = Path(os.path.expanduser(raw))
    if candidate.is_absolute():
        try:
            candidate.resolve().relative_to(LLM_MEMORY_DIR.resolve())
        except Exception:
            return None, None, f"Receipt path must be inside {LLM_MEMORY_DIR}; got {candidate}"
        if candidate.exists() and candidate.is_file():
            try:
                return candidate, json.loads(candidate.read_text(encoding="utf-8")), ""
            except Exception as e:
                return None, None, f"Receipt unreadable: {e}"
    target_id = raw
    for path in _llm_memory_all_receipts():
        if path.stem == target_id or target_id in path.name:
            try:
                return path, json.loads(path.read_text(encoding="utf-8")), ""
            except Exception as e:
                return None, None, f"Receipt unreadable: {e}"
    return None, None, f"No LLM memory receipt matched: {raw}"


def _llm_memory_policy_payload() -> dict:
    return {
        "schema_version": LLM_MEMORY_SCHEMA_VERSION,
        "policy": "Patch 75 LLM Memory Ledger",
        "mode": "Forge-owned LLM memory receipts only",
        "purpose": "Preserve LLM-facing user request summaries, final answer summaries, recommendations, corrections, tool references, outcomes, and next-step context.",
        "authority": {
            "direct_patch_authority": False,
            "project_file_write_authority": False,
            "canonical_engine_authority": False,
            "chroma_write_authority": False,
            "shell_access": False,
        },
        "allowed_storage": [
            str(LLM_MEMORY_DIR),
            str(LLM_MEMORY_TURNS_DIR),
            str(LLM_MEMORY_CORRECTIONS_DIR),
            str(LLM_MEMORY_CONVERSATIONS_DIR),
            str(LLM_MEMORY_INDEXES_DIR),
            str(LLM_MEMORY_EXPORTS_DIR),
        ],
        "forbidden_storage": [
            "hidden chain-of-thought",
            "credentials, API keys, tokens, passwords, secrets, private keys",
            "raw shell execution transcripts containing secrets",
            "unscoped project writes",
            "Chroma/vector writes without future explicit ingestion protocol",
        ],
        "core_rule": "Model memory is advisory only. Forge truth must be backed by receipts, files, hashes, manifests, or audit.",
        "hidden_chain_of_thought_stored": False,
    }


def _llm_memory_seed_corrections(session_id: str) -> list[Path]:
    seeds = [
        {
            "seed_id": "patch67_archive_root_instruction_correction",
            "correction_summary": "Patch 67 install instructions assumed a nested extracted folder that did not exist. Future patch installs must inspect the archive root with find before giving copy paths.",
            "lesson": "Never assume archive wrapper paths. Verify extracted structure first.",
        },
        {
            "seed_id": "patch74_timestamp_helper_correction",
            "correction_summary": "Patch 74 originally called undefined _patch_timestamp(). Patch 74.1 fixed it by using the existing _patch60_timestamp() helper.",
            "lesson": "Before packaging a patch, search for undefined helper calls and run syntax/smoke checks.",
        },
        {
            "seed_id": "llm_memory_reason_for_patch75",
            "correction_summary": "Nic clarified that Forge must not only produce raw reports. The LLM layer needs auditable memory of what it recommended, corrected, explained, and told Nic to run.",
            "lesson": "Forge deterministic code verifies. The LLM explains, recommends, and remembers through receipts.",
        },
    ]
    written = []
    for seed in seeds:
        path = LLM_MEMORY_CORRECTIONS_DIR / f"seed_{seed['seed_id']}.json"
        if path.exists():
            continue
        payload = {
            "schema_version": LLM_MEMORY_SCHEMA_VERSION,
            "receipt_type": "LLM_MEMORY_SEEDED_CORRECTION_V1",
            "receipt_id": f"seed_{seed['seed_id']}",
            "timestamp": _llm_memory_iso(),
            "session_id": session_id,
            "source": "patch75_llm_memory_init",
            "hidden_chain_of_thought_stored": False,
            "project_files_changed": False,
            "user_approved_project_write": False,
            **seed,
        }
        payload["receipt_path"] = str(path)
        _llm_memory_write_json(path, payload)
        written.append(path)
    return written


