def cmd_llm_memory_init(session_id: str) -> None:
    """Initialize Forge-owned LLM memory folders and policy receipts. Usage: llm-memory-init"""
    from agents.forge.memory import write_audit_entry
    _llm_memory_ensure_dirs()
    policy_path = LLM_MEMORY_DIR / "policy.json"
    policy = _llm_memory_policy_payload()
    policy["initialized_at"] = _llm_memory_iso()
    policy["root"] = str(LLM_MEMORY_DIR)
    _llm_memory_write_json(policy_path, policy)
    seeded = _llm_memory_seed_corrections(session_id)
    session_index = {
        "schema_version": LLM_MEMORY_SCHEMA_VERSION,
        "updated_at": _llm_memory_iso(),
        "last_init_session_id": session_id,
        "folders": [str(p) for p in _llm_memory_dirs()],
    }
    _llm_memory_write_json(LLM_MEMORY_INDEXES_DIR / "session_index.json", session_index)
    write_audit_entry(session_id, "LLM_MEMORY_INIT", str(LLM_MEMORY_DIR), f"seeded={len(seeded)}", "forge-owned receipts only")
    print()
    print("── LLM Memory Init ──────────────────────────────────")
    print("  Root           :", LLM_MEMORY_DIR)
    print("  Policy         :", policy_path)
    print(f"  Folders        : {len(_llm_memory_dirs())}")
    print(f"  Seed corrections: {len(seeded)} new")
    print("  Project writes : NO")
    print("  Hidden CoT     : NOT STORED")
    print("──────────────────────────────────────────────────────")
    print()


def cmd_llm_memory_log_turn(arg: str, session_id: str) -> None:
    """Write a safe LLM turn receipt. Usage: llm-memory-log-turn [plain summary]"""
    from agents.forge.memory import write_audit_entry
    _llm_memory_ensure_dirs()
    raw = (arg or "").strip()
    if raw:
        user_summary = "Manual CLI LLM-memory turn log"
        final_summary = raw[:2000]
        recommendation = "Review this memory receipt with llm-memory-show latest."
        next_cmd = "llm-memory-show latest"
        outcome = "manual_receipt_written"
    else:
        user_summary = "Patch 75 smoke test for LLM Memory Ledger"
        final_summary = "Forge wrote a safe LLM turn receipt under memory/llm_memory_v1. This proves the ledger can remember recommendations without storing hidden chain-of-thought or touching project files."
        recommendation = "Run llm-memory-show latest, llm-memory-search patch75, llm-memory-session, and llm-memory-export."
        next_cmd = "llm-memory-show latest"
        outcome = "smoke_receipt_written"
    ts = _llm_memory_ts()
    receipt_id = f"llm_turn_{ts}_{_llm_memory_sha16(final_summary)}"
    path = LLM_MEMORY_TURNS_DIR / f"{receipt_id}.json"
    payload = {
        "schema_version": LLM_MEMORY_SCHEMA_VERSION,
        "receipt_type": "LLM_MEMORY_TURN_RECEIPT_V1",
        "receipt_id": receipt_id,
        "timestamp": _llm_memory_iso(),
        "session_id": session_id,
        "source": "manual_cli_log_turn",
        "user_request_summary": user_summary,
        "final_answer_summary": final_summary,
        "tools_used": [],
        "evidence_referenced": [],
        "recommendations": [recommendation],
        "risk_level": "LOW",
        "next_command_suggested": next_cmd,
        "outcome": outcome,
        "corrections": [],
        "disk_changed": True,
        "disk_changed_scope": str(LLM_MEMORY_DIR),
        "project_files_changed": False,
        "user_approved_project_write": False,
        "hidden_chain_of_thought_stored": False,
        "direct_patch_authority": False,
    }
    payload["receipt_path"] = str(path)
    _llm_memory_write_json(path, payload)
    _llm_memory_append_session_line(session_id, payload)
    _llm_memory_update_latest(payload)
    write_audit_entry(session_id, "LLM_MEMORY_TURN_WRITTEN", str(path), "project_files_changed=NO", f"receipt_id={receipt_id}")
    print()
    print("── LLM Memory Turn Logged ───────────────────────────")
    print("  Receipt        :", receipt_id)
    print("  Path           :", path)
    print("  Risk           : LOW")
    print("  Project writes : NO")
    print("  Hidden CoT     : NOT STORED")
    print("  Next command   : llm-memory-show latest")
    print("──────────────────────────────────────────────────────")
    print()


