def cmd_llm_memory_show(arg: str, session_id: str) -> None:
    """Show latest or selected LLM memory receipt. Usage: llm-memory-show [latest|receipt_id|path]"""
    from agents.forge.memory import write_audit_entry
    path, data, err = _llm_memory_resolve_receipt(arg or "latest")
    if err:
        print()
        print("[forge] LLM memory show failed:", err)
        print("  Try: llm-memory-init")
        print("  Then: llm-memory-log-turn")
        print()
        return
    write_audit_entry(session_id, "LLM_MEMORY_SHOW", str(path), data.get("receipt_id", "?"), "read-only")
    print()
    print("── LLM Memory Receipt ───────────────────────────────")
    print("  Receipt :", data.get("receipt_id", "?"))
    print("  Type    :", data.get("receipt_type", "?"))
    print("  Time    :", data.get("timestamp", "?"))
    print("  Path    :", path)
    print("  Hidden CoT stored:", data.get("hidden_chain_of_thought_stored", False))
    print("  Project writes:", data.get("project_files_changed", False))
    print()
    summary = data.get("final_answer_summary") or data.get("correction_summary") or data.get("summary") or ""
    if summary:
        print("  Summary:")
        print("   ", summary[:1200])
        print()
    print("  Full JSON:")
    print(json.dumps(data, indent=2, sort_keys=True))
    print("──────────────────────────────────────────────────────")
    print()


def cmd_llm_memory_search(query: str, session_id: str) -> None:
    """Search LLM memory receipts by plain text. Usage: llm-memory-search <query>"""
    from agents.forge.memory import write_audit_entry
    q = (query or "").strip().lower()
    if not q:
        q = "patch"
    rows = []
    for path in _llm_memory_all_receipts():
        try:
            text = path.read_text(encoding="utf-8")
        except Exception:
            continue
        low = text.lower()
        if q in low:
            idx = max(0, low.find(q) - 90)
            excerpt = text[idx:idx + 260].replace("\n", " ")
            rows.append((path, excerpt))
        if len(rows) >= 12:
            break
    write_audit_entry(session_id, "LLM_MEMORY_SEARCH", q, f"matches={len(rows)}", "read-only")
    print()
    print("── LLM Memory Search ────────────────────────────────")
    print("  Query   :", q)
    print("  Matches :", len(rows))
    print("  Root    :", LLM_MEMORY_DIR)
    print()
    if not rows:
        print("  No matches found.")
        print("  Try: llm-memory-log-turn")
    for path, excerpt in rows:
        print("  -", path)
        print("   ", excerpt[:240])
    print("──────────────────────────────────────────────────────")
    print()


def cmd_llm_memory_session(session_id: str) -> None:
    """Summarize current LLM memory ledger/session state. Usage: llm-memory-session"""
    from agents.forge.memory import write_audit_entry
    counts = {}
    for folder in _llm_memory_dirs():
        counts[folder.name] = len(list(folder.glob("*.json"))) if folder.exists() else 0
    latest_path, latest_data, _ = _llm_memory_load_latest()
    write_audit_entry(session_id, "LLM_MEMORY_SESSION_SHOWN", str(LLM_MEMORY_DIR), f"receipts={sum(counts.values())}", "read-only")
    print()
    print("── LLM Memory Session ───────────────────────────────")
    print("  Root        :", LLM_MEMORY_DIR)
    print("  Schema      :", LLM_MEMORY_SCHEMA_VERSION)
    print("  Session     :", session_id)
    print("  Project write authority: NO")
    print("  Hidden CoT storage    : NO")
    print()
    print("  Counts:")
    for name in sorted(counts):
        print(f"    {name:22} {counts[name]}")
    print()
    if latest_path and latest_data:
        print("  Latest receipt:")
        print("    ID   :", latest_data.get("receipt_id", "?"))
        print("    Type :", latest_data.get("receipt_type", "?"))
        print("    Path :", latest_path)
    else:
        print("  Latest receipt: none yet")
    print("──────────────────────────────────────────────────────")
    print()


def cmd_llm_memory_export(session_id: str) -> None:
    """Export LLM memory ledger summary as JSON and Markdown. Usage: llm-memory-export"""
    from agents.forge.memory import write_audit_entry
    _llm_memory_ensure_dirs()
    receipts = _llm_memory_all_receipts()
    rows = []
    for path in receipts:
        try:
            data = json.loads(path.read_text(encoding="utf-8"))
        except Exception:
            continue
        rows.append({
            "receipt_id": data.get("receipt_id"),
            "receipt_type": data.get("receipt_type"),
            "timestamp": data.get("timestamp"),
            "path": str(path),
            "summary": (data.get("final_answer_summary") or data.get("correction_summary") or data.get("summary") or "")[:500],
            "project_files_changed": data.get("project_files_changed", False),
            "hidden_chain_of_thought_stored": data.get("hidden_chain_of_thought_stored", False),
        })
    ts = _llm_memory_ts()
    export = {
        "schema_version": LLM_MEMORY_SCHEMA_VERSION,
        "export_type": "LLM_MEMORY_LEDGER_EXPORT_V1",
        "timestamp": _llm_memory_iso(),
        "session_id": session_id,
        "root": str(LLM_MEMORY_DIR),
        "receipt_count": len(rows),
        "project_write_authority": False,
        "hidden_chain_of_thought_stored": False,
        "receipts": rows,
    }
    json_path = LLM_MEMORY_EXPORTS_DIR / f"{ts}_llm_memory_export.json"
    md_path = LLM_MEMORY_EXPORTS_DIR / f"{ts}_llm_memory_export.md"
    _llm_memory_write_json(json_path, export)
    md_lines = [
        "# LLM Memory Ledger Export",
        "",
        f"Generated: {export['timestamp']}",
        f"Root: `{LLM_MEMORY_DIR}`",
        f"Receipts: {len(rows)}",
        "",
        "Project file write authority: **NO**",
        "Hidden chain-of-thought stored: **NO**",
        "",
        "## Receipts",
    ]
    for r in rows[:200]:
        md_lines.append(f"- `{r.get('receipt_id')}` — {r.get('receipt_type')} — {r.get('timestamp')} — `{r.get('path')}`")
    md_path.write_text("\n".join(md_lines), encoding="utf-8")
    write_audit_entry(session_id, "LLM_MEMORY_EXPORT_WRITTEN", str(json_path), str(md_path), f"receipts={len(rows)}")
    print()
    print("── LLM Memory Export ────────────────────────────────")
    print("  JSON           :", json_path)
    print("  Markdown       :", md_path)
    print("  Receipts       :", len(rows))
    print("  Project writes : NO")
    print("  Hidden CoT     : NOT STORED")
    print("──────────────────────────────────────────────────────")
    print()


