def _patch77_decision_map() -> dict[str, dict]:
    rows = _patch77_decision_rows()
    out = {}
    for row in rows:
        base = str(row.get("engine_base", "")).strip().lower()
        if base:
            out[base] = row
    return out


def _patch77_candidate_maps() -> tuple[dict, dict, dict | None, str]:
    candidate, path, err = _patch74_load_latest_candidate(build_if_missing=False)
    included = {}
    excluded = {}
    if candidate:
        for row in candidate.get("candidate_entries", []) or []:
            base = str(row.get("engine_base", "")).strip().lower()
            if base:
                included[base] = row
        for row in candidate.get("excluded_entries", []) or []:
            base = str(row.get("engine_base", "")).strip().lower()
            if base:
                excluded[base] = row
    source = str(path) if path else (err or "no approved candidate artifact found")
    return included, excluded, candidate, source


def _patch77_runtime_roles_for(base: str, path_hint: str = "") -> list[dict]:
    q = str(base or "").lower()
    p = str(path_hint or "").lower()
    roles = []
    try:
        payload = _symbolic_runtime_map_payload()
    except Exception:
        return roles
    for role in payload.get("roles", []) or []:
        hits = []
        for cand in role.get("top_candidates", []) or []:
            cbase = str(cand.get("engine_base", "")).lower()
            croot = str(cand.get("root", "")).lower()
            if q and (q == cbase or q in croot or cbase in q):
                hits.append(cand)
            elif p and p == croot:
                hits.append(cand)
        if hits:
            roles.append({
                "role_id": role.get("role_id"),
                "title": role.get("title"),
                "description": role.get("description"),
                "required": role.get("required"),
                "status": role.get("status"),
                "phases": role.get("phases", []),
                "operators": role.get("operators", []),
                "matched_candidates": hits[:5],
            })
    return roles[:8]


def _patch77_plain_purpose(base: str, roles: list[dict]) -> str:
    b = str(base or "").lower()
    if roles:
        titles = "; ".join(str(r.get("title", "")) for r in roles[:2] if r.get("title"))
        desc = str(roles[0].get("description", "")).strip()
        if titles and desc:
            return f"This engine appears connected to {titles}. In plain English: {desc}"
        if titles:
            return f"This engine appears connected to {titles}."
    mapping = [
        ("phase", "This appears to control symbolic phase logic: how Forge/AI.Web names, tracks, or transitions between phase states."),
        ("christping", "This appears to handle correction pulses: bringing a drifted loop back toward coherence."),
        ("drift", "This appears to detect or arbitrate drift: places where behavior, memory, or logic starts moving out of bounds."),
        ("symbolic_capacitor", "This appears to handle Symbolic Phase Capacitor / cold-storage behavior: holding unresolved loops without deleting them."),
        ("resurrection", "This appears to handle lawful return: bringing archived or collapsed loop material back only when conditions match."),
        ("memory_stack", "This appears to handle memory persistence: keeping structured state across sessions instead of letting context vanish."),
        ("policy", "This appears to enforce rules, boundaries, and refusal logic."),
        ("failsafe", "This appears to protect the system when something unsafe, unstable, or invalid happens."),
        ("plugin", "This appears to manage add-on modules or optional runtime capabilities."),
        ("control_panel", "This appears to support the dashboard/control-panel layer."),
        ("system_log", "This appears to handle logs, records, and operational traceability."),
        ("aiweb_os", "This appears to be a broad AI.Web operating-system layer, so it needs extra care before authority is granted."),
        ("protoforge", "This appears to be a runtime wrapper or dashboard variant, not automatically the same as the current Forge CLI."),
    ]
    for term, meaning in mapping:
        if term in b:
            return meaning
    return "This appears to be an AI.Web engine family, but Forge does not have a strong plain-English role match yet. Treat it as review-needed, not authoritative."


def _patch77_status_and_reason(base: str, decision: dict | None, included: dict, excluded: dict) -> tuple[str, str, dict | None]:
    key = str(base or "").lower()
    if key in included:
        row = included[key]
        return "APPROVED_CANDIDATE_INCLUDED", "This engine is in the Patch 74 approved candidate list. It is still candidate-only, not final authority.", row
    if key in excluded:
        row = excluded[key]
        reason = row.get("reason", "excluded")
        review = row.get("review_status", "?")
        return "NOT_INCLUDED", f"This engine is not in the approved candidate list. Reason: {reason}. Review status: {review}.", row
    if decision:
        d = str(decision.get("draft_decision", "")).upper()
        if d.startswith("HOLD"):
            return "HOLD_REVIEW_REQUIRED", "Decision draft marks this family as a hold/manual-review item. Do not promote it yet.", decision
        if d.startswith("DRAFT"):
            return "DRAFT_ONLY_NOT_HUMAN_APPROVED", "Decision draft has a keep recommendation, but it is not necessarily human-approved yet.", decision
    return "UNKNOWN_OR_NOT_FOUND", "Forge could not match this engine to a current decision/candidate row.", None


def _patch77_risk_level(decision: dict | None, status: str) -> tuple[str, list[str]]:
    reasons = []
    risk = "LOW"
    if status in ("HOLD_REVIEW_REQUIRED", "UNKNOWN_OR_NOT_FOUND"):
        risk = "HIGH"
        reasons.append("engine is held/manual-review or not found in current review data")
    elif status == "NOT_INCLUDED":
        risk = "MEDIUM_HIGH"
        reasons.append("engine is excluded from the approved candidate list")
    elif status == "DRAFT_ONLY_NOT_HUMAN_APPROVED":
        risk = "MEDIUM"
        reasons.append("engine has draft recommendation but lacks approved candidate status")
    elif status == "APPROVED_CANDIDATE_INCLUDED":
        risk = "MEDIUM"
        reasons.append("engine is approved candidate only; final authority is still not granted")
    if decision:
        try:
            vc = int(decision.get("variant_count", 0) or 0)
        except Exception:
            vc = 0
        if vc >= 6:
            reasons.append("many variants exist; compare duplicates before final lockfile")
            if risk == "LOW":
                risk = "MEDIUM"
        if decision.get("required_human_checks"):
            reasons.append("human checks remain: " + ", ".join(decision.get("required_human_checks", [])[:3]))
            if risk == "LOW":
                risk = "MEDIUM"
        if decision.get("cautions"):
            reasons.append("cautions exist: " + ", ".join(decision.get("cautions", [])[:3]))
    if not reasons:
        reasons.append("no major risk flags detected in the current brief data")
    return risk, reasons


def _patch77_recommendation(status: str, risk: str, decision: dict | None) -> str:
    if status == "APPROVED_CANDIDATE_INCLUDED":
        return "Keep this as a candidate only. Use it for planning, but do not treat it as final canonical authority until a future final-lockfile patch exists."
    if status == "NOT_INCLUDED":
        return "Do not promote this engine yet. Review why it was excluded, then decide whether a future human review patch should change its status."
    if status == "HOLD_REVIEW_REQUIRED":
        return "Pause here. This family needs architect review before any lockfile, quarantine, or cleanup work."
    if status == "DRAFT_ONLY_NOT_HUMAN_APPROVED":
        return "Use the draft recommendation as a starting point only. Human approval is still required before it can enter an approved candidate list."
    return "Run the review/show commands first. Forge does not have enough evidence to recommend this engine for authority."


def _patch77_next_command(base: str, status: str) -> str:
    if status == "APPROVED_CANDIDATE_INCLUDED":
        return f"engine-approved-lockfile-show {base}"
    if status in ("NOT_INCLUDED", "HOLD_REVIEW_REQUIRED"):
        return f"engine-review-show {base}"
    return f"engine-decision-exact {base}"


def _patch77_build_brief(engine_base: str) -> dict:
    requested = (engine_base or "").strip()
    normalized = _code_engine_base_name(requested.lower()) if requested else ""
    decisions = _patch77_decision_map()
    included, excluded, candidate, candidate_source = _patch77_candidate_maps()

    decision = decisions.get(normalized)
    if not decision and requested:
        q = requested.lower()
        matches = [row for key, row in decisions.items() if q in key or q in str(row.get("recommended_keep_path", "")).lower()]
        if len(matches) == 1:
            decision = matches[0]
            normalized = str(decision.get("engine_base", normalized)).lower()

    path_hint = ""
    if decision:
        path_hint = str(decision.get("recommended_keep_path") or decision.get("patch68_keep_candidate") or "")
    if normalized in included:
        path_hint = str(included[normalized].get("canonical_path_candidate") or path_hint)
    elif normalized in excluded:
        path_hint = str(excluded[normalized].get("recommended_keep_path") or path_hint)

    roles = _patch77_runtime_roles_for(normalized, path_hint)
    status, status_reason, status_row = _patch77_status_and_reason(normalized, decision, included, excluded)
    risk, risk_reasons = _patch77_risk_level(decision, status)
    purpose = _patch77_plain_purpose(normalized or requested, roles)
    variants = list(decision.get("variants", []) or []) if decision else []

    return {
        "schema_version": ENGINE_BRIEF_SCHEMA_VERSION,
        "brief_type": "ENGINE_PLAIN_ENGLISH_BRIEF_V1",
        "created_at": _llm_memory_iso(),
        "engine_base_requested": requested,
        "engine_base": normalized or requested,
        "plain_english_purpose": purpose,
        "status": status,
        "status_reason": status_reason,
        "risk_level": risk,
        "risk_reasons": risk_reasons,
        "recommendation": _patch77_recommendation(status, risk, decision),
        "suggested_next_command": _patch77_next_command(normalized or requested, status),
        "candidate_source": candidate_source,
        "approved_candidate_status": {
            "candidate_loaded": bool(candidate),
            "included_count": candidate.get("included_count") if candidate else None,
            "excluded_count": candidate.get("excluded_count") if candidate else None,
            "section": "included" if normalized in included else "excluded" if normalized in excluded else "missing",
        },
        "decision_summary": {
            "found": bool(decision),
            "draft_decision": decision.get("draft_decision") if decision else None,
            "decision_confidence": decision.get("decision_confidence") if decision else None,
            "recommended_keep_path": decision.get("recommended_keep_path") if decision else path_hint,
            "patch68_keep_candidate": decision.get("patch68_keep_candidate") if decision else None,
            "variant_count": decision.get("variant_count") if decision else 0,
            "required_human_checks": decision.get("required_human_checks", []) if decision else [],
            "cautions": decision.get("cautions", []) if decision else [],
            "reason": decision.get("reason") if decision else None,
        },
        "symbolic_runtime_roles": roles,
        "variant_summary": [
            {
                "root": v.get("root"),
                "score": v.get("canonical_score"),
                "tags": v.get("status_tags", []),
                "root_class": v.get("root_class"),
                "file_count": v.get("file_count"),
            }
            for v in variants[:10]
        ],
        "authority": {
            "brief_is_authority": False,
            "canonical_lockfile_authority": False,
            "engine_files_changed": False,
            "quarantine_written": False,
        },
    }


def _patch77_print_brief(brief: dict, *, compact: bool = False) -> None:
    print(f"  Engine      : {brief.get('engine_base')}")
    print(f"  Status      : {brief.get('status')}")
    print(f"  Risk        : {brief.get('risk_level')}")
    print(f"  Candidate   : {brief.get('approved_candidate_status', {}).get('section')}  source={brief.get('candidate_source')}")
    print(f"  Purpose     : {brief.get('plain_english_purpose')}")
    print(f"  Recommend   : {brief.get('recommendation')}")
    print(f"  Next command: {brief.get('suggested_next_command')}")
    if compact:
        return
    ds = brief.get("decision_summary", {})
    print()
    print("  Decision evidence:")
    print(f"    found       : {ds.get('found')}")
    print(f"    draft       : {ds.get('draft_decision')}  confidence={ds.get('decision_confidence')}")
    print(f"    keep path   : {ds.get('recommended_keep_path')}")
    print(f"    variants    : {ds.get('variant_count')}")
    if ds.get("required_human_checks"):
        print("    human checks:")
        for item in ds.get("required_human_checks", [])[:8]:
            print(f"      - {item}")
    if ds.get("cautions"):
        print("    cautions:")
        for item in ds.get("cautions", [])[:8]:
            print(f"      - {item}")
    if brief.get("symbolic_runtime_roles"):
        print()
        print("  Symbolic/runtime role matches:")
        for role in brief.get("symbolic_runtime_roles", [])[:5]:
            print(f"    - {role.get('role_id')} — {role.get('title')} [{role.get('status')}]")
            print(f"      {role.get('description')}")
    if brief.get("variant_summary"):
        print()
        print("  Variant sample:")
        for v in brief.get("variant_summary", [])[:8]:
            print(f"    - {v.get('root')} score={v.get('score')} tags={','.join(v.get('tags', []))} class={v.get('root_class')}")
    print()
    print("  Authority:")
    print("    brief authority      : NO")
    print("    final lockfile       : NO")
    print("    engine files changed : NO")
    print("    quarantine written   : NO")


