def _patch77_all_briefs() -> list[dict]:
    bases = sorted(set(_patch77_decision_map().keys()) | set(_patch77_candidate_maps()[0].keys()) | set(_patch77_candidate_maps()[1].keys()))
    return [_patch77_build_brief(base) for base in bases]


def cmd_engine_brief_export(session_id: str) -> None:
    """Export all engine briefs to JSON and Markdown. Usage: engine-brief-export"""
    from agents.forge.memory import write_audit_entry
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    briefs = _patch77_all_briefs()
    payload = {
        "schema_version": ENGINE_BRIEF_SCHEMA_VERSION,
        "report_type": "ENGINE_BRIEF_EXPORT_V1",
        "created_at": _llm_memory_iso(),
        "brief_count": len(briefs),
        "authority": _patch77_policy_payload()["authority"],
        "briefs": briefs,
    }
    ts = _patch60_timestamp()
    json_path = CODE_MANIFESTS_DIR / f"{ts}_{ENGINE_BRIEF_EXPORT_PREFIX}.json"
    md_path = CODE_MANIFESTS_DIR / f"{ts}_{ENGINE_BRIEF_EXPORT_PREFIX}.md"
    json_path.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = [
        "# Patch 77 Engine Brief Export",
        "",
        "Mode: READ-ONLY EXPLANATION EXPORT. No engine files were moved, deleted, renamed, quarantined, promoted, or edited.",
        f"Generated: `{payload['created_at']}`",
        f"Brief count: **{len(briefs)}**",
        "",
        "## Engine Briefs",
    ]
    for brief in briefs:
        lines.append(f"### {brief.get('engine_base')}")
        lines.append(f"- Status: `{brief.get('status')}`")
        lines.append(f"- Risk: `{brief.get('risk_level')}`")
        lines.append(f"- Purpose: {brief.get('plain_english_purpose')}")
        lines.append(f"- Recommendation: {brief.get('recommendation')}")
        lines.append(f"- Suggested next command: `{brief.get('suggested_next_command')}`")
        ds = brief.get("decision_summary", {})
        if ds.get("recommended_keep_path"):
            lines.append(f"- Keep/candidate path: `{ds.get('recommended_keep_path')}`")
        lines.append("")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    print()
    print("── Engine Brief Export ──────────────────────────────")
    print("  Mode      : EXPORT ONLY")
    print("  Read-only : YES — no engine files changed")
    print(f"  JSON      : {json_path}")
    print(f"  Markdown  : {md_path}")
    print(f"  Briefs    : {len(briefs)}")
    print("  Authority : NO — explanation export only")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_BRIEF_EXPORT_WRITTEN", str(json_path), f"briefs={len(briefs)}", str(md_path))


# ─── PATCH 78 — APPROVED CANDIDATE READINESS REPORT (NO FINAL AUTHORITY) ───

ENGINE_READINESS_SCHEMA_VERSION = "engine_readiness_v1_patch78"
ENGINE_READINESS_EXPORT_PREFIX = "engine_approved_candidate_readiness_report"


def _patch78_policy_payload() -> dict:
    return {
        "schema_version": ENGINE_READINESS_SCHEMA_VERSION,
        "policy": "Patch 78 Approved Candidate Readiness Report",
        "mode": "READINESS_REPORT_ONLY",
        "purpose": "Turn the human-approved candidate list into a plain-English readiness package before any final lockfile authority exists.",
        "writes": "engine-readiness-export writes JSON/Markdown reports only under Forge-owned memory/code_library_v1/manifests.",
        "authority": {
            "canonical_lockfile_authority": False,
            "actual_lockfile_written": False,
            "engine_file_write_authority": False,
            "quarantine_authority": False,
            "delete_authority": False,
            "shell_access": False,
            "chroma_write_authority": False,
        },
        "required_next_gates_before_final_authority": [
            "human review of readiness report",
            "explicit final-lockfile proposal patch",
            "path existence/readback checks against disk",
            "variant comparison for approved candidates with multiple variants",
            "held/deferred family resolution or explicit continued exclusion",
            "snapshot/rollback plan before any future write authority",
        ],
        "core_rule": "This report explains readiness. It does not promote, move, delete, quarantine, or make any engine authoritative.",
    }


def _patch78_candidate_rows() -> tuple[list[dict], list[dict], dict | None, str]:
    included, excluded, candidate, source = _patch77_candidate_maps()
    return list(included.values()), list(excluded.values()), candidate, source


def _patch78_readiness_status(entry: dict, brief: dict) -> tuple[str, list[str], list[str]]:
    blockers = []
    next_checks = []
    if str(entry.get("review_status", "")).upper() != "APPROVED":
        blockers.append("candidate row is not human-approved")
    if not entry.get("candidate_only", False):
        blockers.append("candidate_only flag is missing or false")
    if entry.get("canonical_authority") is not False:
        blockers.append("canonical authority flag is not explicitly false")
    if entry.get("no_engine_file_action") is not True:
        blockers.append("no_engine_file_action flag is not true")
    if entry.get("no_quarantine_action") is not True:
        blockers.append("no_quarantine_action flag is not true")
    if not entry.get("canonical_path_candidate"):
        blockers.append("no canonical path candidate recorded")
    if entry.get("required_human_checks"):
        next_checks.extend(entry.get("required_human_checks") or [])
    if entry.get("variant_count", 0) and int(entry.get("variant_count") or 0) > 1:
        next_checks.append("compare variant files before final authority")
    if brief.get("symbolic_runtime_roles"):
        next_checks.append("verify symbolic runtime role match before final authority")
    else:
        next_checks.append("confirm runtime role if this engine becomes final authority")
    if blockers:
        return "NOT_READY_BLOCKED", blockers, sorted(set(next_checks))
    return "READY_FOR_HUMAN_FINAL_REVIEW_NOT_AUTHORITY", [], sorted(set(next_checks))


def _patch78_build_row(entry: dict) -> dict:
    base = str(entry.get("engine_base", "")).strip()
    brief = _patch77_build_brief(base) if base else {}
    readiness_status, blockers, next_checks = _patch78_readiness_status(entry, brief)
    return {
        "schema_version": ENGINE_READINESS_SCHEMA_VERSION,
        "engine_base": base,
        "canonical_path_candidate": entry.get("canonical_path_candidate"),
        "readiness_status": readiness_status,
        "plain_english_purpose": brief.get("plain_english_purpose"),
        "approved_candidate_status": brief.get("status"),
        "risk_level": brief.get("risk_level"),
        "risk_reasons": brief.get("risk_reasons", []),
        "review_status": entry.get("review_status"),
        "review_note": entry.get("review_note"),
        "reviewed_at": entry.get("reviewed_at"),
        "draft_decision": entry.get("draft_decision"),
        "decision_confidence": entry.get("decision_confidence"),
        "variant_count": entry.get("variant_count"),
        "required_human_checks": entry.get("required_human_checks", []),
        "cautions": entry.get("cautions", []),
        "blockers": blockers,
        "next_checks_before_final_authority": next_checks,
        "recommended_next_step": "Review this row, compare variants if required, then include only in a future explicit final-lockfile proposal patch.",
        "suggested_next_command": f"engine-readiness-show {base}" if base else "engine-readiness-report",
        "authority": {
            "ready_report_is_authority": False,
            "final_lockfile_authority": False,
            "engine_files_changed": False,
            "quarantine_written": False,
        },
    }


def _patch78_build_report() -> dict:
    included_rows, excluded_rows, candidate, source = _patch78_candidate_rows()
    rows = [_patch78_build_row(row) for row in sorted(included_rows, key=lambda r: str(r.get("engine_base", "")))]
    ready = [r for r in rows if r.get("readiness_status") == "READY_FOR_HUMAN_FINAL_REVIEW_NOT_AUTHORITY"]
    blocked = [r for r in rows if r.get("readiness_status") != "READY_FOR_HUMAN_FINAL_REVIEW_NOT_AUTHORITY"]
    excluded_hold = [r for r in excluded_rows if bool(r.get("is_hold_family")) or str(r.get("reason", "")).lower() in ("hold family excluded", "deferred by human review")]
    pending = [r for r in excluded_rows if str(r.get("review_status", "")).upper() == "PENDING_REVIEW" or str(r.get("reason", "")).lower() == "pending human review"]
    return {
        "schema_version": ENGINE_READINESS_SCHEMA_VERSION,
        "report_type": "ENGINE_APPROVED_CANDIDATE_READINESS_REPORT_V1",
        "created_at": _llm_memory_iso(),
        "mode": "READINESS_REPORT_ONLY",
        "source_candidate": source,
        "source_candidate_status": (candidate or {}).get("status") if candidate else None,
        "source_validation_status": (candidate or {}).get("validation_status") if candidate else None,
        "authority": _patch78_policy_payload()["authority"],
        "counts": {
            "included_candidates": len(rows),
            "ready_for_human_final_review_not_authority": len(ready),
            "blocked_candidate_rows": len(blocked),
            "excluded_total": len(excluded_rows),
            "excluded_holds_or_deferred": len(excluded_hold),
            "excluded_pending_review": len(pending),
            "automatic_final_lockfile_ready": 0,
        },
        "remaining_global_blockers": [
            "no final lockfile authority exists in this patch",
            "automatic final lockfile readiness is intentionally zero",
            "held/deferred families remain excluded",
            "pending families remain excluded",
            "variant comparisons and disk readbacks still need final proposal gates",
            "snapshot/rollback discipline should exist before any future multi-file authority",
        ],
        "candidate_rows": rows,
    }


def _patch78_print_row(row: dict, compact: bool = False) -> None:
    print(f"  Engine      : {row.get('engine_base')}")
    print(f"  Candidate   : {row.get('canonical_path_candidate')}")
    print(f"  Readiness   : {row.get('readiness_status')}")
    print(f"  Risk        : {row.get('risk_level')}")
    print(f"  Purpose     : {row.get('plain_english_purpose')}")
    print(f"  Review      : {row.get('review_status')} — {row.get('review_note')}")
    if compact:
        return
    if row.get("blockers"):
        print("  Blockers:")
        for item in row.get("blockers", [])[:10]:
            print(f"    - {item}")
    print("  Checks before final authority:")
    for item in row.get("next_checks_before_final_authority", [])[:12]:
        print(f"    - {item}")
    if row.get("cautions"):
        print("  Cautions:")
        for item in row.get("cautions", [])[:10]:
            print(f"    - {item}")
