    payload = _patch79_relationship_payload(base)
    print()
    print("── Code Related Files ──────────────────────────────")
    print(f"  Engine     : {base}")
    print("  Read-only  : YES")
    print(f"  Files shown: {len(payload.get('related_files', []))}")
    print()
    for row in payload.get("related_files", [])[:60]:
        reasons = "; ".join(row.get("relationship_reasons", [])[:4])
        print(f"  - [{row.get('category')}] score={row.get('relationship_score')} lines={row.get('line_count')} sha={row.get('sha256_16')}")
