def cmd_code_relationship_export(session_id: str) -> None:
    """Export relationship maps for all approved readiness candidates. Usage: code-relationship-export"""
    from agents.forge.memory import write_audit_entry
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    readiness = _patch78_build_report()
    bases = [r.get("engine_base") for r in readiness.get("candidate_rows", []) if r.get("engine_base")]
    reports = [_patch79_relationship_payload(b) for b in bases]
    payload = {
        "schema_version": CODE_RELATIONSHIP_SCHEMA_VERSION,
        "report_type": "CODE_RELATIONSHIP_INTELLIGENCE_EXPORT_V1",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "EXPORT_ONLY_READ_ONLY",
        "authority": _patch79_policy_payload()["authority"],
        "source": "approved candidate readiness rows from Patch 78",
        "counts": {
            "engine_reports": len(reports),
            "total_related_files": sum(int(r.get("counts", {}).get("related_files", 0) or 0) for r in reports),
            "total_symbols": sum(int(r.get("counts", {}).get("symbols", 0) or 0) for r in reports),
        },
        "reports": reports,
    }
    ts = _patch60_timestamp()
    json_path = CODE_MANIFESTS_DIR / f"{ts}_{CODE_RELATIONSHIP_EXPORT_PREFIX}.json"
    md_path = CODE_MANIFESTS_DIR / f"{ts}_{CODE_RELATIONSHIP_EXPORT_PREFIX}.md"
    json_path.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = [
        "# Patch 79 Code Relationship Intelligence Report",
        "",
        "Mode: EXPORT ONLY. No final lockfile authority, engine file changes, deletion, quarantine, shell execution, or Chroma writes were performed.",
        f"Generated: `{payload.get('created_at')}`",
        f"Engine reports: **{payload.get('counts', {}).get('engine_reports')}**",
        f"Total related files: **{payload.get('counts', {}).get('total_related_files')}**",
        "",
    ]
    for rep in reports:
        lines.append(f"## {rep.get('engine_base')}")
        lines.append(f"- Readiness: `{rep.get('readiness', {}).get('status')}`")
        lines.append(f"- Candidate: `{rep.get('readiness', {}).get('candidate_path')}`")
        lines.append(f"- Related files: **{rep.get('counts', {}).get('related_files')}**")
        lines.append(f"- Variants: **{rep.get('counts', {}).get('variants')}**")
        lines.append("- Risk notes:")
        for note in rep.get("risk_notes", [])[:8]:
            lines.append(f"  - {note}")
        lines.append("- Top files:")
        for row in rep.get("related_files", [])[:10]:
            lines.append(f"  - `{row.get('relative_path')}` — {row.get('category')} score={row.get('relationship_score')}")
        lines.append("")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    print()
    print("── Code Relationship Export ────────────────────────")
    print("  Mode      : EXPORT ONLY")
    print("  Read-only : YES — no engine files changed")
    print(f"  JSON      : {json_path}")
    print(f"  Markdown  : {md_path}")
    print(f"  Reports   : {len(reports)}")
    print("  Authority : NO — relationship intelligence only")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "CODE_RELATIONSHIP_EXPORT_WRITTEN", str(json_path), f"reports={len(reports)}", str(md_path))


# ─── PATCH 80 — SNAPSHOT PLAN (PLAN/EXPORT ONLY; NO RESTORE) ───────────────

SNAPSHOT_POLICY_VERSION = "patch80_snapshot_plan_v1"
SNAPSHOT_IGNORED_NAMES = {
    ".venv", "venv", "node_modules", "__pycache__", ".pytest_cache",
    ".git", ".mypy_cache", ".ruff_cache", "chroma_db",
}
SNAPSHOT_IGNORED_SUFFIXES = {".pyc", ".pyo", ".sqlite3", ".db", ".bin", ".tar", ".gz", ".zip"}
SNAPSHOT_SECRET_MARKERS = {".env", "secret", "token", "password", "passwd", "credential", "id_rsa", "id_ed25519", ".ssh"}


def _snapshot_policy_payload() -> dict:
    return {
        "schema_version": SNAPSHOT_SCHEMA_VERSION,
        "policy_version": SNAPSHOT_POLICY_VERSION,
        "policy": "Patch 80 Snapshot Plan",
        "mode": "PLAN_AND_EXPORT_ONLY_NO_SNAPSHOT_CREATE_NO_RESTORE",
        "purpose": "Prepare forensic snapshot discipline before any future final lockfile authority or multi-file action.",
        "authority": {
            "snapshot_create_authority": False,
            "restore_authority": False,
            "shadow_restore_authority": False,
            "project_file_write_authority": False,
            "engine_file_write_authority": False,
            "delete_authority": False,
            "quarantine_authority": False,
            "shell_access": False,
            "chroma_write_authority": False,
        },
        "allowed_writes": [
            "Forge-owned snapshot plan JSON/Markdown under /home/nic/forge/memory/snapshot_plans_v1/",
            "Forge audit entries describing plan/export commands",
        ],
        "forbidden": [
            "copying project files into snapshots",
            "restoring files",
            "shadow restore",
            "deleting, moving, or quarantining engines",
            "reading secrets, credentials, keys, .env, ~/.ssh, or token files",
            "writing to Chroma or old vector DBs",
            "treating a plan as a verified snapshot",
        ],
        "future_commands_not_implemented_yet": [
            "snapshot-create", "snapshot-verify", "snapshot-diff", "snapshot-shadow-restore", "snapshot-restore",
        ],
    }


def _snapshot_sha256_16(path: Path) -> str | None:
    try:
        if not path.exists() or not path.is_file():
            return None
        import hashlib as _hashlib
        h = _hashlib.sha256()
        with path.open("rb") as f:
            for chunk in iter(lambda: f.read(1024 * 1024), b""):
                h.update(chunk)
        return h.hexdigest()[:16]
    except Exception:
        return None


def _snapshot_file_row(path: Path, label: str) -> dict:
    p = Path(path)
    row = {
        "label": label,
        "path": str(p),
        "exists": p.exists(),
        "is_file": p.is_file() if p.exists() else False,
        "is_dir": p.is_dir() if p.exists() else False,
        "size_bytes": None,
        "sha256_16": None,
        "note": "metadata only; file content was not copied",
    }
    try:
        if p.exists() and p.is_file():
            row["size_bytes"] = p.stat().st_size
            row["sha256_16"] = _snapshot_sha256_16(p)
        elif p.exists() and p.is_dir():
            row["size_bytes"] = sum(1 for _ in p.iterdir())
            row["note"] = "directory entry count only; recursive copy not performed"
    except Exception as e:
        row["error"] = str(e)
    return row


def _snapshot_count_files(root: Path, limit: int = 5000) -> dict:
    root = Path(root)
    result = {"path": str(root), "exists": root.exists(), "file_count_sampled": 0, "dir_count_sampled": 0, "ignored_sampled": 0, "truncated": False}
    if not root.exists() or not root.is_dir():
        return result
    count = 0
    try:
        for p in root.rglob("*"):
            if count >= limit:
                result["truncated"] = True
                break
            parts = set(p.parts)
            name_low = p.name.lower()
            if any(part in SNAPSHOT_IGNORED_NAMES for part in parts) or any(marker in name_low for marker in SNAPSHOT_SECRET_MARKERS):
                result["ignored_sampled"] += 1
                continue
            if p.suffix.lower() in SNAPSHOT_IGNORED_SUFFIXES:
                result["ignored_sampled"] += 1
                continue
            if p.is_file():
                result["file_count_sampled"] += 1
            elif p.is_dir():
                result["dir_count_sampled"] += 1
            count += 1
    except Exception as e:
        result["error"] = str(e)
    return result


def _snapshot_latest_readiness_path() -> Path | None:
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    files = sorted(CODE_MANIFESTS_DIR.glob("*engine_approved_candidate_readiness_report*.json"), reverse=True)
    return files[0] if files else None


def _snapshot_latest_relationship_path() -> Path | None:
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    files = sorted(CODE_MANIFESTS_DIR.glob("*code_relationship_intelligence_report*.json"), reverse=True)
    return files[0] if files else None


def _snapshot_latest_plan_path() -> Path | None:
    SNAPSHOT_PLANS_DIR.mkdir(parents=True, exist_ok=True)
    files = sorted(SNAPSHOT_PLANS_DIR.glob(f"*_{SNAPSHOT_PLAN_PREFIX}.json"), reverse=True)
    return files[0] if files else None


def _snapshot_plan_paths() -> list[Path]:
    SNAPSHOT_PLANS_DIR.mkdir(parents=True, exist_ok=True)
    return sorted(SNAPSHOT_PLANS_DIR.glob(f"*_{SNAPSHOT_PLAN_PREFIX}.json"), reverse=True)


def _snapshot_load_json(path: Path) -> dict | None:
    try:
        return json.loads(Path(path).read_text(encoding="utf-8"))
    except Exception:
        return None


def _snapshot_candidate_engine_rows() -> list[dict]:
    readiness_path = _snapshot_latest_readiness_path()
    if not readiness_path:
        return []
    data = _snapshot_load_json(readiness_path) or {}
    rows = data.get("candidate_rows") or data.get("included_candidates") or []
    clean = []
    for row in rows:
        if isinstance(row, dict):
            clean.append({
                "engine_base": row.get("engine_base"),
                "candidate_path": row.get("candidate_path") or row.get("root"),
                "status": row.get("status") or row.get("readiness_status"),
                "final_authority": False,
            })
    return clean


def _snapshot_relationship_counts() -> dict:
    rel_path = _snapshot_latest_relationship_path()
    if not rel_path:
        return {"available": False, "path": None}
    data = _snapshot_load_json(rel_path) or {}
    return {
        "available": True,
        "path": str(rel_path),
        "engine_reports": data.get("counts", {}).get("engine_reports"),
        "total_related_files": data.get("counts", {}).get("total_related_files"),
        "total_symbols": data.get("counts", {}).get("total_symbols"),
    }


def _snapshot_build_plan() -> dict:
    from agents.forge.permissions import get_session_paths
    now = datetime.datetime.now().isoformat(timespec="seconds")
    readiness_path = _snapshot_latest_readiness_path()
    relationship_path = _snapshot_latest_relationship_path()
    candidate_rows = _snapshot_candidate_engine_rows()
    control_files = [
        _snapshot_file_row(FORGE_ROOT / "main.py", "forge_main_py"),
        _snapshot_file_row(CONFIG_DIR / "tool_registry.json", "tool_registry"),
        _snapshot_file_row(CONFIG_DIR / "approved_paths.json", "approved_paths"),
        _snapshot_file_row(CONFIG_DIR / "session_scope.json", "session_scope"),
        _snapshot_file_row(AUDIT_LOG, "audit_log"),
    ]
    manifest_files = [
        _snapshot_file_row(CODE_MANIFESTS_DIR / "engine_review_ledger_v1.json", "engine_review_ledger"),
        _snapshot_file_row(readiness_path, "latest_readiness_report") if readiness_path else {"label": "latest_readiness_report", "exists": False},
        _snapshot_file_row(relationship_path, "latest_relationship_report") if relationship_path else {"label": "latest_relationship_report", "exists": False},
    ]
    memory_roots = [
        _snapshot_count_files(LLM_MEMORY_DIR),
        _snapshot_count_files(CODE_LIBRARY_DIR),
        _snapshot_count_files(PATCH_SANDBOX_REPORTS_DIR),
        _snapshot_count_files(MEMORY_DIR / "test_run_reports"),
        _snapshot_count_files(MEMORY_DIR / "patch_test_bindings"),
    ]
    return {
        "schema_version": SNAPSHOT_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_PLAN_V1_PATCH80",
        "created_at": now,
        "mode": "PLAN_ONLY_NO_COPY_NO_RESTORE",
        "authority": _snapshot_policy_payload()["authority"],
        "scope": {
            "forge_root": str(FORGE_ROOT),
            "current_session_paths": get_session_paths(),
            "approved_paths_file": str(APPROVED_PATHS_FILE),
        },
        "what_this_plan_would_cover_in_future_snapshot_create": {
            "forge_control_files": control_files,
            "critical_manifest_files": manifest_files,
            "memory_roots_metadata_only": memory_roots,
            "candidate_engine_roots_from_readiness": candidate_rows,
            "relationship_report_counts": _snapshot_relationship_counts(),
        },
        "ignored_by_default": {
            "names": sorted(SNAPSHOT_IGNORED_NAMES),
            "suffixes": sorted(SNAPSHOT_IGNORED_SUFFIXES),
            "secret_markers": sorted(SNAPSHOT_SECRET_MARKERS),
        },
        "future_required_gates_before_snapshot_create": [
            "explicit snapshot-create patch",
            "path allowlist and secret-scan refusal",
            "manifest hash list",
            "verify command",
            "shadow replay before any restore",
            "explicit human approval for restore",
        ],
        "plain_english": {
            "meaning": "This is only a forensic plan. It records what a future snapshot system should capture and what it must ignore.",
            "why_now": "Patch 79 showed many related files around approved engines. Forge needs snapshot discipline before any future final authority or multi-file action.",
            "next_safe_step": "Review this plan. A later patch may add snapshot-create, but this patch does not copy or restore project files.",
        },
    }


def _snapshot_write_plan_files(plan: dict) -> tuple[Path, Path]:
    SNAPSHOT_PLANS_DIR.mkdir(parents=True, exist_ok=True)
    ts = _patch60_timestamp()
    json_path = SNAPSHOT_PLANS_DIR / f"{ts}_{SNAPSHOT_PLAN_PREFIX}.json"
    md_path = SNAPSHOT_PLANS_DIR / f"{ts}_{SNAPSHOT_PLAN_PREFIX}.md"
    json_path.write_text(json.dumps(plan, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = [
        "# Patch 80 Snapshot Plan",
        "",
        "Mode: PLAN ONLY. No project files were copied. No restore authority exists.",
        f"Generated: `{plan.get('created_at')}`",
        f"Forge root: `{plan.get('scope', {}).get('forge_root')}`",
        "",
        "## Authority",
    ]
    for k, v in plan.get("authority", {}).items():
        lines.append(f"- {k}: `{v}`")
    lines.extend(["", "## Candidate engine roots from readiness"])
    for row in plan.get("what_this_plan_would_cover_in_future_snapshot_create", {}).get("candidate_engine_roots_from_readiness", []):
        lines.append(f"- `{row.get('engine_base')}` → `{row.get('candidate_path')}` status=`{row.get('status')}`")
    lines.extend(["", "## Future gates before snapshot-create"])
    for gate in plan.get("future_required_gates_before_snapshot_create", []):
        lines.append(f"- {gate}")
    lines.extend(["", "## Plain English", "", plan.get("plain_english", {}).get("meaning", "")])
    md_path.write_text("\n".join(lines), encoding="utf-8")
    return json_path, md_path


def _snapshot_print_plan_summary(plan: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    covered = plan.get("what_this_plan_would_cover_in_future_snapshot_create", {})
    print()
    print("── Snapshot Plan ───────────────────────────────────")
    print("  Mode       : PLAN ONLY")
    print("  Authority  : NO restore, NO project writes, NO file copies")
    print(f"  Created    : {plan.get('created_at')}")
    if json_path:
        print(f"  JSON       : {json_path}")
    if md_path:
        print(f"  Markdown   : {md_path}")
    print(f"  Candidates : {len(covered.get('candidate_engine_roots_from_readiness', []))}")
    rel = covered.get("relationship_report_counts", {})
    print(f"  Relationship report available: {rel.get('available')}")
    if rel.get("available"):
        print(f"  Related files from Patch 79 : {rel.get('total_related_files')}")
    print("  Next       : review plan; future snapshot-create must be a separate patch")
    print("──────────────────────────────────────────────────────")
    print()


