def cmd_snapshot_show(arg: str, session_id: str) -> None:
    """Show a snapshot plan. Usage: snapshot-show [latest|path]"""
    from agents.forge.memory import write_audit_entry
    target = (arg or "latest").strip()
    path = None
    if target.lower() in {"latest", ""}:
        path = _snapshot_latest_plan_path()
    else:
        p = Path(os.path.expanduser(target))
        if not p.is_absolute():
            p = SNAPSHOT_PLANS_DIR / target
        path = p
    if not path or not path.exists():
        print()
        print("  No snapshot plan found. Run: snapshot-plan")
        print()
        return
    data = _snapshot_load_json(path)
    if not data:
        print()
        print(f"  Could not read snapshot plan JSON: {path}")
        print()
        return
    _snapshot_print_plan_summary(data, Path(path), None)
    write_audit_entry(session_id, "SNAPSHOT_PLAN_SHOWN", str(path), "read-only", target)


def cmd_snapshot_diff_plan(arg: str, session_id: str) -> None:
    """Compare latest snapshot plan metadata only. Usage: snapshot-diff-plan"""
    from agents.forge.memory import write_audit_entry
    plans = _snapshot_plan_paths()
    print()
    print("── Snapshot Diff Plan ───────────────────────────────")
    print("  Mode      : READ ONLY METADATA COMPARISON")
    print("  Authority : NO file diff, NO restore, NO project writes")
    if len(plans) < 2:
        print("  Status    : Not enough snapshot plans to compare yet")
        print("  Next      : Run snapshot-plan again after meaningful changes, then rerun snapshot-diff-plan")
        print("──────────────────────────────────────────────────────")
        print()
        write_audit_entry(session_id, "SNAPSHOT_DIFF_PLAN_SHOWN", "-", "not-enough-plans", "read-only")
        return
    a, b = plans[0], plans[1]
    da = _snapshot_load_json(a) or {}
    db = _snapshot_load_json(b) or {}
    ca = da.get("what_this_plan_would_cover_in_future_snapshot_create", {}).get("candidate_engine_roots_from_readiness", [])
    cb = db.get("what_this_plan_would_cover_in_future_snapshot_create", {}).get("candidate_engine_roots_from_readiness", [])
    rela = da.get("what_this_plan_would_cover_in_future_snapshot_create", {}).get("relationship_report_counts", {})
    relb = db.get("what_this_plan_would_cover_in_future_snapshot_create", {}).get("relationship_report_counts", {})
    print(f"  Newer plan : {a}")
    print(f"  Older plan : {b}")
    print(f"  Candidate count: {len(cb)} → {len(ca)}")
    print(f"  Related files : {relb.get('total_related_files')} → {rela.get('total_related_files')}")
    print("  Note       : This is not a content diff. Future snapshot-diff requires a separate patch.")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_DIFF_PLAN_SHOWN", str(a), str(b), "metadata-only")


