def cmd_snapshot_manifest_show(arg: str, session_id: str) -> None:
    """Show a snapshot manifest dry-run receipt. Usage: snapshot-manifest-show [latest|path]"""
    from agents.forge.memory import write_audit_entry
    target = (arg or "latest").strip()
    if target.lower() in {"latest", ""}:
        path = _snapshot_manifest_latest_path()
    else:
        p = Path(os.path.expanduser(target))
        if not p.is_absolute():
            p = SNAPSHOT_MANIFESTS_DIR / target
        path = p
    if not path or not path.exists():
        print()
        print("  No snapshot manifest dry-run found. Run: snapshot-manifest-dry-run")
        print()
        return
    data = _snapshot_manifest_load(path)
    if not data:
        print()
        print(f"  Could not read snapshot manifest JSON: {path}")
        print()
        return
    _snapshot_manifest_print_summary(data, Path(path), None)
    write_audit_entry(session_id, "SNAPSHOT_MANIFEST_SHOWN", str(path), "read-only", target)


def cmd_snapshot_manifest_validate(arg: str, session_id: str) -> None:
    """Validate snapshot manifest dry-run invariants. Usage: snapshot-manifest-validate [latest|path]"""
    from agents.forge.memory import write_audit_entry
    target = (arg or "latest").strip()
    if target.lower() in {"latest", ""}:
        path = _snapshot_manifest_latest_path()
    else:
        p = Path(os.path.expanduser(target))
        if not p.is_absolute():
            p = SNAPSHOT_MANIFESTS_DIR / target
        path = p
    print()
    print("── Snapshot Manifest Validate ───────────────────────")
    if not path or not path.exists():
        print("  Status : FAIL")
        print("  Reason : no manifest found; run snapshot-manifest-dry-run")
        print("──────────────────────────────────────────────────────")
        print()
        write_audit_entry(session_id, "SNAPSHOT_MANIFEST_VALIDATE_FAIL", "-", "missing", target)
        return
    data = _snapshot_manifest_load(path)
    ok, problems = _snapshot_manifest_validate_payload(data or {})
    print(f"  File   : {path}")
    print(f"  Status : {'PASS' if ok else 'FAIL'}")
    if problems:
        print("  Problems:")
        for problem in problems[:50]:
            print(f"    - {problem}")
    else:
        print("  Invariants OK: no copy authority, no restore authority, hashes present")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_MANIFEST_VALIDATE_PASS" if ok else "SNAPSHOT_MANIFEST_VALIDATE_FAIL", str(path), f"problems={len(problems)}", "dry-run-invariants")


def cmd_snapshot_manifest_export(session_id: str) -> None:
    """Export snapshot manifest dry-run index. Usage: snapshot-manifest-export"""
    from agents.forge.memory import write_audit_entry
    SNAPSHOT_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    manifests = _snapshot_manifest_paths()
    rows = []
    for p in manifests:
        data = _snapshot_manifest_load(p) or {}
        ok, problems = _snapshot_manifest_validate_payload(data)
        rows.append({
            "path": str(p),
            "created_at": data.get("created_at"),
            "source_plan": data.get("source_plan"),
            "total_files_hashed": data.get("counts", {}).get("total_files_hashed"),
            "candidate_engine_roots": data.get("counts", {}).get("candidate_engine_roots"),
            "valid": ok,
            "problem_count": len(problems),
        })
    payload = {
        "schema_version": SNAPSHOT_MANIFEST_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_MANIFEST_EXPORT_V1_PATCH81",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "EXPORT_ONLY_NO_FILE_COPY_NO_RESTORE",
        "authority": _snapshot_manifest_authority(),
        "count": len(rows),
        "manifests": rows,
    }
    ts = _patch60_timestamp()
    json_path = SNAPSHOT_MANIFESTS_DIR / f"{ts}_{SNAPSHOT_MANIFEST_EXPORT_PREFIX}.json"
    md_path = SNAPSHOT_MANIFESTS_DIR / f"{ts}_{SNAPSHOT_MANIFEST_EXPORT_PREFIX}.md"
    json_path.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = [
        "# Patch 81 Snapshot Manifest Export",
        "",
        "Mode: EXPORT ONLY. No files were copied. No restore authority exists.",
        f"Generated: `{payload.get('created_at')}`",
        f"Manifests: **{len(rows)}**",
        "",
    ]
    for row in rows[:100]:
        lines.append(f"- `{row.get('created_at')}` valid=`{row.get('valid')}` files_hashed=`{row.get('total_files_hashed')}` candidate_roots=`{row.get('candidate_engine_roots')}` path=`{row.get('path')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    print()
    print("── Snapshot Manifest Export ────────────────────────")
    print("  Mode      : EXPORT ONLY")
    print("  JSON      :", json_path)
    print("  Markdown  :", md_path)
    print("  Manifests :", len(rows))
    print("  Authority : NO restore, NO project writes")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_MANIFEST_EXPORT_WRITTEN", str(json_path), str(md_path), f"manifests={len(rows)}")


