def _snapshot_readiness_latest_path() -> Path | None:
    SNAPSHOT_READINESS_DIR.mkdir(parents=True, exist_ok=True)
    files = sorted(SNAPSHOT_READINESS_DIR.glob(f"*_{SNAPSHOT_READINESS_PREFIX}.json"), reverse=True)
    return files[0] if files else None


def _snapshot_readiness_paths() -> list[Path]:
    SNAPSHOT_READINESS_DIR.mkdir(parents=True, exist_ok=True)
    return sorted(SNAPSHOT_READINESS_DIR.glob(f"*_{SNAPSHOT_READINESS_PREFIX}.json"), reverse=True)


def _snapshot_readiness_load(path: Path) -> dict | None:
    try:
        return json.loads(Path(path).read_text(encoding="utf-8"))
    except Exception:
        return None


def _snapshot_readiness_manifest_rows(manifest: dict) -> list[dict]:
    rows = []
    if not isinstance(manifest, dict):
        return rows
    for row in manifest.get("direct_files", []) or []:
        if isinstance(row, dict):
            rows.append(dict(row))
    for scan in (manifest.get("root_scans", []) or []) + (manifest.get("candidate_engine_root_scans", []) or []):
        if not isinstance(scan, dict):
            continue
        for row in scan.get("files", []) or []:
            if isinstance(row, dict):
                rows.append(dict(row))
    return rows


def _snapshot_readiness_is_expected_volatile(path: str) -> bool:
    try:
        resolved = str(Path(path).resolve())
    except Exception:
        resolved = str(path)
    return resolved in SNAPSHOT_READINESS_EXPECTED_VOLATILE_PATHS or resolved == str(AUDIT_LOG)


def _snapshot_readiness_rehash_row(row: dict) -> dict:
    path = row.get("path")
    original_sha = row.get("sha256")
    result = {
        "path": path,
        "label": row.get("label"),
        "root_label": row.get("root_label"),
        "original_sha256": original_sha,
        "current_sha256": None,
        "status": "NOT_CHECKED",
        "expected_volatile": False,
        "blocker": False,
        "note": "read-only rehash; no content copied",
    }
    if not row.get("included"):
        result["status"] = "SKIPPED_NOT_INCLUDED"
        return result
    if not path:
        result["status"] = "MISSING_PATH_IN_MANIFEST_ROW"
        result["blocker"] = True
        return result
    result["expected_volatile"] = _snapshot_readiness_is_expected_volatile(path)
    p = Path(path)
    try:
        if not p.exists():
            result["status"] = "MISSING_ON_DISK"
            result["blocker"] = not result["expected_volatile"]
            return result
        if not p.is_file():
            result["status"] = "NOT_A_FILE_ON_DISK"
            result["blocker"] = not result["expected_volatile"]
            return result
        ok, reason = _snapshot_manifest_safe_to_hash(p)
        if not ok:
            result["status"] = f"UNSAFE_TO_REHASH:{reason}"
            result["blocker"] = not result["expected_volatile"]
            return result
        import hashlib as _hashlib
        h = _hashlib.sha256()
        with p.open("rb") as f:
            for chunk in iter(lambda: f.read(1024 * 1024), b""):
                h.update(chunk)
        current = h.hexdigest()
        result["current_sha256"] = current
        if not original_sha:
            result["status"] = "ORIGINAL_SHA_MISSING"
            result["blocker"] = not result["expected_volatile"]
        elif current == original_sha:
            result["status"] = "MATCH"
        elif result["expected_volatile"]:
            result["status"] = "EXPECTED_VOLATILE_DRIFT"
        else:
            result["status"] = "UNEXPECTED_HASH_DRIFT"
            result["blocker"] = True
    except Exception as e:
        result["status"] = f"REHASH_ERROR:{e}"
        result["blocker"] = not result["expected_volatile"]
    return result


def _snapshot_readiness_build_report() -> dict:
    now = datetime.datetime.now().isoformat(timespec="seconds")
    manifest_path = _snapshot_manifest_latest_path()
    plan_path = _snapshot_latest_plan_path()
    readiness_source = _snapshot_latest_readiness_path()
    relationship_source = _snapshot_latest_relationship_path()
    blockers = []
    warnings = []
    manifest = None
    manifest_ok = False
    manifest_problems = []
    rehash_rows = []

    if not manifest_path or not manifest_path.exists():
        blockers.append("No Patch 81 snapshot manifest dry-run exists. Run snapshot-manifest-dry-run first.")
    else:
        manifest = _snapshot_manifest_load(manifest_path) or {}
        manifest_ok, manifest_problems = _snapshot_manifest_validate_payload(manifest)
        if not manifest_ok:
            blockers.extend([f"Manifest invariant problem: {p}" for p in manifest_problems])

    if not plan_path or not plan_path.exists():
        blockers.append("No Patch 80 snapshot plan exists. Run snapshot-plan first.")
    if not readiness_source or not readiness_source.exists():
        warnings.append("No Patch 78 readiness report found; final lockfile readiness context may be incomplete.")
    if not relationship_source or not relationship_source.exists():
        warnings.append("No Patch 79 relationship report found; code relationship context may be incomplete.")

    if manifest:
        rows = [row for row in _snapshot_readiness_manifest_rows(manifest) if row.get("included")]
        for row in rows:
            check = _snapshot_readiness_rehash_row(row)
            rehash_rows.append(check)
            if check.get("blocker"):
                blockers.append(f"{check.get('status')}: {check.get('path')}")
        expected_drift = [row for row in rehash_rows if row.get("status") == "EXPECTED_VOLATILE_DRIFT"]
        if expected_drift:
            warnings.append(f"Expected volatile drift observed in {len(expected_drift)} file(s), normally audit log growth.")
        if len(rows) <= 0:
            blockers.append("Manifest contains zero included rows to rehash.")

    candidate_root_scans = (manifest or {}).get("candidate_engine_root_scans", []) if manifest else []
    missing_candidate_roots = [scan for scan in candidate_root_scans if isinstance(scan, dict) and not scan.get("exists")]
    if missing_candidate_roots:
        warnings.append(f"{len(missing_candidate_roots)} approved candidate engine root scan(s) did not resolve to existing directories in the manifest. This blocks authority later unless explained by path metadata.")

    status = "BLOCKED"
    future_snapshot_create_proposal_eligible = False
    if not blockers:
        future_snapshot_create_proposal_eligible = True
        status = "READY_WITH_WARNINGS_FOR_FUTURE_SNAPSHOT_CREATE_PATCH" if warnings else "READY_FOR_FUTURE_SNAPSHOT_CREATE_PATCH"

    counts = {
        "manifest_rows_rehashed": len(rehash_rows),
        "matches": sum(1 for row in rehash_rows if row.get("status") == "MATCH"),
        "expected_volatile_drifts": sum(1 for row in rehash_rows if row.get("status") == "EXPECTED_VOLATILE_DRIFT"),
        "unexpected_drifts": sum(1 for row in rehash_rows if row.get("status") == "UNEXPECTED_HASH_DRIFT"),
        "blockers": len(blockers),
        "warnings": len(warnings),
        "candidate_engine_root_scans": len(candidate_root_scans),
        "missing_candidate_roots": len(missing_candidate_roots),
    }
    return {
        "schema_version": SNAPSHOT_READINESS_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_CREATE_READINESS_GATE_V1_PATCH82",
        "created_at": now,
        "mode": "READINESS_GATE_ONLY_NO_SNAPSHOT_CREATE_NO_RESTORE",
        "status": status,
        "authority": _snapshot_readiness_authority(),
        "future_snapshot_create_proposal_eligible": future_snapshot_create_proposal_eligible,
        "snapshot_create_command_exists": False,
        "sources": {
            "snapshot_manifest": str(manifest_path) if manifest_path else None,
            "snapshot_plan": str(plan_path) if plan_path else None,
            "engine_readiness_report": str(readiness_source) if readiness_source else None,
            "code_relationship_report": str(relationship_source) if relationship_source else None,
        },
        "manifest_validation": {
            "passed": manifest_ok,
            "problems": manifest_problems,
        },
        "counts": counts,
        "blockers": blockers,
        "warnings": warnings,
        "rehash_rows": rehash_rows,
        "plain_english": {
            "meaning": "Forge rechecked the latest dry-run manifest without copying files or creating a snapshot.",
            "audit_note": "Audit log hash drift is expected after a manifest because Forge writes new audit entries after the manifest is created.",
            "next_safe_step": "If this gate is not blocked, the next patch may add snapshot-create as a separate explicit command that still has no restore authority.",
        },
    }


def _snapshot_readiness_write_files(report: dict) -> tuple[Path, Path]:
    SNAPSHOT_READINESS_DIR.mkdir(parents=True, exist_ok=True)
    ts = _patch60_timestamp()
    json_path = SNAPSHOT_READINESS_DIR / f"{ts}_{SNAPSHOT_READINESS_PREFIX}.json"
    md_path = SNAPSHOT_READINESS_DIR / f"{ts}_{SNAPSHOT_READINESS_PREFIX}.md"
    json_path.write_text(json.dumps(report, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = [
        "# Patch 82 Snapshot Create Readiness Gate",
        "",
        "Mode: READINESS GATE ONLY. No snapshot was created. No restore authority exists.",
        f"Generated: `{report.get('created_at')}`",
        f"Status: **{report.get('status')}**",
        f"Future snapshot-create proposal eligible: `{report.get('future_snapshot_create_proposal_eligible')}`",
        "",
        "## Counts",
    ]
    for k, v in (report.get("counts") or {}).items():
        lines.append(f"- `{k}`: `{v}`")
    lines.append("")
    lines.append("## Blockers")
    if report.get("blockers"):
        for item in report.get("blockers", [])[:100]:
            lines.append(f"- {item}")
    else:
        lines.append("- None")
    lines.append("")
    lines.append("## Warnings")
    if report.get("warnings"):
        for item in report.get("warnings", [])[:100]:
            lines.append(f"- {item}")
    else:
        lines.append("- None")
    lines.append("")
    lines.append("## Authority")
    lines.append("All authority flags remain false. This report does not create, copy, restore, quarantine, delete, or authorize a final lockfile.")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    return json_path, md_path


def _snapshot_readiness_print_summary(report: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    counts = report.get("counts", {}) or {}
    print()
    print("── Snapshot Create Readiness Gate ───────────────────")
    print("  Mode      : READINESS ONLY — no snapshot create, no restore")
    print(f"  Status    : {report.get('status')}")
    print(f"  Eligible  : {report.get('future_snapshot_create_proposal_eligible')}")
    print(f"  Rehashed  : {counts.get('manifest_rows_rehashed')}")
    print(f"  Matches   : {counts.get('matches')}")
    print(f"  Expected volatile drift : {counts.get('expected_volatile_drifts')}")
    print(f"  Unexpected drift        : {counts.get('unexpected_drifts')}")
    print(f"  Blockers  : {counts.get('blockers')}")
    print(f"  Warnings  : {counts.get('warnings')}")
    if json_path:
        print(f"  JSON      : {json_path}")
    if md_path:
        print(f"  Markdown  : {md_path}")
    print("  Authority : NO create, NO restore, NO project writes")
    print("──────────────────────────────────────────────────────")
    print()


