def cmd_snapshot_readiness_check(session_id: str) -> None:
    """Verify latest dry-run manifest and write readiness receipt. Usage: snapshot-readiness-check"""
    from agents.forge.memory import write_audit_entry
    report = _snapshot_readiness_build_report()
    json_path, md_path = _snapshot_readiness_write_files(report)
    _snapshot_readiness_print_summary(report, json_path, md_path)
    write_audit_entry(session_id, "SNAPSHOT_READINESS_CHECK_WRITTEN", str(json_path), str(md_path), f"status={report.get('status')} blockers={len(report.get('blockers', []))}")


def cmd_snapshot_readiness_show(arg: str, session_id: str) -> None:
    """Show snapshot readiness receipt. Usage: snapshot-readiness-show [latest|path]"""
    from agents.forge.memory import write_audit_entry
    target = (arg or "latest").strip()
    if target.lower() in {"latest", ""}:
        path = _snapshot_readiness_latest_path()
    else:
        p = Path(os.path.expanduser(target))
        if not p.is_absolute():
            p = SNAPSHOT_READINESS_DIR / target
        path = p
    if not path or not path.exists():
        print()
        print("  No snapshot readiness receipt found. Run: snapshot-readiness-check")
        print()
        return
    report = _snapshot_readiness_load(path)
    if not report:
        print()
        print(f"  Could not read snapshot readiness JSON: {path}")
        print()
        return
    _snapshot_readiness_print_summary(report, Path(path), None)
    write_audit_entry(session_id, "SNAPSHOT_READINESS_SHOWN", str(path), "read-only", target)


