def cmd_snapshot_shadow_validate(arg: str, session_id: str) -> None:
    """Validate a shadow restore plan. Usage: snapshot-shadow-validate [latest|path]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_shadow_resolve_path(arg)
    print()
