# ─── PATCH 115 — FINAL APPROVED ENGINE LOCKFILE PROPOSAL/APPLY ──────────────

_PATCH115_POLICY_VERSION = "patch115_final_approved_engine_lockfile_v1"
_PATCH115_PROPOSAL_PREFIX = "engine_final_lockfile_proposal_v1"
_PATCH115_FINAL_PREFIX = "engine_canonical_lockfile_v1"
_PATCH115_RECEIPT_PREFIX = "engine_final_lockfile_apply_receipt_v1"
_PATCH115_EXPORT_PREFIX = "engine_final_lockfile_export_v1"
_PATCH115_CONFIRM_TOKEN = "CONFIRM_WRITE_FINAL_ENGINE_LOCKFILE"


def _patch115_now() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch115_iso_now() -> str:
    return datetime.datetime.now().isoformat(timespec="seconds")


def _patch115_sha256(path: Path | str | None) -> str | None:
    if not path:
        return None
    try:
        p = Path(path)
        h = hashlib.sha256()
        with p.open("rb") as f:
            for block in iter(lambda: f.read(1024 * 1024), b""):
                h.update(block)
        return h.hexdigest()
    except Exception:
        return None


def _patch115_load_json(path: Path | str | None) -> dict | None:
    if not path:
        return None
    try:
        p = Path(path)
        return json.loads(p.read_text(encoding="utf-8"))
    except Exception:
        return None


def _patch115_latest_manifest(pattern: str) -> Path | None:
    try:
        CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
        files = [p for p in CODE_MANIFESTS_DIR.glob(pattern) if p.is_file()]
        return max(files, key=lambda p: p.stat().st_mtime) if files else None
    except Exception:
        return None


def _patch115_latest_candidate() -> tuple[dict | None, Path | None, str | None]:
    candidate, path, err = _patch74_load_latest_candidate(build_if_missing=False)
    return candidate, path, err


def _patch115_latest_readiness() -> tuple[dict | None, Path | None, str | None]:
    path = _patch115_latest_manifest("*_engine_approved_candidate_readiness_report.json")
    if not path:
        return None, None, "readiness report not found; run engine-readiness-export first"
    data = _patch115_load_json(path)
    if not data:
        return None, path, "readiness report unreadable"
    return data, path, None


def _patch115_latest_proposal_path() -> Path | None:
    return _patch115_latest_manifest(f"*_{_PATCH115_PROPOSAL_PREFIX}.json")


def _patch115_latest_final_path() -> Path:
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    return CODE_MANIFESTS_DIR / f"{_PATCH115_FINAL_PREFIX}.json"


def _patch115_latest_apply_receipt_path() -> Path | None:
    return _patch115_latest_manifest(f"*_{_PATCH115_RECEIPT_PREFIX}.json")


def _patch115_policy_payload() -> dict:
    final_path = _patch115_latest_final_path()
    return {
        "schema_version": "engine_final_lockfile_policy_v1_patch115",
        "policy_version": _PATCH115_POLICY_VERSION,
        "policy": "Patch 115 Final Approved Engine Lockfile Proposal/Apply",
        "mode": "PROPOSAL_FIRST_CONFIRMED_APPLY_ONLY",
        "purpose": "Convert the validated human-approved candidate lockfile into the final Forge-owned canonical engine lockfile after SHA verification and an explicit confirmation token.",
        "confirm_token": _PATCH115_CONFIRM_TOKEN,
        "stable_final_lockfile_path": str(final_path),
        "allowed_writes": [
            "Forge-owned final lockfile proposal JSON/Markdown under /home/nic/forge/memory/code_library_v1/manifests/",
            "Forge-owned final canonical engine lockfile JSON/Markdown under /home/nic/forge/memory/code_library_v1/manifests/",
            "Forge-owned final lockfile apply receipt JSON/Markdown under /home/nic/forge/memory/code_library_v1/manifests/",
            "Forge audit entries",
        ],
        "forbidden": [
            "editing AI.Web engine files",
            "deleting, moving, quarantining, or renaming engine folders",
            "changing the human review ledger",
            "approving/defering/rejecting engines",
            "writing Chroma/vector databases",
            "running shell commands",
            "reading secrets, keys, credentials, .env files, or ~/.ssh",
            "silent final lockfile writes without confirmation token",
        ],
        "required_inputs": [
            "latest VALID_CANDIDATE from engine-approved-lockfile-candidate",
            "latest PASS validation from engine-approved-lockfile-validate",
            "latest approved candidate readiness report from engine-readiness-export",
            "engine review ledger with pending=0",
            "candidate SHA, readiness SHA, and ledger SHA must remain unchanged between proposal and apply",
        ],
        "authority": {
            "final_lockfile_proposal_authority": True,
            "final_lockfile_write_authority": "only with explicit confirm token",
            "engine_file_write_authority": False,
            "quarantine_authority": False,
            "delete_authority": False,
            "human_review_ledger_write_authority": False,
            "chroma_write_authority": False,
            "shell_execution_authority": False,
            "llm_autonomous_decision_authority": False,
        },
    }


def _patch115_build_proposal() -> dict:
    candidate, candidate_path, candidate_err = _patch115_latest_candidate()
    readiness, readiness_path, readiness_err = _patch115_latest_readiness()
    errors: list[str] = []
    warnings: list[str] = []

    if candidate_err or not candidate or not candidate_path:
        errors.append(candidate_err or "approved lockfile candidate missing")
    if readiness_err or not readiness or not readiness_path:
        errors.append(readiness_err or "readiness report missing")

    candidate_sha = _patch115_sha256(candidate_path) if candidate_path else None
    readiness_sha = _patch115_sha256(readiness_path) if readiness_path else None

    ledger_path: Path | None = None
    ledger_sha: str | None = None
    ledger = None
    if candidate:
        raw_ledger_path = candidate.get("source_ledger_path")
        if raw_ledger_path:
            ledger_path = Path(raw_ledger_path)
            ledger = _patch115_load_json(ledger_path)
            ledger_sha = _patch115_sha256(ledger_path)
        else:
            errors.append("candidate does not include source_ledger_path")

    if candidate:
        if candidate.get("status") != "VALID_CANDIDATE":
            errors.append(f"candidate status is not VALID_CANDIDATE: {candidate.get('status')}")
        if candidate.get("validation_status") != "PASS":
            errors.append(f"candidate validation_status is not PASS: {candidate.get('validation_status')}")
        if candidate.get("canonical_authority") is not False:
            errors.append("candidate unexpectedly already claims canonical authority")
        if candidate.get("actual_lockfile_written") is not False:
            errors.append("candidate unexpectedly says actual lockfile was already written")
        review_counts = candidate.get("review_counts") or {}
        if int(review_counts.get("pending", -1)) != 0:
            errors.append(f"candidate review_counts.pending is not 0: {review_counts.get('pending')}")
        if int(candidate.get("included_count") or 0) <= 0:
            errors.append("candidate has no included entries")
        seen: set[str] = set()
        for row in candidate.get("candidate_entries") or []:
            base = str(row.get("engine_base") or "").strip()
            path = str(row.get("canonical_path_candidate") or "").strip()
            if not base:
                errors.append("candidate row missing engine_base")
            if not path:
                errors.append(f"candidate row missing canonical_path_candidate: {base or '?'}")
            if base in seen:
                errors.append(f"duplicate candidate row engine_base: {base}")
            seen.add(base)

    if readiness:
        counts = readiness.get("counts") or {}
        if readiness.get("source_candidate_status") != "VALID_CANDIDATE":
            errors.append(f"readiness source_candidate_status is not VALID_CANDIDATE: {readiness.get('source_candidate_status')}")
        if readiness.get("source_validation_status") != "PASS":
            errors.append(f"readiness source_validation_status is not PASS: {readiness.get('source_validation_status')}")
        if int(counts.get("blocked_candidate_rows") or 0) != 0:
            errors.append(f"readiness blocked_candidate_rows is not 0: {counts.get('blocked_candidate_rows')}")
        if int(counts.get("excluded_pending_review") or 0) != 0:
            errors.append(f"readiness excluded_pending_review is not 0: {counts.get('excluded_pending_review')}")
        if candidate and int(counts.get("included_candidates") or -1) != int(candidate.get("included_count") or -2):
            errors.append("readiness included_candidates does not match candidate included_count")
        if int(counts.get("automatic_final_lockfile_ready") or 0) != 0:
            warnings.append("readiness correctly reports automatic_final_lockfile_ready=0; Patch 115 requires explicit confirmation token")

    if ledger:
        entries = ledger.get("entries") or []
        pending = [e for e in entries if str(e.get("review_status", "")).upper() in ("PENDING_REVIEW", "PENDING", "")]
        if pending:
            errors.append(f"ledger still has pending review rows: {len(pending)}")
    elif ledger_path:
        errors.append(f"source ledger unreadable: {ledger_path}")

    final_path = _patch115_latest_final_path()
    timestamped_final_path = CODE_MANIFESTS_DIR / f"{_patch115_now()}_{_PATCH115_FINAL_PREFIX}.json"
    proposal_status = "READY_FOR_FINAL_LOCKFILE_WRITE" if not errors else "BLOCKED_FINAL_LOCKFILE_WRITE"

    entries_preview = []
    if candidate:
        for row in candidate.get("candidate_entries") or []:
            entries_preview.append({
                "engine_base": row.get("engine_base"),
                "canonical_path": row.get("canonical_path_candidate"),
                "review_status": row.get("review_status"),
                "decision_confidence": row.get("decision_confidence"),
                "variant_count": row.get("variant_count"),
                "required_human_checks": row.get("required_human_checks") or [],
                "cautions": row.get("cautions") or [],
            })

    return {
        "schema_version": "engine_final_lockfile_proposal_v1_patch115",
        "report_type": "ENGINE_FINAL_LOCKFILE_PROPOSAL_V1",
        "policy_version": _PATCH115_POLICY_VERSION,
        "created_at": _patch115_iso_now(),
        "mode": "FINAL_LOCKFILE_PROPOSAL_ONLY_NO_WRITE",
        "proposal_status": proposal_status,
        "confirm_token_required": _PATCH115_CONFIRM_TOKEN,
        "authority": {
            "proposal_authority": True,
            "final_lockfile_authority_now": False,
            "final_lockfile_write_requires_confirm_token": True,
            "engine_file_write_authority": False,
            "quarantine_authority": False,
            "delete_authority": False,
            "human_review_ledger_write_authority": False,
            "chroma_write_authority": False,
            "shell_execution_authority": False,
            "llm_autonomous_decision_authority": False,
        },
        "source_candidate_path": str(candidate_path) if candidate_path else None,
        "source_candidate_sha256": candidate_sha,
        "source_readiness_path": str(readiness_path) if readiness_path else None,
        "source_readiness_sha256": readiness_sha,
        "source_ledger_path": str(ledger_path) if ledger_path else None,
        "source_ledger_sha256": ledger_sha,
        "would_write": {
            "stable_final_lockfile_path": str(final_path),
            "timestamped_final_lockfile_path": str(timestamped_final_path),
            "markdown_stable_path": str(final_path.with_suffix(".md")),
        },
        "counts": {
            "included": int(candidate.get("included_count") or 0) if candidate else 0,
            "excluded": int(candidate.get("excluded_count") or 0) if candidate else 0,
            "ledger_total": (candidate.get("review_counts") or {}).get("total") if candidate else None,
            "ledger_approved": (candidate.get("review_counts") or {}).get("approved") if candidate else None,
            "ledger_deferred": (candidate.get("review_counts") or {}).get("deferred") if candidate else None,
            "ledger_pending": (candidate.get("review_counts") or {}).get("pending") if candidate else None,
            "future_lockfile_eligible": (candidate.get("review_counts") or {}).get("eligible_approved") if candidate else None,
        },
        "entries_preview": entries_preview,
        "excluded_entries": candidate.get("excluded_entries", []) if candidate else [],
        "verification": {
            "status": "PASS" if not errors else "FAIL",
            "errors": errors,
            "warnings": warnings,
            "required_invariants": [
                "latest approved candidate exists",
                "approved candidate status is VALID_CANDIDATE",
                "approved candidate validation_status is PASS",
                "readiness report exists",
                "readiness blocked_candidate_rows is zero",
                "ledger pending count is zero",
                "candidate/readiness/ledger SHAs must be unchanged at apply time",
                "final apply requires explicit confirmation token",
                "final lockfile write is Forge-owned manifest only",
                "engine files remain unchanged",
                "human review ledger remains unchanged",
            ],
        },
    }


def _patch115_markdown_for_proposal(proposal: dict) -> str:
    lines = [
        "# Patch 115 Final Approved Engine Lockfile Proposal",
        "",
        f"Created: `{proposal.get('created_at')}`",
        f"Status: `{proposal.get('proposal_status')}`",
        f"Confirm token required: `{proposal.get('confirm_token_required')}`",
        "",
        "## Source SHAs",
        f"- Candidate: `{proposal.get('source_candidate_path')}`",
        f"- Candidate SHA: `{proposal.get('source_candidate_sha256')}`",
        f"- Readiness: `{proposal.get('source_readiness_path')}`",
        f"- Readiness SHA: `{proposal.get('source_readiness_sha256')}`",
        f"- Ledger: `{proposal.get('source_ledger_path')}`",
        f"- Ledger SHA: `{proposal.get('source_ledger_sha256')}`",
        "",
        "## Counts",
    ]
    for k, v in (proposal.get("counts") or {}).items():
        lines.append(f"- {k}: `{v}`")
    lines.extend(["", "## Would write"])
    for k, v in (proposal.get("would_write") or {}).items():
        lines.append(f"- {k}: `{v}`")
    ver = proposal.get("verification") or {}
    lines.extend(["", "## Verification", f"- Status: `{ver.get('status')}`"])
    lines.extend(["", "### Errors"])
    for item in ver.get("errors") or ["None"]:
        lines.append(f"- {item}")
    lines.extend(["", "### Warnings"])
    for item in ver.get("warnings") or ["None"]:
        lines.append(f"- {item}")
    lines.extend(["", "## Included engines"])
    for row in proposal.get("entries_preview", [])[:200]:
        lines.append(f"- `{row.get('engine_base')}` → `{row.get('canonical_path')}`")
    lines.extend(["", "## Excluded engines"])
    for row in proposal.get("excluded_entries", [])[:200]:
        lines.append(f"- `{row.get('engine_base')}` — `{row.get('reason')}`")
    return "\n".join(lines) + "\n"


def _patch115_save_proposal(proposal: dict) -> tuple[Path, Path]:
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    ts = _patch115_now()
    json_path = CODE_MANIFESTS_DIR / f"{ts}_{_PATCH115_PROPOSAL_PREFIX}.json"
    md_path = CODE_MANIFESTS_DIR / f"{ts}_{_PATCH115_PROPOSAL_PREFIX}.md"
    json_path.write_text(json.dumps(proposal, indent=2, ensure_ascii=False), encoding="utf-8")
    md_path.write_text(_patch115_markdown_for_proposal(proposal), encoding="utf-8")
    (CODE_MANIFESTS_DIR / f"latest_{_PATCH115_PROPOSAL_PREFIX}.json").write_text(json.dumps(proposal, indent=2, ensure_ascii=False), encoding="utf-8")
    (CODE_MANIFESTS_DIR / f"latest_{_PATCH115_PROPOSAL_PREFIX}.md").write_text(_patch115_markdown_for_proposal(proposal), encoding="utf-8")
    return json_path, md_path


def _patch115_load_proposal(ref: str = "latest") -> tuple[dict | None, Path | None, str | None]:
    ref = (ref or "latest").strip()
    if ref.lower() == "latest":
        path = _patch115_latest_manifest(f"*_{_PATCH115_PROPOSAL_PREFIX}.json")
    else:
        path = Path(ref).expanduser()
    if not path or not path.exists():
        return None, path, "final lockfile proposal not found"
    data = _patch115_load_json(path)
    if not data:
        return None, path, "final lockfile proposal unreadable"
    return data, path, None


def _patch115_verify_proposal_data(proposal: dict, proposal_path: Path | None = None) -> tuple[bool, list[str], list[str]]:
    errors: list[str] = []
    warnings: list[str] = []
    if not proposal:
        return False, ["proposal missing"], warnings
    if proposal.get("proposal_status") != "READY_FOR_FINAL_LOCKFILE_WRITE":
        errors.append(f"proposal_status is not READY_FOR_FINAL_LOCKFILE_WRITE: {proposal.get('proposal_status')}")
    ver = proposal.get("verification") or {}
    if ver.get("status") != "PASS":
        errors.append(f"proposal verification status is not PASS: {ver.get('status')}")
    for label, path_key, sha_key in [
        ("candidate", "source_candidate_path", "source_candidate_sha256"),
        ("readiness", "source_readiness_path", "source_readiness_sha256"),
        ("ledger", "source_ledger_path", "source_ledger_sha256"),
    ]:
        raw_path = proposal.get(path_key)
        expected_sha = proposal.get(sha_key)
        if not raw_path or not expected_sha:
            errors.append(f"{label} path or sha missing from proposal")
            continue
        p = Path(raw_path)
        current_sha = _patch115_sha256(p)
        if not p.exists():
            errors.append(f"{label} path missing: {p}")
        elif current_sha != expected_sha:
            errors.append(f"{label} SHA changed since proposal: expected={expected_sha} current={current_sha}")
    if proposal_path and not proposal_path.exists():
        errors.append(f"proposal path missing: {proposal_path}")
    if _patch115_latest_final_path().exists():
        warnings.append("stable final lockfile already exists; confirmed apply will overwrite the Forge-owned stable manifest path")
    return len(errors) == 0, errors, warnings


def _patch115_build_final_lockfile(proposal: dict, proposal_path: Path) -> dict:
    candidate = _patch115_load_json(proposal.get("source_candidate_path")) or {}
    entries = []
    for idx, row in enumerate(candidate.get("candidate_entries") or [], start=1):
        entries.append({
            "index": idx,
            "engine_base": row.get("engine_base"),
            "canonical_path": row.get("canonical_path_candidate"),
            "review_status": row.get("review_status"),
            "review_note": row.get("review_note"),
            "reviewed_at": row.get("reviewed_at"),
            "reviewed_by": row.get("reviewed_by"),
            "draft_decision": row.get("draft_decision"),
            "decision_confidence": row.get("decision_confidence"),
            "variant_count": row.get("variant_count"),
            "required_human_checks": row.get("required_human_checks") or [],
            "cautions": row.get("cautions") or [],
            "source_candidate": str(proposal.get("source_candidate_path")),
            "source_candidate_sha256": proposal.get("source_candidate_sha256"),
        })
    return {
        "schema_version": "engine_canonical_lockfile_v1_patch115",
        "report_type": "ENGINE_CANONICAL_LOCKFILE_V1",
        "policy_version": _PATCH115_POLICY_VERSION,
        "created_at": _patch115_iso_now(),
        "mode": "FINAL_ENGINE_LOCKFILE_WRITTEN_BY_EXPLICIT_CONFIRM_TOKEN",
        "canonical_authority": True,
        "actual_lockfile_written": True,
        "authority": {
            "final_engine_lockfile_authority": True,
            "engine_file_write_authority": False,
            "quarantine_authority": False,
            "delete_authority": False,
            "human_review_ledger_write_authority": False,
            "chroma_write_authority": False,
            "shell_execution_authority": False,
            "llm_autonomous_decision_authority": False,
        },
        "source_proposal_path": str(proposal_path),
        "source_proposal_sha256": _patch115_sha256(proposal_path),
        "source_candidate_path": proposal.get("source_candidate_path"),
        "source_candidate_sha256": proposal.get("source_candidate_sha256"),
        "source_readiness_path": proposal.get("source_readiness_path"),
        "source_readiness_sha256": proposal.get("source_readiness_sha256"),
        "source_ledger_path": proposal.get("source_ledger_path"),
        "source_ledger_sha256": proposal.get("source_ledger_sha256"),
        "counts": proposal.get("counts") or {},
        "included_count": len(entries),
        "excluded_count": len(candidate.get("excluded_entries") or []),
        "canonical_entries": entries,
        "excluded_entries": candidate.get("excluded_entries") or [],
        "safety": {
            "engine_files_changed": False,
            "project_files_changed": False,
            "quarantine_written": False,
            "delete_performed": False,
            "only_forge_manifest_files_written": True,
            "confirmation_token_used": _PATCH115_CONFIRM_TOKEN,
        },
    }


def _patch115_markdown_for_final(final: dict) -> str:
    lines = [
        "# Final Canonical Engine Lockfile — Patch 115",
        "",
        f"Created: `{final.get('created_at')}`",
        f"Canonical authority: `{final.get('canonical_authority')}`",
        f"Included: `{final.get('included_count')}`",
        f"Excluded: `{final.get('excluded_count')}`",
        "",
        "No AI.Web engine files were edited. This is a Forge-owned manifest lockfile.",
        "",
        "## Source SHAs",
        f"- Proposal: `{final.get('source_proposal_path')}`",
        f"- Proposal SHA: `{final.get('source_proposal_sha256')}`",
        f"- Candidate SHA: `{final.get('source_candidate_sha256')}`",
        f"- Readiness SHA: `{final.get('source_readiness_sha256')}`",
        f"- Ledger SHA: `{final.get('source_ledger_sha256')}`",
        "",
        "## Canonical entries",
    ]
    for row in final.get("canonical_entries", [])[:300]:
        lines.append(f"- `{row.get('engine_base')}` → `{row.get('canonical_path')}`")
    lines.extend(["", "## Excluded entries"])
    for row in final.get("excluded_entries", [])[:300]:
        lines.append(f"- `{row.get('engine_base')}` — `{row.get('reason')}`")
    return "\n".join(lines) + "\n"


def _patch115_save_final_lockfile(final: dict) -> tuple[Path, Path, Path, Path]:
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    ts = _patch115_now()
    stable_json = _patch115_latest_final_path()
    stable_md = stable_json.with_suffix(".md")
    stamped_json = CODE_MANIFESTS_DIR / f"{ts}_{_PATCH115_FINAL_PREFIX}.json"
    stamped_md = CODE_MANIFESTS_DIR / f"{ts}_{_PATCH115_FINAL_PREFIX}.md"
    payload = json.dumps(final, indent=2, ensure_ascii=False)
    md = _patch115_markdown_for_final(final)
    stable_json.write_text(payload, encoding="utf-8")
    stable_md.write_text(md, encoding="utf-8")
    stamped_json.write_text(payload, encoding="utf-8")
    stamped_md.write_text(md, encoding="utf-8")
    return stable_json, stable_md, stamped_json, stamped_md


def _patch115_save_receipt(final: dict, stable_json: Path, stamped_json: Path) -> tuple[dict, Path, Path]:
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    ts = _patch115_now()
    receipt = {
        "schema_version": "engine_final_lockfile_apply_receipt_v1_patch115",
        "report_type": "ENGINE_FINAL_LOCKFILE_APPLY_RECEIPT_V1",
        "policy_version": _PATCH115_POLICY_VERSION,
        "created_at": _patch115_iso_now(),
        "status": "ENGINE_FINAL_LOCKFILE_WRITTEN",
        "stable_final_lockfile_path": str(stable_json),
        "stable_final_lockfile_sha256": _patch115_sha256(stable_json),
        "timestamped_final_lockfile_path": str(stamped_json),
        "timestamped_final_lockfile_sha256": _patch115_sha256(stamped_json),
        "included_count": final.get("included_count"),
        "excluded_count": final.get("excluded_count"),
        "source_proposal_path": final.get("source_proposal_path"),
        "source_proposal_sha256": final.get("source_proposal_sha256"),
        "source_candidate_sha256": final.get("source_candidate_sha256"),
        "source_readiness_sha256": final.get("source_readiness_sha256"),
        "source_ledger_sha256": final.get("source_ledger_sha256"),
        "engine_files_changed": False,
        "human_review_ledger_changed": False,
        "quarantine_written": False,
        "delete_performed": False,
        "confirmation_token_used": True,
    }
    json_path = CODE_MANIFESTS_DIR / f"{ts}_{_PATCH115_RECEIPT_PREFIX}.json"
    md_path = CODE_MANIFESTS_DIR / f"{ts}_{_PATCH115_RECEIPT_PREFIX}.md"
    json_path.write_text(json.dumps(receipt, indent=2, ensure_ascii=False), encoding="utf-8")
    md_lines = [
        "# Patch 115 Final Engine Lockfile Apply Receipt",
        "",
        f"Status: `{receipt.get('status')}`",
        f"Stable final lockfile: `{stable_json}`",
        f"Stable SHA: `{receipt.get('stable_final_lockfile_sha256')}`",
        f"Included: `{receipt.get('included_count')}`",
        f"Excluded: `{receipt.get('excluded_count')}`",
        "",
        "No engine files were edited. No ledger rows were changed. No quarantine/delete actions were performed.",
    ]
    md_path.write_text("\n".join(md_lines) + "\n", encoding="utf-8")
    return receipt, json_path, md_path


