def cmd_engine_final_lockfile_verify(ref: str, session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    proposal, path, err = _patch115_load_proposal(ref or "latest")
    ok, errors, warnings = _patch115_verify_proposal_data(proposal or {}, path)
    if err:
        ok = False
        errors.insert(0, err)
    print()
    print("── Engine Final Lockfile Verify — Patch 115 ────────")
    print(f"  Proposal    : {path}")
    print(f"  Status      : {'PASS' if ok else 'FAIL'}")
    print(f"  Problems    : {len(errors)}")
    print(f"  Warnings    : {len(warnings)}")
    for e in errors[:30]:
        print(f"    - {e}")
    if warnings:
        print("  Warning details:")
        for w in warnings[:30]:
            print(f"    - {w}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_FINAL_LOCKFILE_VERIFY", str(path), f"status={'PASS' if ok else 'FAIL'}", f"problems={len(errors)}")


def cmd_engine_final_lockfile_apply(confirm: str, session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    confirm = (confirm or "").strip()
    print()
    print("── Engine Final Lockfile Apply — Patch 115 ─────────")
    if confirm != _PATCH115_CONFIRM_TOKEN:
        print("  Status : REFUSED_CONFIRM_TOKEN_REQUIRED")
        print(f"  Needed : {_PATCH115_CONFIRM_TOKEN}")
        print("  Result : no final lockfile write")
        print("──────────────────────────────────────────────────────")
        print()
        write_audit_entry(session_id, "ENGINE_FINAL_LOCKFILE_APPLY_REFUSED", "-", "missing_confirm_token", "no_final_write")
        return
    proposal, proposal_path, err = _patch115_load_proposal("latest")
    ok, errors, warnings = _patch115_verify_proposal_data(proposal or {}, proposal_path)
    if err:
        ok = False
        errors.insert(0, err)
    if not ok or not proposal or not proposal_path:
        print("  Status : REFUSED_PROPOSAL_VERIFY_FAILED")
        print(f"  Problems: {len(errors)}")
        for e in errors[:30]:
            print(f"    - {e}")
        print("  Result : no final lockfile write")
        print("──────────────────────────────────────────────────────")
        print()
        write_audit_entry(session_id, "ENGINE_FINAL_LOCKFILE_APPLY_REFUSED", str(proposal_path), f"verify_failed={len(errors)}", "no_final_write")
        return
    final = _patch115_build_final_lockfile(proposal, proposal_path)
    stable_json, stable_md, stamped_json, stamped_md = _patch115_save_final_lockfile(final)
    receipt, receipt_json, receipt_md = _patch115_save_receipt(final, stable_json, stamped_json)
    print("  Status    : ENGINE_FINAL_LOCKFILE_WRITTEN")
    print(f"  Included  : {final.get('included_count')}")
    print(f"  Excluded  : {final.get('excluded_count')}")
    print(f"  Stable    : {stable_json}")
    print(f"  Timestamp : {stamped_json}")
    print(f"  Receipt   : {receipt_json}")
    print(f"  SHA       : {receipt.get('stable_final_lockfile_sha256')}")
    print("  Authority : final Forge-owned lockfile only; NO engine files changed")
    if warnings:
        print("  Warnings:")
        for w in warnings[:20]:
            print(f"    - {w}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_FINAL_LOCKFILE_WRITTEN", str(stable_json), f"included={final.get('included_count')}", f"receipt={receipt_json}")


def cmd_engine_final_lockfile_export(session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    proposal_path = _patch115_latest_proposal_path()
    receipt_path = _patch115_latest_apply_receipt_path()
