# ─── PATCH 88 — LIVE RESTORE PROPOSAL GATE (NO RESTORE AUTHORITY) ─────────

SNAPSHOT_LIVE_PROPOSAL_SCHEMA_VERSION = "snapshot_live_restore_proposal_v1_patch88"
SNAPSHOT_LIVE_PROPOSAL_POLICY_VERSION = "patch88_live_restore_proposal_gate_v1"
SNAPSHOT_LIVE_PROPOSALS_DIR = MEMORY_DIR / "live_restore_proposals_v1"
SNAPSHOT_LIVE_PROPOSAL_PREFIX = "snapshot_live_restore_proposal_v1"
SNAPSHOT_LIVE_PROPOSAL_EXPORT_PREFIX = "snapshot_live_restore_proposal_export_v1"


def _snapshot_live_proposal_authority() -> dict:
    return {
        "live_restore_proposal_authority": True,
        "restore_authority": False,
        "live_restore_authority": False,
        "shadow_restore_copy_authority": False,
        "snapshot_create_authority": False,
        "project_file_write_authority": False,
        "engine_file_write_authority": False,
        "delete_authority": False,
        "quarantine_authority": False,
        "shell_execution_authority": False,
        "chroma_write_authority": False,
        "final_lockfile_authority": False,
    }


def _snapshot_live_proposal_policy_payload() -> dict:
    return {
        "schema_version": SNAPSHOT_LIVE_PROPOSAL_SCHEMA_VERSION,
        "policy_version": SNAPSHOT_LIVE_PROPOSAL_POLICY_VERSION,
        "policy": "Patch 88 Live Restore Proposal Gate",
        "mode": "PROPOSAL_AND_GATE_ONLY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "purpose": "Turn a clean Patch 87 shadow inspection into a human-readable live-restore proposal checklist without restoring, copying, moving, deleting, or modifying live files.",
        "authority": _snapshot_live_proposal_authority(),
        "allowed_writes": [
            "Forge-owned live restore proposal JSON/Markdown reports under /home/nic/forge/memory/live_restore_proposals_v1/",
            "Forge audit entries for policy/proposal/show/gate/export commands",
        ],
        "forbidden": [
            "restoring files to /home/nic/forge or /home/nic/aiweb",
            "copying files from shadow restore sandboxes into live locations",
            "editing, deleting, moving, quarantining, or promoting engines",
            "granting final lockfile authority",
            "running shell commands",
            "writing to Chroma or old vector DBs",
            "reading or copying secrets, credentials, keys, .env, ~/.ssh, or token files",
        ],
        "required_inputs": [
            "latest Patch 87 shadow restore inspection report",
            "inspection readiness must pass with zero blockers",
            "source shadow copy, shadow plan, and snapshot receipt must be referenced by inspection report",
        ],
    }


def _snapshot_live_proposal_paths() -> list[Path]:
    SNAPSHOT_LIVE_PROPOSALS_DIR.mkdir(parents=True, exist_ok=True)
    return sorted(SNAPSHOT_LIVE_PROPOSALS_DIR.glob(f"*_{SNAPSHOT_LIVE_PROPOSAL_PREFIX}.json"), reverse=True)


def _snapshot_live_proposal_latest_path() -> Path | None:
    paths = _snapshot_live_proposal_paths()
    return paths[0] if paths else None


def _snapshot_live_proposal_resolve_path(arg: str) -> Path | None:
    target = (arg or "latest").strip()
    if target.lower() in {"latest", ""}:
        return _snapshot_live_proposal_latest_path()
    p = Path(os.path.expanduser(target))
    if not p.is_absolute():
        p = SNAPSHOT_LIVE_PROPOSALS_DIR / target
    return p


def _snapshot_live_proposal_load(path: Path) -> dict | None:
    try:
        return json.loads(Path(path).read_text(encoding="utf-8"))
    except Exception:
        return None


def _snapshot_live_proposal_status(blockers: list[str], warnings: list[str]) -> str:
    if blockers:
        return "LIVE_RESTORE_PROPOSAL_BLOCKED_NO_AUTHORITY"
    if warnings:
        return "LIVE_RESTORE_PROPOSAL_READY_WITH_WARNINGS_NO_AUTHORITY"
    return "LIVE_RESTORE_PROPOSAL_READY_NO_AUTHORITY"


def _snapshot_live_proposal_build(arg: str = "latest") -> tuple[dict, Path, Path]:
    now = datetime.datetime.now().isoformat(timespec="seconds")
    ts = _patch60_timestamp()
    SNAPSHOT_LIVE_PROPOSALS_DIR.mkdir(parents=True, exist_ok=True)
    inspection_path = _snapshot_shadow_inspect_resolve_path(arg or "latest")
    inspection = _snapshot_shadow_inspect_load(inspection_path) if inspection_path and inspection_path.exists() else None
    blockers: list[str] = []
    warnings: list[str] = []
    if not inspection_path or not inspection_path.exists():
        blockers.append("No Patch 87 shadow restore inspection report found. Run snapshot-shadow-inspect first.")
    if not inspection:
        blockers.append("Shadow restore inspection report could not be loaded as JSON.")

    inspection_ok = False
    inspection_problems: list[str] = []
    inspection_warnings: list[str] = []
    if inspection:
        inspection_ok, inspection_problems, inspection_warnings = _snapshot_shadow_inspect_validate_report(inspection)
        if not inspection_ok:
            blockers.append(f"Patch 87 inspection readiness did not pass: {len(inspection_problems)} problems")
            blockers.extend(inspection_problems[:20])
        warnings.extend(inspection_warnings)
        counts = inspection.get("counts") or {}
        if counts.get("blockers", 0) not in (0, None):
            blockers.append(f"Inspection report still has blockers: {counts.get('blockers')}")
        checks = inspection.get("checks") or {}
        for key in ["shadow_copy_verify_pass", "source_shadow_plan_validate_pass", "source_snapshot_verify_pass", "all_hashes_match"]:
            if checks.get(key) is not True:
                blockers.append(f"Inspection check is not passing: {key}")
        readiness = inspection.get("live_restore_readiness") or {}
        if readiness.get("live_restore_authorized_now") is not False:
            blockers.append("Inspection report improperly indicates live restore authorization.")
        auth = inspection.get("authority") or {}
        if auth.get("live_restore_authority") is not False or auth.get("project_file_write_authority") is not False:
            blockers.append("Inspection report contains forbidden live/project write authority.")

    inspected_files = (inspection or {}).get("inspected_files") or []
    proposal_files: list[dict] = []
    for idx, row in enumerate(inspected_files, start=1):
        original = str(row.get("original_live_path_for_future_restore_ONLY") or "")
        shadow_file = str(row.get("shadow_file") or "")
        rel = str(row.get("planned_shadow_relative_path") or "")
        lower_original = original.lower()
        sensitive = any(token in lower_original for token in ["/.ssh/", "/.gnupg/", "/.env", "secret", "credential", "token"])
        if sensitive:
            blockers.append(f"Potential sensitive live restore target is forbidden: {original}")
        if not original:
            blockers.append(f"Proposal row missing original live path at index {idx}")
        if not shadow_file:
            blockers.append(f"Proposal row missing shadow file path at index {idx}")
        if row.get("hash_match") is not True:
            blockers.append(f"Proposal row hash is not verified: {rel or original}")
        proposal_files.append({
            "index": idx,
            "future_live_target_path_FOR_REVIEW_ONLY": original,
            "verified_shadow_source_file": shadow_file,
            "shadow_relative_path": rel,
            "expected_sha256": row.get("expected_sha256"),
            "verified_shadow_sha256": row.get("copied_sha256"),
            "hash_match": row.get("hash_match") is True,
            "size_bytes": row.get("size_bytes"),
            "proposed_future_action": "WOULD_RESTORE_ONLY_IF_A_SEPARATE_FUTURE_LIVE_RESTORE_PATCH_AND_EXPLICIT_NIC_APPROVAL_EXIST",
            "live_write_authorized_now": False,
            "sensitive_path_blocked": sensitive,
        })

    if inspection and not proposal_files:
        blockers.append("Inspection report contains no inspected files for proposal review.")

    future_gate_requirements = [
        "A separate future patch must define any live-restore command; Patch 88 does not contain one.",
        "Nic must explicitly approve a live-restore proposal after reviewing target paths and counts.",
        "Forge must make a fresh backup immediately before any future live restore.",
        "Forge must verify live target current hashes immediately before any future overwrite.",
        "Forge must refuse secrets, credentials, keys, .env files, ~/.ssh, and unscoped paths.",
        "Forge must write a restore receipt and preserve rollback evidence if a future live restore ever exists.",
    ]
    status = _snapshot_live_proposal_status(blockers, warnings)
    proposal = {
        "schema_version": SNAPSHOT_LIVE_PROPOSAL_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_LIVE_RESTORE_PROPOSAL_V1_PATCH88",
        "created_at": now,
        "mode": "PROPOSAL_AND_GATE_ONLY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "status": status,
        "authority": _snapshot_live_proposal_authority(),
        "source_inspection_report": str(inspection_path) if inspection_path else None,
        "source_shadow_copy_receipt": (inspection or {}).get("source_shadow_copy_receipt") if inspection else None,
        "source_shadow_plan": (inspection or {}).get("source_shadow_plan") if inspection else None,
        "source_snapshot_receipt": (inspection or {}).get("source_snapshot_receipt") if inspection else None,
        "checks": {
            "inspection_report_loaded": inspection is not None,
            "inspection_validate_pass": inspection_ok,
            "inspection_blockers_zero": ((inspection or {}).get("counts") or {}).get("blockers", 999) == 0,
            "all_shadow_hashes_verified": all(r.get("hash_match") is True for r in proposal_files) if proposal_files else False,
            "live_restore_authorized_now": False,
            "project_write_authorized_now": False,
            "future_patch_required": True,
        },
        "counts": {
            "proposed_files": len(proposal_files),
            "blockers": len(blockers),
            "warnings": len(warnings),
            "inspection_problems": len(inspection_problems),
            "inspection_warnings": len(inspection_warnings),
        },
        "blockers": blockers,
        "warnings": warnings,
        "future_gate_requirements": future_gate_requirements,
        "proposal_files": proposal_files,
        "live_restore_gate": {
            "proposal_ready_for_future_live_restore_GATE_ONLY": not blockers,
            "live_restore_authorized_now": False,
            "project_file_write_authorized_now": False,
            "required_future_patch": "Patch 89 or later would need to define live-restore authority separately. Patch 88 intentionally does not.",
            "no_authority_reason": "Patch 88 is a proposal checklist. It cannot restore, copy to live paths, delete, move, or modify project files.",
        },
        "plain_english": [
            "Patch 88 converts the verified shadow restore inspection into a live-restore proposal checklist.",
            "It shows what a future restore would need to review, but it does not restore anything.",
            "If blockers are zero, Forge may consider a future live-restore gate patch; it still may not restore now.",
        ],
    }
    json_path = SNAPSHOT_LIVE_PROPOSALS_DIR / f"{ts}_{SNAPSHOT_LIVE_PROPOSAL_PREFIX}.json"
    md_path = SNAPSHOT_LIVE_PROPOSALS_DIR / f"{ts}_{SNAPSHOT_LIVE_PROPOSAL_PREFIX}.md"
    json_path.write_text(json.dumps(proposal, indent=2, ensure_ascii=False), encoding="utf-8")
    _snapshot_live_proposal_markdown(proposal, md_path)
    return proposal, json_path, md_path


def _snapshot_live_proposal_markdown(proposal: dict, md_path: Path) -> None:
    c = proposal.get("counts") or {}
    lines = [
        "# Patch 88 Live Restore Proposal Gate",
        "",
        "Mode: PROPOSAL AND GATE ONLY. No live restore authority exists.",
        f"Created: `{proposal.get('created_at')}`",
        f"Status: `{proposal.get('status')}`",
        f"Source inspection: `{proposal.get('source_inspection_report')}`",
        "",
        "## Counts",
        f"- Proposed files: `{c.get('proposed_files')}`",
        f"- Blockers: `{c.get('blockers')}`",
        f"- Warnings: `{c.get('warnings')}`",
        "",
        "## Authority",
    ]
    for k, v in (proposal.get("authority") or {}).items():
        lines.append(f"- {k}: `{v}`")
    lines.extend(["", "## Future Gate Requirements"])
    for item in proposal.get("future_gate_requirements") or []:
        lines.append(f"- {item}")
    lines.extend(["", "## Blockers"])
    for item in proposal.get("blockers") or ["None"]:
        lines.append(f"- {item}")
    lines.extend(["", "## Warnings"])
    for item in proposal.get("warnings") or ["None"]:
        lines.append(f"- {item}")
    lines.extend(["", "## Proposed Files — Review Only"])
    for row in (proposal.get("proposal_files") or [])[:200]:
        lines.append(f"- `{row.get('verified_shadow_source_file')}` → future live target `{row.get('future_live_target_path_FOR_REVIEW_ONLY')}` hash_match=`{row.get('hash_match')}` live_write_now=`{row.get('live_write_authorized_now')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")


def _snapshot_live_proposal_validate(proposal: dict) -> tuple[bool, list[str], list[str]]:
    problems: list[str] = []
    warnings: list[str] = []
    if not isinstance(proposal, dict):
        return False, ["proposal is not a JSON object"], warnings
    if proposal.get("schema_version") != SNAPSHOT_LIVE_PROPOSAL_SCHEMA_VERSION:
        problems.append("schema_version mismatch")
    if proposal.get("mode") != "PROPOSAL_AND_GATE_ONLY_NO_LIVE_RESTORE_NO_PROJECT_WRITE":
        problems.append("mode is not proposal/gate only")
    authority = proposal.get("authority") or {}
    if authority.get("live_restore_proposal_authority") is not True:
        problems.append("live_restore_proposal_authority is not true")
    for key in ["restore_authority", "live_restore_authority", "shadow_restore_copy_authority", "snapshot_create_authority", "project_file_write_authority", "engine_file_write_authority", "delete_authority", "quarantine_authority", "shell_execution_authority", "chroma_write_authority", "final_lockfile_authority"]:
        if authority.get(key) is not False:
            problems.append(f"forbidden authority flag not false: {key}")
    gate = proposal.get("live_restore_gate") or {}
    if gate.get("live_restore_authorized_now") is not False:
        problems.append("gate incorrectly authorizes live restore now")
    if gate.get("project_file_write_authorized_now") is not False:
        problems.append("gate incorrectly authorizes project writes now")
    rows = proposal.get("proposal_files") or []
    if not rows:
        problems.append("proposal contains no proposal_files rows")
    for row in rows:
        target = str(row.get("future_live_target_path_FOR_REVIEW_ONLY") or "")
        shadow = str(row.get("verified_shadow_source_file") or "")
        if not target or not shadow:
            problems.append("proposal row missing target or shadow path")
        if row.get("live_write_authorized_now") is not False:
            problems.append(f"proposal row incorrectly authorizes live write now: {target}")
        if row.get("hash_match") is not True:
            problems.append(f"proposal row hash not verified: {target}")
        lower_target = target.lower()
        if any(token in lower_target for token in ["/.ssh/", "/.gnupg/", "/.env", "secret", "credential", "token"]):
            problems.append(f"sensitive target path present in proposal: {target}")
    if proposal.get("warnings"):
        warnings.extend(proposal.get("warnings") or [])
    if proposal.get("blockers"):
        problems.extend(proposal.get("blockers") or [])
    return not problems, problems, warnings


def _snapshot_live_proposal_print(proposal: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    c = proposal.get("counts") or {}
    print()
    print("── Live Restore Proposal Gate ───────────────────────")
    print("  Mode      : PROPOSAL ONLY — no live restore")
    print(f"  Status    : {proposal.get('status')}")
    print(f"  Files     : proposed={c.get('proposed_files')}")
    print(f"  Blockers  : {c.get('blockers')}")
    print(f"  Warnings  : {c.get('warnings')}")
    print(f"  Source    : {proposal.get('source_inspection_report')}")
    if json_path:
        print(f"  JSON      : {json_path}")
    if md_path:
        print(f"  Markdown  : {md_path}")
    print("  Authority : NO live restore, NO project writes, NO engine writes")
    if proposal.get("blockers"):
        print("  Blockers:")
        for item in (proposal.get("blockers") or [])[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()


def cmd_snapshot_live_proposal_policy(session_id: str) -> None:
    """Show Patch 88 live restore proposal gate policy. Usage: snapshot-live-proposal-policy"""
    from agents.forge.memory import write_audit_entry
    p = _snapshot_live_proposal_policy_payload()
    print()
    print("── Live Restore Proposal Gate Policy ────────────────")
    print(f"  Policy    : {p.get('policy')}")
    print(f"  Mode      : {p.get('mode')}")
    print("  Writes    : Forge-owned proposal/gate receipts only")
    print("  Authority : NO live restore, NO project writes, NO engine writes")
    print("  Future    : any real restore command must be a separate future patch")
    print()
    print("  Forbidden:")
    for item in p.get("forbidden", []):
        print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_LIVE_PROPOSAL_POLICY_SHOWN", "-", "proposal-only", "patch88")


def cmd_snapshot_live_proposal(arg: str, session_id: str) -> None:
    """Write a live restore proposal gate report. Usage: snapshot-live-proposal [latest|inspection_report]"""
    from agents.forge.memory import write_audit_entry
    proposal, json_path, md_path = _snapshot_live_proposal_build(arg or "latest")
    _snapshot_live_proposal_print(proposal, json_path, md_path)
    tool = "SNAPSHOT_LIVE_PROPOSAL_WRITTEN" if not proposal.get("blockers") else "SNAPSHOT_LIVE_PROPOSAL_BLOCKED"
    write_audit_entry(session_id, tool, str(json_path), f"status={proposal.get('status')} files={(proposal.get('counts') or {}).get('proposed_files')}", "no-live-restore")


def cmd_snapshot_live_proposal_show(arg: str, session_id: str) -> None:
    """Show a live restore proposal report. Usage: snapshot-live-proposal-show [latest|path]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_live_proposal_resolve_path(arg)
    if not path or not path.exists():
        print()
        print("  No live restore proposal found. Run: snapshot-live-proposal")
        print()
        return
    proposal = _snapshot_live_proposal_load(path) or {}
    _snapshot_live_proposal_print(proposal, Path(path), None)
    write_audit_entry(session_id, "SNAPSHOT_LIVE_PROPOSAL_SHOWN", str(path), "read-only", arg or "latest")


def cmd_snapshot_live_proposal_gate(arg: str, session_id: str) -> None:
    """Validate the live restore proposal gate. Usage: snapshot-live-proposal-gate [latest|path]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_live_proposal_resolve_path(arg)
    print()
    print("── Live Restore Proposal Gate Check ─────────────────")
    if not path or not path.exists():
        print("  Status    : FAIL")
        print("  Reason    : no live restore proposal found")
        print("──────────────────────────────────────────────────────")
        print()
        return
    proposal = _snapshot_live_proposal_load(path) or {}
    ok, problems, warnings = _snapshot_live_proposal_validate(proposal)
    print(f"  Proposal  : {path}")
    print(f"  Status    : {'PASS' if ok else 'FAIL'}")
    print(f"  Problems  : {len(problems)}")
    print(f"  Warnings  : {len(warnings)}")
    print("  Authority : NO live restore, NO project writes, NO engine writes")
    if problems:
        print("  Problems:")
        for item in problems[:30]:
            print(f"    - {item}")
    if warnings:
        print("  Warnings:")
        for item in warnings[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()
    tool = "SNAPSHOT_LIVE_PROPOSAL_GATE_PASS" if ok else "SNAPSHOT_LIVE_PROPOSAL_GATE_FAIL"
    write_audit_entry(session_id, tool, str(path), f"problems={len(problems)}", f"warnings={len(warnings)}")


def cmd_snapshot_live_proposal_export(session_id: str) -> None:
    """Export live restore proposal reports. Usage: snapshot-live-proposal-export"""
    from agents.forge.memory import write_audit_entry
    SNAPSHOT_LIVE_PROPOSALS_DIR.mkdir(parents=True, exist_ok=True)
    reports = []
    for path in _snapshot_live_proposal_paths():
        data = _snapshot_live_proposal_load(path)
        if data:
            reports.append({
                "path": str(path),
                "created_at": data.get("created_at"),
                "status": data.get("status"),
                "counts": data.get("counts"),
                "authority": data.get("authority"),
            })
    ts = _patch60_timestamp()
    export = {
        "schema_version": SNAPSHOT_LIVE_PROPOSAL_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_LIVE_RESTORE_PROPOSAL_EXPORT_V1_PATCH88",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "EXPORT_ONLY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "authority": _snapshot_live_proposal_authority(),
        "count": len(reports),
        "reports": reports,
    }
    json_path = SNAPSHOT_LIVE_PROPOSALS_DIR / f"{ts}_{SNAPSHOT_LIVE_PROPOSAL_EXPORT_PREFIX}.json"
    md_path = SNAPSHOT_LIVE_PROPOSALS_DIR / f"{ts}_{SNAPSHOT_LIVE_PROPOSAL_EXPORT_PREFIX}.md"
    json_path.write_text(json.dumps(export, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = ["# Patch 88 Live Restore Proposal Export", "", f"Reports: `{len(reports)}`", "", "No live restore authority exists.", ""]
    for row in reports:
        lines.append(f"- `{row.get('created_at')}` `{row.get('status')}` `{row.get('path')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    print()
    print("── Live Restore Proposal Export ─────────────────────")
    print(f"  JSON      : {json_path}")
    print(f"  Markdown  : {md_path}")
    print(f"  Reports   : {len(reports)}")
    print("  Authority : NO live restore, NO project writes")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_LIVE_PROPOSAL_EXPORT_WRITTEN", str(json_path), str(md_path), f"reports={len(reports)}")



# ─── PATCH 89 — LIVE RESTORE PREFLIGHT (NO RESTORE AUTHORITY) ─────────────

SNAPSHOT_LIVE_PREFLIGHT_SCHEMA_VERSION = "snapshot_live_restore_preflight_v1_patch89"
SNAPSHOT_LIVE_PREFLIGHT_POLICY_VERSION = "patch89_live_restore_preflight_v1"
SNAPSHOT_LIVE_PREFLIGHT_DIR = MEMORY_DIR / "live_restore_preflight_v1"
SNAPSHOT_LIVE_PREFLIGHT_PREFIX = "snapshot_live_restore_preflight_v1"
SNAPSHOT_LIVE_PREFLIGHT_EXPORT_PREFIX = "snapshot_live_restore_preflight_export_v1"


def _snapshot_live_preflight_authority() -> dict:
    return {
        "live_restore_preflight_authority": True,
        "restore_authority": False,
        "live_restore_authority": False,
        "shadow_restore_copy_authority": False,
        "snapshot_create_authority": False,
        "project_file_write_authority": False,
        "engine_file_write_authority": False,
        "delete_authority": False,
        "quarantine_authority": False,
        "shell_execution_authority": False,
        "chroma_write_authority": False,
        "final_lockfile_authority": False,
    }


def _snapshot_live_preflight_policy_payload() -> dict:
    return {
        "schema_version": SNAPSHOT_LIVE_PREFLIGHT_SCHEMA_VERSION,
        "policy_version": SNAPSHOT_LIVE_PREFLIGHT_POLICY_VERSION,
        "policy": "Patch 89 Live Restore Preflight",
        "mode": "PREFLIGHT_READ_ONLY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "purpose": "Check current live destination paths and hashes against the latest Patch 88 live-restore proposal without copying, restoring, deleting, quarantining, or modifying live files.",
        "authority": _snapshot_live_preflight_authority(),
        "allowed_reads": [
            "latest Patch 88 live restore proposal report",
            "current metadata and hashes for proposed future live target files",
            "shadow source file metadata already referenced by the proposal",
        ],
        "allowed_writes": [
            "Forge-owned live restore preflight JSON/Markdown reports under /home/nic/forge/memory/live_restore_preflight_v1/",
            "Forge audit entries for policy/preflight/show/gate/export commands",
        ],
        "forbidden": [
            "restoring files to /home/nic/forge or /home/nic/aiweb",
            "copying files from shadow restore sandboxes into live locations",
            "editing, deleting, moving, quarantining, or promoting engines",
            "granting final lockfile authority",
            "running shell commands",
            "writing to Chroma or old vector DBs",
            "reading or copying secrets, credentials, keys, .env, ~/.ssh, or token files",
        ],
    }


def _snapshot_live_preflight_paths() -> list[Path]:
    SNAPSHOT_LIVE_PREFLIGHT_DIR.mkdir(parents=True, exist_ok=True)
    return sorted(SNAPSHOT_LIVE_PREFLIGHT_DIR.glob(f"*_{SNAPSHOT_LIVE_PREFLIGHT_PREFIX}.json"), reverse=True)


def _snapshot_live_preflight_latest_path() -> Path | None:
    paths = _snapshot_live_preflight_paths()
    return paths[0] if paths else None


def _snapshot_live_preflight_resolve_path(arg: str) -> Path | None:
    target = (arg or "latest").strip()
    if target.lower() in {"latest", ""}:
        return _snapshot_live_preflight_latest_path()
    p = Path(os.path.expanduser(target))
    if not p.is_absolute():
        p = SNAPSHOT_LIVE_PREFLIGHT_DIR / target
    return p


def _snapshot_live_preflight_load(path: Path) -> dict | None:
    try:
        return json.loads(Path(path).read_text(encoding="utf-8"))
    except Exception:
        return None


def _snapshot_live_preflight_status(blockers: list[str], warnings: list[str], overwrite_count: int) -> str:
    if blockers:
        return "LIVE_RESTORE_PREFLIGHT_BLOCKED_NO_AUTHORITY"
    if warnings or overwrite_count:
        return "LIVE_RESTORE_PREFLIGHT_READY_WITH_WARNINGS_NO_AUTHORITY"
    return "LIVE_RESTORE_PREFLIGHT_READY_NO_AUTHORITY"


def _snapshot_live_preflight_is_sensitive(path_text: str) -> bool:
    lower = (path_text or "").lower()
    return any(token in lower for token in ["/.ssh/", "/.gnupg/", "/.env", "secret", "credential", "token", "password", "id_rsa", "id_ed25519"])


def _snapshot_live_preflight_under_allowed_root(path: Path) -> bool:
    try:
        resolved = path.resolve()
        forge_root = FORGE_ROOT.resolve()
        aiweb_root = Path("/home/nic/aiweb").resolve()
        return resolved == forge_root or forge_root in resolved.parents or resolved == aiweb_root or aiweb_root in resolved.parents
    except Exception:
        return False


def _snapshot_live_preflight_file_state(path: Path) -> dict:
    row = {
        "path": str(path),
        "exists": False,
        "is_file": False,
        "is_dir": False,
        "size_bytes": None,
        "sha256": None,
        "read_error": None,
    }
    try:
        row["exists"] = path.exists()
        row["is_file"] = path.is_file() if row["exists"] else False
        row["is_dir"] = path.is_dir() if row["exists"] else False
        if row["is_file"]:
            row["size_bytes"] = path.stat().st_size
            row["sha256"] = _snapshot_create_current_sha(path)
    except Exception as e:
        row["read_error"] = str(e)
    return row


def _snapshot_live_preflight_build(arg: str = "latest") -> tuple[dict, Path, Path]:
    now = datetime.datetime.now().isoformat(timespec="seconds")
    ts = _patch60_timestamp()
    SNAPSHOT_LIVE_PREFLIGHT_DIR.mkdir(parents=True, exist_ok=True)

    proposal_path = _snapshot_live_proposal_resolve_path(arg or "latest")
    proposal = _snapshot_live_proposal_load(proposal_path) if proposal_path and proposal_path.exists() else None
    blockers: list[str] = []
    warnings: list[str] = []
    proposal_gate_ok = False
    proposal_gate_problems: list[str] = []
    proposal_gate_warnings: list[str] = []

    if not proposal_path or not proposal_path.exists():
        blockers.append("No Patch 88 live restore proposal found. Run snapshot-live-proposal first.")
    if not proposal:
        blockers.append("Live restore proposal could not be loaded as JSON.")
    else:
        proposal_gate_ok, proposal_gate_problems, proposal_gate_warnings = _snapshot_live_proposal_validate(proposal)
        if not proposal_gate_ok:
            blockers.append(f"Patch 88 live restore proposal gate did not pass: {len(proposal_gate_problems)} problems")
            blockers.extend(proposal_gate_problems[:20])
        warnings.extend(proposal_gate_warnings)
        auth = proposal.get("authority") or {}
        if auth.get("live_restore_authority") is not False or auth.get("project_file_write_authority") is not False:
            blockers.append("Proposal contains forbidden live restore/project write authority.")

    proposal_files = (proposal or {}).get("proposal_files") or []
    preflight_files: list[dict] = []
    overwrite_candidates = 0
    no_op_count = 0
    missing_targets = 0
    unreadable_targets = 0

    for idx, row in enumerate(proposal_files, start=1):
        target_text = str(row.get("future_live_target_path_FOR_REVIEW_ONLY") or "")
        expected_sha = row.get("expected_sha256")
        shadow_sha = row.get("verified_shadow_sha256")
        shadow_source = row.get("verified_shadow_source_file")
        target_path = Path(os.path.expanduser(target_text)) if target_text else Path("")
        sensitive = _snapshot_live_preflight_is_sensitive(target_text)
        under_allowed_root = _snapshot_live_preflight_under_allowed_root(target_path) if target_text else False
        current = _snapshot_live_preflight_file_state(target_path) if target_text else {"exists": False, "is_file": False, "is_dir": False, "sha256": None, "size_bytes": None, "read_error": "missing target path"}

        blocker_notes: list[str] = []
        warning_notes: list[str] = []
        if not target_text:
            blocker_notes.append("missing future live target path")
        if sensitive:
            blocker_notes.append("sensitive live target path is forbidden")
        if target_text and not under_allowed_root:
            blocker_notes.append("future live target path is outside allowed Forge/AI.Web roots")
        if row.get("live_write_authorized_now") is not False:
            blocker_notes.append("proposal row improperly authorizes live write now")
        if row.get("hash_match") is not True:
            blocker_notes.append("proposal row shadow/source hash was not verified")
        if current.get("read_error"):
            warning_notes.append(f"current live target read issue: {current.get('read_error')}")
            unreadable_targets += 1

        action_class = "UNKNOWN_NO_ACTION_NOW"
        if current.get("exists") is False:
            action_class = "LIVE_TARGET_MISSING_WOULD_CREATE_ONLY_IF_FUTURE_APPROVED"
            warning_notes.append("future restore would create this missing target if later authorized")
            missing_targets += 1
        elif not current.get("is_file"):
            action_class = "LIVE_TARGET_NOT_A_FILE_BLOCKED"
            blocker_notes.append("future live target exists but is not a regular file")
        elif current.get("sha256") == expected_sha:
            action_class = "LIVE_TARGET_ALREADY_MATCHES_SNAPSHOT_NO_OVERWRITE_NEEDED"
            no_op_count += 1
        else:
            action_class = "LIVE_TARGET_DIFFERS_FROM_SNAPSHOT_WOULD_OVERWRITE_ONLY_IF_FUTURE_APPROVED"
            warning_notes.append("future restore would overwrite a live file that currently differs from the snapshot")
            overwrite_candidates += 1

        if blocker_notes:
            blockers.extend([f"{target_text}: {note}" for note in blocker_notes])
        if warning_notes:
            warnings.extend([f"{target_text}: {note}" for note in warning_notes])

        preflight_files.append({
            "index": idx,
            "future_live_target_path_FOR_REVIEW_ONLY": target_text,
            "verified_shadow_source_file": shadow_source,
            "expected_snapshot_sha256": expected_sha,
            "verified_shadow_sha256": shadow_sha,
            "current_live_state": current,
            "target_under_allowed_root": under_allowed_root,
            "sensitive_path_blocked": sensitive,
            "action_classification": action_class,
            "blocker_notes": blocker_notes,
            "warning_notes": warning_notes,
            "live_write_authorized_now": False,
            "restore_authorized_now": False,
            "preflight_only_no_action_taken": True,
        })

    if proposal and not proposal_files:
        blockers.append("Proposal contains no files to preflight.")

    status = _snapshot_live_preflight_status(blockers, warnings, overwrite_candidates)
    report = {
        "schema_version": SNAPSHOT_LIVE_PREFLIGHT_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_LIVE_RESTORE_PREFLIGHT_V1_PATCH89",
        "created_at": now,
        "mode": "PREFLIGHT_READ_ONLY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "status": status,
        "authority": _snapshot_live_preflight_authority(),
        "source_live_restore_proposal": str(proposal_path) if proposal_path else None,
        "source_shadow_inspection_report": (proposal or {}).get("source_inspection_report") if proposal else None,
        "source_shadow_copy_receipt": (proposal or {}).get("source_shadow_copy_receipt") if proposal else None,
        "source_snapshot_receipt": (proposal or {}).get("source_snapshot_receipt") if proposal else None,
        "checks": {
            "proposal_loaded": proposal is not None,
            "proposal_gate_pass": proposal_gate_ok,
            "live_target_hashes_checked_read_only": True,
            "live_restore_authorized_now": False,
            "project_write_authorized_now": False,
            "future_restore_command_exists_in_this_patch": False,
            "all_blockers_zero": len(blockers) == 0,
        },
        "counts": {
            "preflight_files": len(preflight_files),
            "overwrite_candidates_if_future_approved": overwrite_candidates,
            "already_matching_snapshot": no_op_count,
            "missing_targets": missing_targets,
            "unreadable_targets": unreadable_targets,
            "blockers": len(blockers),
            "warnings": len(warnings),
            "proposal_gate_problems": len(proposal_gate_problems),
            "proposal_gate_warnings": len(proposal_gate_warnings),
        },
        "blockers": blockers,
        "warnings": warnings,
        "future_gate_requirements": [
            "A separate future patch must define any live-restore command; Patch 89 does not contain one.",
            "Nic must explicitly approve the preflight report and target overwrite list before any future restore lever exists.",
            "Forge must create a fresh backup immediately before any future overwrite.",
            "Forge must re-run this preflight immediately before any future live restore.",
            "Forge must refuse secrets, credentials, keys, .env files, ~/.ssh, and unscoped paths.",
            "Forge must preserve rollback evidence and audit every file if a future restore command is ever created.",
        ],
        "preflight_files": preflight_files,
        "live_restore_preflight_gate": {
            "preflight_ready_for_future_live_restore_COMMAND_PROPOSAL_ONLY": len(blockers) == 0,
            "restore_authorized_now": False,
            "project_write_authorized_now": False,
            "separate_future_patch_required": True,
        },
        "plain_english": {
            "summary": "Patch 89 checked current live target files against the latest restore proposal. It did not copy, restore, overwrite, delete, or modify any live file.",
            "meaning": "Rows marked as overwrite candidates are exactly what a future restore would replace if a later patch and Nic approval ever allow it. This patch only exposes that risk list.",
        },
    }
    json_path = SNAPSHOT_LIVE_PREFLIGHT_DIR / f"{ts}_{SNAPSHOT_LIVE_PREFLIGHT_PREFIX}.json"
    md_path = SNAPSHOT_LIVE_PREFLIGHT_DIR / f"{ts}_{SNAPSHOT_LIVE_PREFLIGHT_PREFIX}.md"
    json_path.write_text(json.dumps(report, indent=2, ensure_ascii=False), encoding="utf-8")
    _snapshot_live_preflight_write_markdown(report, md_path)
    return report, json_path, md_path


def _snapshot_live_preflight_write_markdown(report: dict, md_path: Path) -> None:
    c = report.get("counts") or {}
    lines = [
        "# Patch 89 Live Restore Preflight",
        "",
        "Mode: PREFLIGHT ONLY. No live restore authority exists.",
        f"Created: `{report.get('created_at')}`",
        f"Status: `{report.get('status')}`",
        f"Source proposal: `{report.get('source_live_restore_proposal')}`",
        "",
        "## Counts",
        f"- Preflight files: `{c.get('preflight_files')}`",
        f"- Overwrite candidates if future approved: `{c.get('overwrite_candidates_if_future_approved')}`",
        f"- Already matching snapshot: `{c.get('already_matching_snapshot')}`",
        f"- Missing targets: `{c.get('missing_targets')}`",
        f"- Blockers: `{c.get('blockers')}`",
        f"- Warnings: `{c.get('warnings')}`",
        "",
        "## Authority",
        "- Live restore: `NO`",
        "- Project writes: `NO`",
        "- Engine writes: `NO`",
        "",
        "## First 25 Preflight Rows",
    ]
    for row in (report.get("preflight_files") or [])[:25]:
        cur = row.get("current_live_state") or {}
        lines.append(f"- `{row.get('action_classification')}` `{row.get('future_live_target_path_FOR_REVIEW_ONLY')}` current_sha=`{cur.get('sha256')}` expected=`{row.get('expected_snapshot_sha256')}`")
    if report.get("blockers"):
        lines.extend(["", "## Blockers"])
        for item in report.get("blockers", [])[:40]:
            lines.append(f"- {item}")
    if report.get("warnings"):
        lines.extend(["", "## Warnings"])
        for item in report.get("warnings", [])[:40]:
            lines.append(f"- {item}")
    md_path.write_text("\n".join(lines), encoding="utf-8")


def _snapshot_live_preflight_validate(report: dict) -> tuple[bool, list[str], list[str]]:
    problems: list[str] = []
    warnings: list[str] = []
    if not isinstance(report, dict):
        return False, ["preflight report is not a JSON object"], warnings
    auth = report.get("authority") or {}
    forbidden_true = [
        "restore_authority", "live_restore_authority", "project_file_write_authority",
        "engine_file_write_authority", "delete_authority", "quarantine_authority",
        "shell_execution_authority", "chroma_write_authority", "final_lockfile_authority",
    ]
    for key in forbidden_true:
        if auth.get(key) is not False:
            problems.append(f"forbidden authority flag is not false: {key}")
    checks = report.get("checks") or {}
    if checks.get("proposal_loaded") is not True:
        problems.append("source live restore proposal was not loaded")
    if checks.get("proposal_gate_pass") is not True:
        problems.append("source live restore proposal gate did not pass")
    if checks.get("live_restore_authorized_now") is not False:
        problems.append("preflight improperly authorizes live restore")
    if checks.get("project_write_authorized_now") is not False:
        problems.append("preflight improperly authorizes project writes")
    rows = report.get("preflight_files") or []
    if not rows:
        problems.append("preflight contains no file rows")
    for row in rows:
        target = row.get("future_live_target_path_FOR_REVIEW_ONLY") or ""
        if row.get("live_write_authorized_now") is not False or row.get("restore_authorized_now") is not False:
            problems.append(f"row improperly authorizes live action: {target}")
        if row.get("sensitive_path_blocked") is True:
            problems.append(f"sensitive path present: {target}")
        if row.get("target_under_allowed_root") is not True:
            problems.append(f"target outside allowed root: {target}")
        if row.get("blocker_notes"):
            problems.extend([f"{target}: {note}" for note in row.get("blocker_notes")])
        if row.get("warning_notes"):
            warnings.extend([f"{target}: {note}" for note in row.get("warning_notes")])
    if report.get("blockers"):
        problems.extend(report.get("blockers") or [])
    if report.get("warnings"):
        warnings.extend(report.get("warnings") or [])
    return not problems, problems, warnings


def _snapshot_live_preflight_print(report: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    c = report.get("counts") or {}
    print()
    print("── Live Restore Preflight ───────────────────────────")
    print("  Mode      : PREFLIGHT ONLY — no live restore")
    print(f"  Status    : {report.get('status')}")
    print(f"  Files     : checked={c.get('preflight_files')} overwrite_candidates={c.get('overwrite_candidates_if_future_approved')} matching={c.get('already_matching_snapshot')} missing={c.get('missing_targets')}")
    print(f"  Blockers  : {c.get('blockers')}")
    print(f"  Warnings  : {c.get('warnings')}")
    print(f"  Proposal  : {report.get('source_live_restore_proposal')}")
    if json_path:
        print(f"  JSON      : {json_path}")
    if md_path:
        print(f"  Markdown  : {md_path}")
    print("  Authority : NO live restore, NO project writes, NO engine writes")
    if report.get("blockers"):
        print("  Blockers:")
        for item in (report.get("blockers") or [])[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()


def cmd_snapshot_live_preflight_policy(session_id: str) -> None:
    """Show Patch 89 live restore preflight policy. Usage: snapshot-live-preflight-policy"""
    from agents.forge.memory import write_audit_entry
    p = _snapshot_live_preflight_policy_payload()
    print()
    print("── Live Restore Preflight Policy ────────────────────")
    print(f"  Policy    : {p.get('policy')}")
    print(f"  Mode      : {p.get('mode')}")
    print("  Writes    : Forge-owned preflight reports only")
    print("  Reads     : current live target metadata and hashes only")
    print("  Authority : NO live restore, NO project writes, NO engine writes")
    print("  Future    : any real restore command must be a separate future patch")
    print()
    print("  Forbidden:")
    for item in p.get("forbidden", []):
        print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_LIVE_PREFLIGHT_POLICY_SHOWN", "-", "preflight-only", "patch89")


def cmd_snapshot_live_preflight(arg: str, session_id: str) -> None:
    """Write a live restore preflight report. Usage: snapshot-live-preflight [latest|proposal_report]"""
    from agents.forge.memory import write_audit_entry
    report, json_path, md_path = _snapshot_live_preflight_build(arg or "latest")
    _snapshot_live_preflight_print(report, json_path, md_path)
    tool = "SNAPSHOT_LIVE_PREFLIGHT_WRITTEN" if not report.get("blockers") else "SNAPSHOT_LIVE_PREFLIGHT_BLOCKED"
    c = report.get("counts") or {}
    write_audit_entry(session_id, tool, str(json_path), f"status={report.get('status')} files={c.get('preflight_files')} overwrite={c.get('overwrite_candidates_if_future_approved')}", "no-live-restore")


def cmd_snapshot_live_preflight_show(arg: str, session_id: str) -> None:
    """Show a live restore preflight report. Usage: snapshot-live-preflight-show [latest|path]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_live_preflight_resolve_path(arg)
    if not path or not path.exists():
        print()
        print("  No live restore preflight found. Run: snapshot-live-preflight")
        print()
        return
    report = _snapshot_live_preflight_load(path) or {}
    _snapshot_live_preflight_print(report, Path(path), None)
    write_audit_entry(session_id, "SNAPSHOT_LIVE_PREFLIGHT_SHOWN", str(path), "read-only", arg or "latest")


def cmd_snapshot_live_preflight_gate(arg: str, session_id: str) -> None:
    """Validate the live restore preflight gate. Usage: snapshot-live-preflight-gate [latest|path]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_live_preflight_resolve_path(arg)
    print()
    print("── Live Restore Preflight Gate Check ────────────────")
    if not path or not path.exists():
        print("  Status    : FAIL")
        print("  Reason    : no live restore preflight found")
        print("──────────────────────────────────────────────────────")
        print()
        return
    report = _snapshot_live_preflight_load(path) or {}
    ok, problems, warnings = _snapshot_live_preflight_validate(report)
    print(f"  Preflight : {path}")
    print(f"  Status    : {'PASS' if ok else 'FAIL'}")
    print(f"  Problems  : {len(problems)}")
    print(f"  Warnings  : {len(warnings)}")
    print("  Authority : NO live restore, NO project writes, NO engine writes")
    if problems:
        print("  Problems:")
        for item in problems[:30]:
            print(f"    - {item}")
    if warnings:
        print("  Warnings:")
        for item in warnings[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()
    tool = "SNAPSHOT_LIVE_PREFLIGHT_GATE_PASS" if ok else "SNAPSHOT_LIVE_PREFLIGHT_GATE_FAIL"
    write_audit_entry(session_id, tool, str(path), f"problems={len(problems)}", f"warnings={len(warnings)}")


def cmd_snapshot_live_preflight_export(session_id: str) -> None:
    """Export live restore preflight reports. Usage: snapshot-live-preflight-export"""
    from agents.forge.memory import write_audit_entry
    SNAPSHOT_LIVE_PREFLIGHT_DIR.mkdir(parents=True, exist_ok=True)
    reports = []
    for path in _snapshot_live_preflight_paths():
        data = _snapshot_live_preflight_load(path)
        if data:
            reports.append({
                "path": str(path),
                "created_at": data.get("created_at"),
                "status": data.get("status"),
                "counts": data.get("counts"),
                "authority": data.get("authority"),
            })
    ts = _patch60_timestamp()
    export = {
        "schema_version": SNAPSHOT_LIVE_PREFLIGHT_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_LIVE_RESTORE_PREFLIGHT_EXPORT_V1_PATCH89",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "EXPORT_ONLY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "authority": _snapshot_live_preflight_authority(),
        "count": len(reports),
        "reports": reports,
    }
    json_path = SNAPSHOT_LIVE_PREFLIGHT_DIR / f"{ts}_{SNAPSHOT_LIVE_PREFLIGHT_EXPORT_PREFIX}.json"
    md_path = SNAPSHOT_LIVE_PREFLIGHT_DIR / f"{ts}_{SNAPSHOT_LIVE_PREFLIGHT_EXPORT_PREFIX}.md"
    json_path.write_text(json.dumps(export, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = ["# Patch 89 Live Restore Preflight Export", "", f"Reports: `{len(reports)}`", "", "No live restore authority exists.", ""]
    for row in reports:
        lines.append(f"- `{row.get('created_at')}` `{row.get('status')}` `{row.get('path')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    print()
    print("── Live Restore Preflight Export ────────────────────")
    print(f"  JSON      : {json_path}")
    print(f"  Markdown  : {md_path}")
    print(f"  Reports   : {len(reports)}")
    print("  Authority : NO live restore, NO project writes")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_LIVE_PREFLIGHT_EXPORT_WRITTEN", str(json_path), str(md_path), f"reports={len(reports)}")


# ─── PATCH 90: LIVE RESTORE APPROVAL TOKEN (NO RESTORE AUTHORITY) ─────────────
SNAPSHOT_LIVE_APPROVAL_SCHEMA_VERSION = "snapshot_live_restore_approval_token_v1_patch90"
SNAPSHOT_LIVE_APPROVAL_POLICY_VERSION = "patch90_live_restore_approval_token_v1"
SNAPSHOT_LIVE_APPROVAL_DIR = MEMORY_DIR / "live_restore_approval_tokens_v1"
SNAPSHOT_LIVE_APPROVAL_PREFIX = "snapshot_live_restore_approval_token_v1"
SNAPSHOT_LIVE_APPROVAL_EXPORT_PREFIX = "snapshot_live_restore_approval_export_v1"


def _snapshot_live_approval_authority() -> dict:
    return {
        "approval_token_authority": True,
        "restore_authority": False,
        "live_restore_authority": False,
        "shadow_restore_copy_authority": False,
        "snapshot_create_authority": False,
        "project_file_write_authority": False,
        "engine_file_write_authority": False,
        "delete_authority": False,
        "quarantine_authority": False,
        "shell_execution_authority": False,
        "chroma_write_authority": False,
        "final_lockfile_authority": False,
    }


def _snapshot_live_approval_policy_payload() -> dict:
    return {
        "schema_version": SNAPSHOT_LIVE_APPROVAL_SCHEMA_VERSION,
        "policy_version": SNAPSHOT_LIVE_APPROVAL_POLICY_VERSION,
        "policy": "Patch 90 Live Restore Approval Token",
        "mode": "APPROVAL_TOKEN_ONLY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "purpose": "Freeze a human-review approval token against the latest Patch 89 live-restore preflight without restoring, copying, deleting, quarantining, or modifying live files.",
        "authority": _snapshot_live_approval_authority(),
        "allowed_reads": [
            "latest Patch 89 live restore preflight report",
            "Patch 89 preflight gate status",
            "preflight target/action classifications and SHA-256 metadata",
        ],
        "allowed_writes": [
            "Forge-owned approval token JSON/Markdown receipts under /home/nic/forge/memory/live_restore_approval_tokens_v1/",
            "Forge audit entries for policy/token/show/gate/export commands",
        ],
        "forbidden": [
            "restoring files to /home/nic/forge or /home/nic/aiweb",
            "copying files from snapshot or shadow restore sandboxes into live locations",
            "editing, deleting, moving, quarantining, or promoting engines",
            "granting final lockfile authority",
            "running shell commands",
            "writing to Chroma or old vector DBs",
            "reading or copying secrets, credentials, keys, .env, ~/.ssh, or token files",
        ],
        "plain_english": "This token records that the current preflight package is ready for human review. It is not a restore command and cannot change live files.",
    }


def _snapshot_live_approval_paths() -> list[Path]:
    SNAPSHOT_LIVE_APPROVAL_DIR.mkdir(parents=True, exist_ok=True)
    return sorted(SNAPSHOT_LIVE_APPROVAL_DIR.glob(f"*_{SNAPSHOT_LIVE_APPROVAL_PREFIX}.json"), reverse=True)


def _snapshot_live_approval_latest_path() -> Path | None:
    paths = _snapshot_live_approval_paths()
    return paths[0] if paths else None


def _snapshot_live_approval_resolve_path(arg: str) -> Path | None:
    target = (arg or "latest").strip()
    if target.lower() in {"latest", ""}:
        return _snapshot_live_approval_latest_path()
    p = Path(os.path.expanduser(target))
    if not p.is_absolute():
        p = SNAPSHOT_LIVE_APPROVAL_DIR / target
    return p


def _snapshot_live_approval_load(path: Path) -> dict | None:
    try:
        return json.loads(Path(path).read_text(encoding="utf-8"))
    except Exception:
        return None


def _snapshot_live_approval_token_id(preflight: dict, ts: str) -> str:
    import hashlib as _hashlib
    basis = {
        "created_for_patch": "patch90",
        "timestamp": ts,
        "source_preflight": preflight.get("source_live_restore_proposal"),
        "preflight_created_at": preflight.get("created_at"),
        "preflight_status": preflight.get("status"),
        "counts": preflight.get("counts"),
        "file_fingerprints": [
            {
                "target": row.get("future_live_target_path_FOR_REVIEW_ONLY"),
                "expected_snapshot_sha256": row.get("expected_snapshot_sha256"),
                "current_live_sha256": ((row.get("current_live_state") or {}).get("sha256")),
                "action": row.get("action_classification"),
            }
            for row in (preflight.get("preflight_files") or [])
        ],
    }
    raw = json.dumps(basis, sort_keys=True, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    return "LRA-" + _hashlib.sha256(raw).hexdigest()[:24]


def _snapshot_live_approval_status(blockers: list[str], warnings: list[str]) -> str:
    if blockers:
        return "LIVE_RESTORE_APPROVAL_TOKEN_BLOCKED_NO_AUTHORITY"
    if warnings:
        return "LIVE_RESTORE_APPROVAL_TOKEN_READY_WITH_WARNINGS_NO_AUTHORITY"
    return "LIVE_RESTORE_APPROVAL_TOKEN_READY_NO_AUTHORITY"


def _snapshot_live_approval_build(arg: str = "latest") -> tuple[dict, Path, Path]:
    now = datetime.datetime.now().isoformat(timespec="seconds")
    ts = _patch60_timestamp()
    SNAPSHOT_LIVE_APPROVAL_DIR.mkdir(parents=True, exist_ok=True)

    preflight_path = _snapshot_live_preflight_resolve_path(arg or "latest")
    preflight = _snapshot_live_preflight_load(preflight_path) if preflight_path and preflight_path.exists() else None
    blockers: list[str] = []
    warnings: list[str] = []
    gate_ok = False
    gate_problems: list[str] = []
    gate_warnings: list[str] = []

    if not preflight_path or not preflight_path.exists():
        blockers.append("No Patch 89 live restore preflight found. Run snapshot-live-preflight first.")
    if not preflight:
        blockers.append("Live restore preflight could not be loaded as JSON.")
    else:
        gate_ok, gate_problems, gate_warnings = _snapshot_live_preflight_validate(preflight)
        if not gate_ok:
            blockers.append(f"Patch 89 preflight gate did not pass: {len(gate_problems)} problems")
            blockers.extend(gate_problems[:30])
        warnings.extend(gate_warnings)
        if (preflight.get("counts") or {}).get("blockers", 999) != 0:
            blockers.append(f"Preflight still reports blockers: {(preflight.get('counts') or {}).get('blockers')}")
        checks = preflight.get("checks") or {}
        if checks.get("proposal_gate_pass") is not True:
            blockers.append("Preflight source proposal gate was not passing.")
        if checks.get("live_restore_authorized_now") is not False or checks.get("project_write_authorized_now") is not False:
            blockers.append("Preflight improperly indicates current restore/project-write authorization.")
        auth = preflight.get("authority") or {}
        if auth.get("live_restore_authority") is not False or auth.get("project_file_write_authority") is not False:
            blockers.append("Preflight contains forbidden live restore/project write authority.")

    rows = (preflight or {}).get("preflight_files") or []
    if preflight and not rows:
        blockers.append("Preflight contains no rows to bind into an approval token.")

    overwrite_rows = [r for r in rows if r.get("action_classification") == "LIVE_TARGET_DIFFERS_FROM_SNAPSHOT_WOULD_OVERWRITE_ONLY_IF_FUTURE_APPROVED"]
    matching_rows = [r for r in rows if r.get("action_classification") == "LIVE_TARGET_ALREADY_MATCHES_SNAPSHOT_NO_OVERWRITE_NEEDED"]
    create_rows = [r for r in rows if r.get("action_classification") == "LIVE_TARGET_MISSING_WOULD_CREATE_ONLY_IF_FUTURE_APPROVED"]

    token_id = _snapshot_live_approval_token_id(preflight or {}, ts)
    status = _snapshot_live_approval_status(blockers, warnings)
    approval = {
        "schema_version": SNAPSHOT_LIVE_APPROVAL_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_LIVE_RESTORE_APPROVAL_TOKEN_V1_PATCH90",
        "created_at": now,
        "mode": "APPROVAL_TOKEN_ONLY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "status": status,
        "approval_token_id": token_id,
        "authority": _snapshot_live_approval_authority(),
        "source_live_restore_preflight": str(preflight_path) if preflight_path else None,
        "source_live_restore_proposal": (preflight or {}).get("source_live_restore_proposal"),
        "source_shadow_inspection_report": (preflight or {}).get("source_shadow_inspection_report"),
        "source_shadow_copy_receipt": (preflight or {}).get("source_shadow_copy_receipt"),
        "source_snapshot_receipt": (preflight or {}).get("source_snapshot_receipt"),
        "checks": {
            "preflight_loaded": preflight is not None,
            "preflight_gate_pass": gate_ok,
            "preflight_blockers_zero": ((preflight or {}).get("counts") or {}).get("blockers", 999) == 0,
            "approval_token_created": True,
            "live_restore_authorized_now": False,
            "project_write_authorized_now": False,
            "future_restore_command_exists_in_this_patch": False,
            "separate_future_restore_patch_required": True,
        },
        "counts": {
            "token_files_bound": len(rows),
            "overwrite_candidates_if_future_approved": len(overwrite_rows),
            "already_matching_snapshot": len(matching_rows),
            "missing_targets_if_future_approved": len(create_rows),
            "blockers": len(blockers),
            "warnings": len(warnings),
            "preflight_gate_problems": len(gate_problems),
            "preflight_gate_warnings": len(gate_warnings),
        },
        "blockers": blockers,
        "warnings": warnings,
        "human_review_acknowledgement_REQUIRED_FOR_FUTURE_PATCH_ONLY": [
            "I understand this token does not restore files.",
            "I understand future restore authority would require a separate patch.",
            "I understand any future live restore must re-run preflight against current disk state.",
            "I understand overwrite candidates must be backed up immediately before any future restore.",
            "I understand Forge must refuse secrets, credentials, keys, .env, ~/.ssh, and unscoped paths.",
        ],
        "future_gate_requirements": [
            "A separate future patch must define a live-restore candidate command; Patch 90 does not contain one.",
            "A future command must require this token id or a newer valid token id.",
            "A future command must make a fresh backup before any overwrite.",
            "A future command must re-run live preflight immediately before writing.",
            "A future command must write per-file restore receipts and rollback evidence.",
            "Nic must explicitly approve any future live restore command after reviewing target paths and counts.",
        ],
        "bound_preflight_summary": {
            "preflight_status": (preflight or {}).get("status"),
            "preflight_created_at": (preflight or {}).get("created_at"),
            "preflight_counts": (preflight or {}).get("counts"),
        },
        "approval_scope_rows": [
            {
                "index": row.get("index"),
                "future_live_target_path_FOR_REVIEW_ONLY": row.get("future_live_target_path_FOR_REVIEW_ONLY"),
                "action_classification": row.get("action_classification"),
                "expected_snapshot_sha256": row.get("expected_snapshot_sha256"),
                "current_live_sha256_at_preflight": ((row.get("current_live_state") or {}).get("sha256")),
                "live_write_authorized_now": False,
                "restore_authorized_now": False,
            }
            for row in rows
        ],
        "live_restore_approval_gate": {
            "approval_token_ready_for_future_live_restore_PATCH_PROPOSAL_ONLY": len(blockers) == 0,
            "approval_token_id": token_id,
            "restore_authorized_now": False,
            "project_file_write_authorized_now": False,
            "separate_future_patch_required": True,
            "no_authority_reason": "Patch 90 creates only an approval token receipt. It cannot restore, copy to live paths, delete, move, or modify project files.",
        },
        "plain_english": {
            "summary": "Patch 90 creates a review/approval token tied to the latest Patch 89 preflight package.",
            "meaning": "The token freezes what was reviewed and what a future restore would need to prove. It does not authorize any live write today.",
        },
    }
    json_path = SNAPSHOT_LIVE_APPROVAL_DIR / f"{ts}_{SNAPSHOT_LIVE_APPROVAL_PREFIX}.json"
    md_path = SNAPSHOT_LIVE_APPROVAL_DIR / f"{ts}_{SNAPSHOT_LIVE_APPROVAL_PREFIX}.md"
    json_path.write_text(json.dumps(approval, indent=2, ensure_ascii=False), encoding="utf-8")
    _snapshot_live_approval_write_markdown(approval, md_path)
    return approval, json_path, md_path


def _snapshot_live_approval_write_markdown(report: dict, md_path: Path) -> None:
    c = report.get("counts") or {}
    lines = [
        "# Patch 90 Live Restore Approval Token",
        "",
        "Mode: APPROVAL TOKEN ONLY. No live restore authority exists.",
        f"Created: `{report.get('created_at')}`",
        f"Status: `{report.get('status')}`",
        f"Approval token: `{report.get('approval_token_id')}`",
        f"Source preflight: `{report.get('source_live_restore_preflight')}`",
        "",
        "## Counts",
        f"- Bound files: `{c.get('token_files_bound')}`",
        f"- Overwrite candidates if future approved: `{c.get('overwrite_candidates_if_future_approved')}`",
        f"- Already matching snapshot: `{c.get('already_matching_snapshot')}`",
        f"- Missing targets if future approved: `{c.get('missing_targets_if_future_approved')}`",
        f"- Blockers: `{c.get('blockers')}`",
        f"- Warnings: `{c.get('warnings')}`",
        "",
        "## Authority",
        "- Live restore: `NO`",
        "- Project writes: `NO`",
        "- Engine writes: `NO`",
        "- Shell execution: `NO`",
        "",
        "## Human Review Acknowledgement Required For Future Patch Only",
    ]
    for item in report.get("human_review_acknowledgement_REQUIRED_FOR_FUTURE_PATCH_ONLY", []):
        lines.append(f"- {item}")
    lines.extend(["", "## First 25 Bound Rows"])
    for row in (report.get("approval_scope_rows") or [])[:25]:
        lines.append(f"- `{row.get('action_classification')}` `{row.get('future_live_target_path_FOR_REVIEW_ONLY')}` expected=`{row.get('expected_snapshot_sha256')}` live_at_preflight=`{row.get('current_live_sha256_at_preflight')}`")
    if report.get("blockers"):
        lines.extend(["", "## Blockers"])
        for item in report.get("blockers", [])[:40]:
            lines.append(f"- {item}")
    if report.get("warnings"):
        lines.extend(["", "## Warnings"])
        for item in report.get("warnings", [])[:40]:
            lines.append(f"- {item}")
    md_path.write_text("\n".join(lines), encoding="utf-8")


def _snapshot_live_approval_validate(report: dict) -> tuple[bool, list[str], list[str]]:
    problems: list[str] = []
    warnings: list[str] = []
    if not isinstance(report, dict):
        return False, ["approval token report is not a JSON object"], warnings
    auth = report.get("authority") or {}
    forbidden_true = [
        "restore_authority", "live_restore_authority", "project_file_write_authority",
        "engine_file_write_authority", "delete_authority", "quarantine_authority",
        "shell_execution_authority", "chroma_write_authority", "final_lockfile_authority",
    ]
    for key in forbidden_true:
        if auth.get(key) is not False:
            problems.append(f"forbidden authority flag is not false: {key}")
    if not report.get("approval_token_id"):
        problems.append("approval token id missing")
    checks = report.get("checks") or {}
    if checks.get("preflight_loaded") is not True:
        problems.append("source Patch 89 preflight was not loaded")
    if checks.get("preflight_gate_pass") is not True:
        problems.append("source Patch 89 preflight gate did not pass")
    if checks.get("live_restore_authorized_now") is not False:
        problems.append("approval token improperly authorizes live restore")
    if checks.get("project_write_authorized_now") is not False:
        problems.append("approval token improperly authorizes project writes")
    if checks.get("future_restore_command_exists_in_this_patch") is not False:
        problems.append("approval token claims a restore command exists in Patch 90")
    rows = report.get("approval_scope_rows") or []
    if not rows:
        problems.append("approval token has no bound file rows")
    for row in rows:
        if row.get("live_write_authorized_now") is not False:
            problems.append(f"row improperly authorizes live write: {row.get('future_live_target_path_FOR_REVIEW_ONLY')}")
        if row.get("restore_authorized_now") is not False:
            problems.append(f"row improperly authorizes restore: {row.get('future_live_target_path_FOR_REVIEW_ONLY')}")
    if report.get("blockers"):
        problems.extend(report.get("blockers") or [])
    if report.get("warnings"):
        warnings.extend(report.get("warnings") or [])
    return not problems, problems, warnings


def _snapshot_live_approval_print(report: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    c = report.get("counts") or {}
    print()
    print("── Live Restore Approval Token ─────────────────────")
    print("  Mode      : TOKEN ONLY — no live restore")
    print(f"  Status    : {report.get('status')}")
    print(f"  Token     : {report.get('approval_token_id')}")
    print(f"  Files     : bound={c.get('token_files_bound')} overwrite={c.get('overwrite_candidates_if_future_approved')} matching={c.get('already_matching_snapshot')} missing={c.get('missing_targets_if_future_approved')}")
    print(f"  Blockers  : {c.get('blockers')}")
    print(f"  Warnings  : {c.get('warnings')}")
    print(f"  Preflight : {report.get('source_live_restore_preflight')}")
    if json_path:
        print(f"  JSON      : {json_path}")
    if md_path:
        print(f"  Markdown  : {md_path}")
    print("  Authority : NO live restore, NO project writes, NO engine writes")
    if report.get("blockers"):
        print("  Blockers:")
        for item in (report.get("blockers") or [])[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()


def cmd_snapshot_live_approval_policy(session_id: str) -> None:
    """Show Patch 90 live restore approval token policy. Usage: snapshot-live-approval-policy"""
    from agents.forge.memory import write_audit_entry
    p = _snapshot_live_approval_policy_payload()
    print()
    print("── Live Restore Approval Token Policy ──────────────")
    print(f"  Policy    : {p.get('policy')}")
    print(f"  Mode      : {p.get('mode')}")
    print("  Writes    : Forge-owned approval token receipts only")
    print("  Reads     : latest Patch 89 preflight report only")
    print("  Authority : NO live restore, NO project writes, NO engine writes")
    print("  Future    : any real restore command must be a separate future patch")
    print()
    print("  Forbidden:")
    for item in p.get("forbidden", []):
        print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_LIVE_APPROVAL_POLICY_SHOWN", "-", "token-only", "patch90")


def cmd_snapshot_live_approval_token(arg: str, session_id: str) -> None:
    """Write a live restore approval token receipt. Usage: snapshot-live-approval-token [latest|preflight_report]"""
    from agents.forge.memory import write_audit_entry
    report, json_path, md_path = _snapshot_live_approval_build(arg or "latest")
    _snapshot_live_approval_print(report, json_path, md_path)
    tool = "SNAPSHOT_LIVE_APPROVAL_TOKEN_WRITTEN" if not report.get("blockers") else "SNAPSHOT_LIVE_APPROVAL_TOKEN_BLOCKED"
    c = report.get("counts") or {}
    write_audit_entry(session_id, tool, str(json_path), f"status={report.get('status')} token={report.get('approval_token_id')}", f"files={c.get('token_files_bound')} no-restore")


def cmd_snapshot_live_approval_show(arg: str, session_id: str) -> None:
    """Show a live restore approval token. Usage: snapshot-live-approval-show [latest|path]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_live_approval_resolve_path(arg)
    if not path or not path.exists():
        print()
        print("  No live restore approval token found. Run: snapshot-live-approval-token")
        print()
        return
    report = _snapshot_live_approval_load(path) or {}
    _snapshot_live_approval_print(report, Path(path), None)
    write_audit_entry(session_id, "SNAPSHOT_LIVE_APPROVAL_TOKEN_SHOWN", str(path), "read-only", arg or "latest")


def cmd_snapshot_live_approval_gate(arg: str, session_id: str) -> None:
    """Validate the live restore approval token gate. Usage: snapshot-live-approval-gate [latest|path]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_live_approval_resolve_path(arg)
    print()
    print("── Live Restore Approval Token Gate ────────────────")
    if not path or not path.exists():
        print("  Status    : FAIL")
        print("  Reason    : no live restore approval token found")
        print("──────────────────────────────────────────────────────")
        print()
        return
    report = _snapshot_live_approval_load(path) or {}
    ok, problems, warnings = _snapshot_live_approval_validate(report)
    print(f"  Token     : {path}")
    print(f"  Token ID  : {report.get('approval_token_id')}")
    print(f"  Status    : {'PASS' if ok else 'FAIL'}")
    print(f"  Problems  : {len(problems)}")
    print(f"  Warnings  : {len(warnings)}")
    print("  Authority : NO live restore, NO project writes, NO engine writes")
    if problems:
        print("  Problems:")
        for item in problems[:30]:
            print(f"    - {item}")
    if warnings:
        print("  Warnings:")
        for item in warnings[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()
    tool = "SNAPSHOT_LIVE_APPROVAL_GATE_PASS" if ok else "SNAPSHOT_LIVE_APPROVAL_GATE_FAIL"
    write_audit_entry(session_id, tool, str(path), f"problems={len(problems)}", f"warnings={len(warnings)}")


def cmd_snapshot_live_approval_export(session_id: str) -> None:
    """Export live restore approval token receipts. Usage: snapshot-live-approval-export"""
    from agents.forge.memory import write_audit_entry
    SNAPSHOT_LIVE_APPROVAL_DIR.mkdir(parents=True, exist_ok=True)
    reports = []
    for path in _snapshot_live_approval_paths():
        data = _snapshot_live_approval_load(path)
        if data:
            reports.append({
                "path": str(path),
                "created_at": data.get("created_at"),
                "status": data.get("status"),
                "approval_token_id": data.get("approval_token_id"),
                "counts": data.get("counts"),
                "authority": data.get("authority"),
            })
    ts = _patch60_timestamp()
    export = {
        "schema_version": SNAPSHOT_LIVE_APPROVAL_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_LIVE_RESTORE_APPROVAL_TOKEN_EXPORT_V1_PATCH90",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "EXPORT_ONLY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "authority": _snapshot_live_approval_authority(),
        "count": len(reports),
        "reports": reports,
    }
    json_path = SNAPSHOT_LIVE_APPROVAL_DIR / f"{ts}_{SNAPSHOT_LIVE_APPROVAL_EXPORT_PREFIX}.json"
    md_path = SNAPSHOT_LIVE_APPROVAL_DIR / f"{ts}_{SNAPSHOT_LIVE_APPROVAL_EXPORT_PREFIX}.md"
    json_path.write_text(json.dumps(export, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = ["# Patch 90 Live Restore Approval Token Export", "", f"Reports: `{len(reports)}`", "", "No live restore authority exists.", ""]
    for row in reports:
        lines.append(f"- `{row.get('created_at')}` `{row.get('status')}` token=`{row.get('approval_token_id')}` `{row.get('path')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    print()
    print("── Live Restore Approval Token Export ──────────────")
    print(f"  JSON      : {json_path}")
    print(f"  Markdown  : {md_path}")
    print(f"  Reports   : {len(reports)}")
    print("  Authority : NO live restore, NO project writes")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_LIVE_APPROVAL_EXPORT_WRITTEN", str(json_path), str(md_path), f"reports={len(reports)}")


# ─── PATCH 91: LIVE RESTORE CANDIDATE COMMAND (DRY-RUN ONLY) ─────────────────
SNAPSHOT_LIVE_RESTORE_DRY_RUN_SCHEMA_VERSION = "snapshot_live_restore_candidate_dry_run_v1_patch91"
SNAPSHOT_LIVE_RESTORE_DRY_RUN_POLICY_VERSION = "patch91_live_restore_candidate_dry_run_v1"
SNAPSHOT_LIVE_RESTORE_DRY_RUN_DIR = MEMORY_DIR / "live_restore_dry_runs_v1"
SNAPSHOT_LIVE_RESTORE_DRY_RUN_PREFIX = "snapshot_live_restore_candidate_dry_run_v1"
SNAPSHOT_LIVE_RESTORE_DRY_RUN_EXPORT_PREFIX = "snapshot_live_restore_candidate_dry_run_export_v1"


def _snapshot_live_restore_dry_run_authority() -> dict:
    return {
        "candidate_command_shape_authority": True,
        "dry_run_receipt_authority": True,
        "restore_authority": False,
        "live_restore_authority": False,
        "project_file_write_authority": False,
        "engine_file_write_authority": False,
        "delete_authority": False,
        "quarantine_authority": False,
        "shell_execution_authority": False,
        "chroma_write_authority": False,
        "final_lockfile_authority": False,
    }


def _snapshot_live_restore_dry_run_policy_payload() -> dict:
    return {
        "schema_version": SNAPSHOT_LIVE_RESTORE_DRY_RUN_SCHEMA_VERSION,
        "policy_version": SNAPSHOT_LIVE_RESTORE_DRY_RUN_POLICY_VERSION,
        "policy": "Patch 91 Live Restore Candidate Command Dry Run",
        "mode": "CANDIDATE_COMMAND_DRY_RUN_ONLY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "purpose": "Create the shape of a future live-restore command and prove it refuses to write. This patch only reads the latest approval token and current live destination metadata, then writes a Forge-owned dry-run receipt.",
        "authority": _snapshot_live_restore_dry_run_authority(),
        "allowed_reads": [
            "latest Patch 90 live restore approval token",
            "current live destination file metadata and SHA-256 hashes",
            "safe path metadata for proposed live targets",
        ],
        "allowed_writes": [
            "Forge-owned dry-run JSON/Markdown receipts under /home/nic/forge/memory/live_restore_dry_runs_v1/",
            "Forge audit entries for policy/dry-run/show/gate/export commands",
        ],
        "forbidden": [
            "restoring files to /home/nic/forge or /home/nic/aiweb",
            "copying files from snapshot or shadow restore sandboxes into live locations",
            "editing, deleting, moving, quarantining, or promoting engines",
            "granting final lockfile authority",
            "running shell commands",
            "writing to Chroma or old vector DBs",
            "reading or copying secrets, credentials, keys, .env, ~/.ssh, or token files",
        ],
        "plain_english": "This is the steering-wheel mockup for the future restore command. It checks what would happen, writes a receipt, and refuses all live writes.",
    }


def _snapshot_live_restore_dry_run_paths() -> list[Path]:
    SNAPSHOT_LIVE_RESTORE_DRY_RUN_DIR.mkdir(parents=True, exist_ok=True)
    return sorted(SNAPSHOT_LIVE_RESTORE_DRY_RUN_DIR.glob(f"*_{SNAPSHOT_LIVE_RESTORE_DRY_RUN_PREFIX}.json"), reverse=True)


def _snapshot_live_restore_dry_run_latest_path() -> Path | None:
    paths = _snapshot_live_restore_dry_run_paths()
    return paths[0] if paths else None


def _snapshot_live_restore_dry_run_resolve_path(arg: str) -> Path | None:
    target = (arg or "latest").strip()
    if target.lower() in {"latest", ""}:
        return _snapshot_live_restore_dry_run_latest_path()
    p = Path(os.path.expanduser(target))
    if not p.is_absolute():
        p = SNAPSHOT_LIVE_RESTORE_DRY_RUN_DIR / target
    return p


def _snapshot_live_restore_dry_run_load(path: Path) -> dict | None:
    try:
        return json.loads(Path(path).read_text(encoding="utf-8"))
    except Exception:
        return None


def _snapshot_live_restore_safe_root_check(path: Path) -> tuple[bool, str]:
    try:
        resolved = path.resolve()
    except Exception:
        resolved = Path(os.path.abspath(os.path.expanduser(str(path))))
    allowed_roots = [FORGE_ROOT.resolve(), Path("/home/nic/aiweb").resolve()]
    for root in allowed_roots:
        try:
            resolved.relative_to(root)
            return True, f"inside allowed root: {root}"
        except ValueError:
            continue
    return False, "outside allowed roots (/home/nic/forge, /home/nic/aiweb)"


def _snapshot_live_restore_file_state(path: Path) -> dict:
    state = {
        "path": str(path),
        "exists": False,
        "is_file": False,
        "size_bytes": None,
        "sha256": None,
        "read_error": None,
    }
    try:
        if path.exists():
            state["exists"] = True
            state["is_file"] = path.is_file()
            if path.is_file():
                raw = path.read_bytes()
                state["size_bytes"] = len(raw)
                import hashlib as _hashlib
                state["sha256"] = _hashlib.sha256(raw).hexdigest()
    except Exception as exc:
        state["read_error"] = str(exc)
    return state


def _snapshot_live_restore_dry_run_status(blockers: list[str], warnings: list[str]) -> str:
    if blockers:
        return "LIVE_RESTORE_CANDIDATE_DRY_RUN_BLOCKED_NO_AUTHORITY"
    if warnings:
        return "LIVE_RESTORE_CANDIDATE_DRY_RUN_READY_WITH_WARNINGS_NO_AUTHORITY"
    return "LIVE_RESTORE_CANDIDATE_DRY_RUN_READY_NO_AUTHORITY"


def _snapshot_live_restore_dry_run_id(token: dict, rows: list[dict], ts: str) -> str:
    import hashlib as _hashlib
    basis = {
        "created_for_patch": "patch91",
        "timestamp": ts,
        "approval_token_id": token.get("approval_token_id"),
        "approval_created_at": token.get("created_at"),
        "rows": [
            {
                "target": row.get("future_live_target_path_FOR_REVIEW_ONLY"),
                "expected_snapshot_sha256": row.get("expected_snapshot_sha256"),
                "current_live_sha256_at_preflight": row.get("current_live_sha256_at_preflight"),
            }
            for row in rows
        ],
    }
    raw = json.dumps(basis, sort_keys=True, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    return "LRD-" + _hashlib.sha256(raw).hexdigest()[:24]


def _snapshot_live_restore_dry_run_build(arg: str = "latest") -> tuple[dict, Path, Path]:
    now = datetime.datetime.now().isoformat(timespec="seconds")
    ts = _patch60_timestamp()
    SNAPSHOT_LIVE_RESTORE_DRY_RUN_DIR.mkdir(parents=True, exist_ok=True)

    token_path = _snapshot_live_approval_resolve_path(arg or "latest")
    token = _snapshot_live_approval_load(token_path) if token_path and token_path.exists() else None
    blockers: list[str] = []
    warnings: list[str] = []
    token_ok = False
    token_problems: list[str] = []
    token_warnings: list[str] = []

    if not token_path or not token_path.exists():
        blockers.append("No Patch 90 live restore approval token found. Run snapshot-live-approval-token first.")
    if not token:
        blockers.append("Patch 90 live restore approval token could not be loaded as JSON.")
    else:
        token_ok, token_problems, token_warnings = _snapshot_live_approval_validate(token)
        if not token_ok:
            blockers.append(f"Patch 90 approval token gate did not pass: {len(token_problems)} problems")
            blockers.extend(token_problems[:30])
        warnings.extend(token_warnings)
        auth = token.get("authority") or {}
        if auth.get("live_restore_authority") is not False or auth.get("project_file_write_authority") is not False:
            blockers.append("Approval token contains forbidden live restore/project write authority.")
        if (token.get("counts") or {}).get("blockers", 999) != 0:
            blockers.append(f"Approval token still reports blockers: {(token.get('counts') or {}).get('blockers')}")

    rows = (token or {}).get("approval_scope_rows") or []
    if token and not rows:
        blockers.append("Approval token has no scope rows to dry-run.")

    dry_rows: list[dict] = []
    for idx, row in enumerate(rows, start=1):
        target_s = row.get("future_live_target_path_FOR_REVIEW_ONLY")
        expected_sha = row.get("expected_snapshot_sha256")
        row_blockers: list[str] = []
        row_warnings: list[str] = []
        if not target_s:
            row_blockers.append("missing target path")
            target = Path("/")
        else:
            target = Path(os.path.expanduser(str(target_s)))
        safe_root, safe_root_reason = _snapshot_live_restore_safe_root_check(target)
        if not safe_root:
            row_blockers.append(safe_root_reason)
        sensitive, sensitive_reason = _code_is_sensitive_path(target)
        if sensitive:
            row_blockers.append(sensitive_reason)
        state = _snapshot_live_restore_file_state(target)
        if state.get("read_error"):
            row_warnings.append(f"current live file could not be read for dry-run hash: {state.get('read_error')}")
        current_sha = state.get("sha256")
        if state.get("exists") and not state.get("is_file"):
            row_blockers.append("target exists but is not a regular file")
        if not state.get("exists"):
            action = "DRY_RUN_WOULD_CREATE_IF_FUTURE_PATCH_APPROVED"
        elif current_sha == expected_sha:
            action = "DRY_RUN_NOOP_ALREADY_MATCHES_SNAPSHOT"
        else:
            action = "DRY_RUN_WOULD_OVERWRITE_IF_FUTURE_PATCH_APPROVED"
            row_warnings.append("current live SHA differs from snapshot SHA; future restore would overwrite this file")
        if row.get("live_write_authorized_now") is not False or row.get("restore_authorized_now") is not False:
            row_blockers.append("source approval scope row improperly authorizes live write/restore")
        dry_rows.append({
            "index": idx,
            "future_live_target_path_FOR_REVIEW_ONLY": str(target),
            "safe_root": safe_root,
            "safe_root_reason": safe_root_reason,
            "sensitive_path": sensitive,
            "sensitive_reason": sensitive_reason,
            "expected_snapshot_sha256": expected_sha,
            "current_live_state_now": state,
            "preflight_live_sha256_from_patch89": row.get("current_live_sha256_at_preflight"),
            "source_token_action_classification": row.get("action_classification"),
            "dry_run_action_classification": action,
            "row_blockers": row_blockers,
            "row_warnings": row_warnings,
            "live_write_authorized_now": False,
            "restore_authorized_now": False,
        })
        blockers.extend([f"{target}: {b}" for b in row_blockers])
        warnings.extend([f"{target}: {w}" for w in row_warnings])

    overwrite_now = [r for r in dry_rows if r.get("dry_run_action_classification") == "DRY_RUN_WOULD_OVERWRITE_IF_FUTURE_PATCH_APPROVED"]
    noop_now = [r for r in dry_rows if r.get("dry_run_action_classification") == "DRY_RUN_NOOP_ALREADY_MATCHES_SNAPSHOT"]
    create_now = [r for r in dry_rows if r.get("dry_run_action_classification") == "DRY_RUN_WOULD_CREATE_IF_FUTURE_PATCH_APPROVED"]

    dry_run_id = _snapshot_live_restore_dry_run_id(token or {}, rows, ts)
    status = _snapshot_live_restore_dry_run_status(blockers, warnings)
    report = {
        "schema_version": SNAPSHOT_LIVE_RESTORE_DRY_RUN_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_LIVE_RESTORE_CANDIDATE_COMMAND_DRY_RUN_V1_PATCH91",
        "created_at": now,
        "mode": "CANDIDATE_COMMAND_DRY_RUN_ONLY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "status": status,
        "dry_run_id": dry_run_id,
        "authority": _snapshot_live_restore_dry_run_authority(),
        "source_live_restore_approval_token": str(token_path) if token_path else None,
        "source_approval_token_id": (token or {}).get("approval_token_id"),
        "source_live_restore_preflight": (token or {}).get("source_live_restore_preflight"),
        "checks": {
            "approval_token_loaded": token is not None,
            "approval_token_gate_pass": token_ok,
            "dry_run_receipt_created": True,
            "candidate_command_shape_created": True,
            "live_restore_authorized_now": False,
            "project_write_authorized_now": False,
            "actual_file_copy_performed": False,
            "actual_restore_performed": False,
            "separate_future_restore_patch_required": True,
        },
        "counts": {
            "dry_run_files_checked": len(dry_rows),
            "would_overwrite_if_future_approved": len(overwrite_now),
            "already_matching_snapshot": len(noop_now),
            "would_create_if_future_approved": len(create_now),
            "blockers": len(blockers),
            "warnings": len(warnings),
            "approval_token_gate_problems": len(token_problems),
            "approval_token_gate_warnings": len(token_warnings),
        },
        "blockers": blockers,
        "warnings": warnings,
        "future_restore_refusal_requirements": [
            "A real restore command must not exist in Patch 91.",
            "A future restore patch must require a fresh live preflight immediately before writing.",
            "A future restore patch must require a fresh backup immediately before overwriting.",
            "A future restore patch must require explicit human approval with the current dry-run/proposal/token identifiers.",
            "A future restore patch must refuse secrets, credentials, keys, .env, ~/.ssh, and unscoped paths.",
            "A future restore patch must write per-file receipts and rollback evidence before and after each write.",
        ],
        "dry_run_rows": dry_rows,
        "live_restore_candidate_gate": {
            "dry_run_ready_for_future_restore_PATCH_PROPOSAL_ONLY": len(blockers) == 0,
            "dry_run_id": dry_run_id,
            "approval_token_id": (token or {}).get("approval_token_id"),
            "restore_authorized_now": False,
            "project_file_write_authorized_now": False,
            "separate_future_patch_required": True,
            "no_authority_reason": "Patch 91 creates only a locked dry-run candidate command receipt. It cannot restore, copy to live paths, delete, move, or modify project files.",
        },
        "plain_english": {
            "summary": "Patch 91 creates the dry-run shape of a future live restore command.",
            "meaning": "Forge has checked what a future restore would do against current disk state, but it has not changed any live file.",
        },
    }
    json_path = SNAPSHOT_LIVE_RESTORE_DRY_RUN_DIR / f"{ts}_{SNAPSHOT_LIVE_RESTORE_DRY_RUN_PREFIX}.json"
    md_path = SNAPSHOT_LIVE_RESTORE_DRY_RUN_DIR / f"{ts}_{SNAPSHOT_LIVE_RESTORE_DRY_RUN_PREFIX}.md"
    json_path.write_text(json.dumps(report, indent=2, ensure_ascii=False), encoding="utf-8")
    _snapshot_live_restore_dry_run_write_markdown(report, md_path)
    return report, json_path, md_path


def _snapshot_live_restore_dry_run_write_markdown(report: dict, md_path: Path) -> None:
    c = report.get("counts") or {}
    lines = [
        "# Patch 91 Live Restore Candidate Command Dry Run",
        "",
        "Mode: DRY-RUN ONLY. No live restore authority exists.",
        f"Created: `{report.get('created_at')}`",
        f"Status: `{report.get('status')}`",
        f"Dry-run id: `{report.get('dry_run_id')}`",
        f"Source approval token: `{report.get('source_live_restore_approval_token')}`",
        f"Source approval token id: `{report.get('source_approval_token_id')}`",
        "",
        "## Counts",
        f"- Files checked: `{c.get('dry_run_files_checked')}`",
        f"- Would overwrite if future approved: `{c.get('would_overwrite_if_future_approved')}`",
        f"- Already matching snapshot: `{c.get('already_matching_snapshot')}`",
        f"- Would create if future approved: `{c.get('would_create_if_future_approved')}`",
        f"- Blockers: `{c.get('blockers')}`",
        f"- Warnings: `{c.get('warnings')}`",
        "",
        "## Authority",
        "- Live restore: `NO`",
        "- Project writes: `NO`",
        "- Engine writes: `NO`",
        "- Shell execution: `NO`",
        "",
        "## First 25 Dry-Run Rows",
    ]
    for row in (report.get("dry_run_rows") or [])[:25]:
        state = row.get("current_live_state_now") or {}
        lines.append(
            f"- `{row.get('dry_run_action_classification')}` `{row.get('future_live_target_path_FOR_REVIEW_ONLY')}` "
            f"expected=`{row.get('expected_snapshot_sha256')}` current=`{state.get('sha256')}`"
        )
    if report.get("blockers"):
        lines.extend(["", "## Blockers"])
        for item in report.get("blockers", [])[:40]:
            lines.append(f"- {item}")
    if report.get("warnings"):
        lines.extend(["", "## Warnings"])
        for item in report.get("warnings", [])[:40]:
            lines.append(f"- {item}")
    md_path.write_text("\n".join(lines), encoding="utf-8")


def _snapshot_live_restore_dry_run_validate(report: dict) -> tuple[bool, list[str], list[str]]:
    problems: list[str] = []
    warnings: list[str] = []
    if not isinstance(report, dict):
        return False, ["dry-run report is not a JSON object"], warnings
    auth = report.get("authority") or {}
    forbidden_true = [
        "restore_authority", "live_restore_authority", "project_file_write_authority",
        "engine_file_write_authority", "delete_authority", "quarantine_authority",
        "shell_execution_authority", "chroma_write_authority", "final_lockfile_authority",
    ]
    for key in forbidden_true:
        if auth.get(key) is not False:
            problems.append(f"forbidden authority flag is not false: {key}")
    checks = report.get("checks") or {}
    if checks.get("approval_token_loaded") is not True:
        problems.append("source Patch 90 approval token was not loaded")
    if checks.get("approval_token_gate_pass") is not True:
        problems.append("source Patch 90 approval token gate did not pass")
    if checks.get("live_restore_authorized_now") is not False:
        problems.append("dry-run improperly authorizes live restore")
    if checks.get("project_write_authorized_now") is not False:
        problems.append("dry-run improperly authorizes project writes")
    if checks.get("actual_file_copy_performed") is not False:
        problems.append("dry-run claims an actual file copy was performed")
    if checks.get("actual_restore_performed") is not False:
        problems.append("dry-run claims an actual restore was performed")
    rows = report.get("dry_run_rows") or []
    if not rows:
        problems.append("dry-run has no file rows")
    for row in rows:
        if row.get("live_write_authorized_now") is not False:
            problems.append(f"row improperly authorizes live write: {row.get('future_live_target_path_FOR_REVIEW_ONLY')}")
        if row.get("restore_authorized_now") is not False:
            problems.append(f"row improperly authorizes restore: {row.get('future_live_target_path_FOR_REVIEW_ONLY')}")
        if row.get("row_blockers"):
            problems.extend([f"{row.get('future_live_target_path_FOR_REVIEW_ONLY')}: {b}" for b in row.get("row_blockers")])
        if row.get("row_warnings"):
            warnings.extend([f"{row.get('future_live_target_path_FOR_REVIEW_ONLY')}: {w}" for w in row.get("row_warnings")])
    if report.get("blockers"):
        problems.extend(report.get("blockers") or [])
    if report.get("warnings"):
        warnings.extend(report.get("warnings") or [])
    # Keep warning list readable if row warnings and report warnings overlap.
    warnings = sorted(set(warnings))
    problems = sorted(set(problems))
    return not problems, problems, warnings


def _snapshot_live_restore_dry_run_print(report: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    c = report.get("counts") or {}
    print()
    print("── Live Restore Candidate Dry-Run ──────────────────")
    print("  Mode      : DRY RUN ONLY — no live restore")
    print(f"  Status    : {report.get('status')}")
    print(f"  Dry-run   : {report.get('dry_run_id')}")
    print(f"  Token     : {report.get('source_approval_token_id')}")
    print(f"  Files     : checked={c.get('dry_run_files_checked')} overwrite={c.get('would_overwrite_if_future_approved')} matching={c.get('already_matching_snapshot')} create={c.get('would_create_if_future_approved')}")
    print(f"  Blockers  : {c.get('blockers')}")
    print(f"  Warnings  : {c.get('warnings')}")
    if json_path:
        print(f"  JSON      : {json_path}")
    if md_path:
        print(f"  Markdown  : {md_path}")
    print("  Authority : NO live restore, NO project writes, NO engine writes")
    if report.get("blockers"):
        print("  Blockers:")
        for item in (report.get("blockers") or [])[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()


def cmd_snapshot_live_restore_policy(session_id: str) -> None:
    """Show Patch 91 live restore dry-run policy. Usage: snapshot-live-restore-policy"""
    from agents.forge.memory import write_audit_entry
    p = _snapshot_live_restore_dry_run_policy_payload()
    print()
    print("── Live Restore Candidate Dry-Run Policy ───────────")
    print(f"  Policy    : {p.get('policy')}")
    print(f"  Mode      : {p.get('mode')}")
    print("  Writes    : Forge-owned dry-run receipts only")
    print("  Reads     : latest Patch 90 approval token + current live file hashes")
    print("  Authority : NO live restore, NO project writes, NO engine writes")
    print("  Future    : a real restore command must be a separate future patch")
    print()
    print("  Forbidden:")
    for item in p.get("forbidden", []):
        print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_LIVE_RESTORE_DRY_RUN_POLICY_SHOWN", "-", "-", "patch91 policy displayed")


def cmd_snapshot_live_restore_dry_run(arg: str, session_id: str) -> None:
    """Create a Patch 91 live restore candidate dry-run receipt. Usage: snapshot-live-restore-dry-run [latest|token_path]"""
    from agents.forge.memory import write_audit_entry
    report, json_path, md_path = _snapshot_live_restore_dry_run_build(arg or "latest")
    _snapshot_live_restore_dry_run_print(report, json_path, md_path)
    c = report.get("counts") or {}
    write_audit_entry(
        session_id,
        "SNAPSHOT_LIVE_RESTORE_DRY_RUN_WRITTEN",
        str(json_path),
        str(md_path),
        f"status={report.get('status')} files={c.get('dry_run_files_checked')} blockers={c.get('blockers')} warnings={c.get('warnings')}"
    )


def cmd_snapshot_live_restore_show(arg: str, session_id: str) -> None:
    """Show a Patch 91 live restore candidate dry-run report. Usage: snapshot-live-restore-show latest"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_live_restore_dry_run_resolve_path(arg or "latest")
    if not path or not path.exists():
        print()
        print("[forge] No Patch 91 live restore dry-run report found.")
        print("        Run: snapshot-live-restore-dry-run")
        print()
        write_audit_entry(session_id, "SNAPSHOT_LIVE_RESTORE_DRY_RUN_SHOW_MISSING", "-", "-", f"arg={arg}")
        return
    report = _snapshot_live_restore_dry_run_load(path)
    if not report:
        print(f"[forge] ERROR: Could not read dry-run report: {path}")
        write_audit_entry(session_id, "SNAPSHOT_LIVE_RESTORE_DRY_RUN_SHOW_FAILED", str(path), "-", "json_load_failed")
        return
    _snapshot_live_restore_dry_run_print(report, path, None)
    write_audit_entry(session_id, "SNAPSHOT_LIVE_RESTORE_DRY_RUN_SHOWN", str(path), "-", f"status={report.get('status')}")


def cmd_snapshot_live_restore_gate(arg: str, session_id: str) -> None:
    """Validate a Patch 91 live restore candidate dry-run report. Usage: snapshot-live-restore-gate [latest]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_live_restore_dry_run_resolve_path(arg or "latest")
    report = _snapshot_live_restore_dry_run_load(path) if path and path.exists() else None
    ok, problems, warnings = _snapshot_live_restore_dry_run_validate(report or {})
    print()
    print("── Live Restore Candidate Dry-Run Gate ─────────────")
    print(f"  Report    : {path if path else 'NONE'}")
    print(f"  Status    : {'PASS' if ok else 'BLOCKED'}")
    print(f"  Problems  : {len(problems)}")
    print(f"  Warnings  : {len(warnings)}")
    print("  Authority : NO live restore, NO project writes")
    if problems:
        print("  Problems:")
        for item in problems[:30]:
            print(f"    - {item}")
    if warnings:
        print("  Warnings:")
        for item in warnings[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()
    audit_name = "SNAPSHOT_LIVE_RESTORE_DRY_RUN_GATE_PASS" if ok else "SNAPSHOT_LIVE_RESTORE_DRY_RUN_GATE_BLOCKED"
    write_audit_entry(session_id, audit_name, str(path) if path else "-", f"problems={len(problems)}", f"warnings={len(warnings)}")


def cmd_snapshot_live_restore_export(session_id: str) -> None:
    """Export Patch 91 live restore candidate dry-run reports. Usage: snapshot-live-restore-export"""
    from agents.forge.memory import write_audit_entry
    SNAPSHOT_LIVE_RESTORE_DRY_RUN_DIR.mkdir(parents=True, exist_ok=True)
    reports = []
    for path in _snapshot_live_restore_dry_run_paths():
        data = _snapshot_live_restore_dry_run_load(path)
        if data:
            reports.append({
                "path": str(path),
                "created_at": data.get("created_at"),
                "status": data.get("status"),
                "dry_run_id": data.get("dry_run_id"),
                "source_approval_token_id": data.get("source_approval_token_id"),
                "counts": data.get("counts"),
                "authority": data.get("authority"),
            })
    ts = _patch60_timestamp()
    export = {
        "schema_version": SNAPSHOT_LIVE_RESTORE_DRY_RUN_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_LIVE_RESTORE_CANDIDATE_DRY_RUN_EXPORT_V1_PATCH91",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "EXPORT_ONLY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "authority": _snapshot_live_restore_dry_run_authority(),
        "count": len(reports),
        "reports": reports,
    }
    json_path = SNAPSHOT_LIVE_RESTORE_DRY_RUN_DIR / f"{ts}_{SNAPSHOT_LIVE_RESTORE_DRY_RUN_EXPORT_PREFIX}.json"
    md_path = SNAPSHOT_LIVE_RESTORE_DRY_RUN_DIR / f"{ts}_{SNAPSHOT_LIVE_RESTORE_DRY_RUN_EXPORT_PREFIX}.md"
    json_path.write_text(json.dumps(export, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = ["# Patch 91 Live Restore Candidate Dry-Run Export", "", f"Reports: `{len(reports)}`", "", "No live restore authority exists.", ""]
    for row in reports:
        lines.append(f"- `{row.get('created_at')}` `{row.get('status')}` dry_run=`{row.get('dry_run_id')}` token=`{row.get('source_approval_token_id')}` `{row.get('path')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    print()
    print("── Live Restore Candidate Dry-Run Export ───────────")
    print(f"  JSON      : {json_path}")
    print(f"  Markdown  : {md_path}")
    print(f"  Reports   : {len(reports)}")
    print("  Authority : NO live restore, NO project writes")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_LIVE_RESTORE_DRY_RUN_EXPORT_WRITTEN", str(json_path), str(md_path), f"reports={len(reports)}")



# ─── PATCH 92: LIVE RESTORE BACKUP GATE (NO BACKUP COPY, NO RESTORE) ─────────
SNAPSHOT_LIVE_BACKUP_GATE_SCHEMA_VERSION = "snapshot_live_restore_backup_gate_v1_patch92"
SNAPSHOT_LIVE_BACKUP_GATE_POLICY_VERSION = "patch92_live_restore_backup_gate_v1"
SNAPSHOT_LIVE_BACKUP_GATE_DIR = MEMORY_DIR / "live_restore_backup_gates_v1"
SNAPSHOT_LIVE_BACKUP_GATE_PREFIX = "snapshot_live_restore_backup_gate_v1"
SNAPSHOT_LIVE_BACKUP_GATE_EXPORT_PREFIX = "snapshot_live_restore_backup_gate_export_v1"


def _snapshot_live_backup_authority() -> dict:
    return {
        "backup_gate_receipt_authority": True,
        "backup_plan_authority": True,
        "backup_copy_authority": False,
        "restore_authority": False,
        "live_restore_authority": False,
        "project_file_write_authority": False,
        "engine_file_write_authority": False,
        "delete_authority": False,
        "quarantine_authority": False,
        "shell_execution_authority": False,
        "chroma_write_authority": False,
        "final_lockfile_authority": False,
    }


def _snapshot_live_backup_policy_payload() -> dict:
    return {
        "schema_version": SNAPSHOT_LIVE_BACKUP_GATE_SCHEMA_VERSION,
        "policy_version": SNAPSHOT_LIVE_BACKUP_GATE_POLICY_VERSION,
        "policy": "Patch 92 Live Restore Backup Gate",
        "mode": "BACKUP_GATE_ONLY_NO_BACKUP_COPY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "purpose": "Create the mandatory backup-before-restore gate. This patch reads the latest Patch 91 dry-run receipt, proves which live files must be backed up before any future restore, and writes a Forge-owned gate receipt only.",
        "authority": _snapshot_live_backup_authority(),
        "allowed_reads": [
            "latest Patch 91 live restore candidate dry-run receipt",
            "current live destination metadata already represented by the dry-run rows",
            "safe path metadata for planned future backup targets",
        ],
        "allowed_writes": [
            "Forge-owned backup gate JSON/Markdown receipts under /home/nic/forge/memory/live_restore_backup_gates_v1/",
            "Forge audit entries for policy/plan/show/gate/export commands",
        ],
        "forbidden": [
            "copying live files into backup archives in this patch",
            "restoring files to /home/nic/forge or /home/nic/aiweb",
            "copying files from snapshot or shadow restore sandboxes into live locations",
            "editing, deleting, moving, quarantining, or promoting engines",
            "granting final lockfile authority",
            "running shell commands",
            "writing to Chroma or old vector DBs",
            "reading or copying secrets, credentials, keys, .env, ~/.ssh, or token files",
        ],
        "plain_english": "This is the checklist that says: before Forge ever restores anything, it must first know exactly which current live files need a backup. It does not make the backup yet.",
    }


def _snapshot_live_backup_paths() -> list[Path]:
    SNAPSHOT_LIVE_BACKUP_GATE_DIR.mkdir(parents=True, exist_ok=True)
    return sorted(SNAPSHOT_LIVE_BACKUP_GATE_DIR.glob(f"*_{SNAPSHOT_LIVE_BACKUP_GATE_PREFIX}.json"), reverse=True)


def _snapshot_live_backup_latest_path() -> Path | None:
    paths = _snapshot_live_backup_paths()
    return paths[0] if paths else None


def _snapshot_live_backup_resolve_path(arg: str) -> Path | None:
    target = (arg or "latest").strip()
    if target.lower() in {"latest", ""}:
        return _snapshot_live_backup_latest_path()
    p = Path(os.path.expanduser(target))
    if not p.is_absolute():
        p = SNAPSHOT_LIVE_BACKUP_GATE_DIR / target
    return p


def _snapshot_live_backup_load(path: Path) -> dict | None:
    try:
        return json.loads(Path(path).read_text(encoding="utf-8"))
    except Exception:
        return None


def _snapshot_live_backup_status(blockers: list[str], warnings: list[str]) -> str:
    if blockers:
        return "LIVE_RESTORE_BACKUP_GATE_BLOCKED_NO_AUTHORITY"
    if warnings:
        return "LIVE_RESTORE_BACKUP_GATE_READY_WITH_WARNINGS_NO_AUTHORITY"
    return "LIVE_RESTORE_BACKUP_GATE_READY_NO_AUTHORITY"


def _snapshot_live_backup_gate_id(dry_run: dict, rows: list[dict], ts: str) -> str:
    import hashlib as _hashlib
    basis = {
        "created_for_patch": "patch92",
        "timestamp": ts,
        "source_dry_run_id": dry_run.get("dry_run_id"),
        "source_dry_run_created_at": dry_run.get("created_at"),
        "rows": [
            {
                "target": row.get("future_live_target_path_FOR_REVIEW_ONLY"),
                "current_live_sha256": ((row.get("current_live_state_now") or {}).get("sha256")),
                "expected_snapshot_sha256": row.get("expected_snapshot_sha256"),
                "action": row.get("dry_run_action_classification"),
            }
            for row in rows
        ],
    }
    raw = json.dumps(basis, sort_keys=True, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    return "LBG-" + _hashlib.sha256(raw).hexdigest()[:24]


def _snapshot_live_backup_future_backup_path(gate_id: str, target: Path) -> str:
    # Review-only path. Patch 92 never creates this directory and never copies a file.
    try:
        resolved = target.resolve()
    except Exception:
        resolved = Path(os.path.abspath(os.path.expanduser(str(target))))
    try:
        rel = resolved.relative_to(Path("/home/nic").resolve())
    except Exception:
        rel = Path("outside_home") / str(resolved).lstrip("/")
    return str(MEMORY_DIR / "live_restore_backups_v1" / "FUTURE_BACKUP_ONLY" / gate_id / rel)


def _snapshot_live_backup_build(arg: str = "latest") -> tuple[dict, Path, Path]:
    now = datetime.datetime.now().isoformat(timespec="seconds")
    ts = _patch60_timestamp()
    SNAPSHOT_LIVE_BACKUP_GATE_DIR.mkdir(parents=True, exist_ok=True)

    dry_path = _snapshot_live_restore_dry_run_resolve_path(arg or "latest")
    dry = _snapshot_live_restore_dry_run_load(dry_path) if dry_path and dry_path.exists() else None
    blockers: list[str] = []
    warnings: list[str] = []
    dry_ok = False
    dry_problems: list[str] = []
    dry_warnings: list[str] = []

    if not dry_path or not dry_path.exists():
        blockers.append("No Patch 91 live restore dry-run receipt found. Run snapshot-live-restore-dry-run first.")
    if not dry:
        blockers.append("Patch 91 live restore dry-run receipt could not be loaded as JSON.")
    else:
        dry_ok, dry_problems, dry_warnings = _snapshot_live_restore_dry_run_validate(dry)
        if not dry_ok:
            blockers.append(f"Patch 91 live restore dry-run gate did not pass: {len(dry_problems)} problems")
            blockers.extend(dry_problems[:30])
        warnings.extend(dry_warnings)
        auth = dry.get("authority") or {}
        if auth.get("live_restore_authority") is not False or auth.get("project_file_write_authority") is not False:
            blockers.append("Patch 91 dry-run contains forbidden live restore/project write authority.")
        if (dry.get("counts") or {}).get("blockers", 999) != 0:
            blockers.append(f"Patch 91 dry-run still reports blockers: {(dry.get('counts') or {}).get('blockers')}")

    source_rows = (dry or {}).get("dry_run_rows") or []
    if dry and not source_rows:
        blockers.append("Patch 91 dry-run has no rows to bind backup gate.")

    gate_id = _snapshot_live_backup_gate_id(dry or {}, source_rows, ts)
    backup_rows: list[dict] = []
    for idx, row in enumerate(source_rows, start=1):
        target_s = row.get("future_live_target_path_FOR_REVIEW_ONLY")
        target = Path(os.path.expanduser(str(target_s))) if target_s else Path("/")
        state = row.get("current_live_state_now") or {}
        action = row.get("dry_run_action_classification")
        row_blockers: list[str] = []
        row_warnings: list[str] = []
        safe_root, safe_root_reason = _snapshot_live_restore_safe_root_check(target)
        if not safe_root:
            row_blockers.append(safe_root_reason)
        sensitive, sensitive_reason = _code_is_sensitive_path(target)
        if sensitive:
            row_blockers.append(sensitive_reason)
        exists = bool(state.get("exists"))
        is_file = bool(state.get("is_file"))
        backup_required = exists and is_file
        if exists and not is_file:
            row_blockers.append("live target exists but is not a regular file; backup gate cannot bind it")
        if state.get("read_error"):
            row_warnings.append(f"current live file read error from Patch 91 dry-run: {state.get('read_error')}")
        if action == "DRY_RUN_WOULD_OVERWRITE_IF_FUTURE_PATCH_APPROVED":
            row_warnings.append("future restore would overwrite this live file; backup is mandatory before restore")
        if not exists:
            row_warnings.append("future restore would create this file; no existing live file is available to back up")
        backup_path = _snapshot_live_backup_future_backup_path(gate_id, target)
        backup_rows.append({
            "index": idx,
            "future_live_target_path_FOR_REVIEW_ONLY": target_s,
            "future_backup_path_FOR_REVIEW_ONLY_NOT_CREATED": backup_path,
            "backup_required_before_any_future_restore": backup_required,
            "current_live_exists": exists,
            "current_live_is_file": is_file,
            "current_live_size_bytes": state.get("size_bytes"),
            "current_live_sha256_to_backup": state.get("sha256"),
            "expected_snapshot_sha256_after_restore": row.get("expected_snapshot_sha256"),
            "dry_run_action_classification": action,
            "safe_root": safe_root,
            "safe_root_reason": safe_root_reason,
            "sensitive_path": sensitive,
            "sensitive_reason": sensitive_reason,
            "row_blockers": row_blockers,
            "row_warnings": row_warnings,
            "backup_copy_authorized_now": False,
            "live_write_authorized_now": False,
            "restore_authorized_now": False,
        })
        blockers.extend([f"{target_s}: {b}" for b in row_blockers])
        warnings.extend([f"{target_s}: {w}" for w in row_warnings])

    backup_required_count = sum(1 for r in backup_rows if r.get("backup_required_before_any_future_restore"))
    overwrite_count = sum(1 for r in backup_rows if r.get("dry_run_action_classification") == "DRY_RUN_WOULD_OVERWRITE_IF_FUTURE_PATCH_APPROVED")
    create_count = sum(1 for r in backup_rows if r.get("dry_run_action_classification") == "DRY_RUN_WOULD_CREATE_IF_FUTURE_PATCH_APPROVED")
    matching_count = sum(1 for r in backup_rows if r.get("dry_run_action_classification") == "DRY_RUN_NOOP_ALREADY_MATCHES_SNAPSHOT")
    warnings = sorted(set(warnings))
    blockers = sorted(set(blockers))

    report = {
        "schema_version": SNAPSHOT_LIVE_BACKUP_GATE_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_LIVE_RESTORE_BACKUP_GATE_V1_PATCH92",
        "created_at": now,
        "mode": "BACKUP_GATE_ONLY_NO_BACKUP_COPY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "status": _snapshot_live_backup_status(blockers, warnings),
        "backup_gate_id": gate_id,
        "authority": _snapshot_live_backup_authority(),
        "source_live_restore_dry_run": str(dry_path) if dry_path else None,
        "source_dry_run_id": (dry or {}).get("dry_run_id"),
        "checks": {
            "patch91_dry_run_loaded": bool(dry),
            "patch91_dry_run_gate_pass": bool(dry_ok),
            "backup_gate_receipt_created": True,
            "backup_copy_authorized_now": False,
            "backup_copy_performed_now": False,
            "live_restore_authorized_now": False,
            "project_write_authorized_now": False,
            "actual_restore_performed": False,
            "separate_future_backup_copy_patch_required": True,
            "separate_future_restore_patch_required": True,
        },
        "counts": {
            "gate_files_bound": len(backup_rows),
            "live_files_requiring_backup_before_restore": backup_required_count,
            "future_overwrite_candidates": overwrite_count,
            "future_create_candidates": create_count,
            "already_matching_snapshot": matching_count,
            "blockers": len(blockers),
            "warnings": len(warnings),
            "source_dry_run_gate_problems": len(dry_problems),
            "source_dry_run_gate_warnings": len(dry_warnings),
        },
        "blockers": blockers,
        "warnings": warnings,
        "future_backup_copy_requirements_FOR_FUTURE_PATCH_ONLY": [
            "A future backup-copy patch must create backups before any live restore patch can exist.",
            "The future backup copy must bind to this backup_gate_id and prove current live hashes still match this gate receipt.",
            "The future backup copy must write only under /home/nic/forge/memory/live_restore_backups_v1/ until separately verified.",
            "No live restore command may run unless a verified backup receipt exists and matches the same dry-run/proposal chain.",
        ],
        "backup_gate_rows": backup_rows,
        "plain_english": "Patch 92 says what has to be backed up before any future restore. It did not copy backups and did not restore anything.",
    }

    json_path = SNAPSHOT_LIVE_BACKUP_GATE_DIR / f"{ts}_{SNAPSHOT_LIVE_BACKUP_GATE_PREFIX}.json"
    md_path = SNAPSHOT_LIVE_BACKUP_GATE_DIR / f"{ts}_{SNAPSHOT_LIVE_BACKUP_GATE_PREFIX}.md"
    json_path.write_text(json.dumps(report, indent=2, ensure_ascii=False), encoding="utf-8")
    _snapshot_live_backup_write_md(report, md_path)
    return report, json_path, md_path


def _snapshot_live_backup_write_md(report: dict, md_path: Path) -> None:
    c = report.get("counts") or {}
    lines = [
        "# Patch 92 Live Restore Backup Gate",
        "",
        f"Created: `{report.get('created_at')}`",
        f"Status: `{report.get('status')}`",
        f"Backup gate ID: `{report.get('backup_gate_id')}`",
        f"Source dry-run: `{report.get('source_live_restore_dry_run')}`",
        "",
        "## Counts",
        f"- Files bound: `{c.get('gate_files_bound')}`",
        f"- Live files requiring backup before restore: `{c.get('live_files_requiring_backup_before_restore')}`",
        f"- Future overwrite candidates: `{c.get('future_overwrite_candidates')}`",
        f"- Future create candidates: `{c.get('future_create_candidates')}`",
        f"- Already matching snapshot: `{c.get('already_matching_snapshot')}`",
        f"- Blockers: `{c.get('blockers')}`",
        f"- Warnings: `{c.get('warnings')}`",
        "",
        "## Authority",
        "- Backup copy: `NO`",
        "- Live restore: `NO`",
        "- Project writes: `NO`",
        "- Engine writes: `NO`",
        "- Shell execution: `NO`",
        "",
        "## Future Backup Copy Requirements",
    ]
    for item in report.get("future_backup_copy_requirements_FOR_FUTURE_PATCH_ONLY", []):
        lines.append(f"- {item}")
    lines.extend(["", "## First 25 Backup Gate Rows"])
    for row in (report.get("backup_gate_rows") or [])[:25]:
        lines.append(f"- backup_required=`{row.get('backup_required_before_any_future_restore')}` action=`{row.get('dry_run_action_classification')}` live=`{row.get('future_live_target_path_FOR_REVIEW_ONLY')}` backup_plan=`{row.get('future_backup_path_FOR_REVIEW_ONLY_NOT_CREATED')}`")
    if report.get("blockers"):
        lines.extend(["", "## Blockers"])
        for item in report.get("blockers", [])[:40]:
            lines.append(f"- {item}")
    if report.get("warnings"):
        lines.extend(["", "## Warnings"])
        for item in report.get("warnings", [])[:40]:
            lines.append(f"- {item}")
    md_path.write_text("\n".join(lines), encoding="utf-8")


def _snapshot_live_backup_validate(report: dict) -> tuple[bool, list[str], list[str]]:
    problems: list[str] = []
    warnings: list[str] = []
    if not isinstance(report, dict):
        return False, ["backup gate report is not a JSON object"], warnings
    auth = report.get("authority") or {}
    forbidden_true = [
        "backup_copy_authority", "restore_authority", "live_restore_authority", "project_file_write_authority",
        "engine_file_write_authority", "delete_authority", "quarantine_authority",
        "shell_execution_authority", "chroma_write_authority", "final_lockfile_authority",
    ]
    for key in forbidden_true:
        if auth.get(key) is not False:
            problems.append(f"forbidden authority flag is not false: {key}")
    if not report.get("backup_gate_id"):
        problems.append("backup gate id missing")
    checks = report.get("checks") or {}
    if checks.get("patch91_dry_run_loaded") is not True:
        problems.append("source Patch 91 dry-run was not loaded")
    if checks.get("patch91_dry_run_gate_pass") is not True:
        problems.append("source Patch 91 dry-run gate did not pass")
    if checks.get("backup_copy_authorized_now") is not False:
        problems.append("backup gate improperly authorizes backup copy")
    if checks.get("backup_copy_performed_now") is not False:
        problems.append("backup gate claims a backup copy was performed")
    if checks.get("live_restore_authorized_now") is not False:
        problems.append("backup gate improperly authorizes live restore")
    if checks.get("project_write_authorized_now") is not False:
        problems.append("backup gate improperly authorizes project writes")
    if checks.get("actual_restore_performed") is not False:
        problems.append("backup gate claims an actual restore was performed")
    rows = report.get("backup_gate_rows") or []
    if not rows:
        problems.append("backup gate has no file rows")
    for row in rows:
        if row.get("backup_copy_authorized_now") is not False:
            problems.append(f"row improperly authorizes backup copy: {row.get('future_live_target_path_FOR_REVIEW_ONLY')}")
        if row.get("live_write_authorized_now") is not False:
            problems.append(f"row improperly authorizes live write: {row.get('future_live_target_path_FOR_REVIEW_ONLY')}")
        if row.get("restore_authorized_now") is not False:
            problems.append(f"row improperly authorizes restore: {row.get('future_live_target_path_FOR_REVIEW_ONLY')}")
        if row.get("row_blockers"):
            problems.extend([f"{row.get('future_live_target_path_FOR_REVIEW_ONLY')}: {b}" for b in row.get("row_blockers")])
        if row.get("row_warnings"):
            warnings.extend([f"{row.get('future_live_target_path_FOR_REVIEW_ONLY')}: {w}" for w in row.get("row_warnings")])
    if report.get("blockers"):
        problems.extend(report.get("blockers") or [])
    if report.get("warnings"):
        warnings.extend(report.get("warnings") or [])
    warnings = sorted(set(warnings))
    problems = sorted(set(problems))
    return not problems, problems, warnings


def _snapshot_live_backup_print(report: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    c = report.get("counts") or {}
    print()
    print("── Live Restore Backup Gate ────────────────────────")
    print("  Mode      : BACKUP GATE ONLY — no backup copy, no restore")
    print(f"  Status    : {report.get('status')}")
    print(f"  Gate ID   : {report.get('backup_gate_id')}")
    print(f"  Dry-run   : {report.get('source_dry_run_id')}")
    print(f"  Files     : bound={c.get('gate_files_bound')} backup_required={c.get('live_files_requiring_backup_before_restore')} overwrite={c.get('future_overwrite_candidates')} matching={c.get('already_matching_snapshot')} create={c.get('future_create_candidates')}")
    print(f"  Blockers  : {c.get('blockers')}")
    print(f"  Warnings  : {c.get('warnings')}")
    if json_path:
        print(f"  JSON      : {json_path}")
    if md_path:
        print(f"  Markdown  : {md_path}")
    print("  Authority : NO backup copy, NO live restore, NO project writes")
    if report.get("blockers"):
        print("  Blockers:")
        for item in (report.get("blockers") or [])[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()


def cmd_snapshot_live_backup_policy(session_id: str) -> None:
    """Show Patch 92 live restore backup gate policy. Usage: snapshot-live-backup-policy"""
    from agents.forge.memory import write_audit_entry
    p = _snapshot_live_backup_policy_payload()
    print()
    print("── Live Restore Backup Gate Policy ─────────────────")
    print(f"  Policy    : {p.get('policy')}")
    print(f"  Mode      : {p.get('mode')}")
    print("  Writes    : Forge-owned backup gate receipts only")
    print("  Reads     : latest Patch 91 dry-run receipt")
    print("  Authority : NO backup copy, NO live restore, NO project writes")
    print("  Future    : backup-copy must be a separate future patch before any live restore")
    print()
    print("  Forbidden:")
    for item in p.get("forbidden", []):
        print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_LIVE_BACKUP_POLICY_SHOWN", "-", "gate-only", "patch92")


def cmd_snapshot_live_backup_plan(arg: str, session_id: str) -> None:
    """Write a Patch 92 live restore backup gate receipt. Usage: snapshot-live-backup-plan [latest|dry_run_path]"""
    from agents.forge.memory import write_audit_entry
    report, json_path, md_path = _snapshot_live_backup_build(arg or "latest")
    _snapshot_live_backup_print(report, json_path, md_path)
    c = report.get("counts") or {}
    tool = "SNAPSHOT_LIVE_BACKUP_GATE_WRITTEN" if not report.get("blockers") else "SNAPSHOT_LIVE_BACKUP_GATE_BLOCKED"
    write_audit_entry(
        session_id,
        tool,
        str(json_path),
        str(md_path),
        f"status={report.get('status')} files={c.get('gate_files_bound')} backup_required={c.get('live_files_requiring_backup_before_restore')} blockers={c.get('blockers')} warnings={c.get('warnings')}"
    )


def cmd_snapshot_live_backup_show(arg: str, session_id: str) -> None:
    """Show a Patch 92 live restore backup gate receipt. Usage: snapshot-live-backup-show latest"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_live_backup_resolve_path(arg or "latest")
    if not path or not path.exists():
        print()
        print("[forge] No Patch 92 live restore backup gate found.")
        print("        Run: snapshot-live-backup-plan")
        print()
        write_audit_entry(session_id, "SNAPSHOT_LIVE_BACKUP_SHOW_MISSING", "-", "-", f"arg={arg}")
        return
    report = _snapshot_live_backup_load(path)
    if not report:
        print(f"[forge] ERROR: Could not read backup gate report: {path}")
        write_audit_entry(session_id, "SNAPSHOT_LIVE_BACKUP_SHOW_FAILED", str(path), "-", "json_load_failed")
        return
    _snapshot_live_backup_print(report, path, None)
    write_audit_entry(session_id, "SNAPSHOT_LIVE_BACKUP_SHOWN", str(path), "-", f"status={report.get('status')}")


def cmd_snapshot_live_backup_gate(arg: str, session_id: str) -> None:
    """Validate a Patch 92 live restore backup gate receipt. Usage: snapshot-live-backup-gate [latest]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_live_backup_resolve_path(arg or "latest")
    report = _snapshot_live_backup_load(path) if path and path.exists() else None
    ok, problems, warnings = _snapshot_live_backup_validate(report or {})
    print()
    print("── Live Restore Backup Gate Check ──────────────────")
    print(f"  Report    : {path if path else 'NONE'}")
    print(f"  Status    : {'PASS' if ok else 'BLOCKED'}")
    print(f"  Problems  : {len(problems)}")
    print(f"  Warnings  : {len(warnings)}")
    print("  Authority : NO backup copy, NO live restore, NO project writes")
    if problems:
        print("  Problems:")
        for item in problems[:30]:
            print(f"    - {item}")
    if warnings:
        print("  Warnings:")
        for item in warnings[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()
    audit_name = "SNAPSHOT_LIVE_BACKUP_GATE_PASS" if ok else "SNAPSHOT_LIVE_BACKUP_GATE_BLOCKED"
    write_audit_entry(session_id, audit_name, str(path) if path else "-", f"problems={len(problems)}", f"warnings={len(warnings)}")


def cmd_snapshot_live_backup_export(session_id: str) -> None:
    """Export Patch 92 live restore backup gate receipts. Usage: snapshot-live-backup-export"""
    from agents.forge.memory import write_audit_entry
    SNAPSHOT_LIVE_BACKUP_GATE_DIR.mkdir(parents=True, exist_ok=True)
    reports = []
    for path in _snapshot_live_backup_paths():
        data = _snapshot_live_backup_load(path)
        if data:
            reports.append({
                "path": str(path),
                "created_at": data.get("created_at"),
                "status": data.get("status"),
                "backup_gate_id": data.get("backup_gate_id"),
                "source_dry_run_id": data.get("source_dry_run_id"),
                "counts": data.get("counts"),
                "authority": data.get("authority"),
            })
    ts = _patch60_timestamp()
    export = {
        "schema_version": SNAPSHOT_LIVE_BACKUP_GATE_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_LIVE_RESTORE_BACKUP_GATE_EXPORT_V1_PATCH92",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "EXPORT_ONLY_NO_BACKUP_COPY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "authority": _snapshot_live_backup_authority(),
        "count": len(reports),
        "reports": reports,
    }
    json_path = SNAPSHOT_LIVE_BACKUP_GATE_DIR / f"{ts}_{SNAPSHOT_LIVE_BACKUP_GATE_EXPORT_PREFIX}.json"
    md_path = SNAPSHOT_LIVE_BACKUP_GATE_DIR / f"{ts}_{SNAPSHOT_LIVE_BACKUP_GATE_EXPORT_PREFIX}.md"
    json_path.write_text(json.dumps(export, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = ["# Patch 92 Live Restore Backup Gate Export", "", f"Reports: `{len(reports)}`", "", "No backup copy or live restore authority exists.", ""]
    for row in reports:
        lines.append(f"- `{row.get('created_at')}` `{row.get('status')}` gate=`{row.get('backup_gate_id')}` dry_run=`{row.get('source_dry_run_id')}` `{row.get('path')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    print()
    print("── Live Restore Backup Gate Export ─────────────────")
    print(f"  JSON      : {json_path}")
    print(f"  Markdown  : {md_path}")
    print(f"  Reports   : {len(reports)}")
    print("  Authority : NO backup copy, NO live restore, NO project writes")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_LIVE_BACKUP_EXPORT_WRITTEN", str(json_path), str(md_path), f"reports={len(reports)}")

def main():
    parser = argparse.ArgumentParser(
        prog="forge",
        description="Forge — AI.Web local coding assistant"
    )
    subparsers = parser.add_subparsers(dest="command")

    # forge approve <path>
    approve_parser = subparsers.add_parser("approve", help="Approve a path for Forge access")
    approve_parser.add_argument("path", help="Absolute or relative path to approve")

    # forge add <path> [--mode core|docs|logs|all] [--preview]
    add_parser = subparsers.add_parser("add", help="Index a path into the local knowledge base")
    add_parser.add_argument("path", help="Path to scan and index")
    add_parser.add_argument(
        "--mode",
        choices=["core", "docs", "logs", "all", "project"],
        default="core",
        help="Indexing mode (default: core)"
    )
    add_parser.add_argument(
        "--preview", "--dry-run",
        dest="preview",
        action="store_true",
        default=False,
        help="Scan and show detailed preview without indexing"
    )

    # forge audit
    subparsers.add_parser("audit", help="Verify integrity of forge_audit.log")

    # forge status
    subparsers.add_parser("status", help="Show current Forge configuration")

    # forge kb [search <query>] [--results N]
    kb_parser = subparsers.add_parser("kb", help="Knowledge base: status or direct search")
    kb_sub = kb_parser.add_subparsers(dest="kb_subcommand")
    kb_search_parser = kb_sub.add_parser("search", help="Search the KB directly without the LLM")
    kb_search_parser.add_argument("query", help="Search query")
    kb_search_parser.add_argument(
        "--results", "-n",
        type=int,
        default=5,
        dest="n_results",
        help="Number of results to return (default: 5)"
    )

    args = parser.parse_args()

    if args.command == "approve":
        cmd_approve(args.path)
    elif args.command == "add":
        cmd_add(args.path, mode=args.mode, preview_only=args.preview)
    elif args.command == "audit":
        cmd_audit()
    elif args.command == "status":
        cmd_status()
    elif args.command == "kb":
        if hasattr(args, "kb_subcommand") and args.kb_subcommand == "search":
            cmd_kb("search", args.query, args.n_results)
        else:
            cmd_kb("status")
    else:
        # No subcommand — start a session
        run_session()






# ─── PATCH 93: LIVE RESTORE BACKUP COPY SANDBOX (NO RESTORE) ─────────────────
SNAPSHOT_LIVE_BACKUP_COPY_SCHEMA_VERSION = "snapshot_live_restore_backup_copy_v1_patch93"
SNAPSHOT_LIVE_BACKUP_COPY_POLICY_VERSION = "patch93_live_restore_backup_copy_sandbox_v1"
SNAPSHOT_LIVE_BACKUP_COPY_DIR = MEMORY_DIR / "live_restore_backups_v1"
SNAPSHOT_LIVE_BACKUP_COPY_PREFIX = "snapshot_live_restore_backup_copy_v1"
SNAPSHOT_LIVE_BACKUP_COPY_EXPORT_PREFIX = "snapshot_live_restore_backup_copy_export_v1"


def _snapshot_live_backup_copy_authority() -> dict:
    return {
        "backup_copy_sandbox_authority": True,
        "forge_memory_write_authority": True,
        "backup_copy_authority": True,
        "restore_authority": False,
        "live_restore_authority": False,
        "project_file_write_authority": False,
        "engine_file_write_authority": False,
        "delete_authority": False,
        "quarantine_authority": False,
        "shell_execution_authority": False,
        "chroma_write_authority": False,
        "final_lockfile_authority": False,
    }


def _snapshot_live_backup_copy_policy_payload() -> dict:
    return {
        "schema_version": SNAPSHOT_LIVE_BACKUP_COPY_SCHEMA_VERSION,
        "policy_version": SNAPSHOT_LIVE_BACKUP_COPY_POLICY_VERSION,
        "policy": "Patch 93 Live Restore Backup Copy Sandbox",
        "mode": "BACKUP_COPY_SANDBOX_ONLY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "purpose": "Copy the current live files identified by Patch 92 into a Forge-owned backup folder before any future restore command is allowed to exist.",
        "authority": _snapshot_live_backup_copy_authority(),
        "allowed_reads": [
            "latest Patch 92 live restore backup gate receipt",
            "current live files explicitly listed by the Patch 92 gate rows",
        ],
        "allowed_writes": [
            "Forge-owned backup copies under /home/nic/forge/memory/live_restore_backups_v1/",
            "Forge-owned backup copy JSON/Markdown receipts under /home/nic/forge/memory/live_restore_backups_v1/",
            "Forge audit entries for policy/copy/show/verify/export commands",
        ],
        "forbidden": [
            "restoring files to /home/nic/forge or /home/nic/aiweb",
            "copying snapshot files into live locations",
            "editing, deleting, moving, quarantining, or promoting engines",
            "granting final lockfile authority",
            "running shell commands",
            "writing to Chroma or old vector DBs",
            "reading or copying secrets, credentials, keys, .env, ~/.ssh, or token files",
            "copying any file not explicitly bound by the latest Patch 92 backup gate receipt",
        ],
        "plain_english": "This patch makes the safety backup. It copies the current live Forge files into Forge memory only. It still cannot restore anything.",
    }


def _snapshot_live_backup_copy_paths() -> list[Path]:
    SNAPSHOT_LIVE_BACKUP_COPY_DIR.mkdir(parents=True, exist_ok=True)
    return sorted(SNAPSHOT_LIVE_BACKUP_COPY_DIR.glob(f"*_{SNAPSHOT_LIVE_BACKUP_COPY_PREFIX}.json"), reverse=True)


def _snapshot_live_backup_copy_latest_path() -> Path | None:
    paths = _snapshot_live_backup_copy_paths()
    return paths[0] if paths else None


def _snapshot_live_backup_copy_resolve_path(arg: str) -> Path | None:
    target = (arg or "latest").strip()
    if target.lower() in {"latest", ""}:
        return _snapshot_live_backup_copy_latest_path()
    p = Path(os.path.expanduser(target))
    if not p.is_absolute():
        p = SNAPSHOT_LIVE_BACKUP_COPY_DIR / target
    return p


def _snapshot_live_backup_copy_load(path: Path) -> dict | None:
    try:
        return json.loads(Path(path).read_text(encoding="utf-8"))
    except Exception:
        return None


def _snapshot_live_backup_copy_status(blockers: list[str], warnings: list[str]) -> str:
    if blockers:
        return "LIVE_RESTORE_BACKUP_COPY_BLOCKED_NO_RESTORE_AUTHORITY"
    if warnings:
        return "LIVE_RESTORE_BACKUP_COPY_READY_WITH_WARNINGS_NO_RESTORE_AUTHORITY"
    return "LIVE_RESTORE_BACKUP_COPY_READY_NO_RESTORE_AUTHORITY"


def _snapshot_live_backup_copy_id(gate: dict, ts: str) -> str:
    import hashlib as _hashlib
    rows = gate.get("backup_gate_rows") or []
    basis = {
        "created_for_patch": "patch93",
        "timestamp": ts,
        "source_backup_gate_id": gate.get("backup_gate_id"),
        "source_backup_gate_created_at": gate.get("created_at"),
        "rows": [
            {
                "target": row.get("future_live_target_path_FOR_REVIEW_ONLY"),
                "current_live_sha256_to_backup": row.get("current_live_sha256_to_backup"),
                "backup_required_before_any_future_restore": row.get("backup_required_before_any_future_restore"),
            }
            for row in rows
        ],
    }
    raw = json.dumps(basis, sort_keys=True, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    return "LBC-" + _hashlib.sha256(raw).hexdigest()[:24]


def _snapshot_live_backup_copy_safe_rel_for_live_path(path: Path) -> str:
    try:
        resolved = Path(path).resolve()
    except Exception:
        resolved = Path(os.path.abspath(os.path.expanduser(str(path))))
    try:
        rel = resolved.relative_to(Path("/home/nic").resolve())
    except Exception:
        rel = Path("outside_home") / str(resolved).lstrip("/")
    rel_s = str(rel)
    rel_s = rel_s.replace("\\", "/")
    parts = [p for p in Path(rel_s).parts if p not in {"", "."}]
    if ".." in parts:
        return "unsafe_path_component"
    return str(Path(*parts)) if parts else "root_file"


def _snapshot_live_backup_copy_is_inside_backup_root(root: Path, target: Path) -> bool:
    try:
        root_r = root.resolve()
        target_r = target.resolve()
        target_r.relative_to(root_r)
        return True
    except Exception:
        return False


def _snapshot_live_backup_copy_markdown(receipt: dict, md_path: Path) -> None:
    c = receipt.get("counts") or {}
    lines = [
        "# Patch 93 Live Restore Backup Copy Sandbox Receipt",
        "",
        f"Status: `{receipt.get('status')}`",
        f"Backup copy ID: `{receipt.get('backup_copy_id')}`",
        f"Source backup gate ID: `{receipt.get('source_backup_gate_id')}`",
        "",
        "This receipt proves Forge copied current live files into a Forge-owned backup folder only. It does not restore anything.",
        "",
        "## Counts",
        "",
        f"- Bound rows: `{c.get('gate_rows_bound')}`",
        f"- Backup required rows: `{c.get('backup_required_rows')}`",
        f"- Files copied: `{c.get('files_copied')}`",
        f"- Files skipped: `{c.get('files_skipped')}`",
        f"- Hash matches: `{c.get('hash_matches')}`",
        f"- Blockers: `{c.get('blockers')}`",
        f"- Warnings: `{c.get('warnings')}`",
        "",
        "## Authority",
        "",
        "- Backup copy sandbox authority: `true`",
        "- Live restore authority: `false`",
        "- Project file write authority: `false`",
        "",
        "## Copied Files",
        "",
    ]
    for row in receipt.get("backup_copy_rows") or []:
        lines.append(f"- `{row.get('copy_status')}` `{row.get('actual_live_source_path_BACKED_UP')}` -> `{row.get('backup_copy_path')}` hash_match=`{row.get('hash_match')}`")
    if receipt.get("blockers"):
        lines += ["", "## Blockers", ""]
        for item in receipt.get("blockers") or []:
            lines.append(f"- {item}")
    if receipt.get("warnings"):
        lines += ["", "## Warnings", ""]
        for item in receipt.get("warnings") or []:
            lines.append(f"- {item}")
    md_path.write_text("\n".join(lines), encoding="utf-8")


def _snapshot_live_backup_copy_build(arg: str = "latest") -> tuple[dict, Path, Path]:
    now = datetime.datetime.now().isoformat(timespec="seconds")
    ts = _patch60_timestamp()
    SNAPSHOT_LIVE_BACKUP_COPY_DIR.mkdir(parents=True, exist_ok=True)

    gate_path = _snapshot_live_backup_resolve_path(arg or "latest")
    gate = _snapshot_live_backup_load(gate_path) if gate_path and gate_path.exists() else None
    blockers: list[str] = []
    warnings: list[str] = []
    gate_ok = False
    gate_problems: list[str] = []
    gate_warnings: list[str] = []

    if not gate_path or not gate_path.exists():
        blockers.append("No Patch 92 live restore backup gate receipt found. Run snapshot-live-backup-plan first.")
    if not gate:
        blockers.append("Patch 92 live restore backup gate receipt could not be loaded as JSON.")
    else:
        gate_ok, gate_problems, gate_warnings = _snapshot_live_backup_validate(gate)
        if not gate_ok:
            blockers.append(f"Patch 92 backup gate did not pass: {len(gate_problems)} problems")
            blockers.extend(gate_problems[:30])
        warnings.extend(gate_warnings)
        auth = gate.get("authority") or {}
        if auth.get("live_restore_authority") is not False or auth.get("project_file_write_authority") is not False:
            blockers.append("Patch 92 backup gate contains forbidden live restore/project write authority.")
        if (gate.get("counts") or {}).get("blockers", 999) != 0:
            blockers.append(f"Patch 92 backup gate still reports blockers: {(gate.get('counts') or {}).get('blockers')}")

    source_rows = (gate or {}).get("backup_gate_rows") or []
    if gate and not source_rows:
        blockers.append("Patch 92 backup gate has no rows to copy.")

    backup_copy_id = _snapshot_live_backup_copy_id(gate or {}, ts)
    backup_root = SNAPSHOT_LIVE_BACKUP_COPY_DIR / f"{ts}_{backup_copy_id}_backup_copy_sandbox"
    backup_files_root = backup_root / "backup_files"

    backup_rows: list[dict] = []
    files_copied = 0
    files_skipped = 0
    hash_matches = 0

    for idx, row in enumerate(source_rows, start=1):
        target_s = row.get("future_live_target_path_FOR_REVIEW_ONLY")
        target = Path(os.path.expanduser(str(target_s or "")))
        row_blockers: list[str] = []
        row_warnings: list[str] = []
        backup_required = bool(row.get("backup_required_before_any_future_restore"))
        expected_live_sha = row.get("current_live_sha256_to_backup")
        expected_snapshot_sha = row.get("expected_snapshot_sha256_after_restore")
        safe_root = row.get("safe_root") is True
        sensitive = row.get("sensitive_path") is True

        if not target_s:
            row_blockers.append("missing future live target path")
        if not target.is_absolute():
            row_blockers.append("future live target path is not absolute")
        if not safe_root:
            row_blockers.append(f"target not marked inside safe root by Patch 92 gate: {row.get('safe_root_reason')}")
        if sensitive:
            row_blockers.append(f"target marked sensitive by Patch 92 gate: {row.get('sensitive_reason')}")
        try:
            sensitive_now, sensitive_reason_now = _code_is_sensitive_path(target)
        except Exception:
            sensitive_now, sensitive_reason_now = (False, "")
        if sensitive_now:
            row_blockers.append(f"target is sensitive by current path policy: {sensitive_reason_now}")

        live_exists = target.exists()
        live_is_file = target.is_file() if live_exists else False
        live_size = target.stat().st_size if live_is_file else None
        live_sha = _snapshot_create_current_sha(target) if live_is_file else None

        if backup_required and not live_exists:
            row_blockers.append("backup required but live target does not exist")
        if backup_required and live_exists and not live_is_file:
            row_blockers.append("backup required but live target is not a regular file")
        if backup_required and expected_live_sha and live_sha and live_sha != expected_live_sha:
            row_warnings.append("current live SHA differs from Patch 92 gate SHA; backup will capture current live state for safety")

        rel = _snapshot_live_backup_copy_safe_rel_for_live_path(target)
        backup_path = backup_files_root / rel
        if not _snapshot_live_backup_copy_is_inside_backup_root(backup_root, backup_path):
            row_blockers.append("computed backup path escapes backup root")

        copied = False
        backup_sha = None
        copy_status = "SKIPPED_NOT_REQUIRED"
        if backup_required and not row_blockers and not blockers:
            try:
                backup_path.parent.mkdir(parents=True, exist_ok=True)
                import shutil as _shutil
                _shutil.copy2(target, backup_path)
                copied = True
                files_copied += 1
                backup_sha = _snapshot_create_current_sha(backup_path)
                copy_status = "BACKUP_COPIED_TO_FORGE_MEMORY"
                if backup_sha == live_sha:
                    hash_matches += 1
                else:
                    row_blockers.append("backup file SHA does not match live file SHA at backup time")
            except Exception as exc:
                row_blockers.append(f"backup copy failed: {exc}")
                copy_status = "BACKUP_COPY_FAILED"
        elif backup_required:
            copy_status = "SKIPPED_DUE_TO_BLOCKERS"
            files_skipped += 1
        else:
            files_skipped += 1

        if row_blockers:
            blockers.extend([f"{target_s}: {b}" for b in row_blockers])
        if row_warnings:
            warnings.extend([f"{target_s}: {w}" for w in row_warnings])

        backup_rows.append({
            "index": idx,
            "source_backup_gate_id": (gate or {}).get("backup_gate_id"),
            "future_live_target_path_FOR_REVIEW_ONLY": str(target_s or ""),
            "actual_live_source_path_BACKED_UP": str(target) if copied else str(target_s or ""),
            "backup_copy_path": str(backup_path) if backup_required else None,
            "backup_required_before_any_future_restore": backup_required,
            "live_exists_at_backup_time": live_exists,
            "live_is_file_at_backup_time": live_is_file,
            "live_size_bytes_at_backup_time": live_size,
            "live_sha256_at_backup_time": live_sha,
            "patch92_expected_live_sha256_to_backup": expected_live_sha,
            "expected_snapshot_sha256_after_future_restore": expected_snapshot_sha,
            "backup_file_sha256": backup_sha,
            "hash_match": bool(backup_sha and live_sha and backup_sha == live_sha),
            "copy_status": copy_status,
            "copied_to_forge_memory_only": copied,
            "safe_root": safe_root,
            "sensitive_path": sensitive or sensitive_now,
            "row_blockers": row_blockers,
            "row_warnings": row_warnings,
            "backup_copy_authorized_now": True,
            "live_restore_authorized_now": False,
            "project_write_authorized_now": False,
            "restore_authorized_now": False,
        })

    warnings = sorted(set(warnings))
    blockers = sorted(set(blockers))
    required_count = sum(1 for r in source_rows if r.get("backup_required_before_any_future_restore"))
    status = _snapshot_live_backup_copy_status(blockers, warnings)
    receipt = {
        "schema_version": SNAPSHOT_LIVE_BACKUP_COPY_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_LIVE_RESTORE_BACKUP_COPY_SANDBOX_V1_PATCH93",
        "created_at": now,
        "mode": "BACKUP_COPY_SANDBOX_ONLY_NO_LIVE_RESTORE_NO_PROJECT_WRITE",
        "status": status,
        "backup_copy_id": backup_copy_id,
        "backup_root": str(backup_root),
        "backup_files_root": str(backup_files_root),
        "authority": _snapshot_live_backup_copy_authority(),
        "source_backup_gate": str(gate_path) if gate_path else None,
        "source_backup_gate_id": (gate or {}).get("backup_gate_id"),
        "source_backup_gate_created_at": (gate or {}).get("created_at"),
        "checks": {
            "source_backup_gate_passed": gate_ok,
            "source_backup_gate_problems": gate_problems,
            "source_backup_gate_warnings": gate_warnings,
            "backup_copy_performed": files_copied > 0,
            "backup_copy_authorized_now": True,
            "live_restore_authorized_now": False,
            "project_write_authorized_now": False,
            "actual_restore_performed": False,
        },
        "counts": {
            "gate_rows_bound": len(source_rows),
            "backup_required_rows": required_count,
            "files_copied": files_copied,
            "files_skipped": files_skipped,
            "hash_matches": hash_matches,
            "hash_mismatches": max(0, files_copied - hash_matches),
            "blockers": len(blockers),
            "warnings": len(warnings),
        },
        "blockers": blockers,
        "warnings": warnings,
        "backup_copy_rows": backup_rows,
        "future_patch94_gate_requirements": [
            "latest Patch 93 backup copy receipt validates PASS",
            "backup copy receipt has zero blockers/problems",
            "all backup-required rows copied to Forge memory",
            "each backup file hash matches the live file hash captured at backup time",
            "live restore authority remains absent until Patch 94 explicitly adds a strict restore command",
            "Patch 94 must re-check live destination hashes immediately before writing",
        ],
        "plain_english": "Patch 93 copies the current live files into Forge memory as a safety backup. Patch 94 must prove this backup exists and verifies before any live restore can run.",
    }
    json_path = SNAPSHOT_LIVE_BACKUP_COPY_DIR / f"{ts}_{SNAPSHOT_LIVE_BACKUP_COPY_PREFIX}.json"
    md_path = SNAPSHOT_LIVE_BACKUP_COPY_DIR / f"{ts}_{SNAPSHOT_LIVE_BACKUP_COPY_PREFIX}.md"
    json_path.write_text(json.dumps(receipt, indent=2, ensure_ascii=False), encoding="utf-8")
    _snapshot_live_backup_copy_markdown(receipt, md_path)
    return receipt, json_path, md_path


def _snapshot_live_backup_copy_validate(receipt: dict) -> tuple[bool, list[str], list[str]]:
    problems: list[str] = []
    warnings: list[str] = []
    if not isinstance(receipt, dict) or not receipt:
        return False, ["backup copy receipt is missing or invalid"], []
    if receipt.get("schema_version") != SNAPSHOT_LIVE_BACKUP_COPY_SCHEMA_VERSION:
        problems.append("unexpected backup copy schema version")
    auth = receipt.get("authority") or {}
    if auth.get("backup_copy_authority") is not True:
        problems.append("backup copy receipt does not declare backup copy authority")
    if auth.get("live_restore_authority") is not False:
        problems.append("backup copy receipt improperly authorizes live restore")
    if auth.get("project_file_write_authority") is not False:
        problems.append("backup copy receipt improperly authorizes project file writes")
    if (receipt.get("checks") or {}).get("actual_restore_performed") is not False:
        problems.append("backup copy receipt claims an actual restore was performed")
    if (receipt.get("counts") or {}).get("blockers", 999) != 0:
        problems.append(f"backup copy receipt reports blockers: {(receipt.get('counts') or {}).get('blockers')}")
    rows = receipt.get("backup_copy_rows") or []
    if not rows:
        problems.append("backup copy receipt has no rows")
    required_rows = [r for r in rows if r.get("backup_required_before_any_future_restore") is True]
    copied_rows = [r for r in required_rows if r.get("copied_to_forge_memory_only") is True]
    if len(copied_rows) != len(required_rows):
        problems.append(f"not all backup-required rows were copied: copied={len(copied_rows)} required={len(required_rows)}")
    for row in rows:
        target = row.get("future_live_target_path_FOR_REVIEW_ONLY")
        if row.get("live_restore_authorized_now") is not False:
            problems.append(f"row improperly authorizes live restore: {target}")
        if row.get("project_write_authorized_now") is not False:
            problems.append(f"row improperly authorizes project write: {target}")
        if row.get("backup_required_before_any_future_restore") is True:
            backup_path = row.get("backup_copy_path")
            if not backup_path:
                problems.append(f"missing backup copy path: {target}")
                continue
            bp = Path(backup_path)
            if not bp.exists() or not bp.is_file():
                problems.append(f"backup copy missing on disk: {backup_path}")
                continue
            current_backup_sha = _snapshot_create_current_sha(bp)
            if current_backup_sha != row.get("backup_file_sha256"):
                problems.append(f"backup copy SHA drifted after receipt: {backup_path}")
            if row.get("hash_match") is not True:
                problems.append(f"backup copy did not match source hash at backup time: {target}")
        if row.get("row_blockers"):
            problems.extend([f"{target}: {b}" for b in row.get("row_blockers")])
        if row.get("row_warnings"):
            warnings.extend([f"{target}: {w}" for w in row.get("row_warnings")])
    if receipt.get("warnings"):
        warnings.extend(receipt.get("warnings") or [])
    warnings = sorted(set(warnings))
    problems = sorted(set(problems))
    return not problems, problems, warnings


def _snapshot_live_backup_copy_print(receipt: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    c = receipt.get("counts") or {}
    print()
    print("── Live Restore Backup Copy Sandbox ────────────────")
    print("  Mode      : BACKUP COPY SANDBOX — no restore")
    print(f"  Status    : {receipt.get('status')}")
    print(f"  Copy ID   : {receipt.get('backup_copy_id')}")
    print(f"  Gate ID   : {receipt.get('source_backup_gate_id')}")
    print(f"  Files     : bound={c.get('gate_rows_bound')} required={c.get('backup_required_rows')} copied={c.get('files_copied')} skipped={c.get('files_skipped')} hash_matches={c.get('hash_matches')}")
    print(f"  Blockers  : {c.get('blockers')}")
    print(f"  Warnings  : {c.get('warnings')}")
    if json_path:
        print(f"  JSON      : {json_path}")
    if md_path:
        print(f"  Markdown  : {md_path}")
    print(f"  BackupDir : {receipt.get('backup_root')}")
    print("  Authority : backup copy to Forge memory ONLY; NO live restore, NO project writes")
    if receipt.get("blockers"):
        print("  Blockers:")
        for item in (receipt.get("blockers") or [])[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()


