def cmd_snapshot_live_backup_copy_verify(arg: str, session_id: str) -> None:
    """Verify a Patch 93 live restore backup copy receipt. Usage: snapshot-live-backup-copy-verify [latest]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_live_backup_copy_resolve_path(arg or "latest")
