    print(f"  Status    : {'PASS' if ok else 'BLOCKED'}")
    print(f"  Problems  : {len(problems)}")
    print(f"  Warnings  : {len(warnings)}")
    print("  Authority : NO live restore, NO project writes")
    if problems:
        print("  Problems:")
        for item in problems[:30]:
            print(f"    - {item}")
    if warnings:
        print("  Warnings:")
        for item in warnings[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()
    audit_name = "SNAPSHOT_LIVE_BACKUP_COPY_VERIFY_PASS" if ok else "SNAPSHOT_LIVE_BACKUP_COPY_VERIFY_BLOCKED"
    write_audit_entry(session_id, audit_name, str(path) if path else "-", f"problems={len(problems)}", f"warnings={len(warnings)}")


