    json_path.write_text(json.dumps(export, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = ["# Patch 93 Live Restore Backup Copy Export", "", f"Reports: `{len(reports)}`", "", "No live restore authority exists.", ""]
