def _snapshot_live_execute_paths() -> list[Path]:
    SNAPSHOT_LIVE_EXECUTE_DIR.mkdir(parents=True, exist_ok=True)
    return sorted(SNAPSHOT_LIVE_EXECUTE_DIR.glob(f"*_{SNAPSHOT_LIVE_EXECUTE_PREFIX}.json"), reverse=True)


def _snapshot_live_execute_latest_path() -> Path | None:
    paths = _snapshot_live_execute_paths()
    return paths[0] if paths else None


def _snapshot_live_execute_resolve_path(arg: str) -> Path | None:
    target = (arg or "latest").strip()
    if target.lower() in {"latest", ""}:
        return _snapshot_live_execute_latest_path()
    p = Path(os.path.expanduser(target))
    if not p.is_absolute():
        p = SNAPSHOT_LIVE_EXECUTE_DIR / target
    return p


def _snapshot_live_execute_load(path: Path) -> dict | None:
    try:
        return json.loads(Path(path).read_text(encoding="utf-8"))
    except Exception:
        return None


def _snapshot_live_execute_home_relative(path: Path) -> str | None:
    try:
        resolved = path.resolve()
    except Exception:
        resolved = Path(os.path.abspath(os.path.expanduser(str(path))))
    try:
        return str(resolved.relative_to(Path("/home/nic").resolve()))
    except Exception:
        return None


def _snapshot_live_execute_is_protected_skip(path: Path) -> tuple[bool, str]:
    rel = _snapshot_live_execute_home_relative(path)
    if rel in SNAPSHOT_LIVE_EXECUTE_PROTECTED_RELATIVE_PATHS:
        return True, "protected volatile audit log; Patch 94 never overwrites live audit chain"
    return False, ""


def _snapshot_live_execute_status(blockers: list[str], warnings: list[str], executed_rows: int) -> str:
    if blockers:
        return "LIVE_RESTORE_EXECUTE_BLOCKED"
    if executed_rows <= 0:
        return "LIVE_RESTORE_EXECUTE_NO_WRITES_PERFORMED"
    if warnings:
        return "LIVE_RESTORE_EXECUTED_WITH_WARNINGS_AUDIT_LOG_PROTECTED"
    return "LIVE_RESTORE_EXECUTED"


def _snapshot_live_execute_id(backup: dict, ts: str) -> str:
    import hashlib as _hashlib
    basis = {
        "created_for_patch": "patch94",
        "timestamp": ts,
        "backup_copy_id": backup.get("backup_copy_id"),
        "source_backup_gate_id": backup.get("source_backup_gate_id"),
        "rows": [
            {
                "target": row.get("future_live_target_path_FOR_REVIEW_ONLY"),
                "expected_snapshot_sha256": row.get("expected_snapshot_sha256_after_future_restore"),
                "backup_sha256": row.get("backup_file_sha256"),
            }
            for row in (backup.get("backup_copy_rows") or [])
        ],
    }
    raw = json.dumps(basis, sort_keys=True, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    return "LRE-" + _hashlib.sha256(raw).hexdigest()[:24]


def _snapshot_live_execute_load_backup(arg: str = "latest") -> tuple[dict | None, Path | None, list[str], list[str]]:
    problems: list[str] = []
    warnings: list[str] = []
    backup_path = _snapshot_live_backup_copy_resolve_path(arg or "latest")
    backup = _snapshot_live_backup_copy_load(backup_path) if backup_path and backup_path.exists() else None
    if not backup_path or not backup_path.exists():
        problems.append("No Patch 93 backup copy receipt found. Run snapshot-live-backup-copy after installing Patch 94 before executing restore.")
    if not backup:
        problems.append("Patch 93 backup copy receipt could not be loaded as JSON.")
    else:
        ok, bproblems, bwarnings = _snapshot_live_backup_copy_validate(backup)
        if not ok:
            problems.append(f"Patch 93 backup copy verification did not pass: {len(bproblems)} problems")
            problems.extend(bproblems[:40])
        warnings.extend(bwarnings)
        auth = backup.get("authority") or {}
        if auth.get("live_restore_authority") is not False or auth.get("project_file_write_authority") is not False:
            problems.append("Patch 93 backup copy receipt contains forbidden live restore/project write authority.")
        if (backup.get("counts") or {}).get("blockers", 999) != 0:
            problems.append(f"Patch 93 backup copy still reports blockers: {(backup.get('counts') or {}).get('blockers')}")
    return backup, backup_path, problems, warnings


def _snapshot_live_execute_load_chain(backup: dict | None) -> tuple[dict | None, dict | None, dict | None, Path | None, list[str], list[str]]:
    problems: list[str] = []
    warnings: list[str] = []
    gate = None
    dry = None
    snapshot = None
    snapshot_path = None
    gate_path = Path(os.path.expanduser(str((backup or {}).get("source_backup_gate") or ""))) if backup else None
    if not gate_path or not gate_path.exists():
        problems.append("Linked Patch 92 backup gate receipt is missing from backup copy receipt.")
    else:
        gate = _snapshot_live_backup_load(gate_path)
        if not gate:
            problems.append(f"Linked Patch 92 backup gate could not be loaded: {gate_path}")
        else:
            if (gate.get("counts") or {}).get("blockers", 999) != 0:
                problems.append(f"Linked Patch 92 backup gate reports blockers: {(gate.get('counts') or {}).get('blockers')}")
            dry_path = Path(os.path.expanduser(str(gate.get("source_live_restore_dry_run") or "")))
            if not dry_path.exists():
                problems.append("Linked Patch 91 dry-run receipt is missing from backup gate receipt.")
            else:
                dry = _snapshot_live_restore_dry_run_load(dry_path)
                if not dry:
                    problems.append(f"Linked Patch 91 dry-run could not be loaded: {dry_path}")
                else:
                    ok, dproblems, dwarnings = _snapshot_live_restore_dry_run_validate(dry)
                    if not ok:
                        problems.append(f"Linked Patch 91 dry-run gate does not pass: {len(dproblems)} problems")
                        problems.extend(dproblems[:40])
                    warnings.extend(dwarnings)
                    token_path = Path(os.path.expanduser(str(dry.get("source_live_restore_approval_token") or "")))
                    token = _snapshot_live_approval_load(token_path) if token_path and token_path.exists() else None
                    if not token:
                        problems.append("Linked Patch 90 approval token is missing or unreadable from Patch 91 dry-run.")
                    else:
                        snapshot_path = Path(os.path.expanduser(str(token.get("source_snapshot_receipt") or "")))
                        if not snapshot_path.exists():
                            problems.append("Linked snapshot receipt is missing from Patch 90 approval token.")
                        else:
                            try:
                                snapshot = json.loads(snapshot_path.read_text(encoding="utf-8"))
                            except Exception as exc:
                                problems.append(f"Linked snapshot receipt could not be loaded as JSON: {exc}")
    return gate, dry, snapshot, snapshot_path, problems, warnings


def _snapshot_live_execute_snapshot_map(snapshot: dict | None) -> dict[str, dict]:
    out: dict[str, dict] = {}
    for row in ((snapshot or {}).get("copied_files") or []):
        sp = row.get("source_path")
        if sp:
            out[str(Path(os.path.expanduser(str(sp))))] = row
    return out


def _snapshot_live_execute_gate_report(arg: str = "latest", execute: bool = False, confirmation: str = "") -> tuple[dict, Path, Path]:
    now = datetime.datetime.now().isoformat(timespec="seconds")
    ts = _patch60_timestamp()
    SNAPSHOT_LIVE_EXECUTE_DIR.mkdir(parents=True, exist_ok=True)
    backup, backup_path, blockers, warnings = _snapshot_live_execute_load_backup(arg or "latest")
    gate, dry, snapshot, snapshot_path, chain_blockers, chain_warnings = _snapshot_live_execute_load_chain(backup)
    blockers.extend(chain_blockers)
    warnings.extend(chain_warnings)
    if execute and confirmation != SNAPSHOT_LIVE_EXECUTE_CONFIRMATION:
        blockers.append(f"Explicit confirmation phrase required: {SNAPSHOT_LIVE_EXECUTE_CONFIRMATION}")
    if execute and backup_path:
        # Force the operator to run a fresh backup copy after installing Patch 94. This prevents stale backup evidence.
        try:
            age_seconds = max(0, int((datetime.datetime.now() - datetime.datetime.fromtimestamp(backup_path.stat().st_mtime)).total_seconds()))
        except Exception:
            age_seconds = None
        if age_seconds is not None and age_seconds > 3600:
            blockers.append(f"Latest backup copy receipt is older than one hour ({age_seconds}s). Run snapshot-live-backup-copy again before live restore.")
    snapshot_by_source = _snapshot_live_execute_snapshot_map(snapshot)
    archive_root = Path(os.path.expanduser(str((snapshot or {}).get("archive_root") or ""))) if snapshot else None
    execute_id = _snapshot_live_execute_id(backup or {}, ts)
    rows: list[dict] = []
    executed_count = 0
    skipped_count = 0
    failed_count = 0
    for idx, row in enumerate((backup or {}).get("backup_copy_rows") or [], start=1):
        target_s = row.get("future_live_target_path_FOR_REVIEW_ONLY")
        target = Path(os.path.expanduser(str(target_s))) if target_s else Path("/")
        row_blockers: list[str] = []
        row_warnings: list[str] = []
        safe_root, safe_root_reason = _snapshot_live_restore_safe_root_check(target)
        sensitive, sensitive_reason = _code_is_sensitive_path(target)
        protected_skip, protected_reason = _snapshot_live_execute_is_protected_skip(target)
        if not safe_root:
            row_blockers.append(safe_root_reason)
        if sensitive:
            row_blockers.append(sensitive_reason)
        snap_row = snapshot_by_source.get(str(target))
        snapshot_file = None
        snapshot_sha = None
        if not snap_row:
            row_blockers.append("target is not present in linked snapshot receipt copied_files")
        else:
            snapshot_sha = snap_row.get("sha256")
            snapshot_rel = snap_row.get("snapshot_relative_path")
            snapshot_file = (archive_root / snapshot_rel) if archive_root and snapshot_rel else None
            if not snapshot_file or not snapshot_file.exists():
                row_blockers.append("snapshot source file missing from archive")
            else:
                state = _snapshot_live_restore_file_state(snapshot_file)
                if state.get("sha256") != snapshot_sha:
                    row_blockers.append("snapshot source file hash does not match snapshot receipt")
                expected = row.get("expected_snapshot_sha256_after_future_restore")
                if expected and snapshot_sha and expected != snapshot_sha:
                    row_blockers.append("backup copy expected snapshot SHA does not match snapshot receipt SHA")
        backup_path_s = row.get("backup_copy_path")
        bfile = Path(os.path.expanduser(str(backup_path_s))) if backup_path_s else None
        bstate = _snapshot_live_restore_file_state(bfile) if bfile else {"exists": False, "sha256": None, "read_error": "missing backup path"}
        if not bfile or not bstate.get("exists"):
            row_blockers.append("backup copy file is missing; restore cannot proceed")
        elif bstate.get("sha256") != row.get("backup_file_sha256"):
            row_blockers.append("backup copy file SHA does not match Patch 93 receipt")
        live_before = _snapshot_live_restore_file_state(target)
        if not protected_skip:
            if not live_before.get("exists") or not live_before.get("is_file"):
                row_blockers.append("live target missing or not a regular file immediately before restore")
            elif live_before.get("sha256") != row.get("live_sha256_at_backup_time"):
                row_blockers.append("current live SHA differs from Patch 93 backup-time SHA; run snapshot-live-backup-copy again before restore")
        else:
            row_warnings.append(protected_reason)
        blockers.extend([f"{target_s}: {b}" for b in row_blockers])
        warnings.extend([f"{target_s}: {w}" for w in row_warnings])
        action = "PENDING_NOT_EXECUTED"
        live_after = None
        write_error = None
        if protected_skip:
            action = "SKIPPED_PROTECTED_AUDIT_LOG_NOT_RESTORED"
            skipped_count += 1
        elif execute and not row_blockers and not blockers:
            try:
                raw = Path(snapshot_file).read_bytes()
                target.parent.mkdir(parents=True, exist_ok=True)
                target.write_bytes(raw)
                live_after = _snapshot_live_restore_file_state(target)
                if live_after.get("sha256") == snapshot_sha:
                    action = "LIVE_FILE_RESTORED_FROM_SNAPSHOT"
                    executed_count += 1
                else:
                    action = "LIVE_FILE_RESTORE_HASH_MISMATCH_AFTER_WRITE"
                    row_blockers.append("live target hash mismatch after restore write")
                    failed_count += 1
            except Exception as exc:
                action = "LIVE_FILE_RESTORE_WRITE_FAILED"
                write_error = str(exc)
                row_blockers.append(f"restore write failed: {exc}")
                failed_count += 1
        rows.append({
            "index": idx,
            "future_live_target_path": target_s,
            "restore_action": action,
            "protected_skip": protected_skip,
            "protected_skip_reason": protected_reason,
            "safe_root": safe_root,
            "safe_root_reason": safe_root_reason,
            "sensitive_path": sensitive,
            "sensitive_reason": sensitive_reason,
            "snapshot_file": str(snapshot_file) if snapshot_file else None,
            "expected_snapshot_sha256": snapshot_sha,
            "backup_copy_path": str(bfile) if bfile else None,
            "backup_file_sha256": bstate.get("sha256"),
            "live_sha256_before_restore": live_before.get("sha256"),
            "live_sha256_at_backup_time": row.get("live_sha256_at_backup_time"),
            "live_sha256_after_restore": (live_after or {}).get("sha256") if live_after else None,
            "write_error": write_error,
            "row_blockers": row_blockers,
            "row_warnings": row_warnings,
        })
    blockers = sorted(set(blockers))
    warnings = sorted(set(warnings))
    if execute and failed_count:
        blockers.append(f"{failed_count} restore writes failed or mismatched after write")
    status = _snapshot_live_execute_status(blockers, warnings, executed_count if execute else 0)
    report = {
        "schema_version": SNAPSHOT_LIVE_EXECUTE_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_LIVE_RESTORE_EXECUTE_V1_PATCH94",
        "created_at": now,
        "mode": "LIVE_RESTORE_EXECUTE_STRICTLY_BOUND_NO_SHELL_NO_DELETE_NO_QUARANTINE",
        "status": status,
        "execute_id": execute_id,
        "confirmation_phrase_required": SNAPSHOT_LIVE_EXECUTE_CONFIRMATION,
        "confirmation_phrase_received": bool(confirmation),
        "actual_restore_performed": bool(execute and not blockers and executed_count > 0),
        "authority": _snapshot_live_execute_authority(),
        "source_backup_copy_receipt": str(backup_path) if backup_path else None,
        "source_backup_copy_id": (backup or {}).get("backup_copy_id"),
        "source_backup_gate_id": (backup or {}).get("source_backup_gate_id"),
        "source_snapshot_receipt": str(snapshot_path) if snapshot_path else None,
        "checks": {
            "backup_copy_loaded": bool(backup),
            "backup_copy_verify_pass": not bool([b for b in blockers if "Patch 93 backup" in b]),
            "chain_receipts_loaded": bool(gate and dry and snapshot),
            "confirmation_phrase_required": True,
            "confirmation_phrase_valid": confirmation == SNAPSHOT_LIVE_EXECUTE_CONFIRMATION,
            "audit_log_overwritten": False,
            "protected_audit_log_skipped": any(r.get("protected_skip") for r in rows),
            "delete_performed": False,
            "quarantine_performed": False,
            "shell_executed": False,
        },
        "counts": {
            "rows_bound": len(rows),
            "files_restored": executed_count,
            "protected_skips": skipped_count,
            "failed_writes": failed_count,
            "blockers": len(blockers),
            "warnings": len(warnings),
        },
        "blockers": blockers,
        "warnings": warnings,
        "restore_rows": rows,
        "plain_english": "Patch 94 restored only chain-bound files whose current SHA still matched the verified Patch 93 backup. The live audit log was protected and not overwritten.",
    }
    json_path = SNAPSHOT_LIVE_EXECUTE_DIR / f"{ts}_{SNAPSHOT_LIVE_EXECUTE_PREFIX}.json"
    md_path = SNAPSHOT_LIVE_EXECUTE_DIR / f"{ts}_{SNAPSHOT_LIVE_EXECUTE_PREFIX}.md"
    json_path.write_text(json.dumps(report, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = [
        "# Patch 94 Live Restore Execute Receipt",
        "",
        f"Status: `{report['status']}`",
        f"Execution ID: `{execute_id}`",
        f"Actual restore performed: `{report['actual_restore_performed']}`",
        f"Files restored: `{executed_count}`",
        f"Protected skips: `{skipped_count}`",
        f"Blockers: `{len(blockers)}`",
        f"Warnings: `{len(warnings)}`",
        "",
        "## Authority",
        "Live restore is strictly bound to prior receipts. No shell, delete, quarantine, Chroma, or final lockfile authority is granted.",
        "",
        "## Protected skip",
        "`/home/nic/forge/logs/forge_audit.log` is not overwritten so the live audit chain remains intact.",
        "",
        "## Rows",
    ]
    for r in rows[:100]:
        lines.append(f"- `{r.get('restore_action')}` `{r.get('future_live_target_path')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    return report, json_path, md_path


def _snapshot_live_execute_validate(report: dict) -> tuple[bool, list[str], list[str]]:
    problems: list[str] = []
    warnings: list[str] = []
    if not report:
        return False, ["missing Patch 94 execution receipt"], []
    if report.get("schema_version") != SNAPSHOT_LIVE_EXECUTE_SCHEMA_VERSION:
        problems.append("unexpected Patch 94 schema_version")
    auth = report.get("authority") or {}
    if auth.get("shell_execution_authority") is not False:
        problems.append("forbidden shell execution authority present")
    if auth.get("delete_authority") is not False or auth.get("quarantine_authority") is not False:
        problems.append("forbidden delete/quarantine authority present")
    if auth.get("audit_log_overwrite_authority") is not False:
        problems.append("forbidden audit log overwrite authority present")
    if (report.get("counts") or {}).get("blockers", 999) != 0:
        problems.append(f"execution receipt reports blockers: {(report.get('counts') or {}).get('blockers')}")
    for b in report.get("blockers") or []:
        problems.append(str(b))
    rows = report.get("restore_rows") or []
    if not rows:
        problems.append("execution receipt has no restore rows")
    for row in rows:
        action = row.get("restore_action")
        target = row.get("future_live_target_path")
        if row.get("protected_skip"):
            if action != "SKIPPED_PROTECTED_AUDIT_LOG_NOT_RESTORED":
                problems.append(f"{target}: protected skip row has unexpected action {action}")
            continue
        if report.get("actual_restore_performed"):
            if action != "LIVE_FILE_RESTORED_FROM_SNAPSHOT":
                problems.append(f"{target}: row was not restored successfully ({action})")
            if row.get("live_sha256_after_restore") != row.get("expected_snapshot_sha256"):
                problems.append(f"{target}: after-restore SHA does not match expected snapshot SHA")
    for w in report.get("warnings") or []:
        warnings.append(str(w))
    return (len(problems) == 0), problems, warnings


def _snapshot_live_execute_print(report: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    c = report.get("counts") or {}
    print()
    print("── Live Restore Execute Report ─────────────────────")
    print(f"  Status    : {report.get('status')}")
    print(f"  ExecuteID : {report.get('execute_id')}")
    print(f"  Restored  : {c.get('files_restored')} files")
    print(f"  Skipped   : {c.get('protected_skips')} protected")
    print(f"  Blockers  : {c.get('blockers')}")
    print(f"  Warnings  : {c.get('warnings')}")
    print(f"  Receipt   : {json_path if json_path else '-'}")
    print("  Authority : STRICTLY BOUND live restore; NO shell, NO delete, NO quarantine")
    print("  Audit log : PROTECTED — not overwritten")
    if report.get("blockers"):
        print("  Blockers:")
        for item in (report.get("blockers") or [])[:30]:
            print(f"    - {item}")
    if report.get("warnings"):
        print("  Warnings:")
        for item in (report.get("warnings") or [])[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()


