def cmd_snapshot_live_execute_export(session_id: str) -> None:
    """Export Patch 94 live restore execution receipts. Usage: snapshot-live-execute-export"""
    from agents.forge.memory import write_audit_entry
    SNAPSHOT_LIVE_EXECUTE_DIR.mkdir(parents=True, exist_ok=True)
    reports = []
    for path in _snapshot_live_execute_paths():
        data = _snapshot_live_execute_load(path)
        if data:
            reports.append({
                "path": str(path),
                "created_at": data.get("created_at"),
                "status": data.get("status"),
                "execute_id": data.get("execute_id"),
                "actual_restore_performed": data.get("actual_restore_performed"),
                "source_backup_copy_id": data.get("source_backup_copy_id"),
                "counts": data.get("counts"),
                "authority": data.get("authority"),
            })
    ts = _patch60_timestamp()
    export = {
        "schema_version": SNAPSHOT_LIVE_EXECUTE_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_LIVE_RESTORE_EXECUTE_EXPORT_V1_PATCH94",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "EXPORT_ONLY_NO_ADDITIONAL_RESTORE",
        "authority": _snapshot_live_execute_authority(),
        "count": len(reports),
        "reports": reports,
    }
    json_path = SNAPSHOT_LIVE_EXECUTE_DIR / f"{ts}_{SNAPSHOT_LIVE_EXECUTE_EXPORT_PREFIX}.json"
    md_path = SNAPSHOT_LIVE_EXECUTE_DIR / f"{ts}_{SNAPSHOT_LIVE_EXECUTE_EXPORT_PREFIX}.md"
    json_path.write_text(json.dumps(export, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = ["# Patch 94 Live Restore Execute Export", "", f"Reports: `{len(reports)}`", ""]
    for row in reports:
        lines.append(f"- `{row.get('created_at')}` `{row.get('status')}` restored=`{(row.get('counts') or {}).get('files_restored')}` `{row.get('path')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    print()
    print("── Live Restore Execute Export ─────────────────────")
    print(f"  JSON      : {json_path}")
    print(f"  Markdown  : {md_path}")
    print(f"  Reports   : {len(reports)}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_LIVE_EXECUTE_EXPORT_WRITTEN", str(json_path), str(md_path), f"reports={len(reports)}")


# ─── PATCH 95: ENGINE REVIEW SOURCE READINESS AUDIT ─────────────────────────

def _patch95_now() -> str:
    import datetime as _dt
    return _dt.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch95_root():
    from pathlib import Path as _Path
    root = _Path.home() / "forge" / "memory" / "engine_review_source_readiness_v1"
    root.mkdir(parents=True, exist_ok=True)
    return root


def _patch95_manifest_root():
    from pathlib import Path as _Path
    return _Path.home() / "forge" / "memory" / "code_library_v1" / "manifests"


def _patch95_safe_json_load(path):
    import json as _json
    try:
        with open(path, "r", encoding="utf-8") as f:
            return _json.load(f)
    except Exception:
        return None


def _patch95_json_files(root):
    from pathlib import Path as _Path
    try:
        return sorted(_Path(root).glob("*.json"))
    except Exception:
        return []


def _patch95_latest(pattern: str):
    files = _patch95_json_files(_patch95_manifest_root())
    matches = [p for p in files if pattern.lower() in p.name.lower()]
    return sorted(matches)[-1] if matches else None


def _patch95_find_engine_ledger():
    root = _patch95_manifest_root()
    direct = root / "engine_review_ledger_v1.json"
    if direct.exists():
        return direct
    matches = [p for p in _patch95_json_files(root) if "engine_review_ledger" in p.name.lower()]
    return sorted(matches)[-1] if matches else None


def _patch95_digest_file(path):
    import hashlib as _hashlib
    try:
        h = _hashlib.sha256()
        with open(path, "rb") as f:
            for chunk in iter(lambda: f.read(1024 * 1024), b""):
                h.update(chunk)
        return h.hexdigest()
    except Exception:
        return None


def _patch95_is_under(path, root) -> bool:
    try:
        path.resolve().relative_to(root.resolve())
        return True
    except Exception:
        return False


def _patch95_resolve_candidate_path(path_text: str):
    from pathlib import Path as _Path
    import os as _os
    home = _Path.home()
    approved_roots = [home / "aiweb", home / "forge"]
    raw = (path_text or "").strip()
    if not raw:
        return None, [], "no candidate path recorded"
    candidates = []
    p = _Path(_os.path.expanduser(raw))
    if p.is_absolute():
        candidates.append(p)
    else:
        candidates.append(home / raw)
        candidates.append(home / "aiweb" / raw)
        if raw.startswith("aiweb/"):
            candidates.append(home / raw)
        if raw.startswith("projects/"):
            candidates.append(home / "aiweb" / raw)
    seen = []
    for c in candidates:
        if c not in seen:
            seen.append(c)
    existing = [c for c in seen if c.exists()]
    chosen = existing[0] if existing else seen[0]
    if not any(_patch95_is_under(chosen, r) for r in approved_roots):
        return chosen, seen, "candidate path is outside approved Forge/AI.Web roots"
    return chosen, seen, ""


def _patch95_readable_files(path, limit=500):
    from pathlib import Path as _Path
    allowed_suffixes = {".py", ".json", ".md", ".txt", ".yaml", ".yml", ".js", ".jsx", ".ts", ".tsx", ".toml", ".ini"}
    skip_dirs = {".venv", "node_modules", "__pycache__", ".git", "chroma_db", ".mypy_cache", ".pytest_cache"}
    files = []
    if not path or not path.exists():
        return files
    try:
        if path.is_file():
            if path.suffix.lower() in allowed_suffixes:
                files.append(path)
            return files
        for root, dirs, names in __import__("os").walk(path):
            dirs[:] = [d for d in dirs if d not in skip_dirs]
            for name in names:
                p = _Path(root) / name
                if p.suffix.lower() in allowed_suffixes:
                    files.append(p)
                    if len(files) >= limit:
                        return files
    except Exception:
        return files
    return files


def _patch95_load_relationship_reports():
    reports = {}
    root = _patch95_manifest_root()
    for p in _patch95_json_files(root):
        if "code_relationship_intelligence_report" not in p.name.lower():
            continue
        data = _patch95_safe_json_load(p)
        if not isinstance(data, dict):
            continue
        for row in data.get("reports", []) or []:
            if isinstance(row, dict) and row.get("engine_base"):
                reports[row.get("engine_base")] = {"path": str(p), "row": row}
    return reports


def _patch95_manifest_text_index(max_bytes_per_file=400000):
    """Build a lightweight text index from manifest JSON files. This is read-only and deterministic."""
    root = _patch95_manifest_root()
    index = []
    for p in _patch95_json_files(root):
        lname = p.name.lower()
        if not any(term in lname for term in ["code", "engine", "symbolic", "relationship", "index", "inventory"]):
            continue
        try:
            txt = p.read_text(encoding="utf-8", errors="ignore")[:max_bytes_per_file]
            index.append({"path": str(p), "name": p.name, "text_lower": txt.lower()})
        except Exception:
            pass
    return index


def _patch95_assess_engine(entry, rel_reports, manifest_index):
    from pathlib import Path as _Path
    engine = entry.get("engine_base") or entry.get("engine_family") or entry.get("name") or "UNKNOWN"
    candidate_text = entry.get("recommended_keep_path") or entry.get("patch68_keep_candidate") or entry.get("candidate_path") or ""
    candidate_path, attempted, path_warning = _patch95_resolve_candidate_path(candidate_text)
    exists = bool(candidate_path and candidate_path.exists())
    inside_scope = bool(candidate_path and any(_patch95_is_under(candidate_path, r) for r in [_Path.home()/"aiweb", _Path.home()/"forge"]))
    readable = _patch95_readable_files(candidate_path) if exists and inside_scope else []
    sample = []
    symbols = []
    file_hashes = []
    for f in readable[:12]:
        sample.append(str(f))
        h = _patch95_digest_file(f)
        if h:
            file_hashes.append({"path": str(f), "sha256": h})
        if f.suffix.lower() == ".py":
            try:
                txt = f.read_text(encoding="utf-8", errors="ignore")[:20000]
                for m in __import__("re").finditer(r"^\s*(?:def|class)\s+([A-Za-z_][A-Za-z0-9_]*)", txt, __import__("re").M):
                    symbols.append(m.group(1))
                    if len(symbols) >= 20:
                        break
            except Exception:
                pass
    rel = rel_reports.get(engine)
    rel_counts = (rel or {}).get("row", {}).get("counts", {}) if rel else {}
    rel_category_counts = (rel or {}).get("row", {}).get("category_counts", {}) if rel else {}
    engine_l = engine.lower()
    cand_l = (candidate_text or "").lower()
    manifest_hits = []
    indexed_strong = False
    symbol_signal = False
    for item in manifest_index:
        txt = item["text_lower"]
        if engine_l and engine_l in txt:
            manifest_hits.append(item["path"])
            if any(term in item["name"].lower() for term in ["code_index", "code_engine", "symbol", "relationship", "inventory"]):
                indexed_strong = True
            if "def " in txt or "class " in txt or "symbol" in txt:
                symbol_signal = True
        elif cand_l and cand_l in txt:
            manifest_hits.append(item["path"])
            indexed_strong = True
        if len(manifest_hits) >= 8:
            break
    if rel:
        indexed_strong = True
        if (rel_counts.get("symbols") or 0) > 0:
            symbol_signal = True
    blockers = []
    warnings = []
    states = []
    if not candidate_text:
        blockers.append("no candidate path recorded in review ledger")
        states.append("NOT_READY_NO_CANDIDATE_PATH")
    if path_warning:
        warnings.append(path_warning)
    if not exists:
        blockers.append("candidate path does not currently exist on disk")
        states.append("NOT_READY_CANDIDATE_PATH_MISSING")
    if exists and not inside_scope:
        blockers.append("candidate path exists but is outside approved Forge/AI.Web roots")
        states.append("NOT_READY_UNSCOPED_PATH")
    if exists and inside_scope and not readable:
        blockers.append("candidate path has no readable source/config/doc files in allowed suffix set")
        states.append("NOT_READY_NO_READABLE_SOURCE")
    if not indexed_strong:
        blockers.append("no strong code index / relationship / inventory evidence found for this engine")
        states.append("NOT_READY_ENGINE_CODE_NOT_INDEXED")
    if not symbol_signal:
        warnings.append("no symbol/function/class evidence found in current manifests")
        states.append("NOT_READY_NO_SYMBOLS")
    source_ready = exists and inside_scope and bool(readable) and indexed_strong
    ready_for_llm = source_ready and not blockers
    if ready_for_llm:
        state = "READY_FOR_LLM_REVIEW"
    else:
        state = states[0] if states else "NOT_READY_FOR_LLM_REVIEW"
    return {
        "engine_family": engine,
        "review_status": entry.get("review_status"),
        "candidate_path_recorded": candidate_text,
        "candidate_path_resolved": str(candidate_path) if candidate_path else "",
        "candidate_path_attempts": [str(p) for p in attempted],
        "candidate_path_exists": exists,
        "inside_approved_scope": inside_scope,
        "readable_file_count": len(readable),
        "readable_file_samples": sample,
        "sample_file_hashes": file_hashes,
        "symbols_sample": symbols[:20],
        "indexed_in_code_library_or_relationship_report": bool(indexed_strong),
        "relationship_report_found": bool(rel),
        "relationship_report_path": (rel or {}).get("path", ""),
        "relationship_counts": rel_counts,
        "relationship_category_counts": rel_category_counts,
        "manifest_hits": list(dict.fromkeys(manifest_hits))[:8],
        "source_evidence_ready": bool(source_ready),
        "ready_for_llm_review": bool(ready_for_llm),
        "readiness_state": state,
        "blockers": blockers,
        "warnings": warnings,
        "no_engine_file_action": True,
        "no_canonical_authority": True,
        "no_ingestion_write": True,
    }


def _patch95_build_report():
    from pathlib import Path as _Path
    ledger_path = _patch95_find_engine_ledger()
    ledger = _patch95_safe_json_load(ledger_path) if ledger_path else None
    entries = []
    if isinstance(ledger, dict):
        entries = ledger.get("entries", []) or []
    rel_reports = _patch95_load_relationship_reports()
    manifest_index = _patch95_manifest_text_index()
    rows = []
    for entry in entries:
        if isinstance(entry, dict):
            rows.append(_patch95_assess_engine(entry, rel_reports, manifest_index))
    pending = [r for r in rows if (r.get("review_status") or "").upper() == "PENDING_REVIEW"]
    ready = [r for r in rows if r.get("ready_for_llm_review")]
    not_ready = [r for r in rows if not r.get("ready_for_llm_review")]
    approved = [r for r in rows if (r.get("review_status") or "").upper() == "APPROVED"]
    deferred = [r for r in rows if (r.get("review_status") or "").upper() == "DEFERRED"]
    state_counts = {}
    for r in rows:
        state_counts[r.get("readiness_state") or "UNKNOWN"] = state_counts.get(r.get("readiness_state") or "UNKNOWN", 0) + 1
    route = "PROCEED_TO_PATCH96_EVIDENCE_BINDER" if pending and len([r for r in pending if r.get("ready_for_llm_review")]) == len(pending) else "ROUTE_TO_98A_98D_OR_97A_97D_BEFORE_LLM_REVIEW"
    return {
        "schema_version": "patch95_engine_review_source_readiness_v1",
        "report_type": "ENGINE_REVIEW_SOURCE_READINESS_AUDIT_V1",
        "created_at": _patch95_now(),
        "mode": "READ_ONLY_SOURCE_EVIDENCE_AUDIT_NO_ENGINE_DECISIONS",
        "authority": {
            "canonical_decision_authority": False,
            "engine_file_write_authority": False,
            "ingestion_write_authority": False,
            "chroma_write_authority": False,
            "shell_execution_authority": False,
            "delete_authority": False,
            "quarantine_authority": False,
        },
        "source_files": {
            "engine_review_ledger": str(ledger_path) if ledger_path else "MISSING",
            "manifest_root": str(_patch95_manifest_root()),
            "relationship_reports_found": len(rel_reports),
            "manifest_index_files_scanned": len(manifest_index),
        },
        "counts": {
            "total_engine_families": len(rows),
            "pending_review": len(pending),
            "approved": len(approved),
            "deferred": len(deferred),
            "ready_for_llm_review": len(ready),
            "not_ready_for_llm_review": len(not_ready),
            "pending_ready_for_llm_review": len([r for r in pending if r.get("ready_for_llm_review")]),
            "pending_not_ready_for_llm_review": len([r for r in pending if not r.get("ready_for_llm_review")]),
        },
        "readiness_state_counts": state_counts,
        "expected_gap_result_is_ok": True,
        "recommended_route": route,
        "routing_note": "NOT_READY rows are a clean expected gate result. Do not start LLM review until code evidence and source-law context are proven.",
        "rows": rows,
    }


def _patch95_write_report(report):
    import json as _json
    root = _patch95_root()
    stamp = report.get("created_at") or _patch95_now()
    json_path = root / f"{stamp}_engine_review_source_readiness_v1.json"
    md_path = root / f"{stamp}_engine_review_source_readiness_v1.md"
    latest_path = root / "latest_engine_review_source_readiness.json"
    json_path.write_text(_json.dumps(report, indent=2, sort_keys=True), encoding="utf-8")
    latest_path.write_text(_json.dumps(report, indent=2, sort_keys=True), encoding="utf-8")
    md_lines = []
    c = report.get("counts", {})
    md_lines.append("# Patch 95 — Engine Review Source Readiness Audit")
    md_lines.append("")
    md_lines.append(f"Created: {report.get('created_at')}")
    md_lines.append(f"Mode: {report.get('mode')}")
    md_lines.append(f"Recommended route: {report.get('recommended_route')}")
    md_lines.append("")
    md_lines.append("## Counts")
    for k, v in c.items():
        md_lines.append(f"- {k}: {v}")
    md_lines.append("")
    md_lines.append("## Readiness States")
    for k, v in sorted((report.get("readiness_state_counts") or {}).items()):
        md_lines.append(f"- {k}: {v}")
    md_lines.append("")
    md_lines.append("## Not Ready Rows")
    for r in report.get("rows", []):
        if not r.get("ready_for_llm_review"):
            md_lines.append(f"- {r.get('engine_family')}: {r.get('readiness_state')} — blockers={len(r.get('blockers') or [])}")
    md_path.write_text("\n".join(md_lines) + "\n", encoding="utf-8")
    return json_path, md_path, latest_path


def _patch95_latest_report():
    root = _patch95_root()
    latest = root / "latest_engine_review_source_readiness.json"
    if latest.exists():
        data = _patch95_safe_json_load(latest)
        if isinstance(data, dict):
            return latest, data
    matches = sorted(root.glob("*_engine_review_source_readiness_v1.json"))
    if matches:
        data = _patch95_safe_json_load(matches[-1])
        if isinstance(data, dict):
            return matches[-1], data
    return None, None


