def _patch97_now() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch97_write_json(path: Path, data: dict) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(data, indent=2, sort_keys=True), encoding="utf-8")


def _patch97_read_json(path: Path):
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return None


def _patch97_hash_path(path: Path) -> str:
    import hashlib
    h = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def _patch97_safe_text(obj, limit: int = 250000) -> str:
    try:
        s = json.dumps(obj, sort_keys=True, ensure_ascii=False)
    except Exception:
        s = str(obj)
    return s[:limit].lower()


def _patch97_authority() -> dict:
    return {
        "patch": "97",
        "mode": "SOURCE_LAW_CONTEXT_READINESS_AUDIT_ONLY",
        "writes": "Forge-owned source_law_context_readiness_v1 reports only",
        "no_engine_review": True,
        "no_llm_drafting": True,
        "no_ingestion_writes": True,
        "no_chroma_writes": True,
        "no_pdf_ocr": True,
        "no_project_writes": True,
        "no_canonical_decisions": True,
        "rule": "PDF/DOCX source law cannot be trusted until extraction, chunking, ingestion, and retrieval evidence exists.",
    }


def _patch97_latest_report_path() -> Path | None:
    if not SOURCE_LAW_READINESS_DIR.exists():
        return None
    rows = sorted(SOURCE_LAW_READINESS_DIR.glob(f"*_{SOURCE_LAW_REVIEW_PREFIX}.json"), key=lambda p: p.stat().st_mtime, reverse=True)
    return rows[0] if rows else None


def _patch97_load_context_receipts() -> list[dict]:
    out = []
    for root in [CONTEXT_LIB_RECEIPTS, CONTEXT_LIB_MANIFESTS, CONTEXT_LIB_INDEXES, CONTEXT_LIB_SYMBOLIC]:
        if not root.exists():
            continue
        for path in sorted(root.glob("*.json")):
            data = _patch97_read_json(path)
            if data is None:
                continue
            out.append({"path": str(path), "data": data, "text": _patch97_safe_text(data)})
    return out


def _patch97_load_extraction_reports() -> list[dict]:
    out = []
    roots = [CORPUS_REPORTS_DIR, CORPUS_REGISTRATION_DIR, INGESTION_PLANS_DIR if 'INGESTION_PLANS_DIR' in globals() else FORGE_ROOT / 'ingestion_plans']
    for root in roots:
        if not root.exists():
            continue
        for path in sorted(root.glob("*.json")):
            data = _patch97_read_json(path)
            if data is None:
                continue
            out.append({"path": str(path), "data": data, "text": _patch97_safe_text(data)})
    return out


def _patch97_load_corpus_rows() -> list[dict]:
    rows = []
    try:
        rows.extend(_corpus_load_json())
    except Exception:
        pass
    try:
        rows.extend(_corpus_load_csv())
    except Exception:
        pass
    unique = []
    seen = set()
    for row in rows:
        key = (row.get("id") or row.get("corpus_id") or row.get("absolute_path") or row.get("filename") or json.dumps(row, sort_keys=True))
        if key in seen:
            continue
        seen.add(key)
        unique.append(row)
    return unique


def _patch97_row_text(row: dict) -> str:
    fields = [
        row.get("id", ""), row.get("corpus_id", ""), row.get("filename", ""), row.get("title", ""),
        row.get("absolute_path", ""), row.get("path", ""), row.get("folder", ""), row.get("category", ""),
        row.get("authority", ""), row.get("role", ""), row.get("notes", ""),
    ]
    return " ".join(str(x) for x in fields).lower()


def _patch97_terms_hit(text: str, terms: list[str]) -> list[str]:
    t = text.lower()
    return [term for term in terms if term.lower() in t]


def _patch97_match_score(text: str, spec: dict) -> tuple[int, list[str]]:
    hits = []
    hits.extend(_patch97_terms_hit(text, spec.get("filename_terms", [])))
    hits.extend(_patch97_terms_hit(text, spec.get("identity_terms", [])))
    return len(set(hits)), sorted(set(hits))


def _patch97_find_matching_corpus_rows(spec: dict, rows: list[dict]) -> list[dict]:
    matches = []
    for row in rows:
        text = _patch97_row_text(row)
        score, hits = _patch97_match_score(text, spec)
        if score > 0:
            path_s = row.get("absolute_path") or row.get("path") or ""
            exists = bool(path_s and Path(path_s).exists())
            suffix = Path(path_s).suffix.lower() if path_s else Path(str(row.get("filename", ""))).suffix.lower()
            matches.append({
                "corpus_id": row.get("id") or row.get("corpus_id") or "",
                "filename": row.get("filename") or Path(path_s).name if path_s else row.get("filename", ""),
                "absolute_path": path_s,
                "exists_on_disk": exists,
                "suffix": suffix,
                "match_score": score,
                "match_hits": hits,
                "index_eligible": row.get("index_eligible", ""),
            })
    return sorted(matches, key=lambda x: (x.get("exists_on_disk") is True, x.get("match_score", 0)), reverse=True)


def _patch97_find_report_matches(spec: dict, reports: list[dict]) -> list[dict]:
    matches = []
    for rpt in reports:
        score, hits = _patch97_match_score(rpt.get("text", ""), spec)
        if score > 0:
            matches.append({"path": rpt.get("path"), "match_score": score, "match_hits": hits})
    return sorted(matches, key=lambda x: x.get("match_score", 0), reverse=True)


def _patch97_context_matches(spec: dict, receipts: list[dict]) -> list[dict]:
    matches = []
    for rec in receipts:
        score, hits = _patch97_match_score(rec.get("text", ""), spec)
        if score <= 0:
            continue
        data = rec.get("data") or {}
        chunks = 0
        for key in ("chunks_written", "chunk_count", "chunks", "ids", "documents"):
            val = data.get(key) if isinstance(data, dict) else None
            if isinstance(val, int):
                chunks = max(chunks, val)
            elif isinstance(val, list):
                chunks = max(chunks, len(val))
        matches.append({
            "path": rec.get("path"),
            "match_score": score,
            "match_hits": hits,
            "chunk_evidence_count": chunks,
            "report_type": data.get("report_type", "") if isinstance(data, dict) else "",
            "collection": data.get("collection", "") if isinstance(data, dict) else "",
        })
    return sorted(matches, key=lambda x: (x.get("chunk_evidence_count", 0), x.get("match_score", 0)), reverse=True)


def _patch97_classify_target(spec: dict, corpus_rows: list[dict], extraction_reports: list[dict], context_receipts: list[dict]) -> dict:
    row_matches = _patch97_find_matching_corpus_rows(spec, corpus_rows)
    extraction_matches = _patch97_find_report_matches(spec, extraction_reports)
    context_matches = _patch97_context_matches(spec, context_receipts)
    suffixes = sorted(set((r.get("suffix") or "").lower() for r in row_matches if r.get("suffix")))
    has_pdf = ".pdf" in suffixes
    has_docx = ".docx" in suffixes
    has_existing_file = any(r.get("exists_on_disk") for r in row_matches)
    has_context = bool(context_matches)
    has_chunk_evidence = any(int(m.get("chunk_evidence_count") or 0) > 0 for m in context_matches)
    has_extraction = bool(extraction_matches)

    warnings = []
    blockers = []
    status = "SOURCE_LAW_MISSING"
    recommended_route = "REGISTER_SOURCE_LAW_DOCUMENT"

    if has_context and has_chunk_evidence:
        status = "RETRIEVABLE_WITH_CITABLE_CHUNKS"
        recommended_route = "READY_FOR_LLM_REVIEW_SOURCE_LAW_USE"
    elif has_context:
        status = "INGESTED_NOT_RETRIEVABLE"
        warnings.append("Context receipt/manifests mention this source, but chunk evidence count was not proven.")
        recommended_route = "VERIFY_CONTEXT_SEARCH_AND_CHUNK_RECEIPTS"
    elif has_extraction and has_existing_file:
        status = "EXTRACTED_NOT_INGESTED"
        recommended_route = "SOURCE_LAW_INGESTION_APPLY_AFTER_DRY_RUN"
    elif has_existing_file:
        if has_pdf:
            status = "PDF_EXTRACTION_PATCH_REQUIRED"
            recommended_route = "PATCH97A_PDF_EXTRACTION_ADAPTER_TEST"
            warnings.append("PDF source-law document exists but no extraction/chunk/ingestion proof was found.")
        elif has_docx:
            status = "DOCX_EXTRACTION_PATCH_REQUIRED"
            recommended_route = "PATCH97A_DOCX_EXTRACTION_ADAPTER_TEST"
            warnings.append("DOCX source-law document exists but no extraction/chunk/ingestion proof was found.")
        else:
            status = "EXTRACTABLE_NOT_EXTRACTED"
            recommended_route = "SOURCE_LAW_EXTRACTION_DRY_RUN"
            warnings.append("Source-law document appears present but extraction proof was not found.")
    elif row_matches:
        status = "REGISTERED_ONLY"
        blockers.append("Source-law row matched metadata, but the referenced source file was not found on disk.")
        recommended_route = "REPAIR_SOURCE_LAW_REGISTRATION_OR_PATH"
    else:
        status = "SOURCE_LAW_MISSING"
        blockers.append("No matching corpus registration, extraction receipt, or context receipt was found.")
        recommended_route = "REGISTER_SOURCE_LAW_DOCUMENT"

    source_law_ready = status == "RETRIEVABLE_WITH_CITABLE_CHUNKS"
    return {
        "source_key": spec.get("source_key"),
        "display_name": spec.get("display_name"),
        "authority_class": spec.get("authority_class"),
        "source_role": spec.get("source_role"),
        "status": status,
        "source_law_ready": source_law_ready,
        "recommended_route": recommended_route,
        "corpus_matches": row_matches[:8],
        "extraction_matches": extraction_matches[:8],
        "context_matches": context_matches[:8],
        "has_pdf_candidate": has_pdf,
        "has_docx_candidate": has_docx,
        "has_existing_source_file": has_existing_file,
        "has_extraction_evidence": has_extraction,
        "has_context_evidence": has_context,
        "has_chunk_evidence": has_chunk_evidence,
        "warnings": warnings,
        "blockers": blockers,
    }


def _patch97_run_audit() -> dict:
    corpus_rows = _patch97_load_corpus_rows()
    extraction_reports = _patch97_load_extraction_reports()
    context_receipts = _patch97_load_context_receipts()
    rows = [_patch97_classify_target(spec, corpus_rows, extraction_reports, context_receipts) for spec in SOURCE_LAW_TARGETS]
    ready = [r for r in rows if r.get("source_law_ready")]
    missing = [r for r in rows if r.get("status") == "SOURCE_LAW_MISSING"]
    pdf_needs = [r for r in rows if r.get("status") == "PDF_EXTRACTION_PATCH_REQUIRED"]
    docx_needs = [r for r in rows if r.get("status") == "DOCX_EXTRACTION_PATCH_REQUIRED"]
    partial = [r for r in rows if not r.get("source_law_ready") and r.get("status") not in ("SOURCE_LAW_MISSING",)]

    if len(ready) == len(rows):
        overall = "SOURCE_LAW_READY"
        next_route = "PROCEED_TO_PATCH98_LLM_ENGINE_REVIEW_GATEWAY_AND_DRAFTS"
    elif ready:
        overall = "SOURCE_LAW_PARTIAL"
        next_route = "PATCH97A_D_EXTRACTION_OR_INGESTION_BRANCH_BEFORE_LLM_REVIEW"
    else:
        overall = "SOURCE_LAW_MISSING_OR_UNPROVEN"
        next_route = "PATCH97A_D_REQUIRED_BEFORE_LLM_REVIEW"

    return {
        "schema_version": SOURCE_LAW_REVIEW_SCHEMA_VERSION,
        "report_type": "SOURCE_LAW_CONTEXT_READINESS_AUDIT_V1_PATCH97",
        "created_at": _patch97_now(),
        "authority": _patch97_authority(),
        "overall_status": overall,
        "recommended_next_route": next_route,
        "counts": {
            "targets": len(rows),
            "ready_retrievable_with_chunks": len(ready),
            "partial_or_registered": len(partial),
            "missing": len(missing),
            "pdf_extraction_patch_required": len(pdf_needs),
            "docx_extraction_patch_required": len(docx_needs),
            "corpus_rows_seen": len(corpus_rows),
            "extraction_reports_seen": len(extraction_reports),
            "context_receipts_manifests_seen": len(context_receipts),
        },
        "rows": rows,
    }


def _patch97_write_report(report: dict) -> tuple[Path, Path]:
    SOURCE_LAW_READINESS_DIR.mkdir(parents=True, exist_ok=True)
    now = report.get("created_at") or _patch97_now()
    json_path = SOURCE_LAW_READINESS_DIR / f"{now}_{SOURCE_LAW_REVIEW_PREFIX}.json"
    md_path = SOURCE_LAW_READINESS_DIR / f"{now}_{SOURCE_LAW_REVIEW_PREFIX}.md"
    _patch97_write_json(json_path, report)
    latest = SOURCE_LAW_READINESS_DIR / "latest_source_law_context_readiness.json"
    _patch97_write_json(latest, report)
    lines = [
        "# Patch 97 Source-Law Context Readiness Audit",
        "",
        f"Overall status: `{report.get('overall_status')}`",
        f"Recommended route: `{report.get('recommended_next_route')}`",
        "",
        "## Counts",
    ]
    for k, v in (report.get("counts") or {}).items():
        lines.append(f"- `{k}`: `{v}`")
    lines.extend(["", "## Source-law targets"])
    for row in report.get("rows", []):
        lines.append(f"- `{row.get('source_key')}` — `{row.get('status')}` — route `{row.get('recommended_route')}`")
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    latest_md = SOURCE_LAW_READINESS_DIR / "latest_source_law_context_readiness.md"
    latest_md.write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")
    return json_path, md_path


def _patch97_print_summary(report: dict) -> None:
    print()
    print("── Source-Law Context Readiness ──────────────────────")
    print(f"  Status     : {report.get('overall_status')}")
    print(f"  Route      : {report.get('recommended_next_route')}")
    c = report.get("counts") or {}
    print(f"  Targets    : {c.get('targets', 0)}")
    print(f"  Ready      : {c.get('ready_retrievable_with_chunks', 0)}")
    print(f"  Partial    : {c.get('partial_or_registered', 0)}")
    print(f"  Missing    : {c.get('missing', 0)}")
    print(f"  PDF proof needed : {c.get('pdf_extraction_patch_required', 0)}")
    print(f"  DOCX proof needed: {c.get('docx_extraction_patch_required', 0)}")
    print("  Authority  : audit only; NO ingestion, NO OCR, NO LLM review")
    print("──────────────────────────────────────────────────────")
    print()


