def _patch98_print_full_draft_to_terminal(draft: dict, path: object = None) -> None:
    """Print a human-readable Patch 98 draft in full enough form for Nic to review in Forge."""
    brief = draft.get("plain_english_brief") or {}
    source_law = brief.get("source_law_basis") or {}

    def _print_list(title: str, values, limit: int = 12) -> None:
        print(f"  {title}:")
        if not values:
            print("   - none recorded")
            return
        for item in list(values)[:limit]:
            print("   -", item)
        if len(values) > limit:
            print(f"   ... {len(values) - limit} more not shown")

    print()
    print("── LLM Engine Review Draft — Human Readable ──────────")
    if path:
        print("  Receipt :", path)
    print("  Engine  :", draft.get("engine_family"))
    print("  Status  :", draft.get("status"))
    print("  Draft ID:", draft.get("draft_id"))
    print("  Evidence:", draft.get("evidence_id"))
    print("  Candidate path:", draft.get("candidate_path_resolved"))
    llm_info = draft.get("llm_invocation") or {}
    if llm_info:
        print("  LLM call:", "YES" if llm_info.get("called") else "NO")
        print("  LLM model:", llm_info.get("model"))
        print("  LLM status:", llm_info.get("status"))
        print("  LLM elapsed:", llm_info.get("elapsed_seconds"))
        print("  Hidden reasoning stored:", llm_info.get("hidden_reasoning_stored"))
    print()
    if draft.get("blockers"):
        print("  BLOCKED:")
        for b in draft.get("blockers", [])[:20]:
            print("   -", b)
        print("──────────────────────────────────────────────────────")
        print()
        return

    visible_review = draft.get("llm_visible_review_text") or ""
    if visible_review:
        print("  Local LLM Visible Review:")
        for line in visible_review.splitlines()[:80]:
            print("   " + line)
        if len(visible_review.splitlines()) > 80:
            print("   ... visible review truncated in terminal; full text is in the Markdown receipt")
        print()

    print("  Deterministic Evidence Summary:")
    print("  Plain-English Purpose:")
    print("   ", brief.get("plain_english_purpose") or "No purpose text recorded.")
    print()
    print("  Likely System Role:")
    print("   ", brief.get("likely_system_role") or "UNKNOWN")
    print("   ", brief.get("role_reason") or "No role reason recorded.")
    print()
    print("  Draft Recommendation:")
    print("   ", brief.get("recommendation") or "NO_RECOMMENDATION_RECORDED")
    print("  Confidence:", brief.get("confidence") or "UNKNOWN")
    print()
    print("  Source-Law Basis:")
    print("   Status:", source_law.get("status"))
    print("   Ready targets:", source_law.get("ready_targets"), "/", source_law.get("total_targets"))
    print("   Report SHA:", source_law.get("report_sha256"))
    print()
    _print_list("Source Excerpt Samples", brief.get("source_excerpt_samples") or [], limit=8)
    print()
    _print_list("Import Samples", brief.get("imports_sample") or [], limit=10)
    print()
    _print_list("Function Samples", brief.get("functions_sample") or [], limit=20)
    print()
    _print_list("Class Samples", brief.get("classes_sample") or [], limit=12)
    print()
    _print_list("Risk Notes", brief.get("risk_notes") or [], limit=12)
    print()
    print("  Suggested Nic Action:")
    print("   ", brief.get("suggested_nic_action") or "No suggested action recorded.")
    print()
    print("  Authority:")
    print("   Draft only. No canonical approval. No ledger mutation. Nic approves later through Patch 99/100 gates.")
    print("──────────────────────────────────────────────────────")
    print()



