def cmd_llm_engine_review_model_test(session_id: str) -> None:
    """Smoke-test local Ollama model availability. Usage: llm-engine-review-model-test"""
    from agents.forge.memory import write_audit_entry
    import subprocess, time
    prompt = (
        "You are Forge's local model availability test. "
        "Reply with exactly: FORGE_LLM_REVIEW_MODEL_OK"
    )
    started = time.time()
    status = "UNKNOWN"
    visible = ""
    err = ""
    try:
        print()
        print("── LLM Engine Review Model Test ─────────────────────")
        print("  Provider : ollama")
        print("  Model    :", LLM_ENGINE_REVIEW_MODEL_NAME)
        print("  Status   : calling local model now...")
        completed = subprocess.run(
            ["ollama", "run", LLM_ENGINE_REVIEW_MODEL_NAME, prompt],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            timeout=60,
        )
        visible, had_think = _patch98_strip_model_thinking(completed.stdout)
        if completed.returncode == 0 and visible:
            status = "PASS_MODEL_RESPONDED"
        else:
            status = "FAIL_MODEL_ERROR"
            err = (completed.stderr or completed.stdout or "").strip()[:1000]
        print("  Result   :", status)
        print("  Elapsed  :", round(time.time() - started, 3), "seconds")
        print("  Visible response:", visible[:500] if visible else "(none)")
        if err:
            print("  Error    :", err)
        print("  Hidden reasoning stored: False")
        print("──────────────────────────────────────────────────────")
        print()
    except Exception as exc:
        status = "FAIL_EXCEPTION"
        err = repr(exc)[:1000]
        print()
        print("── LLM Engine Review Model Test ─────────────────────")
        print("  Result:", status)
        print("  Error :", err)
        print("──────────────────────────────────────────────────────")
        print()
    write_audit_entry(session_id, "LLM_ENGINE_REVIEW_MODEL_TEST", str(LLM_ENGINE_REVIEW_DIR), status, LLM_ENGINE_REVIEW_MODEL_NAME)


