def cmd_llm_engine_review_batch_plan(session_id: str) -> None:
    """Write Patch 98 LLM engine review batch plan. Usage: llm-engine-review-batch-plan"""
    from agents.forge.memory import write_audit_entry
    gateway_ok, gateway_msg = _patch98_gateway_ready()
    source_ok, source_report, source_blockers = _patch98_source_law_ready()
    binders = _patch98_all_latest_evidence_binders()
    ready = []
    blocked = []
    for b in binders:
        fam = b.get("engine_family")
        reasons = []
        if not gateway_ok: reasons.append(gateway_msg)
        if not source_ok: reasons.extend(source_blockers)
        if not b.get("ready_for_llm_brief"): reasons.append("evidence binder not ready_for_llm_brief")
        item = {"engine_family": fam, "evidence_id": b.get("evidence_id"), "review_status": b.get("review_status"), "candidate_path_resolved": b.get("candidate_path_resolved"), "blockers": reasons}
        (ready if not reasons else blocked).append(item)
    now = _patch98_now()
    plan = {
        "schema_version": LLM_ENGINE_REVIEW_SCHEMA_VERSION,
        "report_type": "LLM_ENGINE_REVIEW_BATCH_PLAN_V1_PATCH98",
        "created_at": now,
        "gateway_ready": gateway_ok,
        "gateway_message": gateway_msg,
        "source_law_ready": source_ok,
        "source_law_status": source_report.get("overall_status"),
        "counts": {"total_binders": len(binders), "ready_for_draft": len(ready), "blocked": len(blocked)},
        "ready": ready,
        "blocked": blocked,
        "authority": _patch98_authority(),
        "next_step": "Run llm-engine-review-batch-next or llm-engine-review-draft <engine_family>. Drafts are not canonical approvals.",
    }
    LLM_ENGINE_REVIEW_DIR.mkdir(parents=True, exist_ok=True)
    json_path = LLM_ENGINE_REVIEW_DIR / f"{now}_{LLM_ENGINE_REVIEW_BATCH_PLAN_PREFIX}.json"
    md_path = LLM_ENGINE_REVIEW_DIR / f"{now}_{LLM_ENGINE_REVIEW_BATCH_PLAN_PREFIX}.md"
    _patch98_write_json(json_path, plan)
    lines = ["# Patch 98 LLM Engine Review Batch Plan", "", f"Ready: `{len(ready)}`", f"Blocked: `{len(blocked)}`", f"Gateway ready: `{gateway_ok}`", f"Source-law ready: `{source_ok}`", "", "## Ready Engines"]
    for r in ready[:120]: lines.append(f"- `{r.get('engine_family')}` — `{r.get('review_status')}` — `{r.get('evidence_id')}`")
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    print()
    print("── LLM Engine Review Batch Plan ──────────────────────")
    print("  JSON    :", json_path)
    print("  Ready   :", len(ready))
    print("  Blocked :", len(blocked))
    print("  Gateway :", "PASS" if gateway_ok else "NOT_READY")
    print("  Source  :", "PASS" if source_ok else "NOT_READY")
    print("  Authority: NO canonical decision")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "LLM_ENGINE_REVIEW_BATCH_PLAN_WRITTEN", str(json_path), f"ready={len(ready)}", f"blocked={len(blocked)}")


def cmd_llm_engine_review_batch_next(session_id: str) -> None:
    """Draft the next ready engine lacking a Patch 98 draft. Usage: llm-engine-review-batch-next"""
    from agents.forge.memory import write_audit_entry
    for binder in _patch98_all_latest_evidence_binders():
        fam = binder.get("engine_family")
        if not fam:
            continue
        if _patch98_latest_draft_path(fam):
            continue
        cmd_llm_engine_review_draft(fam, session_id)
        write_audit_entry(session_id, "LLM_ENGINE_REVIEW_BATCH_NEXT_DONE", fam, binder.get("evidence_id", "?"), "one_draft")
        return
    print()
    print("── LLM Engine Review Batch Next ──────────────────────")
    print("  Status: NO_UNDRAFTED_READY_ENGINE_FOUND")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "LLM_ENGINE_REVIEW_BATCH_NEXT_EMPTY", "-", "no_undrafted_ready_engine", "patch98")


def cmd_llm_engine_review_export(session_id: str) -> None:
    """Export Patch 98 LLM engine review draft summary. Usage: llm-engine-review-export"""
    from agents.forge.memory import write_audit_entry
    LLM_ENGINE_REVIEW_DIR.mkdir(parents=True, exist_ok=True)
    drafts = []
    seen = set()
    for path in sorted(LLM_ENGINE_REVIEW_DIR.glob(f"*_{LLM_ENGINE_REVIEW_DRAFT_PREFIX}.json")):
        if path.name.startswith("latest_"):
            continue
        try:
            d = _patch98_read_json(path)
            key = d.get("draft_id") or str(path)
            if key in seen: continue
            seen.add(key)
            drafts.append({"engine_family": d.get("engine_family"), "draft_id": d.get("draft_id"), "status": d.get("status"), "evidence_id": d.get("evidence_id"), "recommendation": (d.get("plain_english_brief") or {}).get("recommendation"), "path": str(path), "sha256": _patch98_sha256(path)})
        except Exception:
            continue
    now = _patch98_now()
    export = {
        "schema_version": LLM_ENGINE_REVIEW_SCHEMA_VERSION,
        "report_type": "LLM_ENGINE_REVIEW_EXPORT_V1_PATCH98",
        "created_at": now,
        "counts": {"drafts": len(drafts)},
        "drafts": drafts,
        "authority": _patch98_authority(),
        "next_step": "Patch 99 human review queue. Patch 100 commits only after human approval and SHA re-verification.",
    }
    json_path = LLM_ENGINE_REVIEW_DIR / f"{now}_{LLM_ENGINE_REVIEW_EXPORT_PREFIX}.json"
    md_path = LLM_ENGINE_REVIEW_DIR / f"{now}_{LLM_ENGINE_REVIEW_EXPORT_PREFIX}.md"
    _patch98_write_json(json_path, export)
    lines = ["# Patch 98 LLM Engine Review Export", "", f"Drafts: `{len(drafts)}`", "", "## Drafts"]
    for d in drafts[:200]: lines.append(f"- `{d.get('engine_family')}` — `{d.get('status')}` — `{d.get('recommendation')}` — `{d.get('evidence_id')}`")
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    print()
    print("── LLM Engine Review Export ──────────────────────────")
    print("  JSON    :", json_path)
    print("  Markdown:", md_path)
    print("  Drafts  :", len(drafts))
    print("  Authority: NO canonical decision")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "LLM_ENGINE_REVIEW_EXPORT_WRITTEN", str(json_path), f"drafts={len(drafts)}", "no_canonical_authority")


# ─── PATCH 99 — HUMAN REVIEW QUEUE (NO CANONICAL AUTHORITY) ──────────────────

ENGINE_REVIEW_QUEUE_DIR = MEMORY_DIR / "engine_review_queue_v1"
ENGINE_REVIEW_QUEUE_SCHEMA_VERSION = "engine_review_queue_v1_patch99"
ENGINE_REVIEW_QUEUE_PREFIX = "engine_review_queue_v1"
ENGINE_REVIEW_QUEUE_DECISION_PREFIX = "engine_review_queue_decision_v1"
ENGINE_REVIEW_QUEUE_EXPORT_PREFIX = "engine_review_queue_export_v1"

def _patch99_now() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")

def _patch99_slug(value: str) -> str:
    return re.sub(r"[^a-zA-Z0-9_.-]+", "_", (value or "").strip()).strip("_") or "unknown"

def _patch99_read_json(path: Path) -> dict:
    return json.loads(path.read_text(encoding="utf-8"))

def _patch99_write_json(path: Path, data: dict) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(data, indent=2, sort_keys=True) + "\n", encoding="utf-8")

def _patch99_sha256(path: Path) -> str:
    h = __import__("hashlib").sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()

def _patch99_authority() -> dict:
    return {
        "patch": "99",
        "mode": "HUMAN_REVIEW_QUEUE_ONLY_NO_LEDGER_MUTATION",
        "writes": str(ENGINE_REVIEW_QUEUE_DIR),
        "canonical_decision_authority": False,
        "human_review_ledger_write_authority": False,
        "engine_file_write_authority": False,
        "project_write_authority": False,
        "chroma_write_authority": False,
        "shell_execution_authority": False,
        "llm_autonomous_decision_authority": False,
        "rule": "Patch 99 queues LLM draft reviews for Nic. It records approve/defer/reject intent only. Patch 100 is required to commit ledger changes after SHA re-verification.",
    }

def _patch99_latest_draft_path(engine_family: str) -> Path | None:
    fam = _patch99_slug(engine_family)
    path = LLM_ENGINE_REVIEW_DIR / f"latest_{fam}_{LLM_ENGINE_REVIEW_DRAFT_PREFIX}.json"
    if path.exists():
        return path
    matches = sorted(LLM_ENGINE_REVIEW_DIR.glob(f"*_{fam}_{LLM_ENGINE_REVIEW_DRAFT_PREFIX}.json"))
    return matches[-1] if matches else None

def _patch99_load_latest_draft(engine_family: str) -> tuple[dict | None, Path | None, str | None]:
    path = _patch99_latest_draft_path(engine_family)
    if not path:
        return None, None, f"No LLM review draft found for engine family: {engine_family}"
    try:
        return _patch99_read_json(path), path, None
    except Exception as e:
        return None, path, f"LLM review draft is unreadable: {e}"

def _patch99_list_latest_drafts() -> list[dict]:
    """
    Return latest LLM review drafts for queue building.

    Patch 101.1 visibility fix:
    Patch 98 writes compatibility aliases like:
      latest_activity_log_llm_engine_review_draft.json
    while earlier queue code only looked for:
      latest_activity_log_llm_engine_review_draft_v1.json

    That caused engine-review-queue-build to report zero items even though
    real LLM draft receipts existed. This loader accepts both filename shapes
    and falls back to timestamped draft receipts if needed.
    """
    drafts = []
    seen = set()
    if not LLM_ENGINE_REVIEW_DIR.exists():
        return []

    candidate_paths = []
    candidate_paths.extend(sorted(LLM_ENGINE_REVIEW_DIR.glob("latest_*_llm_engine_review_draft.json")))
    candidate_paths.extend(sorted(LLM_ENGINE_REVIEW_DIR.glob(f"latest_*_{LLM_ENGINE_REVIEW_DRAFT_PREFIX}.json")))
    candidate_paths.extend(sorted(LLM_ENGINE_REVIEW_DIR.glob(f"*_{LLM_ENGINE_REVIEW_DRAFT_PREFIX}.json"), key=lambda p: p.stat().st_mtime, reverse=True))

    for path in candidate_paths:
        try:
            d = _patch99_read_json(path)
            fam = d.get("engine_family")
            if not fam or fam in seen:
                continue
            seen.add(fam)
            drafts.append({
                "engine_family": fam,
                "draft": d,
                "draft_path": str(path),
                "draft_sha256": _patch99_sha256(path),
            })
        except Exception:
            continue
    return sorted(drafts, key=lambda x: x.get("engine_family", ""))

def _patch99_decision_paths(engine_family: str) -> list[Path]:
    fam = _patch99_slug(engine_family)
    if not ENGINE_REVIEW_QUEUE_DIR.exists():
        return []
    return sorted(ENGINE_REVIEW_QUEUE_DIR.glob(f"*_{fam}_{ENGINE_REVIEW_QUEUE_DECISION_PREFIX}.json"))

def _patch99_latest_decision(engine_family: str) -> dict | None:
    paths = _patch99_decision_paths(engine_family)
    if not paths:
        return None
    try:
        return _patch99_read_json(paths[-1])
    except Exception:
        return None

def _patch99_queue_items() -> list[dict]:
    rows = []
    for rec in _patch99_list_latest_drafts():
        d = rec["draft"]
        fam = d.get("engine_family")
        brief = d.get("plain_english_brief") or {}
        llm_inv = d.get("llm_invocation") or {}
        decision = _patch99_latest_decision(fam)
        rows.append({
            "engine_family": fam,
            "draft_id": d.get("draft_id"),
            "draft_status": d.get("status"),
            "evidence_id": d.get("evidence_id"),
            "evidence_binder_sha256": d.get("evidence_binder_sha256"),
            "draft_path": rec["draft_path"],
            "draft_sha256": rec["draft_sha256"],
            "candidate_path": d.get("candidate_path_resolved") or d.get("candidate_path_recorded"),
            "likely_system_role": brief.get("likely_system_role"),
            "recommendation_draft": brief.get("recommendation"),
            "confidence": brief.get("confidence"),
            "llm_called": bool(llm_inv.get("called")),
            "llm_status": llm_inv.get("status"),
            "human_queue_decision": decision.get("human_queue_decision") if decision else "UNDECIDED",
            "human_decision_id": decision.get("decision_id") if decision else None,
        })
    return rows

def _patch99_write_queue_report() -> tuple[dict, Path, Path]:
    ENGINE_REVIEW_QUEUE_DIR.mkdir(parents=True, exist_ok=True)
    now = _patch99_now()
    rows = _patch99_queue_items()
    counts = {
        "drafts_in_queue": len(rows),
        "undecided": sum(1 for r in rows if r.get("human_queue_decision") == "UNDECIDED"),
        "approved_for_future_commit": sum(1 for r in rows if r.get("human_queue_decision") == "APPROVED_FOR_FUTURE_COMMIT"),
        "deferred_for_more_review": sum(1 for r in rows if r.get("human_queue_decision") == "DEFERRED_FOR_MORE_REVIEW"),
        "rejected_from_canonical_review": sum(1 for r in rows if r.get("human_queue_decision") == "REJECTED_FROM_CANONICAL_REVIEW"),
    }
    report = {
        "schema_version": ENGINE_REVIEW_QUEUE_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_QUEUE_V1_PATCH99",
        "created_at": now,
        "status": "ENGINE_REVIEW_QUEUE_READY_NO_CANONICAL_AUTHORITY",
        "counts": counts,
        "items": rows,
        "authority": _patch99_authority(),
        "next_step": "Nic may mark queue decisions. Patch 100 is required to commit approved decisions after live candidate SHA re-verification.",
    }
    json_path = ENGINE_REVIEW_QUEUE_DIR / f"{now}_{ENGINE_REVIEW_QUEUE_PREFIX}.json"
    md_path = ENGINE_REVIEW_QUEUE_DIR / f"{now}_{ENGINE_REVIEW_QUEUE_PREFIX}.md"
    _patch99_write_json(json_path, report)
    latest_json = ENGINE_REVIEW_QUEUE_DIR / f"latest_{ENGINE_REVIEW_QUEUE_PREFIX}.json"
    latest_md = ENGINE_REVIEW_QUEUE_DIR / f"latest_{ENGINE_REVIEW_QUEUE_PREFIX}.md"
    _patch99_write_json(latest_json, report)
    lines = [
        "# Patch 99 Engine Review Queue",
        "",
        f"Status: `{report['status']}`",
        f"Drafts in queue: `{counts['drafts_in_queue']}`",
        f"Undecided: `{counts['undecided']}`",
        f"Approved for future commit: `{counts['approved_for_future_commit']}`",
        f"Deferred: `{counts['deferred_for_more_review']}`",
        f"Rejected: `{counts['rejected_from_canonical_review']}`",
        "",
        "Authority: no canonical decision, no review ledger mutation, no engine writes.",
        "",
        "## Queue Items",
    ]
    for r in rows:
        lines.append(f"- `{r.get('engine_family')}` — `{r.get('human_queue_decision')}` — draft `{r.get('draft_id')}` — evidence `{r.get('evidence_id')}` — rec `{r.get('recommendation_draft')}`")
    md_text = "\n".join(lines) + "\n"
    md_path.write_text(md_text, encoding="utf-8")
    latest_md.write_text(md_text, encoding="utf-8")
    return report, json_path, md_path

def _patch99_format_draft_for_terminal(d: dict) -> list[str]:
    brief = d.get("plain_english_brief") or {}
    llm_text = (d.get("llm_visible_review_text") or "").strip()
    lines = []
    lines.append(f"Engine              : {d.get('engine_family')}")
    lines.append(f"Draft ID            : {d.get('draft_id')}")
    lines.append(f"Draft status        : {d.get('status')}")
    lines.append(f"Evidence ID         : {d.get('evidence_id')}")
    lines.append(f"Candidate path      : {d.get('candidate_path_resolved') or d.get('candidate_path_recorded')}")
    lines.append(f"Likely role         : {brief.get('likely_system_role')}")
    lines.append(f"Recommendation      : {brief.get('recommendation')}")
    lines.append(f"Confidence          : {brief.get('confidence')}")
    if d.get("llm_invocation"):
        inv = d.get("llm_invocation") or {}
        lines.append(f"LLM call            : {inv.get('called')}")
        lines.append(f"LLM model           : {inv.get('model')}")
        lines.append(f"LLM status          : {inv.get('status')}")
    lines.append("")
    if llm_text:
        lines.append("── Local LLM Visible Review ─────────────────────────")
        lines.extend(llm_text.splitlines())
        lines.append("")
    lines.append("── Deterministic Evidence Summary ───────────────────")
    lines.append("Plain-English Purpose:")
    lines.append(str(brief.get("plain_english_purpose") or ""))
    lines.append("")
    lines.append("Role Reason:")
    lines.append(str(brief.get("role_reason") or ""))
    lines.append("")
    lines.append("Risk Notes:")
    for risk in brief.get("risk_notes") or []:
        lines.append(f"- {risk}")
    lines.append("")
    lines.append("Suggested Nic Action:")
    lines.append(str(brief.get("suggested_nic_action") or ""))
    lines.append("")
    lines.append("Authority:")
    lines.append("This is queue review only. It does not approve, reject, or mutate the canonical ledger.")
    return lines

