def cmd_engine_review_queue_show(arg: str, session_id: str) -> None:
    """Show an engine review queue item or latest queue summary. Usage: engine-review-queue-show [latest|engine_family]"""
    from agents.forge.memory import write_audit_entry
    arg = (arg or "latest").strip()
    if arg.lower() == "latest":
        path = ENGINE_REVIEW_QUEUE_DIR / f"latest_{ENGINE_REVIEW_QUEUE_PREFIX}.json"
        if not path.exists():
            print()
            print("── Engine Review Queue Show ──────────────────────────")
            print("  Status: NO_QUEUE_FOUND")
            print("  Run   : engine-review-queue-build")
            print("──────────────────────────────────────────────────────")
            print()
            return
        report = _patch99_read_json(path)
        c = report.get("counts", {})
        print()
        print("── Engine Review Queue Summary ───────────────────────")
        print("  Status    :", report.get("status"))
        print("  Drafts    :", c.get("drafts_in_queue", 0))
        print("  Undecided :", c.get("undecided", 0))
        print("  Approved  :", c.get("approved_for_future_commit", 0))
        print("  Deferred  :", c.get("deferred_for_more_review", 0))
        print("  Rejected  :", c.get("rejected_from_canonical_review", 0))
