# ─── PATCH 100 — CANONICAL DECISION COMMITTER ────────────────────────────────

ENGINE_REVIEW_COMMIT_DIR = Path.home() / "forge" / "memory" / "engine_review_commits_v1"
ENGINE_REVIEW_COMMIT_SCHEMA_VERSION = "engine_review_commit_v1_patch100"
ENGINE_REVIEW_COMMIT_PLAN_PREFIX = "engine_review_commit_plan_v1"
ENGINE_REVIEW_COMMIT_RECEIPT_PREFIX = "engine_review_commit_receipt_v1"
ENGINE_REVIEW_COMMIT_EXPORT_PREFIX = "engine_review_commit_export_v1"
ENGINE_REVIEW_COMMIT_CONFIRM_TOKEN = "CONFIRM_COMMIT_APPROVED_QUEUE"
# Patch 100.2 hotfix: deterministic approved root for live evidence recheck.
# Current engine review candidates are scoped under /home/nic/aiweb.
APPROVED_ROOT = Path.home() / "aiweb"


def _patch100_now() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch100_authority(commit_authority: bool = False) -> dict:
    return {
        "patch": "100",
        "mode": "CANONICAL_DECISION_COMMITTER_LEDGER_ONLY",
        "writes": [
            str(ENGINE_REVIEW_LEDGER_FILE),
            str(ENGINE_REVIEW_COMMIT_DIR),
        ],
        "human_review_ledger_write_authority": bool(commit_authority),
        "canonical_decision_authority": False,
        "final_lockfile_authority": False,
        "engine_file_write_authority": False,
        "project_file_write_authority": False,
        "llm_autonomous_decision_authority": False,
        "shell_execution_authority": False,
        "chroma_write_authority": False,
        "ingestion_write_authority": False,
        "quarantine_authority": False,
        "delete_authority": False,
        "rule": "Patch 100 may update the human review ledger only from Patch 99 queue decisions after stale-evidence re-verification. It does not create final canonical authority or modify engine files.",
    }


def _patch100_write_json(path: Path, payload: dict) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")


def _patch100_read_json(path: Path) -> dict:
    return json.loads(Path(path).read_text(encoding="utf-8"))


def _patch100_sha256(path: Path) -> str | None:
    path = Path(path)
    if not path.exists() or not path.is_file():
        return None
    h = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def _patch100_latest_file(directory: Path, pattern: str) -> Path | None:
    try:
        matches = sorted(directory.glob(pattern), key=lambda p: p.stat().st_mtime, reverse=True)
        return matches[0] if matches else None
    except Exception:
        return None


def _patch100_resolve_report_path(arg: str, directory: Path, latest_pattern: str) -> Path | None:
    arg = (arg or "latest").strip()
    if not arg or arg.lower() == "latest":
        return _patch100_latest_file(directory, latest_pattern)
    p = Path(arg).expanduser()
    if p.exists():
        return p
    candidate = directory / arg
    if candidate.exists():
        return candidate
    return None


def _patch100_decision_files() -> list[Path]:
    if not ENGINE_REVIEW_QUEUE_DIR.exists():
        return []
    paths = []
    for p in ENGINE_REVIEW_QUEUE_DIR.glob(f"*_{ENGINE_REVIEW_QUEUE_DECISION_PREFIX}.json"):
        # skip symlinks or non-files just to keep the ledger flow boring and safe
        if p.is_file():
            paths.append(p)
    return sorted(paths, key=lambda p: p.stat().st_mtime)


def _patch100_latest_decisions_by_engine() -> dict[str, tuple[dict, Path]]:
    latest: dict[str, tuple[dict, Path]] = {}
    for path in _patch100_decision_files():
        try:
            d = _patch100_read_json(path)
            fam = str(d.get("engine_family") or "").strip()
            if not fam:
                continue
            latest[fam] = (d, path)
        except Exception:
            continue
    return latest


def _patch100_find_binder_for_draft(draft: dict) -> tuple[dict | None, Path | None, str | None]:
    p = Path(str(draft.get("evidence_binder_path") or "")).expanduser()
    if p.exists():
        try:
            return _patch100_read_json(p), p, None
        except Exception as e:
            return None, p, f"evidence binder read failed: {e}"
    fam = str(draft.get("engine_family") or "").strip()
    if fam:
        alt = ENGINE_EVIDENCE_BINDER_DIR / f"latest_{_patch99_slug(fam)}_engine_evidence_binder.json"
        if alt.exists():
            try:
                return _patch100_read_json(alt), alt, None
            except Exception as e:
                return None, alt, f"evidence binder read failed: {e}"
    return None, p if str(p) else None, "evidence binder not found"


def _patch100_verify_binder_live(binder: dict) -> tuple[bool, list[str], list[str], list[dict]]:
    blockers: list[str] = []
    warnings: list[str] = []
    rows: list[dict] = []
    candidate = Path(str(binder.get("candidate_path_resolved") or "")).expanduser()
    if not candidate.exists():
        blockers.append(f"engine candidate path missing on disk: {candidate}")
    if not str(candidate).startswith(str(APPROVED_ROOT)):
        blockers.append(f"engine candidate path outside approved scope: {candidate}")
    evidence_rows = binder.get("file_evidence") or []
    if not evidence_rows:
        blockers.append("evidence binder has no file_evidence rows")
    for ev in evidence_rows:
        p = Path(str(ev.get("path") or "")).expanduser()
        expected = ev.get("sha256")
        current = _patch100_sha256(p)
        row = {
            "path": str(p),
            "expected_sha256_from_evidence_binder": expected,
            "current_sha256": current,
            "exists_now": p.exists(),
            "sha_match": bool(expected and current and expected == current),
        }
        if not p.exists():
            blockers.append(f"evidence file missing on disk: {p}")
        elif not str(p).startswith(str(APPROVED_ROOT)):
            blockers.append(f"evidence file outside approved scope: {p}")
        elif expected != current:
            blockers.append(f"REFUSED_STALE_ENGINE_EVIDENCE: {p}")
        rows.append(row)
    return not blockers, blockers, warnings, rows


def _patch100_decision_to_commit_status(decision: str) -> str | None:
    d = (decision or "").strip().upper()
    if d == "APPROVED_FOR_FUTURE_COMMIT":
        return "approved"
    if d == "DEFERRED_FOR_MORE_REVIEW":
        return "deferred"
    if d == "REJECTED_FROM_CANONICAL_REVIEW":
        return "rejected"
    return None


def _patch100_build_plan() -> tuple[dict, Path, Path]:
    ENGINE_REVIEW_COMMIT_DIR.mkdir(parents=True, exist_ok=True)
    now = _patch100_now()
    decisions = _patch100_latest_decisions_by_engine()
    ledger, ledger_path, ledger_err = _patch72_load_ledger(create_if_missing=False)
    ledger_sha = _patch100_sha256(ledger_path) if ledger_path and ledger_path.exists() else None
    rows: list[dict] = []
    blockers: list[str] = []
    warnings: list[str] = []
    if ledger_err:
        blockers.append(f"review ledger unavailable: {ledger_err}")
    if not decisions:
        blockers.append("no Patch 99 queue decision receipts found")
    for fam, (decision, decision_path) in sorted(decisions.items()):
        row_blockers: list[str] = []
        row_warnings: list[str] = []
        commit_status = _patch100_decision_to_commit_status(decision.get("human_queue_decision"))
        if not commit_status:
            row_blockers.append(f"unsupported queue decision: {decision.get('human_queue_decision')}")
        draft_path = Path(str(decision.get("draft_path") or "")).expanduser()
        draft = None
        if not draft_path.exists():
            row_blockers.append(f"draft path missing: {draft_path}")
        else:
            draft_sha = _patch100_sha256(draft_path)
            if decision.get("draft_sha256") and draft_sha != decision.get("draft_sha256"):
                row_blockers.append("draft SHA mismatch against queue decision receipt")
            try:
                draft = _patch100_read_json(draft_path)
            except Exception as e:
                row_blockers.append(f"draft read failed: {e}")
        binder = None
        binder_path = None
        binder_sha = None
        live_rows: list[dict] = []
        if draft:
            binder, binder_path, binder_err = _patch100_find_binder_for_draft(draft)
            if binder_err:
                row_blockers.append(binder_err)
            if binder_path and binder_path.exists():
                binder_sha = _patch100_sha256(binder_path)
                expected_binder_sha = decision.get("evidence_binder_sha256") or draft.get("evidence_binder_sha256")
                if expected_binder_sha and binder_sha != expected_binder_sha:
                    row_blockers.append("evidence binder SHA mismatch against queue/draft receipt")
            if binder:
                ok, b_blockers, b_warnings, live_rows = _patch100_verify_binder_live(binder)
                row_blockers.extend(b_blockers)
                row_warnings.extend(b_warnings)
        ledger_entry = None
        if ledger:
            ledger_entry = _patch72_find_entry(ledger, fam)
            if not ledger_entry:
                row_blockers.append("engine family not found in engine_review_ledger_v1.json")
        candidate_path = None
        if binder:
            candidate_path = binder.get("candidate_path_resolved")
        elif draft:
            candidate_path = draft.get("candidate_path_resolved") or draft.get("candidate_path_recorded")
        row_ready = not row_blockers
        rows.append({
            "engine_family": fam,
            "queue_decision": decision.get("human_queue_decision"),
            "commit_status_if_applied": commit_status.upper() if commit_status else None,
            "ready_for_commit": row_ready,
            "decision_path": str(decision_path),
            "decision_sha256": _patch100_sha256(decision_path),
            "draft_path": str(draft_path),
            "draft_sha256_current": _patch100_sha256(draft_path) if draft_path.exists() else None,
            "evidence_id": decision.get("evidence_id") or (draft or {}).get("evidence_id"),
            "evidence_binder_path": str(binder_path) if binder_path else None,
            "evidence_binder_sha256_current": binder_sha,
            "candidate_path": candidate_path,
            "candidate_path_exists_now": Path(str(candidate_path or "")).expanduser().exists() if candidate_path else False,
            "ledger_entry_found": bool(ledger_entry),
            "ledger_current_review_status": (ledger_entry or {}).get("review_status"),
            "ledger_is_hold_family": bool((ledger_entry or {}).get("is_hold_family")) if ledger_entry else None,
            "future_lockfile_eligible_if_applied": bool(commit_status == "approved" and ledger_entry and not ledger_entry.get("is_hold_family")),
            "live_evidence_file_checks": live_rows,
            "blockers": row_blockers,
            "warnings": row_warnings,
        })
        blockers.extend([f"{fam}: {b}" for b in row_blockers])
        warnings.extend([f"{fam}: {w}" for w in row_warnings])
    ready = [r for r in rows if r.get("ready_for_commit")]
    plan = {
        "schema_version": ENGINE_REVIEW_COMMIT_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_COMMIT_PLAN_V1_PATCH100",
        "created_at": now,
        "status": "ENGINE_REVIEW_COMMIT_PLAN_READY" if ready and not blockers else "ENGINE_REVIEW_COMMIT_PLAN_BLOCKED",
        "authority": _patch100_authority(commit_authority=False),
        "source_queue_decision_count": len(decisions),
        "ledger_path": str(ledger_path),
        "ledger_sha256_at_plan_time": ledger_sha,
        "counts": {
            "decision_receipts": len(decisions),
            "ready_for_commit": len(ready),
            "blocked": len(rows) - len(ready),
            "approved_ready": sum(1 for r in ready if r.get("commit_status_if_applied") == "APPROVED"),
            "deferred_ready": sum(1 for r in ready if r.get("commit_status_if_applied") == "DEFERRED"),
            "rejected_ready": sum(1 for r in ready if r.get("commit_status_if_applied") == "REJECTED"),
            "blockers": len(blockers),
            "warnings": len(warnings),
        },
        "commit_rows": rows,
        "blockers": blockers,
        "warnings": warnings,
        "required_confirm_token_for_apply": ENGINE_REVIEW_COMMIT_CONFIRM_TOKEN,
        "stale_evidence_refusal": "If any candidate path/file SHA changed since the evidence binder, apply must refuse with REFUSED_STALE_ENGINE_EVIDENCE.",
        "next_step": "Run engine-review-commit-apply CONFIRM_COMMIT_APPROVED_QUEUE only if this plan has ready rows and zero blockers.",
    }
    json_path = ENGINE_REVIEW_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_COMMIT_PLAN_PREFIX}.json"
    md_path = ENGINE_REVIEW_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_COMMIT_PLAN_PREFIX}.md"
    _patch100_write_json(json_path, plan)
    _patch100_write_plan_markdown(plan, md_path)
    # latest pointer copy for convenience
    _patch100_write_json(ENGINE_REVIEW_COMMIT_DIR / f"latest_{ENGINE_REVIEW_COMMIT_PLAN_PREFIX}.json", plan)
    (ENGINE_REVIEW_COMMIT_DIR / f"latest_{ENGINE_REVIEW_COMMIT_PLAN_PREFIX}.md").write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")
    return plan, json_path, md_path


def _patch100_write_plan_markdown(plan: dict, md_path: Path) -> None:
    c = plan.get("counts") or {}
    lines = [
        "# Patch 100 Engine Review Commit Plan",
        "",
        "Mode: human review ledger commit plan only. No engine files, lockfiles, quarantine folders, Chroma data, or project source files are modified.",
        f"Created: `{plan.get('created_at')}`",
        f"Status: `{plan.get('status')}`",
        f"Ledger SHA at plan time: `{plan.get('ledger_sha256_at_plan_time')}`",
        "",
        "## Counts",
        f"- Decision receipts: `{c.get('decision_receipts')}`",
        f"- Ready for commit: `{c.get('ready_for_commit')}`",
        f"- Blocked: `{c.get('blocked')}`",
        f"- Approved ready: `{c.get('approved_ready')}`",
        f"- Deferred ready: `{c.get('deferred_ready')}`",
        f"- Rejected ready: `{c.get('rejected_ready')}`",
        f"- Blockers: `{c.get('blockers')}`",
        f"- Warnings: `{c.get('warnings')}`",
        "",
        "## Rows",
    ]
    for row in plan.get("commit_rows") or []:
        lines.append(f"- `{row.get('engine_family')}` decision=`{row.get('queue_decision')}` ready=`{row.get('ready_for_commit')}` commit=`{row.get('commit_status_if_applied')}` evidence=`{row.get('evidence_id')}`")
        if row.get("blockers"):
            for b in row.get("blockers")[:8]:
                lines.append(f"  - BLOCKER: {b}")
    if plan.get("blockers"):
        lines.extend(["", "## Blockers"])
        for b in plan.get("blockers")[:80]:
            lines.append(f"- {b}")
    lines.extend(["", "## Authority", "- Ledger write: `NO` in plan", "- Engine file writes: `NO`", "- Final canonical lockfile: `NO`"])
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")


def _patch100_print_plan(plan: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    c = plan.get("counts") or {}
    print()
    print("── Engine Review Commit Plan ───────────────────────")
    print("  Mode      : PLAN ONLY — no ledger mutation")
    print("  Status    :", plan.get("status"))
    print("  Decisions :", c.get("decision_receipts"))
    print("  Ready     :", c.get("ready_for_commit"), " blocked=", c.get("blocked"))
    print("  Approved  :", c.get("approved_ready"), " deferred=", c.get("deferred_ready"), " rejected=", c.get("rejected_ready"))
    print("  Blockers  :", c.get("blockers"))
    print("  Warnings  :", c.get("warnings"))
    if json_path:
        print("  JSON      :", json_path)
    if md_path:
        print("  Markdown  :", md_path)
    print("  Authority : NO ledger mutation in plan; NO engine writes; NO final canonical authority")
    if plan.get("blockers"):
        print("  First blockers:")
        for b in plan.get("blockers")[:12]:
            print("    -", b)
    print("──────────────────────────────────────────────────────")
    print()


def _patch100_resolve_plan(arg: str = "latest") -> Path | None:
    return _patch100_resolve_report_path(arg, ENGINE_REVIEW_COMMIT_DIR, f"*_{ENGINE_REVIEW_COMMIT_PLAN_PREFIX}.json")


def _patch100_resolve_receipt(arg: str = "latest") -> Path | None:
    return _patch100_resolve_report_path(arg, ENGINE_REVIEW_COMMIT_DIR, f"*_{ENGINE_REVIEW_COMMIT_RECEIPT_PREFIX}.json")


def _patch100_validate_plan(plan: dict) -> tuple[bool, list[str], list[str]]:
    problems: list[str] = []
    warnings: list[str] = []
    if not isinstance(plan, dict):
        return False, ["commit plan is not a JSON object"], warnings
    auth = plan.get("authority") or {}
    forbidden_true = [
        "canonical_decision_authority", "final_lockfile_authority", "engine_file_write_authority",
        "project_file_write_authority", "llm_autonomous_decision_authority", "shell_execution_authority",
        "chroma_write_authority", "ingestion_write_authority", "quarantine_authority", "delete_authority",
    ]
    for key in forbidden_true:
        if auth.get(key) is not False:
            problems.append(f"forbidden authority flag is not false: {key}")
    if not plan.get("commit_rows"):
        problems.append("plan has no commit rows")
    if (plan.get("counts") or {}).get("ready_for_commit", 0) < 1:
        problems.append("plan has no ready rows")
    for row in plan.get("commit_rows") or []:
        if row.get("ready_for_commit") and row.get("blockers"):
            problems.append(f"ready row contains blockers: {row.get('engine_family')}")
        if row.get("warnings"):
            warnings.extend([f"{row.get('engine_family')}: {w}" for w in row.get("warnings")])
    if plan.get("blockers"):
        problems.extend(plan.get("blockers") or [])
    if plan.get("warnings"):
        warnings.extend(plan.get("warnings") or [])
    return not problems, problems, warnings


def cmd_engine_review_commit_policy(session_id: str) -> None:
    """Show Patch 100 engine review commit policy. Usage: engine-review-commit-policy"""
    from agents.forge.memory import write_audit_entry
    print()
    print("── Engine Review Commit Policy ─────────────────────")
    print("  Patch     : 100")
    print("  Purpose   : commit Patch 99 human queue decisions into engine_review_ledger_v1 only after stale-evidence recheck")
    print("  Writes    : human review ledger + Forge-owned commit receipts")
    print("  Authority : Ledger write only after explicit confirm token")
    print("  Still NO  : engine file writes, final canonical lockfile, quarantine, delete, Chroma writes, shell")
    print("  Required  : queue decision, draft SHA, binder SHA, live candidate path, live file SHA match, ledger SHA match")
    print("  Refusal   : REFUSED_STALE_ENGINE_EVIDENCE if live file SHA differs from evidence binder")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_COMMIT_POLICY_SHOWN", str(ENGINE_REVIEW_COMMIT_DIR), "ledger_commit_policy", "patch100")


def cmd_engine_review_commit_plan(session_id: str) -> None:
    """Build a Patch 100 engine review commit plan. Usage: engine-review-commit-plan"""
    from agents.forge.memory import write_audit_entry
    plan, json_path, md_path = _patch100_build_plan()
    _patch100_print_plan(plan, json_path, md_path)
    c = plan.get("counts") or {}
    write_audit_entry(session_id, "ENGINE_REVIEW_COMMIT_PLAN_WRITTEN", str(json_path), f"ready={c.get('ready_for_commit')} blockers={c.get('blockers')}", "no_ledger_mutation")


def cmd_engine_review_commit_show(arg: str, session_id: str) -> None:
    """Show a Patch 100 plan or receipt. Usage: engine-review-commit-show [latest|path]"""
    from agents.forge.memory import write_audit_entry
    path = _patch100_resolve_receipt(arg) or _patch100_resolve_plan(arg)
    print()
    print("── Engine Review Commit Show ───────────────────────")
    if not path or not path.exists():
        print("  Status: NO_COMMIT_PLAN_OR_RECEIPT_FOUND")
        print("  Next  : engine-review-commit-plan")
        print("──────────────────────────────────────────────────────")
        print()
        return
    data = _patch100_read_json(path)
    c = data.get("counts") or {}
    print("  Path   :", path)
    print("  Type   :", data.get("report_type"))
    print("  Status :", data.get("status"))
    print("  Counts :", c)
    if data.get("commit_rows"):
        print("  Rows:")
        for row in data.get("commit_rows")[:25]:
            print(f"    - {row.get('engine_family')} :: ready={row.get('ready_for_commit')} :: commit={row.get('commit_status_if_applied')} :: decision={row.get('queue_decision')}")
    if data.get("applied_rows"):
        print("  Applied rows:")
        for row in data.get("applied_rows")[:25]:
            print(f"    - {row.get('engine_family')} :: {row.get('applied_review_status')} :: eligible={row.get('future_lockfile_eligible')}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_COMMIT_SHOWN", str(path), "read-only", data.get("status") or "shown")


def cmd_engine_review_commit_verify(arg: str, session_id: str) -> None:
    """Verify a Patch 100 plan or receipt. Usage: engine-review-commit-verify [latest|path]"""
    from agents.forge.memory import write_audit_entry
    path = _patch100_resolve_receipt(arg) or _patch100_resolve_plan(arg)
    print()
    print("── Engine Review Commit Verify ─────────────────────")
    if not path or not path.exists():
        print("  Status  : FAIL")
        print("  Reason  : no plan/receipt found")
        print("──────────────────────────────────────────────────────")
        print()
        return
    data = _patch100_read_json(path)
    if data.get("report_type") == "ENGINE_REVIEW_COMMIT_RECEIPT_V1_PATCH100":
        problems = list(data.get("blockers") or [])
        if not data.get("ledger_sha256_after_apply"):
            problems.append("receipt missing ledger_sha256_after_apply")
        status_ok = data.get("status") in {"ENGINE_REVIEW_COMMIT_APPLIED", "ENGINE_REVIEW_COMMIT_APPLIED_WITH_WARNINGS"}
        if not status_ok:
            problems.append(f"unexpected receipt status: {data.get('status')}")
        warnings = list(data.get("warnings") or [])
    else:
        _, problems, warnings = _patch100_validate_plan(data)
    print("  Path     :", path)
    print("  Type     :", data.get("report_type"))
    print("  Status   :", "PASS" if not problems else "FAIL")
    print("  Problems :", len(problems))
    print("  Warnings :", len(warnings))
    for p in problems[:20]:
        print("    -", p)
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_COMMIT_VERIFY", str(path), f"problems={len(problems)}", "read-only")


def cmd_engine_review_commit_apply(arg: str, session_id: str) -> None:
    """Apply ready Patch 99 queue decisions into engine_review_ledger_v1. Usage: engine-review-commit-apply CONFIRM_COMMIT_APPROVED_QUEUE"""
    from agents.forge.memory import write_audit_entry
    token = (arg or "").strip()
    print()
    print("── Engine Review Commit Apply ──────────────────────")
    if token != ENGINE_REVIEW_COMMIT_CONFIRM_TOKEN:
        print("  Status : REFUSED_CONFIRM_TOKEN_REQUIRED")
        print("  Usage  : engine-review-commit-apply CONFIRM_COMMIT_APPROVED_QUEUE")
        print("  Result : no ledger mutation")
        print("──────────────────────────────────────────────────────")
        print()
        write_audit_entry(session_id, "ENGINE_REVIEW_COMMIT_APPLY_REFUSED", "-", "missing_confirm", "no_ledger_mutation")
        return
    # Build a fresh plan at apply time. This is the stale-evidence re-check.
    plan, plan_path, _ = _patch100_build_plan()
    ok, problems, warnings = _patch100_validate_plan(plan)
    if not ok:
        print("  Status   : REFUSED_COMMIT_PLAN_BLOCKED")
        print("  Plan     :", plan_path)
        print("  Problems :", len(problems))
        for p in problems[:20]:
            print("    -", p)
        print("  Result   : no ledger mutation")
        print("──────────────────────────────────────────────────────")
        print()
        write_audit_entry(session_id, "ENGINE_REVIEW_COMMIT_APPLY_REFUSED", str(plan_path), f"problems={len(problems)}", "no_ledger_mutation")
        return
    ledger, ledger_path, err = _patch72_load_ledger(create_if_missing=False)
    if err or not ledger:
        print("  Status : REFUSED_LEDGER_UNAVAILABLE")
        print("  Reason :", err)
        print("──────────────────────────────────────────────────────")
        print()
        return
    current_ledger_sha = _patch100_sha256(ledger_path)
    if current_ledger_sha != plan.get("ledger_sha256_at_plan_time"):
        print("  Status : REFUSED_LEDGER_SHA_CHANGED_AFTER_PLAN")
        print("  Plan SHA   :", plan.get("ledger_sha256_at_plan_time"))
        print("  Current SHA:", current_ledger_sha)
        print("──────────────────────────────────────────────────────")
        print()
        write_audit_entry(session_id, "ENGINE_REVIEW_COMMIT_APPLY_REFUSED", str(ledger_path), "ledger_sha_changed", "no_ledger_mutation")
        return
    now = _patch100_now()
    backup_path = ENGINE_REVIEW_COMMIT_DIR / f"{now}_engine_review_ledger_before_patch100_commit.json"
    ENGINE_REVIEW_COMMIT_DIR.mkdir(parents=True, exist_ok=True)
    backup_path.write_text(json.dumps(ledger, indent=2, ensure_ascii=False), encoding="utf-8")
    applied_rows: list[dict] = []
    for row in plan.get("commit_rows") or []:
        if not row.get("ready_for_commit"):
            continue
        entry = _patch72_find_entry(ledger, row.get("engine_family"))
        if not entry:
            continue
        status = str(row.get("commit_status_if_applied") or "").lower()
        note = (
            f"Patch100 commit from Patch99 queue decision. "
            f"decision={row.get('queue_decision')} evidence_id={row.get('evidence_id')} "
            f"decision_sha={row.get('decision_sha256')} binder_sha={row.get('evidence_binder_sha256_current')}"
        )
        _patch72_mark_row(entry, status, note)
        entry["patch100_commit"] = {
            "committed_at": now,
            "source_decision_path": row.get("decision_path"),
            "source_decision_sha256": row.get("decision_sha256"),
            "source_draft_path": row.get("draft_path"),
            "source_evidence_id": row.get("evidence_id"),
            "source_evidence_binder_path": row.get("evidence_binder_path"),
            "source_evidence_binder_sha256": row.get("evidence_binder_sha256_current"),
            "live_evidence_sha_reverified_at_commit": True,
            "canonical_authority": False,
            "engine_files_changed": False,
        }
        applied_rows.append({
            "engine_family": entry.get("engine_base"),
            "applied_review_status": entry.get("review_status"),
            "future_lockfile_eligible": entry.get("future_lockfile_eligible"),
            "future_lockfile_block_reason": entry.get("future_lockfile_block_reason"),
            "source_evidence_id": row.get("evidence_id"),
        })
    _patch72_save_ledger(ledger)
    after_sha = _patch100_sha256(ledger_path)
    receipt = {
        "schema_version": ENGINE_REVIEW_COMMIT_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_COMMIT_RECEIPT_V1_PATCH100",
        "created_at": now,
        "status": "ENGINE_REVIEW_COMMIT_APPLIED_WITH_WARNINGS" if warnings else "ENGINE_REVIEW_COMMIT_APPLIED",
        "authority": _patch100_authority(commit_authority=True),
        "confirm_token_used": token,
        "source_plan_path": str(plan_path),
        "source_plan_sha256": _patch100_sha256(plan_path),
        "ledger_path": str(ledger_path),
        "ledger_backup_before_apply": str(backup_path),
        "ledger_sha256_before_apply": current_ledger_sha,
        "ledger_sha256_after_apply": after_sha,
        "counts": {
            "ready_rows_in_plan": (plan.get("counts") or {}).get("ready_for_commit"),
            "applied_rows": len(applied_rows),
            "blockers": 0,
            "warnings": len(warnings),
        },
        "applied_rows": applied_rows,
        "blockers": [],
        "warnings": warnings,
        "post_commit_counts": _patch72_counts(ledger),
        "still_no_authority": {
            "final_canonical_lockfile_authority": False,
            "engine_file_write_authority": False,
            "quarantine_authority": False,
            "delete_authority": False,
        },
    }
    json_path = ENGINE_REVIEW_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_COMMIT_RECEIPT_PREFIX}.json"
    md_path = ENGINE_REVIEW_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_COMMIT_RECEIPT_PREFIX}.md"
    _patch100_write_json(json_path, receipt)
    _patch100_write_receipt_markdown(receipt, md_path)
    _patch100_write_json(ENGINE_REVIEW_COMMIT_DIR / f"latest_{ENGINE_REVIEW_COMMIT_RECEIPT_PREFIX}.json", receipt)
    (ENGINE_REVIEW_COMMIT_DIR / f"latest_{ENGINE_REVIEW_COMMIT_RECEIPT_PREFIX}.md").write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")
    print("  Status   :", receipt.get("status"))
    print("  Applied  :", len(applied_rows))
    print("  Ledger   :", ledger_path)
    print("  Backup   :", backup_path)
    print("  Receipt  :", json_path)
    print("  Authority: LEDGER WRITE ONLY; NO engine files; NO final canonical authority")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_COMMIT_APPLIED", str(json_path), f"applied={len(applied_rows)}", "ledger_only_no_engine_files")


def _patch100_write_receipt_markdown(receipt: dict, md_path: Path) -> None:
    c = receipt.get("counts") or {}
    lines = [
        "# Patch 100 Engine Review Commit Receipt",
        "",
        f"Status: `{receipt.get('status')}`",
        f"Created: `{receipt.get('created_at')}`",
        f"Ledger: `{receipt.get('ledger_path')}`",
        f"Backup before apply: `{receipt.get('ledger_backup_before_apply')}`",
        "",
        "## Counts",
        f"- Ready rows in plan: `{c.get('ready_rows_in_plan')}`",
        f"- Applied rows: `{c.get('applied_rows')}`",
        f"- Warnings: `{c.get('warnings')}`",
        "",
        "## Applied Rows",
    ]
    for row in receipt.get("applied_rows") or []:
        lines.append(f"- `{row.get('engine_family')}` → `{row.get('applied_review_status')}` eligible=`{row.get('future_lockfile_eligible')}` evidence=`{row.get('source_evidence_id')}`")
    lines.extend(["", "## Authority", "- Human review ledger write: `YES`", "- Engine file write: `NO`", "- Final canonical lockfile: `NO`", "- Quarantine/delete: `NO`"]) 
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")


def cmd_engine_review_commit_export(session_id: str) -> None:
    """Export Patch 100 commit receipts. Usage: engine-review-commit-export"""
    from agents.forge.memory import write_audit_entry
    ENGINE_REVIEW_COMMIT_DIR.mkdir(parents=True, exist_ok=True)
    now = _patch100_now()
    plans = []
    receipts = []
    for p in sorted(ENGINE_REVIEW_COMMIT_DIR.glob(f"*_{ENGINE_REVIEW_COMMIT_PLAN_PREFIX}.json")):
        if not p.name.startswith("latest_"):
            plans.append({"path": str(p), "sha256": _patch100_sha256(p)})
    for p in sorted(ENGINE_REVIEW_COMMIT_DIR.glob(f"*_{ENGINE_REVIEW_COMMIT_RECEIPT_PREFIX}.json")):
        if not p.name.startswith("latest_"):
            receipts.append({"path": str(p), "sha256": _patch100_sha256(p)})
    export = {
        "schema_version": ENGINE_REVIEW_COMMIT_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_COMMIT_EXPORT_V1_PATCH100",
        "created_at": now,
        "plans": plans,
        "receipts": receipts,
        "counts": {"plans": len(plans), "receipts": len(receipts)},
        "authority": _patch100_authority(commit_authority=False),
    }
    json_path = ENGINE_REVIEW_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_COMMIT_EXPORT_PREFIX}.json"
    md_path = ENGINE_REVIEW_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_COMMIT_EXPORT_PREFIX}.md"
    _patch100_write_json(json_path, export)
    lines = ["# Patch 100 Engine Review Commit Export", "", f"Plans: `{len(plans)}`", f"Receipts: `{len(receipts)}`", "", "## Receipts"]
    for r in receipts:
        lines.append(f"- `{r.get('path')}` sha=`{r.get('sha256')}`")
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    print()
    print("── Engine Review Commit Export ─────────────────────")
    print("  JSON    :", json_path)
    print("  Markdown:", md_path)
    print("  Plans   :", len(plans))
    print("  Receipts:", len(receipts))
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_COMMIT_EXPORT_WRITTEN", str(json_path), f"receipts={len(receipts)}", "read-only")


# ─── PATCH 101 — ENGINE REVIEW BATCH DRAFT RUNNER (LLM MAP, NO KEYS) ─────────

LLM_ENGINE_REVIEW_BATCH_RUN_DIR = MEMORY_DIR / "llm_engine_review_batch_runs_v1"
LLM_ENGINE_REVIEW_BATCH_RUN_SCHEMA_VERSION = "llm_engine_review_batch_run_v1_patch101"
LLM_ENGINE_REVIEW_BATCH_RUN_PREFIX = "llm_engine_review_batch_run_v1"
LLM_ENGINE_REVIEW_BATCH_RUN_EXPORT_PREFIX = "llm_engine_review_batch_run_export_v1"
LLM_ENGINE_REVIEW_BATCH_RUN_DEFAULT_LIMIT = 5
LLM_ENGINE_REVIEW_BATCH_RUN_MAX_LIMIT = 10


def _patch101_now() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch101_slug(value: str) -> str:
    return re.sub(r"[^a-zA-Z0-9_.-]+", "_", (value or "").strip()).strip("_") or "unknown"


def _patch101_read_json(path: Path) -> dict:
    return json.loads(path.read_text(encoding="utf-8"))


def _patch101_write_json(path: Path, data: dict) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(data, indent=2, sort_keys=True) + "\n", encoding="utf-8")


def _patch101_sha256(path: Path) -> str:
    h = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def _patch101_authority() -> dict:
    return {
        "patch": "101",
        "mode": "LLM_ENGINE_REVIEW_BATCH_DRAFT_RUNNER_NO_CANONICAL_AUTHORITY",
        "writes": [str(LLM_ENGINE_REVIEW_DIR), str(LLM_ENGINE_REVIEW_BATCH_RUN_DIR)],
        "llm_inference_authority": True,
        "canonical_decision_authority": False,
        "human_review_ledger_write_authority": False,
        "engine_file_write_authority": False,
        "project_file_write_authority": False,
        "chroma_write_authority": False,
        "ingestion_write_authority": False,
        "shell_execution_authority": False,
        "quarantine_authority": False,
        "delete_authority": False,
        "rule": "Patch 101 runs small, explicit LLM review draft batches from existing evidence binders. It does not approve engines, mutate ledgers, or write project files.",
    }


def _patch101_existing_draft_families() -> set[str]:
    fams = set()
    if not LLM_ENGINE_REVIEW_DIR.exists():
        return fams
    for path in LLM_ENGINE_REVIEW_DIR.glob(f"latest_*_{LLM_ENGINE_REVIEW_DRAFT_PREFIX}.json"):
        try:
            d = _patch101_read_json(path)
            fam = d.get("engine_family")
            if fam:
                fams.add(fam)
        except Exception:
            continue
    return fams


def _patch101_decided_families() -> set[str]:
    fams = set()
    if not ENGINE_REVIEW_QUEUE_DIR.exists():
        return fams
    for path in ENGINE_REVIEW_QUEUE_DIR.glob(f"*_{ENGINE_REVIEW_QUEUE_DECISION_PREFIX}.json"):
        try:
            d = _patch101_read_json(path)
            fam = d.get("engine_family")
            decision = d.get("human_queue_decision")
            if fam and decision and decision != "UNDECIDED":
                fams.add(fam)
        except Exception:
            continue
    return fams


def _patch101_committed_families() -> set[str]:
    fams = set()
    if not ENGINE_REVIEW_COMMIT_DIR.exists():
        return fams
    for path in ENGINE_REVIEW_COMMIT_DIR.glob(f"*_{ENGINE_REVIEW_COMMIT_RECEIPT_PREFIX}.json"):
        if path.name.startswith("latest_"):
            continue
        try:
            d = _patch101_read_json(path)
            for row in d.get("applied_rows") or []:
                fam = row.get("engine_family")
                if fam:
                    fams.add(fam)
        except Exception:
            continue
    return fams


def _patch101_candidate_rows() -> list[dict]:
    gateway_ok, gateway_msg = _patch98_gateway_ready()
    source_ok, source_report, source_blockers = _patch98_source_law_ready()
    existing = _patch101_existing_draft_families()
    decided = _patch101_decided_families()
    committed = _patch101_committed_families()
    rows = []
    for binder in _patch98_all_latest_evidence_binders():
        fam = binder.get("engine_family")
        if not fam:
            continue
        blockers = []
        skipped_reason = None
        if not gateway_ok:
            blockers.append(gateway_msg)
        if not source_ok:
            blockers.extend(source_blockers)
        if not binder.get("ready_for_llm_brief"):
            blockers.append("Evidence binder is not marked ready_for_llm_brief.")
        if fam in committed:
            skipped_reason = "already_committed_by_patch100"
        elif fam in decided:
            skipped_reason = "already_has_human_queue_decision"
        elif fam in existing:
            skipped_reason = "already_has_llm_review_draft"
        rows.append({
            "engine_family": fam,
            "evidence_id": binder.get("evidence_id"),
            "candidate_path_resolved": binder.get("candidate_path_resolved"),
            "review_status": binder.get("review_status"),
            "ready_for_batch_draft": bool(not blockers and skipped_reason is None),
            "skipped_reason": skipped_reason,
            "blockers": blockers,
        })
    rows.sort(key=lambda r: (not r.get("ready_for_batch_draft"), r.get("engine_family") or ""))
    return rows


def _patch101_parse_limit(arg: str) -> int:
    raw = (arg or "").strip()
    if not raw:
        return LLM_ENGINE_REVIEW_BATCH_RUN_DEFAULT_LIMIT
    try:
        n = int(raw.split()[0])
    except Exception:
        return LLM_ENGINE_REVIEW_BATCH_RUN_DEFAULT_LIMIT
    return max(1, min(LLM_ENGINE_REVIEW_BATCH_RUN_MAX_LIMIT, n))


def _patch101_write_run_report(report: dict) -> tuple[Path, Path]:
    LLM_ENGINE_REVIEW_BATCH_RUN_DIR.mkdir(parents=True, exist_ok=True)
    now = report.get("created_at") or _patch101_now()
    json_path = LLM_ENGINE_REVIEW_BATCH_RUN_DIR / f"{now}_{LLM_ENGINE_REVIEW_BATCH_RUN_PREFIX}.json"
    md_path = LLM_ENGINE_REVIEW_BATCH_RUN_DIR / f"{now}_{LLM_ENGINE_REVIEW_BATCH_RUN_PREFIX}.md"
    latest_json = LLM_ENGINE_REVIEW_BATCH_RUN_DIR / f"latest_{LLM_ENGINE_REVIEW_BATCH_RUN_PREFIX}.json"
    latest_md = LLM_ENGINE_REVIEW_BATCH_RUN_DIR / f"latest_{LLM_ENGINE_REVIEW_BATCH_RUN_PREFIX}.md"
    _patch101_write_json(json_path, report)
    _patch101_write_json(latest_json, report)
    lines = [
        "# Patch 101 LLM Engine Review Batch Run",
        "",
        f"Status: `{report.get('status')}`",
        f"Requested limit: `{report.get('requested_limit')}`",
        f"Drafted: `{(report.get('counts') or {}).get('drafted')}`",
        f"Ready remaining after run: `{(report.get('counts') or {}).get('ready_remaining_after_run')}`",
        "",
        "Authority: LLM draft generation only. No canonical decisions, no review ledger mutation, no engine writes.",
        "",
        "## Drafted Engines",
    ]
    for row in report.get("drafted_rows") or []:
        lines.append(f"- `{row.get('engine_family')}` — `{row.get('status')}` — llm=`{row.get('llm_status')}` — evidence `{row.get('evidence_id')}`")
    if report.get("blockers"):
        lines.extend(["", "## Blockers"])
        for b in report.get("blockers") or []:
            lines.append(f"- {b}")
    md_text = "\n".join(lines) + "\n"
    md_path.write_text(md_text, encoding="utf-8")
    latest_md.write_text(md_text, encoding="utf-8")
    return json_path, md_path


def _patch101_latest_run_path(arg: str | None = None) -> Path | None:
    target = (arg or "latest").strip()
    if target == "latest":
        p = LLM_ENGINE_REVIEW_BATCH_RUN_DIR / f"latest_{LLM_ENGINE_REVIEW_BATCH_RUN_PREFIX}.json"
        if p.exists():
            return p
    if not LLM_ENGINE_REVIEW_BATCH_RUN_DIR.exists():
        return None
    matches = sorted(LLM_ENGINE_REVIEW_BATCH_RUN_DIR.glob(f"*_{LLM_ENGINE_REVIEW_BATCH_RUN_PREFIX}.json"))
    matches = [p for p in matches if not p.name.startswith("latest_")]
    return matches[-1] if matches else None


def cmd_llm_engine_review_batch_run_policy(session_id: str) -> None:
    """Show Patch 101 LLM batch run policy. Usage: llm-engine-review-batch-run-policy"""
    from agents.forge.memory import write_audit_entry
    print()
    print("── LLM Engine Review Batch Run Policy ───────────────")
    print("  Patch     : 101")
    print("  Purpose   : draft several LLM engine reviews in a controlled small batch")
    print("  Default   :", LLM_ENGINE_REVIEW_BATCH_RUN_DEFAULT_LIMIT, "engine drafts")
    print("  Maximum   :", LLM_ENGINE_REVIEW_BATCH_RUN_MAX_LIMIT, "engine drafts per run")
    print("  Uses      : existing evidence binders + source-law chunk proof + review gateway")
    print("  Still NO  : canonical decisions, ledger mutation, engine edits, Chroma writes, shell")
    print("  Next      : run llm-engine-review-batch-run-plan then llm-engine-review-batch-run 3")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "LLM_ENGINE_REVIEW_BATCH_RUN_POLICY_SHOWN", str(LLM_ENGINE_REVIEW_BATCH_RUN_DIR), "patch101", "no_canonical_authority")


def cmd_llm_engine_review_batch_run_plan(session_id: str) -> None:
    """Show Patch 101 batch draft candidates. Usage: llm-engine-review-batch-run-plan"""
    from agents.forge.memory import write_audit_entry
    rows = _patch101_candidate_rows()
    ready = [r for r in rows if r.get("ready_for_batch_draft")]
    skipped = [r for r in rows if r.get("skipped_reason")]
    blocked = [r for r in rows if r.get("blockers")]
    now = _patch101_now()
    plan = {
        "schema_version": LLM_ENGINE_REVIEW_BATCH_RUN_SCHEMA_VERSION,
        "report_type": "LLM_ENGINE_REVIEW_BATCH_RUN_PLAN_V1_PATCH101",
        "created_at": now,
        "status": "LLM_ENGINE_REVIEW_BATCH_RUN_PLAN_READY",
        "counts": {"total_evidence_binders": len(rows), "ready_for_batch_run": len(ready), "skipped_existing_or_decided": len(skipped), "blocked": len(blocked)},
        "next_batch_preview": ready[:LLM_ENGINE_REVIEW_BATCH_RUN_MAX_LIMIT],
        "blocked_preview": blocked[:20],
        "authority": _patch101_authority(),
    }
    LLM_ENGINE_REVIEW_BATCH_RUN_DIR.mkdir(parents=True, exist_ok=True)
    path = LLM_ENGINE_REVIEW_BATCH_RUN_DIR / f"{now}_llm_engine_review_batch_run_plan_v1.json"
    _patch101_write_json(path, plan)
    print()
    print("── LLM Engine Review Batch Run Plan ─────────────────")
    print("  Ready for batch draft:", len(ready))
    print("  Skipped existing/decided:", len(skipped))
    print("  Blocked:", len(blocked))
    print("  Next batch preview:")
    for r in ready[:LLM_ENGINE_REVIEW_BATCH_RUN_MAX_LIMIT]:
        print("   -", r.get("engine_family"), "|", r.get("evidence_id"))
    print("  Authority: NO canonical decision")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "LLM_ENGINE_REVIEW_BATCH_RUN_PLAN_WRITTEN", str(path), f"ready={len(ready)}", f"blocked={len(blocked)}")


def cmd_llm_engine_review_batch_run(arg: str, session_id: str) -> None:
    """Run a small Patch 101 LLM draft batch. Usage: llm-engine-review-batch-run [1-5]"""
    from agents.forge.memory import write_audit_entry
    limit = _patch101_parse_limit(arg)
    rows = [r for r in _patch101_candidate_rows() if r.get("ready_for_batch_draft")]
    selected = rows[:limit]
    now = _patch101_now()
    drafted_rows = []
    blockers = []
    print()
    print("── LLM Engine Review Batch Run ──────────────────────")
    print("  Requested limit:", limit)
    print("  Selected:", len(selected))
    print("  Note: each selected engine may call the local model; this can take a bit.")
    print("──────────────────────────────────────────────────────")
    print()
    for r in selected:
        fam = r.get("engine_family")
        try:
            draft = _patch98_make_draft(fam)
            json_path, md_path = _patch98_write_draft(draft)
            llm_status = ((draft.get("llm_invocation") or {}).get("status")) or "NO_LLM_INVOCATION_RECORDED"
            drafted_rows.append({
                "engine_family": fam,
                "status": draft.get("status"),
                "draft_id": draft.get("draft_id"),
                "draft_path": str(json_path),
                "draft_sha256": _patch101_sha256(json_path),
                "evidence_id": draft.get("evidence_id"),
                "llm_status": llm_status,
                "recommendation": (draft.get("plain_english_brief") or {}).get("recommendation"),
            })
            print(f"[forge] Drafted {fam}: {draft.get('status')} | llm={llm_status}")
        except Exception as exc:
            msg = f"{fam}: {repr(exc)[:500]}"
            blockers.append(msg)
            print("[forge] Draft error:", msg)
    remaining = [r for r in _patch101_candidate_rows() if r.get("ready_for_batch_draft")]
    report = {
        "schema_version": LLM_ENGINE_REVIEW_BATCH_RUN_SCHEMA_VERSION,
        "report_type": "LLM_ENGINE_REVIEW_BATCH_RUN_RECEIPT_V1_PATCH101",
        "created_at": now,
        "status": "LLM_ENGINE_REVIEW_BATCH_RUN_COMPLETED_NO_CANONICAL_AUTHORITY" if drafted_rows else "LLM_ENGINE_REVIEW_BATCH_RUN_NO_DRAFTS_WRITTEN",
        "requested_limit": limit,
        "counts": {"selected": len(selected), "drafted": len(drafted_rows), "errors": len(blockers), "ready_remaining_after_run": len(remaining)},
        "drafted_rows": drafted_rows,
        "blockers": blockers,
        "warnings": [],
        "authority": _patch101_authority(),
        "next_step": "Run llm-engine-review-batch-run-show latest, then engine-review-queue-build when enough drafts exist.",
    }
    json_path, md_path = _patch101_write_run_report(report)
    print()
    print("── LLM Engine Review Batch Run Complete ─────────────")
    print("  Status  :", report.get("status"))
    print("  Drafted :", len(drafted_rows))
    print("  Errors  :", len(blockers))
    print("  JSON    :", json_path)
    print("  Markdown:", md_path)
    print("  Authority: NO canonical decision")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "LLM_ENGINE_REVIEW_BATCH_RUN_WRITTEN", str(json_path), f"drafted={len(drafted_rows)}", f"errors={len(blockers)}")


def cmd_llm_engine_review_batch_run_show(arg: str, session_id: str) -> None:
    """Show latest Patch 101 batch run receipt with full visible LLM reviews. Usage: llm-engine-review-batch-run-show [latest]"""
    from agents.forge.memory import write_audit_entry
    path = _patch101_latest_run_path(arg)
    if not path:
        print("[forge] No Patch 101 batch run receipt found. Run llm-engine-review-batch-run first.")
        return
    report = _patch101_read_json(path)
    print()
    print("── LLM Engine Review Batch Run Receipt ──────────────")
    print("  Status :", report.get("status"))
    print("  Path   :", path)
    print("  Drafted:", (report.get("counts") or {}).get("drafted"))
    print("  Errors :", (report.get("counts") or {}).get("errors"))
    print("  Ready remaining:", (report.get("counts") or {}).get("ready_remaining_after_run"))
    print("  Authority: draft display only; NO approval, NO canonical ledger mutation")
    print()
    print("  Drafted engines:")
    for r in report.get("drafted_rows") or []:
        print("   -", r.get("engine_family"), "|", r.get("llm_status"), "|", r.get("evidence_id"))
    if report.get("blockers"):
        print("  Blockers:")
        for b in report.get("blockers") or []:
            print("   -", b)

    # Patch 101.1 visibility fix:
    # Immediately print the full visible LLM reviews for drafted engines so Nic
    # can verify the model's recommendation instead of seeing only stubs.
    drafted = report.get("drafted_rows") or []
    if drafted:
        print()
        print("── Full Visible LLM Review Text For This Batch ──────")
        for r in drafted:
            fam = r.get("engine_family")
            d, draft_path, err = _patch99_load_latest_draft(fam)
            print()
            print("══════════════════════════════════════════════════════")
            print(f"ENGINE: {fam}")
            print("══════════════════════════════════════════════════════")
            if err:
                print("  Status: DRAFT_NOT_READABLE")
                print("  Reason:", err)
                print("  Expected command to inspect manually:")
                print(f"    llm-engine-review-show {fam}")
                continue
            for line in _patch99_format_draft_for_terminal(d):
                print("  " + line if line else "")
            print()
            print(f"  Manual inspect command: engine-review-queue-show {fam}")
    else:
        print()
        print("  No drafted engines found in this batch receipt.")

    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "LLM_ENGINE_REVIEW_BATCH_RUN_SHOWN", str(path), report.get("status", "?"), "full_visible_reviews_displayed")


def cmd_llm_engine_review_batch_run_export(session_id: str) -> None:
    """Export Patch 101 batch run receipts. Usage: llm-engine-review-batch-run-export"""
    from agents.forge.memory import write_audit_entry
    LLM_ENGINE_REVIEW_BATCH_RUN_DIR.mkdir(parents=True, exist_ok=True)
    receipts = []
    for path in sorted(LLM_ENGINE_REVIEW_BATCH_RUN_DIR.glob(f"*_{LLM_ENGINE_REVIEW_BATCH_RUN_PREFIX}.json")):
        if path.name.startswith("latest_"):
            continue
        try:
            d = _patch101_read_json(path)
            receipts.append({"path": str(path), "sha256": _patch101_sha256(path), "status": d.get("status"), "drafted": (d.get("counts") or {}).get("drafted")})
        except Exception:
            continue
    now = _patch101_now()
    export = {
        "schema_version": LLM_ENGINE_REVIEW_BATCH_RUN_SCHEMA_VERSION,
        "report_type": "LLM_ENGINE_REVIEW_BATCH_RUN_EXPORT_V1_PATCH101",
        "created_at": now,
        "counts": {"receipts": len(receipts)},
        "receipts": receipts,
        "authority": _patch101_authority(),
    }
    json_path = LLM_ENGINE_REVIEW_BATCH_RUN_DIR / f"{now}_{LLM_ENGINE_REVIEW_BATCH_RUN_EXPORT_PREFIX}.json"
    md_path = LLM_ENGINE_REVIEW_BATCH_RUN_DIR / f"{now}_{LLM_ENGINE_REVIEW_BATCH_RUN_EXPORT_PREFIX}.md"
    _patch101_write_json(json_path, export)
    lines = ["# Patch 101 LLM Engine Review Batch Run Export", "", f"Receipts: `{len(receipts)}`", ""]
    for r in receipts:
        lines.append(f"- `{r.get('path')}` — `{r.get('status')}` — drafted `{r.get('drafted')}`")
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    print()
    print("── LLM Engine Review Batch Run Export ───────────────")
    print("  JSON    :", json_path)
    print("  Markdown:", md_path)
    print("  Receipts:", len(receipts))
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "LLM_ENGINE_REVIEW_BATCH_RUN_EXPORT_WRITTEN", str(json_path), f"receipts={len(receipts)}", "read-only")


# ─────────────────────────────────────────────────────────────────────────────
# Patch 102 — Engine Review Evidence Cross-Check
# Purpose: show the local LLM review side-by-side with bound evidence so Nic can
# verify recommendations and spot confabulation before approval/commit.
# ─────────────────────────────────────────────────────────────────────────────

from pathlib import Path as _Patch102Path

ENGINE_REVIEW_EVIDENCE_DIR = _Patch102Path.home() / "forge" / "memory" / "engine_review_evidence_crosschecks_v1"
ENGINE_REVIEW_EVIDENCE_SCHEMA_VERSION = "engine_review_evidence_crosscheck_v1_patch102"
ENGINE_REVIEW_EVIDENCE_PREFIX = "engine_review_evidence_crosscheck_v1"
ENGINE_REVIEW_EVIDENCE_EXPORT_PREFIX = "engine_review_evidence_crosscheck_export_v1"

def _patch102_now() -> str:
    from datetime import datetime
    return datetime.now().strftime("%Y-%m-%d_%H%M%S")

def _patch102_sha256(path) -> str:
    import hashlib
    h = hashlib.sha256()
    p = _Patch102Path(path)
    with p.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()

def _patch102_read_json(path) -> dict:
    import json
    return json.loads(_Patch102Path(path).read_text(encoding="utf-8"))

def _patch102_write_json(path, data: dict) -> None:
    import json
    p = _Patch102Path(path)
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, indent=2, sort_keys=True) + "\n", encoding="utf-8")

def _patch102_authority() -> dict:
    return {
        "patch": "102",
        "mode": "ENGINE_REVIEW_EVIDENCE_CROSSCHECK_READ_ONLY",
        "writes": str(ENGINE_REVIEW_EVIDENCE_DIR),
        "canonical_decision_authority": False,
        "engine_file_write_authority": False,
        "review_ledger_write_authority": False,
        "chroma_write_authority": False,
        "ingestion_write_authority": False,
        "shell_execution_authority": False,
        "project_write_authority": False,
        "rule": "Show LLM review beside bound evidence. This is a verification aid only, not approval."
    }

def _patch102_section(text: str, heading: str) -> str:
    import re
    if not text:
        return ""
    headings = [
        "Plain-English Purpose", "Likely System Role", "Evidence Used",
        "Risks / Uncertainties", "Recommendation Draft", "Suggested Nic Action"
    ]
    pattern = r"(?im)^" + re.escape(heading) + r"\s*:?\s*$"
    m = re.search(pattern, text)
    if not m:
        # also accept heading on same line with content
        pattern2 = r"(?im)^" + re.escape(heading) + r"\s*:?\s*(.*)$"
        m2 = re.search(pattern2, text)
        if not m2:
            return ""
        start = m2.start(1)
    else:
        start = m.end()
    next_pos = len(text)
    for h in headings:
        if h == heading:
            continue
        nm = re.search(r"(?im)^" + re.escape(h) + r"\s*:?", text[start:])
        if nm:
            next_pos = min(next_pos, start + nm.start())
    return text[start:next_pos].strip()

def _patch102_normalize_engine_arg(arg: str) -> str:
    return (arg or "").strip().split()[0] if arg else ""

def _patch102_load_draft_and_binder(engine_family: str):
    # Uses Patch 99 loader when present because it already handles latest aliases.
    if "_patch99_load_latest_draft" in globals():
        draft, draft_path, err = _patch99_load_latest_draft(engine_family)
        if err:
            return None, None, None, None, err
    else:
        return None, None, None, None, "Patch 99 draft loader unavailable"

    binder_path = draft.get("evidence_binder_path") or ""
    if binder_path:
        bp = _Patch102Path(binder_path)
    else:
        bp = _Patch102Path.home() / "forge" / "memory" / "engine_evidence_binders_v1" / f"latest_{engine_family}_engine_evidence_binder.json"
    if not bp.exists():
        return draft, draft_path, None, bp, f"Evidence binder not found: {bp}"
    try:
        binder = _patch102_read_json(bp)
    except Exception as e:
        return draft, draft_path, None, bp, f"Evidence binder unreadable: {e}"
    return draft, draft_path, binder, bp, None

def _patch102_keyword_hits(llm_text: str, binder: dict) -> dict:
    text_low = (llm_text or "").lower()
    hits = {
        "functions_mentioned": [],
        "imports_mentioned": [],
        "classes_mentioned": [],
        "file_names_mentioned": [],
        "evidence_terms_present": [],
    }
    for fe in binder.get("file_evidence") or []:
        for fn in fe.get("functions_sample") or []:
            if fn and fn.lower() in text_low:
                hits["functions_mentioned"].append(fn)
        for cl in fe.get("classes_sample") or []:
            if cl and cl.lower() in text_low:
                hits["classes_mentioned"].append(cl)
        for imp in fe.get("imports_sample") or []:
            # match module-ish fragments without requiring whole import line
            parts = [x.strip(", ") for x in imp.replace("from ", "").replace("import ", "").split() if len(x.strip(", ")) > 2]
            if any(part.lower() in text_low for part in parts):
                hits["imports_mentioned"].append(imp)
        rel = fe.get("relative_to_candidate") or _Patch102Path(fe.get("path","")).name
        if rel and _Patch102Path(rel).name.lower() in text_low:
            hits["file_names_mentioned"].append(rel)
    # de-dupe
    for k, v in list(hits.items()):
        seen = []
        for item in v:
            if item not in seen:
                seen.append(item)
        hits[k] = seen
    return hits

def _patch102_build_crosscheck(engine_family: str):
    engine_family = _patch102_normalize_engine_arg(engine_family)
    if not engine_family:
        return None, None, None, "REFUSED_NO_ENGINE_FAMILY"
    draft, draft_path, binder, binder_path, err = _patch102_load_draft_and_binder(engine_family)
    if err:
        report = {
            "schema_version": ENGINE_REVIEW_EVIDENCE_SCHEMA_VERSION,
            "report_type": "ENGINE_REVIEW_EVIDENCE_CROSSCHECK_V1_PATCH102",
            "created_at": _patch102_now(),
            "engine_family": engine_family,
            "status": "REFUSED_EVIDENCE_NOT_AVAILABLE",
            "blockers": [err],
            "warnings": [],
            "authority": _patch102_authority(),
        }
        return report, None, None, None

    llm_text = (draft.get("llm_visible_review_text") or (draft.get("llm_invocation") or {}).get("visible_response") or "").strip()
    brief = draft.get("plain_english_brief") or {}
    file_rows = []
    for fe in binder.get("file_evidence") or []:
        file_rows.append({
            "path": fe.get("path"),
            "relative_to_candidate": fe.get("relative_to_candidate"),
            "sha256": fe.get("sha256"),
            "size_bytes": fe.get("size_bytes"),
            "line_count": fe.get("line_count"),
            "imports_sample": fe.get("imports_sample") or [],
            "functions_sample": fe.get("functions_sample") or [],
            "classes_sample": fe.get("classes_sample") or [],
            "excerpt_start": fe.get("excerpt_start") or "",
            "excerpt_sha256": fe.get("excerpt_sha256"),
        })

    sections = {
        "plain_english_purpose": _patch102_section(llm_text, "Plain-English Purpose"),
        "likely_system_role": _patch102_section(llm_text, "Likely System Role"),
        "evidence_used": _patch102_section(llm_text, "Evidence Used"),
        "risks_uncertainties": _patch102_section(llm_text, "Risks / Uncertainties"),
        "recommendation_draft": _patch102_section(llm_text, "Recommendation Draft"),
        "suggested_nic_action": _patch102_section(llm_text, "Suggested Nic Action"),
    }
    keyword_hits = _patch102_keyword_hits(llm_text, binder)
    warnings = []
    blockers = []
    if not llm_text:
        blockers.append("No LLM visible review text found for this engine.")
    if not file_rows:
        blockers.append("No file evidence rows found in binder.")
    if "Evidence Used" not in llm_text:
        warnings.append("LLM review does not contain an explicit Evidence Used heading.")
    if not any(keyword_hits.values()):
        warnings.append("No simple keyword overlap found between LLM text and bound code samples. This does not prove confabulation, but Nic should inspect carefully.")
    if brief.get("likely_system_role") and sections.get("likely_system_role") and str(brief.get("likely_system_role")).lower() not in sections.get("likely_system_role","").lower():
        warnings.append("LLM role wording does not explicitly repeat deterministic role label.")

    status = "EVIDENCE_CROSSCHECK_READY_NO_AUTHORITY" if not blockers else "EVIDENCE_CROSSCHECK_BLOCKED"
    now = _patch102_now()
    report = {
        "schema_version": ENGINE_REVIEW_EVIDENCE_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_EVIDENCE_CROSSCHECK_V1_PATCH102",
        "created_at": now,
        "crosscheck_id": f"ERE-{engine_family}-{now}",
        "engine_family": engine_family,
        "status": status,
        "draft_path": str(draft_path),
        "draft_sha256": _patch102_sha256(draft_path),
        "evidence_binder_path": str(binder_path),
        "evidence_binder_sha256": _patch102_sha256(binder_path),
        "evidence_id": draft.get("evidence_id") or binder.get("evidence_id"),
        "candidate_path": draft.get("candidate_path_resolved") or binder.get("candidate_path_resolved"),
        "llm_invocation": draft.get("llm_invocation") or {},
        "llm_visible_review_text": llm_text,
        "llm_sections": sections,
        "deterministic_brief": brief,
        "bound_file_evidence": file_rows,
        "keyword_overlap": keyword_hits,
        "source_law_basis": brief.get("source_law_basis") or {},
        "manual_verification_rule": "Use this report to compare the LLM review against exact file evidence. If a claim is not visible in the bound evidence or source-law basis, defer the engine instead of approving.",
        "warnings": warnings,
        "blockers": blockers,
        "authority": _patch102_authority(),
    }
    ENGINE_REVIEW_EVIDENCE_DIR.mkdir(parents=True, exist_ok=True)
    json_path = ENGINE_REVIEW_EVIDENCE_DIR / f"{now}_{engine_family}_{ENGINE_REVIEW_EVIDENCE_PREFIX}.json"
    md_path = ENGINE_REVIEW_EVIDENCE_DIR / f"{now}_{engine_family}_{ENGINE_REVIEW_EVIDENCE_PREFIX}.md"
    _patch102_write_json(json_path, report)
    _patch102_write_markdown(md_path, report)
    _patch102_write_json(ENGINE_REVIEW_EVIDENCE_DIR / f"latest_{engine_family}_{ENGINE_REVIEW_EVIDENCE_PREFIX}.json", report)
    (ENGINE_REVIEW_EVIDENCE_DIR / f"latest_{engine_family}_{ENGINE_REVIEW_EVIDENCE_PREFIX}.md").write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")
    _patch102_write_json(ENGINE_REVIEW_EVIDENCE_DIR / f"latest_{ENGINE_REVIEW_EVIDENCE_PREFIX}.json", report)
    (ENGINE_REVIEW_EVIDENCE_DIR / f"latest_{ENGINE_REVIEW_EVIDENCE_PREFIX}.md").write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")
    return report, json_path, md_path, None

def _patch102_write_markdown(path, report: dict) -> None:
    lines = []
    lines.append("# Patch 102 Engine Review Evidence Cross-Check")
    lines.append("")
    lines.append(f"Engine: `{report.get('engine_family')}`")
    lines.append(f"Status: `{report.get('status')}`")
    lines.append(f"Evidence ID: `{report.get('evidence_id')}`")
    lines.append(f"Candidate path: `{report.get('candidate_path')}`")
    lines.append("")
    inv = report.get("llm_invocation") or {}
    lines.append("## LLM Invocation")
    lines.append(f"- Called: `{inv.get('called')}`")
    lines.append(f"- Provider: `{inv.get('provider')}`")
    lines.append(f"- Model: `{inv.get('model')}`")
    lines.append(f"- Status: `{inv.get('status')}`")
    lines.append(f"- Hidden reasoning stored: `{inv.get('hidden_reasoning_stored')}`")
    lines.append("")
    lines.append("## Local LLM Visible Review")
    lines.append("")
    lines.append(report.get("llm_visible_review_text") or "_No LLM visible review text found._")
    lines.append("")
    lines.append("## Bound Evidence Files")
    for fe in report.get("bound_file_evidence") or []:
        lines.append("")
        lines.append(f"### `{fe.get('relative_to_candidate') or fe.get('path')}`")
        lines.append(f"- Path: `{fe.get('path')}`")
        lines.append(f"- SHA-256: `{fe.get('sha256')}`")
        lines.append(f"- Lines: `{fe.get('line_count')}`")
        if fe.get("imports_sample"):
            lines.append(f"- Imports sample: `{', '.join(fe.get('imports_sample'))}`")
        if fe.get("functions_sample"):
            lines.append(f"- Functions sample: `{', '.join(fe.get('functions_sample'))}`")
        if fe.get("classes_sample"):
            lines.append(f"- Classes sample: `{', '.join(fe.get('classes_sample'))}`")
        lines.append("")
        lines.append("```text")
        excerpt = (fe.get("excerpt_start") or "")[:2200]
        lines.append(excerpt.rstrip())
        lines.append("```")
    lines.append("")
    lines.append("## Simple Keyword Overlap")
    for k, v in (report.get("keyword_overlap") or {}).items():
        lines.append(f"- {k}: `{', '.join(v) if v else 'none'}`")
    lines.append("")
    if report.get("warnings"):
        lines.append("## Warnings")
        for w in report.get("warnings") or []:
            lines.append(f"- {w}")
        lines.append("")
    if report.get("blockers"):
        lines.append("## Blockers")
        for b in report.get("blockers") or []:
            lines.append(f"- {b}")
        lines.append("")
    lines.append("## Authority")
    lines.append("This report is for human verification only. It does not approve, reject, mutate the ledger, edit engine files, or create lockfile authority.")
    _Patch102Path(path).write_text("\n".join(lines) + "\n", encoding="utf-8")

def _patch102_print_report(report: dict) -> None:
    print()
    print("── Engine Review Evidence Cross-Check ───────────────")
    print("  Engine     :", report.get("engine_family"))
    print("  Status     :", report.get("status"))
    print("  Evidence ID:", report.get("evidence_id"))
    print("  Candidate  :", report.get("candidate_path"))
    inv = report.get("llm_invocation") or {}
    print("  LLM called :", inv.get("called"))
    print("  LLM model  :", inv.get("model"))
    print("  LLM status :", inv.get("status"))
    print("  Authority  : NO approval, NO ledger mutation, NO engine writes")
    print()
    print("── Local LLM Visible Review ─────────────────────────")
    llm_text = (report.get("llm_visible_review_text") or "").strip()
    if llm_text:
        for line in llm_text.splitlines():
            print("  " + line if line else "")
    else:
        print("  No LLM visible review text found.")
    print()
    print("── Bound Evidence Files ─────────────────────────────")
    for fe in report.get("bound_file_evidence") or []:
        print()
        print("  File:", fe.get("relative_to_candidate") or fe.get("path"))
        print("  Path:", fe.get("path"))
        print("  SHA :", fe.get("sha256"))
        if fe.get("imports_sample"):
            print("  Imports:", ", ".join(fe.get("imports_sample")))
        if fe.get("functions_sample"):
            print("  Functions:", ", ".join(fe.get("functions_sample")))
        if fe.get("classes_sample"):
            print("  Classes:", ", ".join(fe.get("classes_sample")))
        excerpt = (fe.get("excerpt_start") or "").rstrip()
        if excerpt:
            print("  Excerpt:")
            for line in excerpt.splitlines()[:40]:
                print("    " + line)
    print()
    print("── Simple Keyword Overlap ───────────────────────────")
    for k, v in (report.get("keyword_overlap") or {}).items():
        print(" ", k + ":", ", ".join(v) if v else "none")
    if report.get("warnings"):
        print()
        print("  Warnings:")
        for w in report.get("warnings") or []:
            print("   -", w)
    if report.get("blockers"):
        print()
        print("  Blockers:")
        for b in report.get("blockers") or []:
            print("   -", b)
    print()
    print("  Manual rule: If the LLM claims something not visible in the evidence above, defer it.")
    print("──────────────────────────────────────────────────────")
    print()

