def cmd_engine_review_evidence_batch_plan(session_id: str) -> None:
    """List draft reviews ready for evidence cross-check. Usage: engine-review-evidence-batch-plan"""
    from agents.forge.memory import write_audit_entry
    rows = []
    if "LLM_ENGINE_REVIEW_DRAFT_DIR" in globals() and LLM_ENGINE_REVIEW_DRAFT_DIR.exists():
        for path in sorted(LLM_ENGINE_REVIEW_DRAFT_DIR.glob("latest_*_llm_engine_review_draft.json")):
            try:
                d = _patch102_read_json(path)
                fam = d.get("engine_family")
                if fam:
                    report_path = ENGINE_REVIEW_EVIDENCE_DIR / f"latest_{fam}_{ENGINE_REVIEW_EVIDENCE_PREFIX}.json"
                    rows.append({
                        "engine_family": fam,
                        "draft_path": str(path),
                        "draft_sha256": _patch102_sha256(path),
                        "evidence_id": d.get("evidence_id"),
                        "llm_status": (d.get("llm_invocation") or {}).get("status"),
                        "crosscheck_exists": report_path.exists(),
                    })
            except Exception:
                continue
    print()
    print("── Engine Review Evidence Batch Plan ─────────────────")
    print("  Drafts found:", len(rows))
    print("  Authority   : plan only; NO approval, NO ledger mutation")
    for r in rows[:80]:
        print(f"   - {r.get('engine_family')} | llm={r.get('llm_status')} | evidence={r.get('evidence_id')} | checked={r.get('crosscheck_exists')}")
        print(f"     Run: engine-review-evidence-check {r.get('engine_family')}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_EVIDENCE_BATCH_PLAN_SHOWN", str(ENGINE_REVIEW_EVIDENCE_DIR), f"drafts={len(rows)}", "plan_only")

def cmd_engine_review_evidence_check(arg: str, session_id: str) -> None:
    """Build and show an evidence cross-check for one engine. Usage: engine-review-evidence-check <engine_family>"""
    from agents.forge.memory import write_audit_entry
    engine = _patch102_normalize_engine_arg(arg)
    report, json_path, md_path, err = _patch102_build_crosscheck(engine)
    if err and report is None:
        print("[forge] Evidence cross-check failed:", err)
        return
    _patch102_print_report(report)
    if json_path:
        print("  JSON    :", json_path)
        print("  Markdown:", md_path)
        print()
    write_audit_entry(session_id, "ENGINE_REVIEW_EVIDENCE_CROSSCHECK_WRITTEN", str(json_path or "-"), report.get("engine_family", engine), report.get("status", "unknown"))

def cmd_engine_review_evidence_show(arg: str, session_id: str) -> None:
    """Show latest evidence cross-check. Usage: engine-review-evidence-show [latest|engine_family]"""
    from agents.forge.memory import write_audit_entry
    arg = (arg or "latest").strip()
    if arg.lower() == "latest":
        path = ENGINE_REVIEW_EVIDENCE_DIR / f"latest_{ENGINE_REVIEW_EVIDENCE_PREFIX}.json"
    else:
        engine = _patch102_normalize_engine_arg(arg)
        path = ENGINE_REVIEW_EVIDENCE_DIR / f"latest_{engine}_{ENGINE_REVIEW_EVIDENCE_PREFIX}.json"
    if not path.exists():
        print()
        print("── Engine Review Evidence Show ───────────────────────")
        print("  Status: NO_CROSSCHECK_FOUND")
        print("  Run   : engine-review-evidence-check <engine_family>")
        print("──────────────────────────────────────────────────────")
        print()
        return
    report = _patch102_read_json(path)
    _patch102_print_report(report)
    write_audit_entry(session_id, "ENGINE_REVIEW_EVIDENCE_CROSSCHECK_SHOWN", str(path), report.get("engine_family", arg), "shown")

def cmd_engine_review_evidence_export(session_id: str) -> None:
    """Export Patch 102 evidence cross-check index. Usage: engine-review-evidence-export"""
    from agents.forge.memory import write_audit_entry
    ENGINE_REVIEW_EVIDENCE_DIR.mkdir(parents=True, exist_ok=True)
    receipts = []
    for path in sorted(ENGINE_REVIEW_EVIDENCE_DIR.glob(f"*_{ENGINE_REVIEW_EVIDENCE_PREFIX}.json")):
        if path.name.startswith("latest_"):
            continue
        try:
            d = _patch102_read_json(path)
            receipts.append({
                "engine_family": d.get("engine_family"),
                "status": d.get("status"),
                "path": str(path),
                "sha256": _patch102_sha256(path),
                "evidence_id": d.get("evidence_id"),
                "llm_status": (d.get("llm_invocation") or {}).get("status"),
                "warnings": len(d.get("warnings") or []),
                "blockers": len(d.get("blockers") or []),
            })
        except Exception:
            continue
    now = _patch102_now()
    export = {
        "schema_version": ENGINE_REVIEW_EVIDENCE_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_EVIDENCE_CROSSCHECK_EXPORT_V1_PATCH102",
        "created_at": now,
        "counts": {"receipts": len(receipts)},
        "receipts": receipts,
        "authority": _patch102_authority(),
    }
    json_path = ENGINE_REVIEW_EVIDENCE_DIR / f"{now}_{ENGINE_REVIEW_EVIDENCE_EXPORT_PREFIX}.json"
    md_path = ENGINE_REVIEW_EVIDENCE_DIR / f"{now}_{ENGINE_REVIEW_EVIDENCE_EXPORT_PREFIX}.md"
    _patch102_write_json(json_path, export)
    lines = ["# Patch 102 Engine Review Evidence Cross-Check Export", "", f"Receipts: `{len(receipts)}`", ""]
    for r in receipts:
        lines.append(f"- `{r.get('engine_family')}` — `{r.get('status')}` — warnings `{r.get('warnings')}` — blockers `{r.get('blockers')}`")
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    print()
    print("── Engine Review Evidence Export ─────────────────────")
    print("  JSON    :", json_path)
    print("  Markdown:", md_path)
    print("  Receipts:", len(receipts))
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_EVIDENCE_EXPORT_WRITTEN", str(json_path), f"receipts={len(receipts)}", "read-only")



# ─── PATCH 103 — EVIDENCE-BASED HUMAN APPROVAL HELPER ───────────────────────
# Purpose: prevent human queue approval from being recorded unless a Patch 102
# evidence cross-check exists and shows the LLM review beside exact evidence.

from pathlib import Path as _Patch103Path

ENGINE_REVIEW_APPROVAL_DIR = _Patch103Path.home() / "forge" / "memory" / "engine_review_approval_helpers_v1"
ENGINE_REVIEW_APPROVAL_SCHEMA_VERSION = "engine_review_approval_helper_v1_patch103"
ENGINE_REVIEW_APPROVAL_PREFIX = "engine_review_approval_helper_v1"
ENGINE_REVIEW_APPROVAL_EXPORT_PREFIX = "engine_review_approval_helper_export_v1"


def _patch103_now() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch103_slug(value: str) -> str:
    return re.sub(r"[^a-zA-Z0-9_\-]+", "_", (value or "").strip()).strip("_").lower()


def _patch103_sha256(path) -> str | None:
    p = _Patch103Path(path)
    if not p.exists() or not p.is_file():
        return None
    h = hashlib.sha256()
    with p.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def _patch103_read_json(path) -> dict:
    return json.loads(_Patch103Path(path).read_text(encoding="utf-8"))


def _patch103_write_json(path, payload: dict) -> None:
    p = _Patch103Path(path)
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(payload, indent=2, ensure_ascii=False, sort_keys=True) + "\n", encoding="utf-8")


def _patch103_authority(queue_write_authority: bool = False) -> dict:
    return {
        "patch": "103",
        "mode": "EVIDENCE_BASED_APPROVAL_HELPER",
        "writes": [str(ENGINE_REVIEW_APPROVAL_DIR), str(ENGINE_REVIEW_QUEUE_DIR) if "ENGINE_REVIEW_QUEUE_DIR" in globals() else "engine_review_queue_v1"],
        "queue_decision_write_authority": bool(queue_write_authority),
        "review_ledger_write_authority": False,
        "canonical_decision_authority": False,
        "final_lockfile_authority": False,
        "engine_file_write_authority": False,
        "project_file_write_authority": False,
        "llm_autonomous_decision_authority": False,
        "shell_execution_authority": False,
        "chroma_write_authority": False,
        "ingestion_write_authority": False,
        "rule": "Patch 103 may record a queue decision only after a Patch 102 evidence cross-check exists. It never mutates the review ledger or engine files.",
    }


def _patch103_latest_crosscheck_path(engine_family: str) -> _Patch103Path | None:
    fam = _patch103_slug(engine_family)
    if not fam:
        return None
    if "ENGINE_REVIEW_EVIDENCE_DIR" in globals() and "ENGINE_REVIEW_EVIDENCE_PREFIX" in globals():
        p = ENGINE_REVIEW_EVIDENCE_DIR / f"latest_{fam}_{ENGINE_REVIEW_EVIDENCE_PREFIX}.json"
        if p.exists():
            return p
        # Some engine families contain repeated _engine in file aliases; fall back to glob.
        matches = sorted(ENGINE_REVIEW_EVIDENCE_DIR.glob(f"latest_{fam}*evidence_crosscheck_v1.json"), key=lambda x: x.stat().st_mtime, reverse=True)
        if matches:
            return matches[0]
    return None


def _patch103_queue_decision_dir() -> _Patch103Path:
    if "ENGINE_REVIEW_QUEUE_DIR" in globals():
        return ENGINE_REVIEW_QUEUE_DIR
    return _Patch103Path.home() / "forge" / "memory" / "engine_review_queue_v1"


def _patch103_queue_decision_prefix() -> str:
    if "ENGINE_REVIEW_QUEUE_DECISION_PREFIX" in globals():
        return ENGINE_REVIEW_QUEUE_DECISION_PREFIX
    return "engine_review_queue_decision_v1"


def _patch103_decision_value_to_label(decision_value: str) -> str:
    d = (decision_value or "").strip().upper()
    if d == "APPROVED_FOR_FUTURE_COMMIT":
        return "APPROVE"
    if d == "DEFERRED_FOR_MORE_REVIEW":
        return "DEFER"
    if d == "REJECTED_FROM_CANONICAL_REVIEW":
        return "REJECT"
    return "UNKNOWN"


def _patch103_build_check(engine_family: str) -> tuple[dict, _Patch103Path | None]:
    engine_family = _patch103_slug(engine_family)
    now = _patch103_now()
    blockers: list[str] = []
    warnings: list[str] = []
    x_path = _patch103_latest_crosscheck_path(engine_family)
    crosscheck = None
    if not engine_family:
        blockers.append("No engine family supplied.")
    elif not x_path or not x_path.exists():
        blockers.append("No Patch 102 evidence cross-check receipt found. Run: engine-review-evidence-check <engine_family>")
    else:
        try:
            crosscheck = _patch103_read_json(x_path)
        except Exception as e:
            blockers.append(f"Evidence cross-check receipt unreadable: {e}")
    if crosscheck:
        if crosscheck.get("status") != "EVIDENCE_CROSSCHECK_READY_NO_AUTHORITY":
            blockers.append(f"Evidence cross-check is not ready: {crosscheck.get('status')}")
        if crosscheck.get("blockers"):
            blockers.append("Evidence cross-check contains blockers; defer instead of approve.")
        inv = crosscheck.get("llm_invocation") or {}
        if not inv.get("called"):
            warnings.append("LLM invocation is not marked called=true. This may be deterministic fallback, inspect carefully.")
        if inv.get("hidden_reasoning_stored"):
            blockers.append("Hidden reasoning appears stored in receipt; refuse approval.")
        if not (crosscheck.get("llm_visible_review_text") or "").strip():
            blockers.append("No visible LLM review text in cross-check.")
        if not crosscheck.get("bound_file_evidence"):
            blockers.append("No bound file evidence in cross-check.")
        if crosscheck.get("warnings"):
            warnings.extend([f"Cross-check warning: {w}" for w in crosscheck.get("warnings")])
    status = "EVIDENCE_APPROVAL_CHECK_READY" if not blockers else "EVIDENCE_APPROVAL_CHECK_BLOCKED"
    report = {
        "schema_version": ENGINE_REVIEW_APPROVAL_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_APPROVAL_CHECK_V1_PATCH103",
        "created_at": now,
        "engine_family": engine_family,
        "status": status,
        "ready_for_evidence_based_queue_decision": not blockers,
        "crosscheck_path": str(x_path) if x_path else None,
        "crosscheck_sha256": _patch103_sha256(x_path) if x_path and x_path.exists() else None,
        "crosscheck_status": crosscheck.get("status") if crosscheck else None,
        "evidence_id": crosscheck.get("evidence_id") if crosscheck else None,
        "candidate_path": crosscheck.get("candidate_path") if crosscheck else None,
        "draft_path": crosscheck.get("draft_path") if crosscheck else None,
        "draft_sha256": crosscheck.get("draft_sha256") if crosscheck else None,
        "evidence_binder_path": crosscheck.get("evidence_binder_path") if crosscheck else None,
        "evidence_binder_sha256": crosscheck.get("evidence_binder_sha256") if crosscheck else None,
        "llm_invocation": crosscheck.get("llm_invocation") if crosscheck else {},
        "llm_visible_review_excerpt": (crosscheck.get("llm_visible_review_text") or "")[:4000] if crosscheck else "",
        "bound_file_count": len(crosscheck.get("bound_file_evidence") or []) if crosscheck else 0,
        "keyword_overlap": crosscheck.get("keyword_overlap") if crosscheck else {},
        "manual_verification_rule": "Approve only if the LLM-visible claims are supported by the bound evidence shown in the Patch 102 cross-check. If unsure, defer.",
        "warnings": warnings,
        "blockers": blockers,
        "authority": _patch103_authority(queue_write_authority=False),
    }
    return report, x_path


def _patch103_write_check_receipt(report: dict) -> tuple[_Patch103Path, _Patch103Path]:
    ENGINE_REVIEW_APPROVAL_DIR.mkdir(parents=True, exist_ok=True)
    fam = _patch103_slug(report.get("engine_family"))
    now = report.get("created_at") or _patch103_now()
    json_path = ENGINE_REVIEW_APPROVAL_DIR / f"{now}_{fam}_{ENGINE_REVIEW_APPROVAL_PREFIX}.json"
    md_path = ENGINE_REVIEW_APPROVAL_DIR / f"{now}_{fam}_{ENGINE_REVIEW_APPROVAL_PREFIX}.md"
    _patch103_write_json(json_path, report)
    _patch103_write_markdown(md_path, report)
    _patch103_write_json(ENGINE_REVIEW_APPROVAL_DIR / f"latest_{fam}_{ENGINE_REVIEW_APPROVAL_PREFIX}.json", report)
    (ENGINE_REVIEW_APPROVAL_DIR / f"latest_{fam}_{ENGINE_REVIEW_APPROVAL_PREFIX}.md").write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")
    _patch103_write_json(ENGINE_REVIEW_APPROVAL_DIR / f"latest_{ENGINE_REVIEW_APPROVAL_PREFIX}.json", report)
    (ENGINE_REVIEW_APPROVAL_DIR / f"latest_{ENGINE_REVIEW_APPROVAL_PREFIX}.md").write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")
    return json_path, md_path


def _patch103_write_markdown(path, report: dict) -> None:
    lines = []
    lines.append("# Patch 103 Evidence-Based Approval Helper")
    lines.append("")
    lines.append(f"Engine: `{report.get('engine_family')}`")
    lines.append(f"Status: `{report.get('status')}`")
    lines.append(f"Ready for queue decision: `{report.get('ready_for_evidence_based_queue_decision')}`")
    lines.append(f"Evidence ID: `{report.get('evidence_id')}`")
    lines.append(f"Candidate path: `{report.get('candidate_path')}`")
    lines.append(f"Cross-check: `{report.get('crosscheck_path')}`")
    lines.append("")
    lines.append("## LLM Visible Review Excerpt")
    lines.append("")
    lines.append("```text")
    lines.append((report.get("llm_visible_review_excerpt") or "").rstrip())
    lines.append("```")
    lines.append("")
    lines.append("## Verification Rule")
    lines.append(report.get("manual_verification_rule") or "")
    if report.get("warnings"):
        lines.append("")
        lines.append("## Warnings")
        for w in report.get("warnings") or []:
            lines.append(f"- {w}")
    if report.get("blockers"):
        lines.append("")
        lines.append("## Blockers")
        for b in report.get("blockers") or []:
            lines.append(f"- {b}")
    lines.append("")
    lines.append("## Authority")
    lines.append("This helper may write a queue decision receipt only after evidence cross-check passes. It never mutates the review ledger or engine files.")
    _Patch103Path(path).write_text("\n".join(lines) + "\n", encoding="utf-8")


def _patch103_print_check(report: dict) -> None:
    print()
    print("── Engine Review Evidence-Based Approval Check ───────")
    print("  Engine     :", report.get("engine_family"))
    print("  Status     :", report.get("status"))
    print("  Ready      :", report.get("ready_for_evidence_based_queue_decision"))
    print("  Evidence ID:", report.get("evidence_id"))
    print("  Candidate  :", report.get("candidate_path"))
    inv = report.get("llm_invocation") or {}
    print("  LLM called :", inv.get("called"))
    print("  LLM model  :", inv.get("model"))
    print("  Cross-check:", report.get("crosscheck_path"))
    print("  Authority  : NO ledger mutation, NO engine writes")
    if report.get("warnings"):
        print("  Warnings   :", len(report.get("warnings") or []))
    if report.get("blockers"):
        print("  Blockers:")
        for b in report.get("blockers") or []:
            print("   -", b)
    print()
    print("── LLM Visible Review Excerpt ────────────────────────")
    excerpt = (report.get("llm_visible_review_excerpt") or "").strip()
    if excerpt:
        for line in excerpt.splitlines()[:80]:
            print("  " + line if line else "")
    else:
        print("  No visible review text found.")
    print()
    print("  Rule: approve only if the LLM claims are supported by the Patch 102 evidence cross-check.")
    print("──────────────────────────────────────────────────────")
    print()


def _patch103_write_queue_decision(report: dict, decision_value: str) -> tuple[dict, _Patch103Path, _Patch103Path]:
    qdir = _patch103_queue_decision_dir()
    qdir.mkdir(parents=True, exist_ok=True)
    now = _patch103_now()
    fam = _patch103_slug(report.get("engine_family"))
    prefix = _patch103_queue_decision_prefix()
    decision = {
        "schema_version": globals().get("ENGINE_REVIEW_QUEUE_SCHEMA_VERSION", "engine_review_queue_v1_patch99"),
        "report_type": "ENGINE_REVIEW_QUEUE_DECISION_V1_PATCH103_EVIDENCE_BASED",
        "created_at": now,
        "decision_id": f"ERQ103-{fam}-{now}",
        "engine_family": report.get("engine_family"),
        "human_queue_decision": decision_value,
        "status": "EVIDENCE_BASED_HUMAN_QUEUE_DECISION_RECORDED_NO_LEDGER_MUTATION",
        "draft_path": report.get("draft_path"),
        "draft_sha256": report.get("draft_sha256"),
        "evidence_id": report.get("evidence_id"),
        "evidence_binder_path": report.get("evidence_binder_path"),
        "evidence_binder_sha256": report.get("evidence_binder_sha256"),
        "candidate_path": report.get("candidate_path"),
        "patch102_crosscheck_path": report.get("crosscheck_path"),
        "patch102_crosscheck_sha256": report.get("crosscheck_sha256"),
        "patch103_check_status": report.get("status"),
        "manual_verification_rule": report.get("manual_verification_rule"),
        "stale_evidence_rule": "Patch 100 must re-read candidate path and confirm live file SHA matches the evidence binder before ledger commit.",
        "authority": _patch103_authority(queue_write_authority=True),
    }
    json_path = qdir / f"{now}_{fam}_{prefix}.json"
    md_path = qdir / f"{now}_{fam}_{prefix}.md"
    _patch103_write_json(json_path, decision)
    lines = [
        "# Patch 103 Evidence-Based Queue Decision",
        "",
        f"Engine: `{decision.get('engine_family')}`",
        f"Decision: `{decision_value}`",
        f"Status: `{decision.get('status')}`",
        f"Evidence ID: `{decision.get('evidence_id')}`",
        f"Cross-check: `{decision.get('patch102_crosscheck_path')}`",
        "",
        "Authority: queue decision only; no ledger mutation, no engine writes.",
    ]
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    # Refresh Patch 99 queue report if helper exists.
    try:
        if "_patch99_write_queue_report" in globals():
            _patch99_write_queue_report()
    except Exception:
        pass
    return decision, json_path, md_path


