ENGINE_REVIEW_EVIDENCE_COMMIT_DIR = MEMORY_DIR / "engine_review_evidence_commits_v1"
ENGINE_REVIEW_EVIDENCE_COMMIT_SCHEMA_VERSION = "engine_review_evidence_commit_v1_patch104"
ENGINE_REVIEW_EVIDENCE_COMMIT_PLAN_PREFIX = "engine_review_evidence_commit_plan_v1"
ENGINE_REVIEW_EVIDENCE_COMMIT_RECEIPT_PREFIX = "engine_review_evidence_commit_receipt_v1"
ENGINE_REVIEW_EVIDENCE_COMMIT_EXPORT_PREFIX = "engine_review_evidence_commit_export_v1"
ENGINE_REVIEW_EVIDENCE_COMMIT_CONFIRM_TOKEN = "CONFIRM_COMMIT_EVIDENCE_REVIEW_QUEUE"


def _patch104_now() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch104_authority(commit_authority: bool = False) -> dict:
    return {
        "patch": "104",
        "mode": "EVIDENCE_BASED_HUMAN_REVIEW_LEDGER_COMMIT",
        "writes": [
            str(ENGINE_REVIEW_EVIDENCE_COMMIT_DIR),
            str(ENGINE_REVIEW_LEDGER_FILE),
        ],
        "human_review_ledger_write_authority": bool(commit_authority),
        "canonical_decision_authority": False,
        "final_lockfile_authority": False,
        "engine_file_write_authority": False,
        "project_file_write_authority": False,
        "llm_autonomous_decision_authority": False,
        "shell_execution_authority": False,
        "chroma_write_authority": False,
        "ingestion_write_authority": False,
        "quarantine_authority": False,
        "delete_authority": False,
        "rule": "Patch 104 may update the human review ledger only from Patch 103 evidence-based queue decisions after Patch 102 cross-check verification and live evidence SHA recheck. It does not create final canonical authority or modify engine files.",
    }


def _patch104_write_json(path: Path, payload: dict) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")


def _patch104_read_json(path: Path) -> dict:
    return json.loads(Path(path).read_text(encoding="utf-8"))


def _patch104_sha256(path: Path) -> str | None:
    path = Path(path)
    if not path.exists() or not path.is_file():
        return None
    h = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def _patch104_latest_file(directory: Path, pattern: str) -> Path | None:
    try:
        matches = sorted(directory.glob(pattern), key=lambda p: p.stat().st_mtime, reverse=True)
        return matches[0] if matches else None
    except Exception:
        return None


def _patch104_resolve_path(arg: str, directory: Path, latest_pattern: str) -> Path | None:
    arg = (arg or "latest").strip()
    if not arg or arg.lower() == "latest":
        return _patch104_latest_file(directory, latest_pattern)
    p = Path(arg).expanduser()
    if p.exists():
        return p
    candidate = directory / arg
    if candidate.exists():
        return candidate
    return None


def _patch104_decision_files() -> list[Path]:
    if not ENGINE_REVIEW_QUEUE_DIR.exists():
        return []
    return sorted(
        [p for p in ENGINE_REVIEW_QUEUE_DIR.glob("*_engine_review_queue_decision_v1.json") if p.is_file()],
        key=lambda p: p.stat().st_mtime,
    )


def _patch104_latest_evidence_decisions_by_engine() -> dict[str, tuple[dict, Path]]:
    latest: dict[str, tuple[dict, Path]] = {}
    for path in _patch104_decision_files():
        try:
            d = _patch104_read_json(path)
        except Exception:
            continue
        fam = str(d.get("engine_family") or "").strip()
        if not fam:
            continue
        # Patch 104 intentionally ignores older Patch 99 queue decisions unless they carry
        # Patch 102 cross-check metadata. That prevents committing non-evidence-based approvals.
        if not d.get("patch102_crosscheck_path"):
            continue
        latest[fam] = (d, path)
    return latest


def _patch104_decision_to_status(decision: str | None) -> str | None:
    d = str(decision or "").strip().upper()
    if d == "APPROVED_FOR_FUTURE_COMMIT":
        return "APPROVED"
    if d == "DEFERRED_FOR_MORE_REVIEW":
        return "DEFERRED"
    if d == "REJECTED_FROM_CANONICAL_REVIEW":
        return "REJECTED"
    return None


def _patch104_find_approval_helper(engine_family: str) -> tuple[dict | None, Path | None, str | None]:
    engine_family = str(engine_family or "").strip()
    helper_dir = MEMORY_DIR / "engine_review_approval_helpers_v1"
    candidates = [
        helper_dir / f"latest_{engine_family}_engine_review_approval_helper_v1.json"
    ]
    candidates.extend(sorted(helper_dir.glob(f"*_{engine_family}_engine_review_approval_helper_v1.json"), key=lambda p: p.stat().st_mtime, reverse=True))
    for p in candidates:
        if not p.exists() or not p.is_file():
            continue
        try:
            data = _patch104_read_json(p)
        except Exception as e:
            return None, p, f"approval helper read failed: {e}"
        return data, p, None
    return None, None, "Patch 103 approval helper receipt not found"


def _patch104_load_binder(path_value: str | None) -> tuple[dict | None, Path | None, str | None]:
    if not path_value:
        return None, None, "missing evidence_binder_path"
    path = Path(str(path_value)).expanduser()
    if not path.exists():
        return None, path, f"evidence binder path missing: {path}"
    try:
        return _patch104_read_json(path), path, None
    except Exception as e:
        return None, path, f"evidence binder read failed: {e}"


def _patch104_verify_binder_live(binder: dict) -> tuple[bool, list[str], list[str], list[dict]]:
    blockers: list[str] = []
    warnings: list[str] = []
    live_rows: list[dict] = []
    candidate = Path(str(binder.get("candidate_path_resolved") or "")).expanduser()
    if not candidate.exists():
        blockers.append(f"candidate path missing now: {candidate}")
    try:
        resolved_candidate = candidate.resolve()
        approved_root = APPROVED_ROOT.resolve()
        if not str(resolved_candidate).startswith(str(approved_root)):
            blockers.append(f"candidate path outside approved root: {resolved_candidate}")
    except Exception as e:
        blockers.append(f"candidate path resolve failed: {e}")
    for row in binder.get("file_evidence") or []:
        path = Path(str(row.get("path") or "")).expanduser()
        expected_sha = row.get("sha256")
        current_sha = _patch104_sha256(path)
        ok = bool(current_sha and expected_sha and current_sha == expected_sha)
        live_rows.append({
            "path": str(path),
            "exists_now": path.exists(),
            "expected_sha256": expected_sha,
            "current_sha256": current_sha,
            "sha_matches_evidence_binder": ok,
        })
        if not path.exists():
            blockers.append(f"evidence file missing now: {path}")
        elif expected_sha and current_sha != expected_sha:
            blockers.append(f"REFUSED_STALE_ENGINE_EVIDENCE: {path}")
    if not binder.get("file_evidence"):
        blockers.append("evidence binder has no file_evidence rows")
    return (not blockers), blockers, warnings, live_rows


def _patch104_build_plan() -> tuple[dict, Path, Path]:
    ENGINE_REVIEW_EVIDENCE_COMMIT_DIR.mkdir(parents=True, exist_ok=True)
    now = _patch104_now()
    decisions = _patch104_latest_evidence_decisions_by_engine()
    ledger, ledger_path, ledger_err = _patch72_load_ledger(create_if_missing=False)
    ledger_sha = _patch104_sha256(ledger_path) if ledger_path and ledger_path.exists() else None
    rows: list[dict] = []
    blockers: list[str] = []
    warnings: list[str] = []
    if ledger_err:
        blockers.append(f"review ledger unavailable: {ledger_err}")
    if not decisions:
        blockers.append("no Patch 103 evidence-based queue decision receipts found")
    for fam, (decision, decision_path) in sorted(decisions.items()):
        row_blockers: list[str] = []
        row_warnings: list[str] = []
        commit_status = _patch104_decision_to_status(decision.get("human_queue_decision"))
        if not commit_status:
            row_blockers.append(f"unsupported queue decision: {decision.get('human_queue_decision')}")

        # Verify Patch 102 cross-check receipt is still present and unchanged.
        crosscheck_path = Path(str(decision.get("patch102_crosscheck_path") or "")).expanduser()
        crosscheck_sha = None
        if not crosscheck_path.exists():
            row_blockers.append(f"Patch 102 cross-check path missing: {crosscheck_path}")
        else:
            crosscheck_sha = _patch104_sha256(crosscheck_path)
            expected_crosscheck_sha = decision.get("patch102_crosscheck_sha256")
            if expected_crosscheck_sha and crosscheck_sha != expected_crosscheck_sha:
                row_blockers.append("Patch 102 cross-check SHA mismatch")

        helper, helper_path, helper_err = _patch104_find_approval_helper(fam)
        helper_sha = _patch104_sha256(helper_path) if helper_path else None
        if helper_err:
            row_blockers.append(helper_err)
        elif helper and helper.get("status") not in {"EVIDENCE_APPROVAL_CHECK_READY", "EVIDENCE_BASED_HUMAN_QUEUE_DECISION_RECORDED_NO_LEDGER_MUTATION"}:
            row_warnings.append(f"approval helper status is {helper.get('status')}")

        draft_path = Path(str(decision.get("draft_path") or "")).expanduser()
        draft_sha = None
        if not draft_path.exists():
            row_blockers.append(f"draft path missing: {draft_path}")
        else:
            draft_sha = _patch104_sha256(draft_path)
            if decision.get("draft_sha256") and draft_sha != decision.get("draft_sha256"):
                row_blockers.append("draft SHA mismatch against Patch 103 decision receipt")

        binder, binder_path, binder_err = _patch104_load_binder(decision.get("evidence_binder_path"))
        binder_sha = _patch104_sha256(binder_path) if binder_path else None
        live_rows: list[dict] = []
        if binder_err:
            row_blockers.append(binder_err)
        else:
            expected_binder_sha = decision.get("evidence_binder_sha256")
            if expected_binder_sha and binder_sha != expected_binder_sha:
                row_blockers.append("evidence binder SHA mismatch against Patch 103 decision receipt")
            ok, b_blockers, b_warnings, live_rows = _patch104_verify_binder_live(binder or {})
            row_blockers.extend(b_blockers)
            row_warnings.extend(b_warnings)

        ledger_entry = _patch72_find_entry(ledger, fam) if ledger else None
        if not ledger_entry:
            row_blockers.append("engine family not found in engine_review_ledger_v1.json")

        already_same = False
        if ledger_entry and commit_status:
            already_same = str(ledger_entry.get("review_status") or "").upper() == commit_status and bool(ledger_entry.get("reviewed"))
            if already_same:
                row_warnings.append("ledger already has this same reviewed status; apply will skip duplicate mutation")

        row_ready = not row_blockers and not already_same
        row = {
            "engine_family": fam,
            "queue_decision": decision.get("human_queue_decision"),
            "commit_status_if_applied": commit_status,
            "ready_for_commit": row_ready,
            "already_applied_same_status": already_same,
            "decision_path": str(decision_path),
            "decision_sha256": _patch104_sha256(decision_path),
            "approval_helper_path": str(helper_path) if helper_path else None,
            "approval_helper_sha256": helper_sha,
            "patch102_crosscheck_path": str(crosscheck_path),
            "patch102_crosscheck_sha256_current": crosscheck_sha,
            "draft_path": str(draft_path),
            "draft_sha256_current": draft_sha,
            "evidence_id": decision.get("evidence_id"),
            "evidence_binder_path": str(binder_path) if binder_path else None,
            "evidence_binder_sha256_current": binder_sha,
            "candidate_path": (binder or {}).get("candidate_path_resolved") or decision.get("candidate_path"),
            "ledger_current_review_status": (ledger_entry or {}).get("review_status"),
            "ledger_is_hold_family": bool((ledger_entry or {}).get("is_hold_family")) if ledger_entry else None,
            "future_lockfile_eligible_if_applied": bool(commit_status == "APPROVED" and ledger_entry and not ledger_entry.get("is_hold_family")),
            "live_evidence_file_checks": live_rows,
            "blockers": row_blockers,
            "warnings": row_warnings,
        }
        rows.append(row)
        blockers.extend([f"{fam}: {b}" for b in row_blockers])
        warnings.extend([f"{fam}: {w}" for w in row_warnings])

    ready = [r for r in rows if r.get("ready_for_commit")]
    plan = {
        "schema_version": ENGINE_REVIEW_EVIDENCE_COMMIT_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_EVIDENCE_COMMIT_PLAN_V1_PATCH104",
        "created_at": now,
        "status": "ENGINE_REVIEW_EVIDENCE_COMMIT_PLAN_READY" if ready and not blockers else "ENGINE_REVIEW_EVIDENCE_COMMIT_PLAN_BLOCKED",
        "authority": _patch104_authority(commit_authority=False),
        "source_queue_decision_count": len(decisions),
        "ledger_path": str(ledger_path),
        "ledger_sha256_at_plan_time": ledger_sha,
        "counts": {
            "evidence_based_decision_receipts": len(decisions),
            "ready_for_commit": len(ready),
            "blocked": len([r for r in rows if r.get("blockers")]),
            "already_applied_same_status": len([r for r in rows if r.get("already_applied_same_status")]),
            "approved_ready": sum(1 for r in ready if r.get("commit_status_if_applied") == "APPROVED"),
            "deferred_ready": sum(1 for r in ready if r.get("commit_status_if_applied") == "DEFERRED"),
            "rejected_ready": sum(1 for r in ready if r.get("commit_status_if_applied") == "REJECTED"),
            "blockers": len(blockers),
            "warnings": len(warnings),
        },
        "commit_rows": rows,
        "blockers": blockers,
        "warnings": warnings,
        "required_confirm_token_for_apply": ENGINE_REVIEW_EVIDENCE_COMMIT_CONFIRM_TOKEN,
        "stale_evidence_refusal": "If any candidate path/file SHA changed since the evidence binder, apply must refuse with REFUSED_STALE_ENGINE_EVIDENCE.",
        "next_step": "Run engine-review-evidence-commit-apply CONFIRM_COMMIT_EVIDENCE_REVIEW_QUEUE only if this plan has ready rows and zero blockers.",
    }
    json_path = ENGINE_REVIEW_EVIDENCE_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_EVIDENCE_COMMIT_PLAN_PREFIX}.json"
    md_path = ENGINE_REVIEW_EVIDENCE_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_EVIDENCE_COMMIT_PLAN_PREFIX}.md"
    _patch104_write_json(json_path, plan)
    _patch104_write_plan_markdown(plan, md_path)
    _patch104_write_json(ENGINE_REVIEW_EVIDENCE_COMMIT_DIR / f"latest_{ENGINE_REVIEW_EVIDENCE_COMMIT_PLAN_PREFIX}.json", plan)
    (ENGINE_REVIEW_EVIDENCE_COMMIT_DIR / f"latest_{ENGINE_REVIEW_EVIDENCE_COMMIT_PLAN_PREFIX}.md").write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")
    return plan, json_path, md_path


def _patch104_write_plan_markdown(plan: dict, md_path: Path) -> None:
    c = plan.get("counts") or {}
    lines = [
        "# Patch 104 Evidence-Based Engine Review Commit Plan",
        "",
        "Mode: evidence-based human review ledger commit plan only. No engine files, lockfiles, quarantine folders, Chroma data, or project source files are modified.",
        f"Created: `{plan.get('created_at')}`",
        f"Status: `{plan.get('status')}`",
        f"Ledger SHA at plan time: `{plan.get('ledger_sha256_at_plan_time')}`",
        "",
        "## Counts",
        f"- Evidence-based decision receipts: `{c.get('evidence_based_decision_receipts')}`",
        f"- Ready for commit: `{c.get('ready_for_commit')}`",
        f"- Already applied same status: `{c.get('already_applied_same_status')}`",
        f"- Approved ready: `{c.get('approved_ready')}`",
        f"- Deferred ready: `{c.get('deferred_ready')}`",
        f"- Rejected ready: `{c.get('rejected_ready')}`",
        f"- Blockers: `{c.get('blockers')}`",
        f"- Warnings: `{c.get('warnings')}`",
        "",
        "## Rows",
    ]
    for row in plan.get("commit_rows") or []:
        lines.append(f"- `{row.get('engine_family')}` decision=`{row.get('queue_decision')}` ready=`{row.get('ready_for_commit')}` commit=`{row.get('commit_status_if_applied')}` evidence=`{row.get('evidence_id')}`")
        if row.get("already_applied_same_status"):
            lines.append("  - NOTE: already applied same ledger status; duplicate mutation skipped.")
        if row.get("blockers"):
            for b in row.get("blockers")[:10]:
                lines.append(f"  - BLOCKER: {b}")
        if row.get("warnings"):
            for w in row.get("warnings")[:6]:
                lines.append(f"  - WARNING: {w}")
    if plan.get("blockers"):
        lines.extend(["", "## Blockers"])
        for b in plan.get("blockers")[:100]:
            lines.append(f"- {b}")
    lines.extend(["", "## Authority", "- Ledger write: `NO` in plan", "- Engine file writes: `NO`", "- Final canonical lockfile: `NO`"])
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")


def _patch104_print_plan(plan: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    c = plan.get("counts") or {}
    print()
    print("── Evidence-Based Review Commit Plan ───────────────")
    print("  Mode      : PLAN ONLY — no ledger mutation")
    print("  Status    :", plan.get("status"))
    print("  Decisions :", c.get("evidence_based_decision_receipts"))
    print("  Ready     :", c.get("ready_for_commit"))
    print("  Already   :", c.get("already_applied_same_status"))
    print("  Approved  :", c.get("approved_ready"))
    print("  Deferred  :", c.get("deferred_ready"))
    print("  Rejected  :", c.get("rejected_ready"))
    print("  Blockers  :", c.get("blockers"))
    print("  Warnings  :", c.get("warnings"))
    if json_path:
        print("  JSON      :", json_path)
    if md_path:
        print("  Markdown  :", md_path)
    print("  Rows:")
    for row in plan.get("commit_rows")[:30]:
        print(f"    - {row.get('engine_family')} :: ready={row.get('ready_for_commit')} :: commit={row.get('commit_status_if_applied')} :: decision={row.get('queue_decision')}")
        if row.get("blockers"):
            print(f"      blockers={len(row.get('blockers'))}")
        if row.get("already_applied_same_status"):
            print("      already same status; skipped")
    print("──────────────────────────────────────────────────────")
    print()


def _patch104_validate_plan(plan: dict) -> tuple[bool, list[str], list[str]]:
    problems: list[str] = []
    warnings: list[str] = list(plan.get("warnings") or [])
    c = plan.get("counts") or {}
    if plan.get("report_type") != "ENGINE_REVIEW_EVIDENCE_COMMIT_PLAN_V1_PATCH104":
        problems.append("wrong report type for Patch 104 evidence commit plan")
    if c.get("blockers", 0):
        problems.extend(plan.get("blockers") or [])
    if not c.get("ready_for_commit", 0):
        problems.append("no evidence-based rows ready for commit")
    if not plan.get("ledger_sha256_at_plan_time"):
        problems.append("missing ledger SHA at plan time")
    return (not problems), problems, warnings


def _patch104_resolve_plan(arg: str = "latest") -> Path | None:
    return _patch104_resolve_path(arg, ENGINE_REVIEW_EVIDENCE_COMMIT_DIR, f"*_{ENGINE_REVIEW_EVIDENCE_COMMIT_PLAN_PREFIX}.json")


def _patch104_resolve_receipt(arg: str = "latest") -> Path | None:
    return _patch104_resolve_path(arg, ENGINE_REVIEW_EVIDENCE_COMMIT_DIR, f"*_{ENGINE_REVIEW_EVIDENCE_COMMIT_RECEIPT_PREFIX}.json")


def cmd_engine_review_evidence_commit_policy(session_id: str) -> None:
    """Show Patch 104 evidence-based commit policy."""
    from agents.forge.memory import write_audit_entry
    print()
    print("── Evidence-Based Review Commit Policy ─────────────")
    print("  Patch     : 104")
    print("  Purpose   : commit Patch 103 evidence-based queue decisions into engine_review_ledger_v1 only after Patch 102 cross-check and stale-evidence recheck")
    print("  Writes    : human review ledger + Forge-owned commit receipts")
    print("  Authority : Ledger write only after explicit confirm token")
    print("  Still NO  : engine file writes, final canonical lockfile, quarantine, delete, Chroma writes, shell")
    print("  Required  : Patch 103 decision, Patch 102 cross-check, draft SHA, binder SHA, live candidate path, live file SHA match, ledger SHA match")
    print("  Refusal   : REFUSED_STALE_ENGINE_EVIDENCE if live file SHA differs from evidence binder")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_EVIDENCE_COMMIT_POLICY_SHOWN", str(ENGINE_REVIEW_EVIDENCE_COMMIT_DIR), "ledger_commit_policy", "patch104")


def cmd_engine_review_evidence_commit_plan(session_id: str) -> None:
    """Build a Patch 104 evidence-based commit plan."""
    from agents.forge.memory import write_audit_entry
    plan, json_path, md_path = _patch104_build_plan()
    _patch104_print_plan(plan, json_path, md_path)
    c = plan.get("counts") or {}
    write_audit_entry(session_id, "ENGINE_REVIEW_EVIDENCE_COMMIT_PLAN_WRITTEN", str(json_path), f"ready={c.get('ready_for_commit')} blockers={c.get('blockers')}", "no_ledger_mutation")


def cmd_engine_review_evidence_commit_show(arg: str, session_id: str) -> None:
    """Show a Patch 104 evidence-based commit plan or receipt."""
    from agents.forge.memory import write_audit_entry
    path = _patch104_resolve_receipt(arg) or _patch104_resolve_plan(arg)
    print()
    print("── Evidence-Based Review Commit Show ───────────────")
    if not path or not path.exists():
        print("  Status: NO_EVIDENCE_COMMIT_PLAN_OR_RECEIPT_FOUND")
        print("  Next  : engine-review-evidence-commit-plan")
        print("──────────────────────────────────────────────────────")
        print()
        return
    data = _patch104_read_json(path)
    print("  Path   :", path)
    print("  Type   :", data.get("report_type"))
    print("  Status :", data.get("status"))
    print("  Counts :", data.get("counts"))
    rows = data.get("commit_rows") or data.get("applied_rows") or []
    if rows:
        print("  Rows:")
        for row in rows[:30]:
            print(f"    - {row.get('engine_family')} :: ready={row.get('ready_for_commit')} :: commit={row.get('commit_status_if_applied') or row.get('applied_review_status')} :: decision={row.get('queue_decision')}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_EVIDENCE_COMMIT_SHOWN", str(path), "read-only", data.get("status") or "shown")


def cmd_engine_review_evidence_commit_verify(arg: str, session_id: str) -> None:
    """Verify a Patch 104 evidence-based commit plan or receipt."""
    from agents.forge.memory import write_audit_entry
    path = _patch104_resolve_receipt(arg) or _patch104_resolve_plan(arg)
    print()
    print("── Evidence-Based Review Commit Verify ─────────────")
    if not path or not path.exists():
        print("  Status  : FAIL")
        print("  Reason  : no Patch 104 plan/receipt found")
        print("──────────────────────────────────────────────────────")
        print()
        return
    data = _patch104_read_json(path)
    problems: list[str] = []
    warnings: list[str] = []
    if data.get("report_type") == "ENGINE_REVIEW_EVIDENCE_COMMIT_RECEIPT_V1_PATCH104":
        problems.extend(data.get("blockers") or [])
        if not data.get("ledger_sha256_after_apply"):
            problems.append("receipt missing ledger_sha256_after_apply")
        warnings.extend(data.get("warnings") or [])
    else:
        ok, problems, warnings = _patch104_validate_plan(data)
    print("  Status   :", "PASS" if not problems else "FAIL")
    print("  Problems :", len(problems))
    print("  Warnings :", len(warnings))
    for p in problems[:20]:
        print("    -", p)
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_EVIDENCE_COMMIT_VERIFY", str(path), f"problems={len(problems)}", "read-only")


def cmd_engine_review_evidence_commit_apply(arg: str, session_id: str) -> None:
    """Apply ready Patch 103 evidence-based queue decisions into engine_review_ledger_v1."""
    from agents.forge.memory import write_audit_entry
    token = (arg or "").strip()
    print()
    print("── Evidence-Based Review Commit Apply ──────────────")
    if token != ENGINE_REVIEW_EVIDENCE_COMMIT_CONFIRM_TOKEN:
        print("  Status : REFUSED_CONFIRM_TOKEN_REQUIRED")
        print("  Usage  : engine-review-evidence-commit-apply CONFIRM_COMMIT_EVIDENCE_REVIEW_QUEUE")
        print("  Result : no ledger mutation")
        print("──────────────────────────────────────────────────────")
        print()
        write_audit_entry(session_id, "ENGINE_REVIEW_EVIDENCE_COMMIT_APPLY_REFUSED", "-", "missing_confirm", "no_ledger_mutation")
        return

    plan, plan_path, _ = _patch104_build_plan()
    ok, problems, warnings = _patch104_validate_plan(plan)
    if not ok:
        print("  Status   : REFUSED_EVIDENCE_COMMIT_PLAN_BLOCKED")
        print("  Plan     :", plan_path)
        print("  Problems :", len(problems))
        for p in problems[:25]:
            print("    -", p)
        print("  Result   : no ledger mutation")
        print("──────────────────────────────────────────────────────")
        print()
        write_audit_entry(session_id, "ENGINE_REVIEW_EVIDENCE_COMMIT_APPLY_REFUSED", str(plan_path), f"problems={len(problems)}", "no_ledger_mutation")
        return

    ledger, ledger_path, err = _patch72_load_ledger(create_if_missing=False)
    if err or not ledger:
        print("  Status : REFUSED_LEDGER_UNAVAILABLE")
        print("  Reason :", err)
        print("──────────────────────────────────────────────────────")
        print()
        return

    current_ledger_sha = _patch104_sha256(ledger_path)
    if current_ledger_sha != plan.get("ledger_sha256_at_plan_time"):
        print("  Status : REFUSED_LEDGER_SHA_CHANGED_AFTER_PLAN")
        print("  Plan SHA   :", plan.get("ledger_sha256_at_plan_time"))
        print("  Current SHA:", current_ledger_sha)
        print("──────────────────────────────────────────────────────")
        print()
        write_audit_entry(session_id, "ENGINE_REVIEW_EVIDENCE_COMMIT_APPLY_REFUSED", str(ledger_path), "ledger_sha_changed", "no_ledger_mutation")
        return

    now = _patch104_now()
    ENGINE_REVIEW_EVIDENCE_COMMIT_DIR.mkdir(parents=True, exist_ok=True)
    backup_path = ENGINE_REVIEW_EVIDENCE_COMMIT_DIR / f"{now}_engine_review_ledger_before_patch104_evidence_commit.json"
    backup_path.write_text(json.dumps(ledger, indent=2, ensure_ascii=False), encoding="utf-8")
    applied_rows: list[dict] = []

    for row in plan.get("commit_rows") or []:
        if not row.get("ready_for_commit"):
            continue
        entry = _patch72_find_entry(ledger, row.get("engine_family"))
        if not entry:
            continue
        status = str(row.get("commit_status_if_applied") or "").upper()
        if status not in {"APPROVED", "DEFERRED", "REJECTED"}:
            continue
        entry["review_status"] = status
        entry["reviewed"] = True
        entry["reviewed_at"] = now
        entry["reviewed_by"] = "Nic via Patch103 evidence-based approval + Patch104 evidence commit"
        entry["review_note"] = (
            f"Patch104 evidence commit from Patch103 queue decision. "
            f"Decision={row.get('queue_decision')}; evidence_id={row.get('evidence_id')}; "
            f"decision_sha={row.get('decision_sha256')}; binder_sha={row.get('evidence_binder_sha256_current')}; "
            f"crosscheck_sha={row.get('patch102_crosscheck_sha256_current')}."
        )
        entry["future_lockfile_eligible"] = bool(status == "APPROVED" and not entry.get("is_hold_family"))
        entry["future_lockfile_block_reason"] = None if entry["future_lockfile_eligible"] else f"review_status_{status.lower()}"
        entry["patch104_evidence_commit"] = {
            "committed_at": now,
            "decision_path": row.get("decision_path"),
            "decision_sha256": row.get("decision_sha256"),
            "approval_helper_path": row.get("approval_helper_path"),
            "approval_helper_sha256": row.get("approval_helper_sha256"),
            "patch102_crosscheck_path": row.get("patch102_crosscheck_path"),
            "patch102_crosscheck_sha256": row.get("patch102_crosscheck_sha256_current"),
            "evidence_binder_path": row.get("evidence_binder_path"),
            "evidence_binder_sha256": row.get("evidence_binder_sha256_current"),
            "candidate_path": row.get("candidate_path"),
            "live_evidence_file_checks": row.get("live_evidence_file_checks"),
        }
        applied_rows.append({
            "engine_family": row.get("engine_family"),
            "applied_review_status": status,
            "future_lockfile_eligible": entry["future_lockfile_eligible"],
            "evidence_id": row.get("evidence_id"),
            "decision_path": row.get("decision_path"),
            "candidate_path": row.get("candidate_path"),
        })

    ledger["updated_at"] = now
    ledger["last_patch104_evidence_commit_at"] = now
    ledger["last_patch104_evidence_commit_applied"] = len(applied_rows)
    ledger_path.write_text(json.dumps(ledger, indent=2, ensure_ascii=False), encoding="utf-8")
    ledger_after_sha = _patch104_sha256(ledger_path)

    receipt = {
        "schema_version": ENGINE_REVIEW_EVIDENCE_COMMIT_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_EVIDENCE_COMMIT_RECEIPT_V1_PATCH104",
        "created_at": now,
        "status": "ENGINE_REVIEW_EVIDENCE_COMMIT_APPLIED" if applied_rows else "ENGINE_REVIEW_EVIDENCE_COMMIT_NO_ROWS_APPLIED",
        "authority": _patch104_authority(commit_authority=True),
        "source_plan_path": str(plan_path),
        "source_plan_sha256": _patch104_sha256(plan_path),
        "ledger_path": str(ledger_path),
        "ledger_sha256_before_apply": current_ledger_sha,
        "ledger_sha256_after_apply": ledger_after_sha,
        "ledger_backup_path": str(backup_path),
        "counts": {
            "applied": len(applied_rows),
            "warnings": len(warnings),
            "blockers": 0,
        },
        "applied_rows": applied_rows,
        "warnings": warnings,
        "blockers": [],
        "engine_file_writes": False,
        "final_lockfile_authority": False,
    }
    receipt_path = ENGINE_REVIEW_EVIDENCE_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_EVIDENCE_COMMIT_RECEIPT_PREFIX}.json"
    md_path = ENGINE_REVIEW_EVIDENCE_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_EVIDENCE_COMMIT_RECEIPT_PREFIX}.md"
    _patch104_write_json(receipt_path, receipt)
    _patch104_write_receipt_markdown(receipt, md_path)
    _patch104_write_json(ENGINE_REVIEW_EVIDENCE_COMMIT_DIR / f"latest_{ENGINE_REVIEW_EVIDENCE_COMMIT_RECEIPT_PREFIX}.json", receipt)
    (ENGINE_REVIEW_EVIDENCE_COMMIT_DIR / f"latest_{ENGINE_REVIEW_EVIDENCE_COMMIT_RECEIPT_PREFIX}.md").write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")

    print("  Status :", receipt.get("status"))
    print("  Applied:", len(applied_rows))
    print("  Receipt:", receipt_path)
    print("  Ledger :", ledger_path)
    print("  Result : ledger updated only; no engine files changed")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_EVIDENCE_COMMIT_APPLIED", str(receipt_path), f"applied={len(applied_rows)}", "ledger_only_no_engine_files")


def _patch104_write_receipt_markdown(receipt: dict, md_path: Path) -> None:
    lines = [
        "# Patch 104 Evidence-Based Engine Review Commit Receipt",
        "",
        f"Status: `{receipt.get('status')}`",
        f"Created: `{receipt.get('created_at')}`",
        f"Ledger before: `{receipt.get('ledger_sha256_before_apply')}`",
        f"Ledger after: `{receipt.get('ledger_sha256_after_apply')}`",
        "",
        "## Applied Rows",
    ]
    for row in receipt.get("applied_rows") or []:
        lines.append(f"- `{row.get('engine_family')}` → `{row.get('applied_review_status')}` eligible=`{row.get('future_lockfile_eligible')}` evidence=`{row.get('evidence_id')}`")
    lines.extend(["", "## Authority", "- Ledger write: `YES`", "- Engine file writes: `NO`", "- Final lockfile authority: `NO`"])
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")


def cmd_engine_review_evidence_commit_export(session_id: str) -> None:
    """Export Patch 104 evidence-based commit plans/receipts."""
    from agents.forge.memory import write_audit_entry
    ENGINE_REVIEW_EVIDENCE_COMMIT_DIR.mkdir(parents=True, exist_ok=True)
    now = _patch104_now()
    paths = sorted([p for p in ENGINE_REVIEW_EVIDENCE_COMMIT_DIR.glob("*.json") if p.is_file()])
    rows = []
    for p in paths:
        try:
            d = _patch104_read_json(p)
            rows.append({
                "path": str(p),
                "sha256": _patch104_sha256(p),
                "report_type": d.get("report_type"),
                "status": d.get("status"),
                "counts": d.get("counts"),
            })
        except Exception:
            continue
    payload = {
        "schema_version": ENGINE_REVIEW_EVIDENCE_COMMIT_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_EVIDENCE_COMMIT_EXPORT_V1_PATCH104",
        "created_at": now,
        "authority": _patch104_authority(commit_authority=False),
        "counts": {"receipts": len(rows)},
        "receipts": rows,
    }
    json_path = ENGINE_REVIEW_EVIDENCE_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_EVIDENCE_COMMIT_EXPORT_PREFIX}.json"
    md_path = ENGINE_REVIEW_EVIDENCE_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_EVIDENCE_COMMIT_EXPORT_PREFIX}.md"
    _patch104_write_json(json_path, payload)
    md_path.write_text("# Patch 104 Evidence Commit Export\n\n" + "\n".join([f"- `{r.get('report_type')}` `{r.get('status')}` — {r.get('path')}" for r in rows]) + "\n", encoding="utf-8")
    print()
    print("── Evidence-Based Review Commit Export ─────────────")
    print("  JSON     :", json_path)
    print("  Markdown :", md_path)
    print("  Receipts :", len(rows))
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_EVIDENCE_COMMIT_EXPORT_WRITTEN", str(json_path), f"receipts={len(rows)}", "read-only")




# ─── PATCH 105 — EVIDENCE REVIEW BATCH WORKFLOW ─────────────────────────────
# Purpose: make the human review loop smoother by combining controlled LLM
# draft generation + evidence cross-check + queue rebuild into one auditable,
# non-approving workflow. This is still map-only: no approvals, no ledger
# mutation, no canonical lockfile authority, no engine writes.

from pathlib import Path as _Patch105Path

ENGINE_REVIEW_WORKFLOW_DIR = _Patch105Path.home() / "forge" / "memory" / "engine_review_workflows_v1"
ENGINE_REVIEW_WORKFLOW_SCHEMA_VERSION = "engine_review_workflow_v1_patch105"
ENGINE_REVIEW_WORKFLOW_PREFIX = "engine_review_workflow_v1"
ENGINE_REVIEW_WORKFLOW_EXPORT_PREFIX = "engine_review_workflow_export_v1"
ENGINE_REVIEW_WORKFLOW_DEFAULT_LIMIT = 5
ENGINE_REVIEW_WORKFLOW_MAX_LIMIT = 10


def _patch105_now() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch105_slug(value: str) -> str:
    return re.sub(r"[^a-zA-Z0-9_\-]+", "_", (value or "").strip()).strip("_").lower()


def _patch105_sha256(path) -> str | None:
    p = _Patch105Path(path)
    if not p.exists() or not p.is_file():
        return None
    h = hashlib.sha256()
    with p.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def _patch105_read_json(path) -> dict:
    return json.loads(_Patch105Path(path).read_text(encoding="utf-8"))


def _patch105_write_json(path, payload: dict) -> None:
    p = _Patch105Path(path)
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(payload, indent=2, ensure_ascii=False, sort_keys=True) + "\n", encoding="utf-8")


def _patch105_authority() -> dict:
    return {
        "patch": "105",
        "mode": "EVIDENCE_REVIEW_BATCH_WORKFLOW",
        "writes": [str(ENGINE_REVIEW_WORKFLOW_DIR), "llm_engine_review_drafts_v1", "engine_review_evidence_crosschecks_v1", "engine_review_queue_v1"],
        "llm_draft_write_authority": True,
        "evidence_crosscheck_write_authority": True,
        "queue_rebuild_authority": True,
        "queue_decision_authority": False,
        "review_ledger_write_authority": False,
        "canonical_decision_authority": False,
        "final_lockfile_authority": False,
        "engine_file_write_authority": False,
        "project_file_write_authority": False,
        "shell_execution_authority": False,
        "chroma_write_authority": False,
        "ingestion_write_authority": False,
        "rule": "Patch 105 may draft and cross-check a small batch, then rebuild queue visibility. It may not approve or commit anything.",
    }


def _patch105_parse_limit(arg: str) -> int:
    arg = (arg or "").strip()
    if not arg:
        return ENGINE_REVIEW_WORKFLOW_DEFAULT_LIMIT
    try:
        n = int(arg.split()[0])
    except Exception:
        n = ENGINE_REVIEW_WORKFLOW_DEFAULT_LIMIT
    return max(1, min(ENGINE_REVIEW_WORKFLOW_MAX_LIMIT, n))


def _patch105_existing_crosscheck(engine_family: str) -> bool:
    fam = _patch105_slug(engine_family)
    if not fam or "ENGINE_REVIEW_EVIDENCE_DIR" not in globals() or "ENGINE_REVIEW_EVIDENCE_PREFIX" not in globals():
        return False
    return (ENGINE_REVIEW_EVIDENCE_DIR / f"latest_{fam}_{ENGINE_REVIEW_EVIDENCE_PREFIX}.json").exists()


def _patch105_latest_workflow_path(arg: str | None = None) -> _Patch105Path | None:
    target = (arg or "latest").strip()
    if target == "latest":
        p = ENGINE_REVIEW_WORKFLOW_DIR / f"latest_{ENGINE_REVIEW_WORKFLOW_PREFIX}.json"
        if p.exists():
            return p
    if not ENGINE_REVIEW_WORKFLOW_DIR.exists():
        return None
    matches = sorted(ENGINE_REVIEW_WORKFLOW_DIR.glob(f"*_{ENGINE_REVIEW_WORKFLOW_PREFIX}.json"))
    matches = [p for p in matches if not p.name.startswith("latest_")]
    return matches[-1] if matches else None


def _patch105_candidate_rows() -> list[dict]:
    rows = []
    try:
        base_rows = _patch101_candidate_rows()
    except Exception as exc:
        return [{"engine_family": "_error", "ready_for_workflow": False, "blockers": [f"Patch101 candidate loader failed: {exc}"]}]
    for r in base_rows:
        fam = r.get("engine_family")
        ready = bool(r.get("ready_for_batch_draft"))
        rows.append({
            "engine_family": fam,
            "evidence_id": r.get("evidence_id"),
            "candidate_path": r.get("candidate_path"),
            "ready_for_workflow": ready,
            "crosscheck_exists": _patch105_existing_crosscheck(fam),
            "skipped_reason": r.get("skipped_reason"),
            "blockers": list(r.get("blockers") or []),
        })
    return rows


def _patch105_write_workflow_report(report: dict) -> tuple[_Patch105Path, _Patch105Path]:
    ENGINE_REVIEW_WORKFLOW_DIR.mkdir(parents=True, exist_ok=True)
    now = report.get("created_at") or _patch105_now()
    json_path = ENGINE_REVIEW_WORKFLOW_DIR / f"{now}_{ENGINE_REVIEW_WORKFLOW_PREFIX}.json"
    md_path = ENGINE_REVIEW_WORKFLOW_DIR / f"{now}_{ENGINE_REVIEW_WORKFLOW_PREFIX}.md"
    _patch105_write_json(json_path, report)
    _patch105_write_markdown(md_path, report)
    _patch105_write_json(ENGINE_REVIEW_WORKFLOW_DIR / f"latest_{ENGINE_REVIEW_WORKFLOW_PREFIX}.json", report)
    (ENGINE_REVIEW_WORKFLOW_DIR / f"latest_{ENGINE_REVIEW_WORKFLOW_PREFIX}.md").write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")
    return json_path, md_path


def _patch105_write_markdown(path, report: dict) -> None:
    lines = ["# Patch 105 Evidence Review Batch Workflow", ""]
    lines.append(f"Status: `{report.get('status')}`")
    counts = report.get("counts") or {}
    lines.append(f"Selected: `{counts.get('selected')}`")
    lines.append(f"Drafted: `{counts.get('drafted')}`")
    lines.append(f"Cross-checked: `{counts.get('crosschecked')}`")
    lines.append(f"Errors: `{counts.get('errors')}`")
    lines.append("")
    lines.append("## Rows")
    for r in report.get("workflow_rows") or []:
        lines.append("")
        lines.append(f"### `{r.get('engine_family')}`")
        lines.append(f"- Draft status: `{r.get('draft_status')}`")
        lines.append(f"- LLM status: `{r.get('llm_status')}`")
        lines.append(f"- Cross-check status: `{r.get('crosscheck_status')}`")
        lines.append(f"- Evidence ID: `{r.get('evidence_id')}`")
        lines.append(f"- Candidate path: `{r.get('candidate_path')}`")
        lines.append(f"- Next inspect: `engine-review-evidence-show {r.get('engine_family')}`")
        llm_text = (r.get("llm_visible_review_text") or "").strip()
        if llm_text:
            lines.append("")
            lines.append("#### LLM Visible Review")
            lines.append("")
            lines.append(llm_text[:12000])
    if report.get("blockers"):
        lines.append("")
        lines.append("## Blockers")
        for b in report.get("blockers") or []:
            lines.append(f"- {b}")
    if report.get("warnings"):
        lines.append("")
        lines.append("## Warnings")
        for w in report.get("warnings") or []:
            lines.append(f"- {w}")
    lines.append("")
    lines.append("## Authority")
    lines.append("Patch 105 drafts and cross-checks only. It does not approve, commit, mutate the ledger, or edit engine files.")
    _Patch105Path(path).write_text("\n".join(lines) + "\n", encoding="utf-8")


def _patch105_print_workflow(report: dict) -> None:
    print()
    print("── Evidence Review Batch Workflow ───────────────────")
    print("  Status       :", report.get("status"))
    counts = report.get("counts") or {}
    print("  Selected     :", counts.get("selected"))
    print("  Drafted      :", counts.get("drafted"))
    print("  Cross-checked:", counts.get("crosschecked"))
    print("  Errors       :", counts.get("errors"))
    print("  Authority    : NO approval, NO ledger mutation, NO engine writes")
    print("──────────────────────────────────────────────────────")
    for r in report.get("workflow_rows") or []:
        print()
        print("══════════════════════════════════════════════════════")
        print("ENGINE:", r.get("engine_family"))
        print("══════════════════════════════════════════════════════")
        print("  Draft status     :", r.get("draft_status"))
        print("  LLM status       :", r.get("llm_status"))
        print("  Cross-check      :", r.get("crosscheck_status"))
        print("  Evidence ID      :", r.get("evidence_id"))
        print("  Candidate        :", r.get("candidate_path"))
        if r.get("error"):
            print("  Error            :", r.get("error"))
        text = (r.get("llm_visible_review_text") or "").strip()
        if text:
            print()
            print("── Full Local LLM Visible Review ───────────────────")
            for line in text.splitlines()[:160]:
                print("  " + line if line else "")
        print()
        print("  Evidence inspect : engine-review-evidence-show", r.get("engine_family"))
        print("  Approval helper  : engine-review-approval-check", r.get("engine_family"))
    if report.get("blockers"):
        print()
        print("  Blockers:")
        for b in report.get("blockers") or []:
            print("   -", b)
    if report.get("warnings"):
        print()
        print("  Warnings:")
        for w in report.get("warnings") or []:
            print("   -", w)
    print("──────────────────────────────────────────────────────")
    print()


def cmd_engine_review_workflow_policy(session_id: str) -> None:
    """Show Patch 105 evidence review workflow policy. Usage: engine-review-workflow-policy"""
    from agents.forge.memory import write_audit_entry
    print()
    print("── Engine Review Workflow Policy — Patch 105 ─────────")
    print("  Purpose : batch draft + evidence cross-check + queue rebuild")
    print("  Default :", ENGINE_REVIEW_WORKFLOW_DEFAULT_LIMIT, "engines")
    print("  Maximum :", ENGINE_REVIEW_WORKFLOW_MAX_LIMIT, "engines")
    print("  Writes  :", ENGINE_REVIEW_WORKFLOW_DIR)
    print("  Still NO: approvals, ledger mutation, engine edits, shell, Chroma writes")
    print("  Rule    : read the full evidence cross-check before approving anything")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_WORKFLOW_POLICY_SHOWN", str(ENGINE_REVIEW_WORKFLOW_DIR), "patch105", "no_approval_authority")


def cmd_engine_review_workflow_plan(session_id: str) -> None:
    """Plan the next Patch 105 evidence review workflow batch. Usage: engine-review-workflow-plan"""
    from agents.forge.memory import write_audit_entry
    rows = _patch105_candidate_rows()
    ready = [r for r in rows if r.get("ready_for_workflow")]
    skipped = [r for r in rows if not r.get("ready_for_workflow")]
    now = _patch105_now()
    plan = {
        "schema_version": ENGINE_REVIEW_WORKFLOW_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_WORKFLOW_PLAN_V1_PATCH105",
        "created_at": now,
        "status": "ENGINE_REVIEW_WORKFLOW_PLAN_READY",
        "counts": {"total_candidates": len(rows), "ready_for_workflow": len(ready), "skipped_or_blocked": len(skipped)},
        "next_batch_preview": ready[:ENGINE_REVIEW_WORKFLOW_MAX_LIMIT],
        "skipped_preview": skipped[:20],
        "authority": _patch105_authority(),
    }
    ENGINE_REVIEW_WORKFLOW_DIR.mkdir(parents=True, exist_ok=True)
    path = ENGINE_REVIEW_WORKFLOW_DIR / f"{now}_engine_review_workflow_plan_v1.json"
    _patch105_write_json(path, plan)
    print()
    print("── Engine Review Workflow Plan ──────────────────────")
    print("  Ready for workflow:", len(ready))
    print("  Skipped/blocked    :", len(skipped))
    print("  Next batch preview:")
    for r in ready[:ENGINE_REVIEW_WORKFLOW_MAX_LIMIT]:
        print("   -", r.get("engine_family"), "|", r.get("evidence_id"))
    print("  Authority: NO approvals, NO ledger mutation")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_WORKFLOW_PLAN_WRITTEN", str(path), f"ready={len(ready)}", f"skipped={len(skipped)}")


def cmd_engine_review_workflow_run(arg: str, session_id: str) -> None:
    """Run a controlled evidence review workflow batch. Usage: engine-review-workflow-run [1-10]"""
    from agents.forge.memory import write_audit_entry
    limit = _patch105_parse_limit(arg)
    candidates = [r for r in _patch105_candidate_rows() if r.get("ready_for_workflow")]
    selected = candidates[:limit]
    now = _patch105_now()
    rows = []
    blockers = []
    warnings = []
    print()
    print("── Engine Review Workflow Run ───────────────────────")
    print("  Selected:", len(selected), "of", len(candidates), "ready engines")
    print("  Note: local LLM calls may take time; no approvals or commits will happen.")
    print("──────────────────────────────────────────────────────")
    print()
    for r in selected:
        fam = r.get("engine_family")
        row = {"engine_family": fam, "evidence_id": r.get("evidence_id"), "candidate_path": r.get("candidate_path")}
        try:
            draft = _patch98_make_draft(fam)
            draft_json, draft_md = _patch98_write_draft(draft)
            row["draft_status"] = draft.get("status")
            row["draft_path"] = str(draft_json)
            row["draft_sha256"] = _patch105_sha256(draft_json)
            row["llm_status"] = ((draft.get("llm_invocation") or {}).get("status")) or "NO_LLM_STATUS"
            row["llm_visible_review_text"] = (draft.get("llm_visible_review_text") or "")[:16000]
            row["evidence_id"] = draft.get("evidence_id") or row.get("evidence_id")
            row["candidate_path"] = draft.get("candidate_path_resolved") or row.get("candidate_path")
            print(f"[forge] Drafted {fam}: {row.get('llm_status')}")
            cross, cross_json, cross_md, err = _patch102_build_crosscheck(fam)
            if err:
                row["crosscheck_status"] = "CROSSCHECK_ERROR"
                row["error"] = err
                blockers.append(f"{fam}: cross-check error: {err}")
                print(f"[forge] Cross-check error for {fam}: {err}")
            else:
                row["crosscheck_status"] = cross.get("status") if cross else "NO_CROSSCHECK_STATUS"
                row["crosscheck_path"] = str(cross_json) if cross_json else None
                row["crosscheck_sha256"] = _patch105_sha256(cross_json) if cross_json else None
                row["crosscheck_warnings"] = cross.get("warnings") if cross else []
                row["crosscheck_blockers"] = cross.get("blockers") if cross else []
                if cross and cross.get("blockers"):
                    blockers.append(f"{fam}: cross-check blockers: {cross.get('blockers')}")
                if cross and cross.get("warnings"):
                    warnings.extend([f"{fam}: {w}" for w in cross.get("warnings")])
                print(f"[forge] Cross-checked {fam}: {row.get('crosscheck_status')}")
        except Exception as exc:
            row["draft_status"] = "ERROR"
            row["error"] = repr(exc)[:800]
            blockers.append(f"{fam}: {repr(exc)[:500]}")
            print("[forge] Workflow error:", fam, repr(exc)[:500])
        rows.append(row)
    queue_error = None
    try:
        _patch99_write_queue_report()
    except Exception as exc:
        queue_error = repr(exc)[:500]
        warnings.append(f"Queue rebuild warning: {queue_error}")
    status = "ENGINE_REVIEW_WORKFLOW_COMPLETED_NO_APPROVAL_AUTHORITY" if rows else "ENGINE_REVIEW_WORKFLOW_NO_ROWS_SELECTED"
    if blockers:
        status = "ENGINE_REVIEW_WORKFLOW_COMPLETED_WITH_BLOCKERS_NO_APPROVAL_AUTHORITY"
    report = {
        "schema_version": ENGINE_REVIEW_WORKFLOW_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_WORKFLOW_RECEIPT_V1_PATCH105",
        "created_at": now,
        "status": status,
        "requested_limit": limit,
        "counts": {"selected": len(selected), "drafted": len([r for r in rows if r.get("draft_status") and r.get("draft_status") != "ERROR"]), "crosschecked": len([r for r in rows if r.get("crosscheck_path")]), "errors": len(blockers)},
        "workflow_rows": rows,
        "queue_rebuild_error": queue_error,
        "warnings": warnings,
        "blockers": blockers,
        "authority": _patch105_authority(),
        "next_step": "Inspect each full evidence cross-check, then use engine-review-approval-check/approve/defer/reject. No approval was recorded by Patch 105.",
    }
    json_path, md_path = _patch105_write_workflow_report(report)
    _patch105_print_workflow(report)
    print("  JSON    :", json_path)
    print("  Markdown:", md_path)
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_WORKFLOW_RUN_WRITTEN", str(json_path), f"rows={len(rows)}", f"blockers={len(blockers)}")


def cmd_engine_review_workflow_show(arg: str, session_id: str) -> None:
    """Show latest Patch 105 workflow receipt. Usage: engine-review-workflow-show [latest]"""
    from agents.forge.memory import write_audit_entry
    path = _patch105_latest_workflow_path(arg)
    if not path:
        print("[forge] No Patch 105 workflow receipt found. Run engine-review-workflow-run first.")
        return
    report = _patch105_read_json(path)
    _patch105_print_workflow(report)
    write_audit_entry(session_id, "ENGINE_REVIEW_WORKFLOW_SHOWN", str(path), report.get("status", "?"), "shown")


def cmd_engine_review_workflow_export(session_id: str) -> None:
    """Export Patch 105 workflow receipts. Usage: engine-review-workflow-export"""
    from agents.forge.memory import write_audit_entry
    ENGINE_REVIEW_WORKFLOW_DIR.mkdir(parents=True, exist_ok=True)
    receipts = []
    for path in sorted(ENGINE_REVIEW_WORKFLOW_DIR.glob(f"*_{ENGINE_REVIEW_WORKFLOW_PREFIX}.json")):
        if path.name.startswith("latest_"):
            continue
        try:
            d = _patch105_read_json(path)
            receipts.append({
                "path": str(path),
                "sha256": _patch105_sha256(path),
                "status": d.get("status"),
                "counts": d.get("counts"),
            })
        except Exception:
            continue
    now = _patch105_now()
    export = {
        "schema_version": ENGINE_REVIEW_WORKFLOW_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_WORKFLOW_EXPORT_V1_PATCH105",
        "created_at": now,
        "counts": {"receipts": len(receipts)},
        "receipts": receipts,
        "authority": _patch105_authority(),
    }
    json_path = ENGINE_REVIEW_WORKFLOW_DIR / f"{now}_{ENGINE_REVIEW_WORKFLOW_EXPORT_PREFIX}.json"
    md_path = ENGINE_REVIEW_WORKFLOW_DIR / f"{now}_{ENGINE_REVIEW_WORKFLOW_EXPORT_PREFIX}.md"
    _patch105_write_json(json_path, export)
    lines = ["# Patch 105 Engine Review Workflow Export", "", f"Receipts: `{len(receipts)}`", ""]
    for r in receipts:
        lines.append(f"- `{r.get('path')}` — `{r.get('status')}` — counts `{r.get('counts')}`")
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    print()
    print("── Engine Review Workflow Export ────────────────────")
    print("  JSON    :", json_path)
    print("  Markdown:", md_path)
    print("  Receipts:", len(receipts))
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_WORKFLOW_EXPORT_WRITTEN", str(json_path), f"receipts={len(receipts)}", "read-only")



# ─── PATCH 106 — EVIDENCE-BASED BATCH APPROVAL HELPER ────────────────────────

ENGINE_REVIEW_BATCH_APPROVAL_DIR = MEMORY_DIR / "engine_review_batch_approvals_v1"
ENGINE_REVIEW_BATCH_APPROVAL_SCHEMA_VERSION = "engine_review_batch_approval_v1_patch106"
ENGINE_REVIEW_BATCH_APPROVAL_PREFIX = "engine_review_batch_approval_v1"
ENGINE_REVIEW_BATCH_APPROVAL_EXPORT_PREFIX = "engine_review_batch_approval_export_v1"


def _patch106_now() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch106_authority(decision_write_authority: bool = False) -> dict:
    return {
        "patch": "106",
        "mode": "EVIDENCE_BASED_BATCH_APPROVAL_HELPER",
        "writes": str(ENGINE_REVIEW_BATCH_APPROVAL_DIR),
        "queue_decision_write_authority": bool(decision_write_authority),
        "human_review_ledger_write_authority": False,
        "canonical_decision_authority": False,
        "final_lockfile_authority": False,
        "engine_file_write_authority": False,
        "project_file_write_authority": False,
        "llm_autonomous_decision_authority": False,
        "shell_execution_authority": False,
        "chroma_write_authority": False,
        "ingestion_write_authority": False,
        "rule": "Patch 106 may record Patch99-compatible queue decisions for explicitly named engines, but only after Patch102 evidence cross-check readiness. It never commits ledger changes.",
    }


def _patch106_slug(value: str) -> str:
    if "_patch103_slug" in globals():
        return _patch103_slug(value)
    return re.sub(r"[^a-zA-Z0-9_.-]+", "_", (value or "").strip()).strip("_").lower()


def _patch106_read_json(path) -> dict:
    p = Path(path)
    return json.loads(p.read_text(encoding="utf-8"))


def _patch106_write_json(path, data: dict) -> None:
    p = Path(path)
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, indent=2, sort_keys=True) + "\n", encoding="utf-8")


def _patch106_sha256(path) -> str:
    h = hashlib.sha256()
    p = Path(path)
    with p.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def _patch106_latest_batch_path():
    return ENGINE_REVIEW_BATCH_APPROVAL_DIR / f"latest_{ENGINE_REVIEW_BATCH_APPROVAL_PREFIX}.json"


def _patch106_decision_label(decision_value: str) -> str:
    if decision_value == "APPROVED_FOR_FUTURE_COMMIT":
        return "APPROVE"
    if decision_value == "DEFERRED_FOR_MORE_REVIEW":
        return "DEFER"
    if decision_value == "REJECTED_FROM_CANONICAL_REVIEW":
        return "REJECT"
    return decision_value


def _patch106_available_crosschecks() -> list[dict]:
    rows = []
    if "ENGINE_REVIEW_EVIDENCE_DIR" not in globals() or not ENGINE_REVIEW_EVIDENCE_DIR.exists():
        return rows
    for path in sorted(ENGINE_REVIEW_EVIDENCE_DIR.glob(f"latest_*_{ENGINE_REVIEW_EVIDENCE_PREFIX}.json")):
        if path.name == f"latest_{ENGINE_REVIEW_EVIDENCE_PREFIX}.json":
            continue
        try:
            d = _patch106_read_json(path)
        except Exception:
            continue
        fam = _patch106_slug(d.get("engine_family"))
        if not fam:
            continue
        rows.append({
            "engine_family": fam,
            "status": d.get("status"),
            "blockers": d.get("blockers") or [],
            "warnings": d.get("warnings") or [],
            "llm_called": (d.get("llm_invocation") or {}).get("called"),
            "llm_status": (d.get("llm_invocation") or {}).get("status"),
            "evidence_id": d.get("evidence_id"),
            "candidate_path": d.get("candidate_path"),
            "crosscheck_path": str(path),
            "crosscheck_sha256": _patch106_sha256(path),
            "ready_for_batch_decision": d.get("status") == "EVIDENCE_CROSSCHECK_READY_NO_AUTHORITY" and not (d.get("blockers") or []),
        })
    return rows


def _patch106_latest_workflow_engines(limit: int = 8) -> list[str]:
    engines = []
    try:
        if "ENGINE_REVIEW_WORKFLOW_DIR" in globals():
            wf = ENGINE_REVIEW_WORKFLOW_DIR / f"latest_{ENGINE_REVIEW_WORKFLOW_PREFIX}.json"
            if wf.exists():
                data = _patch106_read_json(wf)
                for row in data.get("workflow_rows") or []:
                    fam = _patch106_slug(row.get("engine_family"))
                    if fam and fam not in engines:
                        engines.append(fam)
    except Exception:
        pass
    return engines[:limit]


def _patch106_parse_engine_args(arg: str) -> list[str]:
    raw = (arg or "").strip()
    if not raw:
        return []
    bits = [b.strip() for b in re.split(r"[,\s]+", raw) if b.strip()]
    # Friendly aliases: latest/workflow means use latest workflow engines.
    if len(bits) == 1 and bits[0].lower() in {"latest", "workflow", "last"}:
        return _patch106_latest_workflow_engines()
    return [_patch106_slug(b) for b in bits if _patch106_slug(b)]


def _patch106_build_batch_plan() -> dict:
    rows = _patch106_available_crosschecks()
    latest_workflow = set(_patch106_latest_workflow_engines(limit=20))
    # Add queue decision visibility when possible.
    existing_decisions = {}
    try:
        qdir = Path.home() / "forge" / "memory" / "engine_review_queue_v1"
        prefix = globals().get("ENGINE_REVIEW_QUEUE_DECISION_PREFIX", "engine_review_queue_decision_v1")
        for p in sorted(qdir.glob(f"*_{prefix}.json")):
            if p.name.startswith("latest_"):
                continue
            try:
                d = _patch106_read_json(p)
                fam = _patch106_slug(d.get("engine_family"))
                if fam:
                    existing_decisions[fam] = d.get("human_queue_decision")
            except Exception:
                continue
    except Exception:
        pass
    for r in rows:
        r["latest_workflow_item"] = r.get("engine_family") in latest_workflow
        r["existing_queue_decision"] = existing_decisions.get(r.get("engine_family"))
        r["suggested_review_command"] = f"engine-review-evidence-show {r.get('engine_family')}"
        r["suggested_check_command"] = f"engine-review-batch-approval-show {r.get('engine_family')}"
    ready = [r for r in rows if r.get("ready_for_batch_decision")]
    undecided = [r for r in ready if not r.get("existing_queue_decision")]
    return {
        "schema_version": ENGINE_REVIEW_BATCH_APPROVAL_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_BATCH_APPROVAL_PLAN_V1_PATCH106",
        "created_at": _patch106_now(),
        "status": "ENGINE_REVIEW_BATCH_APPROVAL_PLAN_READY_NO_LEDGER_AUTHORITY",
        "counts": {
            "crosschecks": len(rows),
            "ready_for_batch_decision": len(ready),
            "undecided_ready": len(undecided),
            "with_existing_queue_decision": len(ready) - len(undecided),
        },
        "rows": rows,
        "latest_workflow_engines": list(latest_workflow),
        "next_step": "Read each evidence cross-check first, then explicitly approve/defer/reject named engines. Do not approve from summary alone.",
        "authority": _patch106_authority(decision_write_authority=False),
    }


def _patch106_write_plan(plan: dict) -> tuple[Path, Path]:
    ENGINE_REVIEW_BATCH_APPROVAL_DIR.mkdir(parents=True, exist_ok=True)
    now = plan.get("created_at") or _patch106_now()
    json_path = ENGINE_REVIEW_BATCH_APPROVAL_DIR / f"{now}_engine_review_batch_approval_plan_v1.json"
    md_path = ENGINE_REVIEW_BATCH_APPROVAL_DIR / f"{now}_engine_review_batch_approval_plan_v1.md"
    _patch106_write_json(json_path, plan)
    lines = [
        "# Patch 106 Evidence-Based Batch Approval Plan",
        "",
        f"Status: `{plan.get('status')}`",
        f"Cross-checks: `{plan.get('counts', {}).get('crosschecks')}`",
        f"Ready: `{plan.get('counts', {}).get('ready_for_batch_decision')}`",
        f"Undecided ready: `{plan.get('counts', {}).get('undecided_ready')}`",
        "",
        "Read full evidence before deciding:",
        "",
    ]
    for r in plan.get("rows", [])[:80]:
        lines.append(f"- `{r.get('engine_family')}` — ready=`{r.get('ready_for_batch_decision')}` — decision=`{r.get('existing_queue_decision')}` — latest_workflow=`{r.get('latest_workflow_item')}`")
        lines.append(f"  - Review: `engine-review-evidence-show {r.get('engine_family')}`")
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    latest_json = ENGINE_REVIEW_BATCH_APPROVAL_DIR / "latest_engine_review_batch_approval_plan_v1.json"
    latest_md = ENGINE_REVIEW_BATCH_APPROVAL_DIR / "latest_engine_review_batch_approval_plan_v1.md"
    _patch106_write_json(latest_json, plan)
    latest_md.write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")
    return json_path, md_path


def _patch106_build_decision_batch(engines: list[str], decision_value: str) -> dict:
    now = _patch106_now()
    rows = []
    blockers = []
    warnings = []
    if not engines:
        blockers.append("No engines supplied. Example: engine-review-batch-approval-approve agent_reflection_engine agents_stack")
    for fam in engines:
        row = {
            "engine_family": fam,
            "requested_decision": decision_value,
            "status": "PENDING",
            "check_path": None,
            "queue_decision_path": None,
            "blockers": [],
            "warnings": [],
        }
        try:
            if "_patch103_build_check" not in globals() or "_patch103_write_queue_decision" not in globals():
                raise RuntimeError("Patch 103 approval helpers are unavailable.")
            report, _x_path = _patch103_build_check(fam)
            check_json, check_md = _patch103_write_check_receipt(report)
            row["check_path"] = str(check_json)
            row["check_sha256"] = _patch106_sha256(check_json)
            row["evidence_id"] = report.get("evidence_id")
            row["candidate_path"] = report.get("candidate_path")
            row["check_status"] = report.get("status")
            row["blockers"] = list(report.get("blockers") or [])
            row["warnings"] = list(report.get("warnings") or [])
            if row["blockers"] and decision_value == "APPROVED_FOR_FUTURE_COMMIT":
                row["status"] = "REFUSED_APPROVAL_CHECK_BLOCKED"
            else:
                decision, q_json, q_md = _patch103_write_queue_decision(report, decision_value)
                row["status"] = "BATCH_QUEUE_DECISION_RECORDED_NO_LEDGER_MUTATION"
                row["queue_decision_path"] = str(q_json)
                row["queue_decision_sha256"] = _patch106_sha256(q_json)
                row["decision_id"] = decision.get("decision_id")
        except Exception as e:
            row["status"] = "ERROR"
            row["blockers"].append(f"{type(e).__name__}: {e}")
        if row["blockers"]:
            blockers.extend([f"{fam}: {b}" for b in row["blockers"]])
        if row["warnings"]:
            warnings.extend([f"{fam}: {w}" for w in row["warnings"]])
        rows.append(row)

    applied = [r for r in rows if r.get("status") == "BATCH_QUEUE_DECISION_RECORDED_NO_LEDGER_MUTATION"]
    status = "ENGINE_REVIEW_BATCH_APPROVAL_RECORDED_NO_LEDGER_MUTATION" if applied and not blockers else (
        "ENGINE_REVIEW_BATCH_APPROVAL_RECORDED_WITH_BLOCKERS_NO_LEDGER_MUTATION" if applied else "ENGINE_REVIEW_BATCH_APPROVAL_BLOCKED_NO_LEDGER_MUTATION"
    )
    return {
        "schema_version": ENGINE_REVIEW_BATCH_APPROVAL_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_BATCH_APPROVAL_RECEIPT_V1_PATCH106",
        "created_at": now,
        "status": status,
        "decision_value": decision_value,
        "decision_label": _patch106_decision_label(decision_value),
        "requested_engines": engines,
        "counts": {
            "requested": len(engines),
            "recorded": len(applied),
            "refused_or_error": len(rows) - len(applied),
            "blockers": len(blockers),
            "warnings": len(warnings),
        },
        "rows": rows,
        "blockers": blockers,
        "warnings": warnings,
        "manual_verification_rule": "This helper assumes Nic has already read engine-review-evidence-show for each named engine. It records queue intent only and never mutates the ledger.",
        "authority": _patch106_authority(decision_write_authority=True),
    }


def _patch106_write_batch_receipt(receipt: dict) -> tuple[Path, Path]:
    ENGINE_REVIEW_BATCH_APPROVAL_DIR.mkdir(parents=True, exist_ok=True)
    now = receipt.get("created_at") or _patch106_now()
    json_path = ENGINE_REVIEW_BATCH_APPROVAL_DIR / f"{now}_{ENGINE_REVIEW_BATCH_APPROVAL_PREFIX}.json"
    md_path = ENGINE_REVIEW_BATCH_APPROVAL_DIR / f"{now}_{ENGINE_REVIEW_BATCH_APPROVAL_PREFIX}.md"
    _patch106_write_json(json_path, receipt)
    lines = [
        "# Patch 106 Evidence-Based Batch Approval Receipt",
        "",
        f"Status: `{receipt.get('status')}`",
        f"Decision: `{receipt.get('decision_value')}`",
        f"Recorded: `{receipt.get('counts', {}).get('recorded')}` / `{receipt.get('counts', {}).get('requested')}`",
        "",
        "Rows:",
        "",
    ]
    for r in receipt.get("rows", []):
        lines.append(f"- `{r.get('engine_family')}` — `{r.get('status')}` — evidence `{r.get('evidence_id')}`")
        if r.get("queue_decision_path"):
            lines.append(f"  - Queue decision: `{r.get('queue_decision_path')}`")
        for b in r.get("blockers") or []:
            lines.append(f"  - BLOCKER: {b}")
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    latest_json = ENGINE_REVIEW_BATCH_APPROVAL_DIR / f"latest_{ENGINE_REVIEW_BATCH_APPROVAL_PREFIX}.json"
    latest_md = ENGINE_REVIEW_BATCH_APPROVAL_DIR / f"latest_{ENGINE_REVIEW_BATCH_APPROVAL_PREFIX}.md"
    _patch106_write_json(latest_json, receipt)
    latest_md.write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")
    return json_path, md_path


def _patch106_print_batch_receipt(receipt: dict) -> None:
    print()
    print("── Engine Review Batch Approval Helper ───────────────")
    print("  Status   :", receipt.get("status"))
    print("  Decision :", receipt.get("decision_value"))
    c = receipt.get("counts") or {}
    print("  Recorded :", c.get("recorded"), "/", c.get("requested"))
    print("  Blockers :", c.get("blockers"))
    print("  Warnings :", c.get("warnings"))
    print("  Authority: queue decisions only; NO ledger mutation")
    print("  Rule     : approve only after reading Patch102 evidence cross-check.")
    print()
    for r in receipt.get("rows") or []:
        print(f"  - {r.get('engine_family')}: {r.get('status')}")
        print(f"    Evidence: {r.get('evidence_id')} | Candidate: {r.get('candidate_path')}")
        if r.get("queue_decision_path"):
            print(f"    Queue decision: {r.get('queue_decision_path')}")
        for b in r.get("blockers") or []:
            print(f"    BLOCKER: {b}")
    print("──────────────────────────────────────────────────────")
    print()


def cmd_engine_review_batch_approval_policy(session_id: str) -> None:
    """Show Patch 106 evidence-based batch approval policy."""
    from agents.forge.memory import write_audit_entry
    print()
    print("── Engine Review Batch Approval Policy — Patch 106 ───")
    print("  Purpose : approve/defer/reject explicitly named engines after Patch102 evidence cross-check.")
    print("  Writes  :", ENGINE_REVIEW_BATCH_APPROVAL_DIR)
    print("  Also writes Patch99-compatible queue decisions through Patch103 helper.")
    print("  Authority: NO review ledger mutation, NO engine writes, NO lockfile authority")
    print("  Safety  : approval refuses if evidence check has blockers; defer/reject remain safe choices.")
    print("  Use     : engine-review-evidence-show <engine> BEFORE any batch approval.")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_BATCH_APPROVAL_POLICY_SHOWN", str(ENGINE_REVIEW_BATCH_APPROVAL_DIR), "patch106", "no_ledger_mutation")


def cmd_engine_review_batch_approval_plan(session_id: str) -> None:
    """Show and write Patch 106 batch approval plan."""
    from agents.forge.memory import write_audit_entry
    plan = _patch106_build_batch_plan()
    json_path, md_path = _patch106_write_plan(plan)
    print()
    print("── Engine Review Batch Approval Plan ─────────────────")
    c = plan.get("counts") or {}
    print("  Cross-checks    :", c.get("crosschecks"))
    print("  Ready           :", c.get("ready_for_batch_decision"))
    print("  Undecided ready :", c.get("undecided_ready"))
    print("  Authority       : plan only; NO queue decision, NO ledger mutation")
    print()
    rows = plan.get("rows") or []
    for r in rows[:30]:
        print(f"  - {r.get('engine_family')} | ready={r.get('ready_for_batch_decision')} | decision={r.get('existing_queue_decision')} | latest_workflow={r.get('latest_workflow_item')}")
        print(f"    Read: engine-review-evidence-show {r.get('engine_family')}")
    print("  JSON    :", json_path)
    print("  Markdown:", md_path)
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_BATCH_APPROVAL_PLAN_WRITTEN", str(json_path), f"ready={c.get('ready_for_batch_decision')}", "plan_only")


def cmd_engine_review_batch_approval_show(arg: str, session_id: str) -> None:
    """Show latest batch receipt or a named engine's approval readiness."""
    from agents.forge.memory import write_audit_entry
    arg = (arg or "latest").strip()
    if arg.lower() in {"latest", "last"}:
        path = _patch106_latest_batch_path()
        if not path.exists():
            print()
            print("── Engine Review Batch Approval Show ─────────────────")
            print("  Status: NO_BATCH_APPROVAL_RECEIPT_FOUND")
            print("  Run   : engine-review-batch-approval-plan")
            print("──────────────────────────────────────────────────────")
            print()
            return
        receipt = _patch106_read_json(path)
        _patch106_print_batch_receipt(receipt)
        write_audit_entry(session_id, "ENGINE_REVIEW_BATCH_APPROVAL_SHOWN", str(path), receipt.get("status", "unknown"), "latest")
        return
    # For named engine, show Patch103 check plus reminder to inspect full evidence.
    engine = _patch106_slug(arg.split()[0])
    if not engine:
        print("Usage: engine-review-batch-approval-show <engine|latest>")
        return
    report, _ = _patch103_build_check(engine) if "_patch103_build_check" in globals() else ({"engine_family": engine, "blockers": ["Patch103 helper missing"]}, None)
    json_path, md_path = _patch103_write_check_receipt(report) if "_patch103_write_check_receipt" in globals() else (None, None)
    if "_patch103_print_check" in globals():
        _patch103_print_check(report)
    print("  Full evidence command:", f"engine-review-evidence-show {engine}")
    print("  To approve explicitly:", f"engine-review-batch-approval-approve {engine}")
    print("  To defer explicitly  :", f"engine-review-batch-approval-defer {engine}")
    write_audit_entry(session_id, "ENGINE_REVIEW_BATCH_APPROVAL_ENGINE_SHOWN", str(json_path) if json_path else "-", engine, "check_shown")


def cmd_engine_review_batch_approval_decision(arg: str, decision_value: str, session_id: str) -> None:
    """Record batch queue decisions. Usage: engine-review-batch-approval-approve|defer|reject <engine> [engine2 ...]"""
    from agents.forge.memory import write_audit_entry
    engines = _patch106_parse_engine_args(arg)
    receipt = _patch106_build_decision_batch(engines, decision_value)
    json_path, md_path = _patch106_write_batch_receipt(receipt)
    _patch106_print_batch_receipt(receipt)
    print("  JSON    :", json_path)
    print("  Markdown:", md_path)
    print()
    action = {
        "APPROVED_FOR_FUTURE_COMMIT": "ENGINE_REVIEW_BATCH_APPROVAL_APPROVE_WRITTEN",
        "DEFERRED_FOR_MORE_REVIEW": "ENGINE_REVIEW_BATCH_APPROVAL_DEFER_WRITTEN",
        "REJECTED_FROM_CANONICAL_REVIEW": "ENGINE_REVIEW_BATCH_APPROVAL_REJECT_WRITTEN",
    }.get(decision_value, "ENGINE_REVIEW_BATCH_APPROVAL_DECISION_WRITTEN")
    write_audit_entry(session_id, action, str(json_path), f"recorded={receipt.get('counts', {}).get('recorded')}", receipt.get("status", "unknown"))


def cmd_engine_review_batch_approval_export(session_id: str) -> None:
    """Export Patch 106 batch approval receipts."""
    from agents.forge.memory import write_audit_entry
    ENGINE_REVIEW_BATCH_APPROVAL_DIR.mkdir(parents=True, exist_ok=True)
    receipts = []
    for path in sorted(ENGINE_REVIEW_BATCH_APPROVAL_DIR.glob(f"*_{ENGINE_REVIEW_BATCH_APPROVAL_PREFIX}.json")):
        if path.name.startswith("latest_"):
            continue
        try:
            d = _patch106_read_json(path)
            receipts.append({
                "path": str(path),
                "sha256": _patch106_sha256(path),
                "status": d.get("status"),
                "decision_value": d.get("decision_value"),
                "counts": d.get("counts"),
                "engines": [r.get("engine_family") for r in d.get("rows") or []],
            })
        except Exception:
            continue
    now = _patch106_now()
    export = {
        "schema_version": ENGINE_REVIEW_BATCH_APPROVAL_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_BATCH_APPROVAL_EXPORT_V1_PATCH106",
        "created_at": now,
        "counts": {"receipts": len(receipts)},
        "receipts": receipts,
        "authority": _patch106_authority(decision_write_authority=False),
    }
    json_path = ENGINE_REVIEW_BATCH_APPROVAL_DIR / f"{now}_{ENGINE_REVIEW_BATCH_APPROVAL_EXPORT_PREFIX}.json"
    md_path = ENGINE_REVIEW_BATCH_APPROVAL_DIR / f"{now}_{ENGINE_REVIEW_BATCH_APPROVAL_EXPORT_PREFIX}.md"
    _patch106_write_json(json_path, export)
    lines = ["# Patch 106 Evidence-Based Batch Approval Export", "", f"Receipts: `{len(receipts)}`", ""]
    for r in receipts:
        lines.append(f"- `{r.get('status')}` — `{r.get('decision_value')}` — engines `{', '.join(r.get('engines') or [])}`")
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    print()
    print("── Engine Review Batch Approval Export ───────────────")
    print("  JSON    :", json_path)
    print("  Markdown:", md_path)
    print("  Receipts:", len(receipts))
    print("  Authority: NO ledger mutation")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_BATCH_APPROVAL_EXPORT_WRITTEN", str(json_path), f"receipts={len(receipts)}", "no_ledger_mutation")




# ─── PATCH 107: EVIDENCE-BASED BATCH COMMIT GATE ───────────────────────────

ENGINE_REVIEW_BATCH_COMMIT_SCHEMA_VERSION = "engine_review_batch_commit_v1_patch107"
ENGINE_REVIEW_BATCH_COMMIT_DIR = Path.home() / "forge" / "memory" / "engine_review_batch_commits_v1"
ENGINE_REVIEW_BATCH_COMMIT_PREFIX = "engine_review_batch_commit_v1"
ENGINE_REVIEW_BATCH_COMMIT_PLAN_PREFIX = "engine_review_batch_commit_plan_v1"
ENGINE_REVIEW_BATCH_COMMIT_EXPORT_PREFIX = "engine_review_batch_commit_export_v1"
ENGINE_REVIEW_BATCH_COMMIT_CONFIRM_TOKEN = "CONFIRM_COMMIT_EVIDENCE_BATCH_QUEUE"


def _patch107_now() -> str:
    from datetime import datetime
    return datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch107_authority(commit_authority: bool = False) -> dict:
    return {
        "patch": "107",
        "mode": "EVIDENCE_BASED_BATCH_COMMIT_GATE",
        "writes": [
            str(ENGINE_REVIEW_BATCH_COMMIT_DIR),
            str(Path.home() / "forge" / "memory" / "code_library_v1" / "manifests" / "engine_review_ledger_v1.json") if commit_authority else "Forge-owned plan/receipt files only until explicit confirm token",
        ],
        "human_review_ledger_write_authority": bool(commit_authority),
        "engine_file_write_authority": False,
        "project_file_write_authority": False,
        "canonical_decision_authority": False,
        "final_lockfile_authority": False,
        "llm_autonomous_decision_authority": False,
        "chroma_write_authority": False,
        "ingestion_write_authority": False,
        "shell_execution_authority": False,
        "rule": "Patch 107 may commit Patch106 evidence-based batch queue decisions into engine_review_ledger_v1 only after queue decision, Patch103 approval helper, Patch102 cross-check, evidence binder, live candidate path, and live file SHA rechecks. It does not edit engine files or create final lockfile authority.",
    }


def _patch107_write_json(path: Path, payload: dict) -> None:
    import json
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, indent=2, sort_keys=True) + "\n", encoding="utf-8")


def _patch107_read_json(path: Path) -> dict:
    import json
    return json.loads(path.read_text(encoding="utf-8"))


def _patch107_sha256(path: Path) -> str | None:
    import hashlib
    try:
        h = hashlib.sha256()
        with path.open("rb") as f:
            for chunk in iter(lambda: f.read(1024 * 1024), b""):
                h.update(chunk)
        return h.hexdigest()
    except Exception:
        return None


def _patch107_latest_file(directory: Path, pattern: str) -> Path | None:
    try:
        files = [p for p in directory.glob(pattern) if p.is_file() and not p.name.startswith("latest_")]
        return sorted(files, key=lambda p: p.stat().st_mtime, reverse=True)[0] if files else None
    except Exception:
        return None


def _patch107_resolve_path(arg: str, directory: Path, latest_pattern: str) -> Path | None:
    arg = (arg or "latest").strip()
    if arg in ("", "latest"):
        latest = directory / latest_pattern
        if latest.exists():
            return latest
        return _patch107_latest_file(directory, latest_pattern.replace("latest_", "*_"))
    p = Path(arg).expanduser()
    if p.exists():
        return p
    candidate = directory / arg
    if candidate.exists():
        return candidate
    return None


def _patch107_ledger_path() -> Path:
    return Path.home() / "forge" / "memory" / "code_library_v1" / "manifests" / "engine_review_ledger_v1.json"


def _patch107_batch_approval_dir() -> Path:
    return Path.home() / "forge" / "memory" / "engine_review_batch_approvals_v1"


def _patch107_latest_batch_approval_receipts() -> list[tuple[dict, Path]]:
    d = _patch107_batch_approval_dir()
    rows = []
    if not d.exists():
        return rows
    for p in sorted(d.glob("*_engine_review_batch_approval_v1.json")):
        if p.name.startswith("latest_"):
            continue
        try:
            data = _patch107_read_json(p)
            rows.append((data, p))
        except Exception:
            continue
    return rows


def _patch107_latest_batch_decisions_by_engine() -> dict[str, tuple[dict, dict, Path]]:
    """Return latest Patch106 decision row per engine from batch approval receipts."""
    latest = {}
    for receipt, path in _patch107_latest_batch_approval_receipts():
        for row in receipt.get("rows") or []:
            engine = row.get("engine_family")
            if not engine:
                continue
            if row.get("status") != "BATCH_QUEUE_DECISION_RECORDED_NO_LEDGER_MUTATION":
                continue
            latest[engine] = (receipt, row, path)
    return latest


def _patch107_decision_to_status(decision: str | None) -> tuple[str | None, bool, str | None]:
    if decision == "APPROVED_FOR_FUTURE_COMMIT":
        return "APPROVED", True, None
    if decision == "DEFERRED_FOR_MORE_REVIEW":
        return "DEFERRED", False, "deferred_by_evidence_based_batch_review"
    if decision == "REJECTED_FROM_CANONICAL_REVIEW":
        return "REJECTED", False, "rejected_by_evidence_based_batch_review"
    return None, False, "unknown_or_missing_decision"


def _patch107_load_json_path(path_value: str | None) -> tuple[dict | None, Path | None, str | None]:
    if not path_value:
        return None, None, "missing path"
    p = Path(path_value).expanduser()
    if not p.exists():
        return None, p, "path missing on disk"
    try:
        return _patch107_read_json(p), p, None
    except Exception as e:
        return None, p, f"failed to read JSON: {type(e).__name__}: {e}"


def _patch107_verify_binder_live(binder: dict) -> tuple[bool, list[str], list[str], list[dict]]:
    blockers: list[str] = []
    warnings: list[str] = []
    live_rows: list[dict] = []
    approved_root = Path.home() / "aiweb"
    candidate_raw = binder.get("candidate_path_resolved") or binder.get("candidate_path") or binder.get("candidate_path_recorded")
    if not candidate_raw:
        blockers.append("evidence binder has no candidate path")
    else:
        candidate = Path(str(candidate_raw)).expanduser()
        if not candidate.is_absolute():
            s = str(candidate)
            if s.startswith("aiweb/"):
                candidate = Path.home() / s
            else:
                candidate = approved_root / s
        try:
            candidate_resolved = candidate.resolve()
            approved_resolved = approved_root.resolve()
            if not str(candidate_resolved).startswith(str(approved_resolved)):
                blockers.append(f"candidate path outside approved AI.Web scope: {candidate_resolved}")
            if not candidate_resolved.exists():
                blockers.append(f"candidate path missing on disk: {candidate_resolved}")
        except Exception as e:
            blockers.append(f"candidate path resolution failed: {type(e).__name__}: {e}")

    for f in binder.get("file_evidence") or []:
        path_text = f.get("path")
        expected = f.get("sha256")
        row = {
            "path": path_text,
            "exists_now": False,
            "expected_sha256": expected,
            "current_sha256": None,
            "sha_matches_evidence_binder": False,
        }
        if not path_text:
            row["blocker"] = "missing file path in evidence binder row"
            blockers.append(row["blocker"])
            live_rows.append(row)
            continue
        p = Path(path_text).expanduser()
        try:
            p_resolved = p.resolve()
            approved_resolved = approved_root.resolve()
            if not str(p_resolved).startswith(str(approved_resolved)):
                row["blocker"] = "evidence file outside approved AI.Web scope"
                blockers.append(f"{path_text}: outside approved AI.Web scope")
            if p_resolved.exists() and p_resolved.is_file():
                row["exists_now"] = True
                current = _patch107_sha256(p_resolved)
                row["current_sha256"] = current
                row["sha_matches_evidence_binder"] = bool(expected and current == expected)
                if expected and current != expected:
                    row["blocker"] = "REFUSED_STALE_ENGINE_EVIDENCE"
                    blockers.append(f"{path_text}: REFUSED_STALE_ENGINE_EVIDENCE current SHA differs from binder")
                elif not expected:
                    row["warning"] = "no expected SHA in binder row"
                    warnings.append(f"{path_text}: no expected SHA in binder row")
            else:
                row["blocker"] = "evidence file missing on disk"
                blockers.append(f"{path_text}: evidence file missing on disk")
        except Exception as e:
            row["blocker"] = f"file check failed: {type(e).__name__}: {e}"
            blockers.append(f"{path_text}: {row['blocker']}")
        live_rows.append(row)
    if not live_rows:
        warnings.append("evidence binder has no file_evidence rows")
    return not blockers, blockers, warnings, live_rows


def _patch107_ledger_entries_by_engine(ledger: dict) -> dict[str, dict]:
    return {e.get("engine_base"): e for e in ledger.get("entries") or [] if e.get("engine_base")}


def _patch107_build_plan() -> tuple[dict, Path, Path]:
    now = _patch107_now()
    ledger_path = _patch107_ledger_path()
    ledger = _patch107_read_json(ledger_path) if ledger_path.exists() else {"entries": []}
    ledger_sha = _patch107_sha256(ledger_path) if ledger_path.exists() else None
    entries_by_engine = _patch107_ledger_entries_by_engine(ledger)
    decisions = _patch107_latest_batch_decisions_by_engine()
    rows = []
    blockers = []
    warnings = []
    eligible_count = 0
    skipped_already_committed = 0

    for engine in sorted(decisions.keys()):
        receipt, decision_row, receipt_path = decisions[engine]
        decision_value = decision_row.get("requested_decision") or receipt.get("decision_value")
        target_status, future_eligible, block_reason = _patch107_decision_to_status(decision_value)
        row = {
            "engine_family": engine,
            "decision_value": decision_value,
            "target_review_status": target_status,
            "future_lockfile_eligible_after_commit": future_eligible,
            "batch_approval_receipt_path": str(receipt_path),
            "batch_approval_receipt_sha256": _patch107_sha256(receipt_path),
            "queue_decision_path": decision_row.get("queue_decision_path"),
            "queue_decision_sha256_expected": decision_row.get("queue_decision_sha256"),
            "approval_helper_path": decision_row.get("check_path"),
            "approval_helper_sha256_expected": decision_row.get("check_sha256"),
            "evidence_id": decision_row.get("evidence_id"),
            "candidate_path": decision_row.get("candidate_path"),
            "blockers": [],
            "warnings": list(decision_row.get("warnings") or []),
            "already_committed": False,
            "eligible_for_commit": False,
        }
        if not target_status:
            row["blockers"].append("unknown or missing target review status")

        q_data, q_path, q_err = _patch107_load_json_path(row["queue_decision_path"])
        if q_err:
            row["blockers"].append(f"queue decision problem: {q_err}")
        else:
            q_sha = _patch107_sha256(q_path)
            row["queue_decision_sha256_actual"] = q_sha
            if row["queue_decision_sha256_expected"] and q_sha != row["queue_decision_sha256_expected"]:
                row["blockers"].append("queue decision SHA mismatch")
            row["queue_decision_id"] = (q_data or {}).get("decision_id")

        helper, helper_path, helper_err = _patch107_load_json_path(row["approval_helper_path"])
        if helper_err:
            row["blockers"].append(f"approval helper problem: {helper_err}")
        else:
            helper_sha = _patch107_sha256(helper_path)
            row["approval_helper_sha256_actual"] = helper_sha
            if row["approval_helper_sha256_expected"] and helper_sha != row["approval_helper_sha256_expected"]:
                row["blockers"].append("approval helper SHA mismatch")
            row["crosscheck_path"] = helper.get("crosscheck_path")
            row["crosscheck_sha256_expected"] = helper.get("crosscheck_sha256")
            row["evidence_binder_path"] = helper.get("evidence_binder_path")
            row["evidence_binder_sha256_expected"] = helper.get("evidence_binder_sha256")

        cc_data, cc_path, cc_err = _patch107_load_json_path(row.get("crosscheck_path"))
        if cc_err:
            row["blockers"].append(f"crosscheck problem: {cc_err}")
        else:
            cc_sha = _patch107_sha256(cc_path)
            row["crosscheck_sha256_actual"] = cc_sha
            if row.get("crosscheck_sha256_expected") and cc_sha != row.get("crosscheck_sha256_expected"):
                row["blockers"].append("Patch102 cross-check SHA mismatch")
            if cc_data and (cc_data.get("blockers") or []):
                row["blockers"].extend([f"crosscheck blocker: {b}" for b in cc_data.get("blockers") or []])

        binder, binder_path, binder_err = _patch107_load_json_path(row.get("evidence_binder_path"))
        if binder_err:
            row["blockers"].append(f"evidence binder problem: {binder_err}")
        else:
            b_sha = _patch107_sha256(binder_path)
            row["evidence_binder_sha256_actual"] = b_sha
            if row.get("evidence_binder_sha256_expected") and b_sha != row.get("evidence_binder_sha256_expected"):
                row["blockers"].append("evidence binder SHA mismatch")
            ok, b_blockers, b_warnings, live_rows = _patch107_verify_binder_live(binder)
            row["live_evidence_file_checks"] = live_rows
            if b_blockers:
                row["blockers"].extend(b_blockers)
            if b_warnings:
                row["warnings"].extend(b_warnings)

        ledger_entry = entries_by_engine.get(engine)
        if not ledger_entry:
            row["blockers"].append("engine not present in engine_review_ledger_v1 entries")
        else:
            row["ledger_current_review_status"] = ledger_entry.get("review_status")
            row["ledger_current_future_lockfile_eligible"] = ledger_entry.get("future_lockfile_eligible")
            if ledger_entry.get("review_status") == target_status and ledger_entry.get("reviewed") is True:
                row["already_committed"] = True
                skipped_already_committed += 1
                row["warnings"].append("ledger already has target review status; skipping as already committed")
            if ledger_entry.get("is_hold_family") and future_eligible:
                row["future_lockfile_eligible_after_commit"] = False
                row["future_lockfile_block_reason"] = "hold_family_requires_manual_review"
                row["warnings"].append("engine is marked hold-family; approval will not make it future-lockfile eligible")
            elif block_reason:
                row["future_lockfile_block_reason"] = block_reason
            else:
                row["future_lockfile_block_reason"] = None

        if row["blockers"]:
            blockers.extend([f"{engine}: {b}" for b in row["blockers"]])
        if row["warnings"]:
            warnings.extend([f"{engine}: {w}" for w in row["warnings"]])
        row["eligible_for_commit"] = (not row["blockers"]) and (not row["already_committed"])
        if row["eligible_for_commit"]:
            eligible_count += 1
        rows.append(row)

    status = "ENGINE_REVIEW_BATCH_COMMIT_PLAN_READY" if eligible_count and not blockers else (
        "ENGINE_REVIEW_BATCH_COMMIT_PLAN_READY_WITH_BLOCKERS" if eligible_count else "ENGINE_REVIEW_BATCH_COMMIT_PLAN_NOT_READY"
    )
    if not rows:
        status = "ENGINE_REVIEW_BATCH_COMMIT_PLAN_NO_BATCH_DECISIONS_FOUND"
        warnings.append("No Patch106 batch queue decisions found.")

    plan = {
        "schema_version": ENGINE_REVIEW_BATCH_COMMIT_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_BATCH_COMMIT_PLAN_V1_PATCH107",
        "created_at": now,
        "status": status,
        "source": "Patch106 batch approval queue decisions only",
        "ledger_path": str(ledger_path),
        "ledger_sha256_at_plan": ledger_sha,
        "counts": {
            "batch_decision_rows": len(rows),
            "eligible_for_commit": eligible_count,
            "already_committed_skipped": skipped_already_committed,
            "blockers": len(blockers),
            "warnings": len(warnings),
        },
        "rows": rows,
        "blockers": blockers,
        "warnings": warnings,
        "confirm_token_required": ENGINE_REVIEW_BATCH_COMMIT_CONFIRM_TOKEN,
        "authority": _patch107_authority(commit_authority=False),
    }
    ENGINE_REVIEW_BATCH_COMMIT_DIR.mkdir(parents=True, exist_ok=True)
    json_path = ENGINE_REVIEW_BATCH_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_BATCH_COMMIT_PLAN_PREFIX}.json"
    md_path = ENGINE_REVIEW_BATCH_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_BATCH_COMMIT_PLAN_PREFIX}.md"
    _patch107_write_json(json_path, plan)
    _patch107_write_plan_md(plan, md_path)
    _patch107_write_json(ENGINE_REVIEW_BATCH_COMMIT_DIR / f"latest_{ENGINE_REVIEW_BATCH_COMMIT_PLAN_PREFIX}.json", plan)
    (ENGINE_REVIEW_BATCH_COMMIT_DIR / f"latest_{ENGINE_REVIEW_BATCH_COMMIT_PLAN_PREFIX}.md").write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")
    return plan, json_path, md_path


def _patch107_write_plan_md(plan: dict, md_path: Path) -> None:
    lines = [
        "# Patch 107 Evidence-Based Batch Commit Plan",
        "",
        f"Status: `{plan.get('status')}`",
        f"Eligible for commit: `{plan.get('counts', {}).get('eligible_for_commit')}`",
        f"Blockers: `{plan.get('counts', {}).get('blockers')}`",
        f"Warnings: `{plan.get('counts', {}).get('warnings')}`",
        "",
        "Rows:",
        "",
    ]
    for r in plan.get("rows", []):
        lines.append(f"- `{r.get('engine_family')}` → `{r.get('target_review_status')}` eligible=`{r.get('eligible_for_commit')}` already_committed=`{r.get('already_committed')}`")
        lines.append(f"  - Evidence: `{r.get('evidence_id')}`")
        lines.append(f"  - Candidate: `{r.get('candidate_path')}`")
        for b in r.get("blockers") or []:
            lines.append(f"  - BLOCKER: {b}")
        for w in r.get("warnings") or []:
            lines.append(f"  - WARNING: {w}")
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")


def _patch107_print_plan(plan: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    print()
    print("── Engine Review Batch Commit Plan — Patch 107 ───────")
    print("  Status   :", plan.get("status"))
    print("  Rows     :", plan.get("counts", {}).get("batch_decision_rows"))
    print("  Eligible :", plan.get("counts", {}).get("eligible_for_commit"))
    print("  Skipped  :", plan.get("counts", {}).get("already_committed_skipped"), "already committed")
    print("  Blockers :", plan.get("counts", {}).get("blockers"))
    print("  Warnings :", plan.get("counts", {}).get("warnings"))
    if json_path:
        print("  JSON     :", json_path)
    if md_path:
        print("  Markdown :", md_path)
    print("  Authority: plan only; NO ledger write until confirm token")
    print("  Confirm  :", ENGINE_REVIEW_BATCH_COMMIT_CONFIRM_TOKEN)
    print("──────────────────────────────────────────────────────")
    for r in plan.get("rows", []):
        print(f"  - {r.get('engine_family')} → {r.get('target_review_status')} | eligible={r.get('eligible_for_commit')} | evidence={r.get('evidence_id')}")
        for b in r.get("blockers") or []:
            print("      BLOCKER:", b)
        for w in (r.get("warnings") or [])[:3]:
            print("      warning:", w)
    print()


def _patch107_resolve_plan(arg: str = "latest") -> Path | None:
    return _patch107_resolve_path(arg, ENGINE_REVIEW_BATCH_COMMIT_DIR, f"latest_{ENGINE_REVIEW_BATCH_COMMIT_PLAN_PREFIX}.json")


def _patch107_resolve_receipt(arg: str = "latest") -> Path | None:
    return _patch107_resolve_path(arg, ENGINE_REVIEW_BATCH_COMMIT_DIR, f"latest_{ENGINE_REVIEW_BATCH_COMMIT_PREFIX}.json")


def _patch107_validate_plan(plan: dict) -> tuple[bool, list[str], list[str]]:
    problems = []
    warnings = []
    if plan.get("report_type") != "ENGINE_REVIEW_BATCH_COMMIT_PLAN_V1_PATCH107":
        problems.append("wrong report type for Patch 107 batch commit plan")
    if plan.get("counts", {}).get("eligible_for_commit", 0) <= 0:
        problems.append("no eligible rows to commit")
    if plan.get("blockers"):
        problems.extend(plan.get("blockers") or [])
    current_ledger_sha = _patch107_sha256(_patch107_ledger_path()) if _patch107_ledger_path().exists() else None
    if plan.get("ledger_sha256_at_plan") != current_ledger_sha:
        problems.append("ledger SHA changed since plan was written")
    warnings.extend(plan.get("warnings") or [])
    return not problems, problems, warnings


def cmd_engine_review_batch_commit_policy(session_id: str) -> None:
    """Show Patch 107 batch commit policy."""
    print()
    print("── Engine Review Batch Commit Policy — Patch 107 ────")
    print("  Purpose   : commit Patch106 evidence-based batch queue decisions into engine_review_ledger_v1 after stale-evidence recheck")
    print("  Writes    : human review ledger + Forge-owned batch commit receipts")
    print("  Authority : ledger write only after explicit confirm token")
    print("  Required  : Patch106 decision, queue decision SHA, Patch103 helper, Patch102 cross-check, binder SHA, live file SHA match, ledger SHA match")
    print("  Still NO  : engine file writes, final lockfile authority, quarantine, delete, Chroma writes, shell")
    print("  Refusal   : REFUSED_STALE_ENGINE_EVIDENCE if live evidence file differs from binder")
    print("──────────────────────────────────────────────────────")
    print()


def cmd_engine_review_batch_commit_plan(session_id: str) -> None:
    """Build a Patch 107 evidence-based batch commit plan."""
    from agents.forge.memory import write_audit_entry
    plan, json_path, md_path = _patch107_build_plan()
    _patch107_print_plan(plan, json_path, md_path)
    write_audit_entry(session_id, "ENGINE_REVIEW_BATCH_COMMIT_PLAN_WRITTEN", str(json_path), f"eligible={plan.get('counts', {}).get('eligible_for_commit')}", plan.get("status", "unknown"))


def cmd_engine_review_batch_commit_show(arg: str, session_id: str) -> None:
    """Show latest Patch 107 batch commit plan or receipt."""
    p = _patch107_resolve_plan(arg) or _patch107_resolve_receipt(arg)
    if not p:
        print("No Patch 107 batch commit plan/receipt found. Run: engine-review-batch-commit-plan")
        return
    data = _patch107_read_json(p)
    if data.get("report_type") == "ENGINE_REVIEW_BATCH_COMMIT_PLAN_V1_PATCH107":
        _patch107_print_plan(data, p, None)
        return
    _patch107_print_receipt(data, p, None)


def cmd_engine_review_batch_commit_verify(arg: str, session_id: str) -> None:
    """Verify latest Patch 107 plan or receipt."""
    p = _patch107_resolve_plan(arg) or _patch107_resolve_receipt(arg)
    print()
    print("── Engine Review Batch Commit Verify — Patch 107 ────")
    if not p:
        print("  Status  : FAIL")
        print("  Reason  : no Patch 107 plan/receipt found")
        print("──────────────────────────────────────────────────────")
        print()
        return
    data = _patch107_read_json(p)
    if data.get("report_type") == "ENGINE_REVIEW_BATCH_COMMIT_PLAN_V1_PATCH107":
        ok, problems, warnings = _patch107_validate_plan(data)
    elif data.get("report_type") == "ENGINE_REVIEW_BATCH_COMMIT_RECEIPT_V1_PATCH107":
        problems = list(data.get("blockers") or [])
        warnings = list(data.get("warnings") or [])
        ok = data.get("status") in ("ENGINE_REVIEW_BATCH_COMMIT_APPLIED", "ENGINE_REVIEW_BATCH_COMMIT_APPLIED_WITH_WARNINGS") and not problems
    else:
        ok = False
        problems = ["unknown Patch 107 report type"]
        warnings = []
    print("  Report  :", p)
    print("  Status  :", "PASS" if ok else "FAIL")
    print("  Problems:", len(problems))
    print("  Warnings:", len(warnings))
    for problem in problems[:20]:
        print("    -", problem)
    print("──────────────────────────────────────────────────────")
    print()


def _patch107_apply_to_ledger(plan: dict) -> tuple[dict, Path, Path]:
    now = _patch107_now()
    ledger_path = _patch107_ledger_path()
    ledger = _patch107_read_json(ledger_path)
    ledger_sha_before = _patch107_sha256(ledger_path)
    entries_by_engine = _patch107_ledger_entries_by_engine(ledger)
    applied_rows = []
    skipped_rows = []
    blockers = []
    warnings = []

    backup_path = ledger_path.with_name(f"{now}_engine_review_ledger_before_patch107_batch_commit.json")
    backup_path.parent.mkdir(parents=True, exist_ok=True)
    backup_path.write_text(ledger_path.read_text(encoding="utf-8"), encoding="utf-8")

    for row in plan.get("rows") or []:
        engine = row.get("engine_family")
        if not row.get("eligible_for_commit"):
            skipped_rows.append({"engine_family": engine, "reason": "not eligible", "blockers": row.get("blockers"), "already_committed": row.get("already_committed")})
            continue
        entry = entries_by_engine.get(engine)
        if not entry:
            blockers.append(f"{engine}: missing ledger entry during apply")
            continue
        target = row.get("target_review_status")
        decision = row.get("decision_value")
        entry["review_status"] = target
        entry["reviewed"] = True
        entry["reviewed_at"] = now
        entry["reviewed_by"] = "Nic via Patch106 evidence-based batch approval + Patch107 batch commit"
        entry["review_note"] = (
            f"Patch107 batch evidence commit from Patch106 queue decision. Decision={decision}; "
            f"evidence_id={row.get('evidence_id')}; batch_receipt_sha={row.get('batch_approval_receipt_sha256')}; "
            f"queue_decision_sha={row.get('queue_decision_sha256_actual') or row.get('queue_decision_sha256_expected')}; "
            f"approval_helper_sha={row.get('approval_helper_sha256_actual') or row.get('approval_helper_sha256_expected')}; "
            f"binder_sha={row.get('evidence_binder_sha256_actual') or row.get('evidence_binder_sha256_expected')}; "
            f"crosscheck_sha={row.get('crosscheck_sha256_actual') or row.get('crosscheck_sha256_expected')} ."
        )
        entry["future_lockfile_eligible"] = bool(row.get("future_lockfile_eligible_after_commit"))
        entry["future_lockfile_block_reason"] = row.get("future_lockfile_block_reason")
        entry["no_engine_file_action"] = True
        entry["no_quarantine_action"] = True
        entry["canonical_authority"] = False
        entry["patch107_batch_evidence_commit"] = {
            "committed_at": now,
            "decision_value": decision,
            "batch_approval_receipt_path": row.get("batch_approval_receipt_path"),
            "batch_approval_receipt_sha256": row.get("batch_approval_receipt_sha256"),
            "queue_decision_path": row.get("queue_decision_path"),
            "queue_decision_sha256": row.get("queue_decision_sha256_actual") or row.get("queue_decision_sha256_expected"),
            "approval_helper_path": row.get("approval_helper_path"),
            "approval_helper_sha256": row.get("approval_helper_sha256_actual") or row.get("approval_helper_sha256_expected"),
            "patch102_crosscheck_path": row.get("crosscheck_path"),
            "patch102_crosscheck_sha256": row.get("crosscheck_sha256_actual") or row.get("crosscheck_sha256_expected"),
            "evidence_binder_path": row.get("evidence_binder_path"),
            "evidence_binder_sha256": row.get("evidence_binder_sha256_actual") or row.get("evidence_binder_sha256_expected"),
            "candidate_path": row.get("candidate_path"),
            "live_evidence_file_checks": row.get("live_evidence_file_checks") or [],
        }
        applied_rows.append({"engine_family": engine, "target_review_status": target, "future_lockfile_eligible": entry.get("future_lockfile_eligible")})

    ledger["updated_at"] = now
    ledger["last_patch107_batch_commit_at"] = now
    ledger["last_patch107_batch_commit_applied"] = len(applied_rows)
    ledger["canonical_authority"] = False
    ledger["actual_lockfile_written"] = False
    ledger["engine_files_changed"] = False
    ledger["quarantine_written"] = False
    _patch107_write_json(ledger_path, ledger)
    ledger_sha_after = _patch107_sha256(ledger_path)

    status = "ENGINE_REVIEW_BATCH_COMMIT_APPLIED" if applied_rows and not blockers and not warnings else (
        "ENGINE_REVIEW_BATCH_COMMIT_APPLIED_WITH_WARNINGS" if applied_rows and not blockers else "ENGINE_REVIEW_BATCH_COMMIT_BLOCKED"
    )
    receipt = {
        "schema_version": ENGINE_REVIEW_BATCH_COMMIT_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_BATCH_COMMIT_RECEIPT_V1_PATCH107",
        "created_at": now,
        "status": status,
        "applied_count": len(applied_rows),
        "skipped_count": len(skipped_rows),
        "applied_rows": applied_rows,
        "skipped_rows": skipped_rows,
        "blockers": blockers,
        "warnings": warnings,
        "ledger_path": str(ledger_path),
        "ledger_backup_path": str(backup_path),
        "ledger_sha256_before": ledger_sha_before,
        "ledger_sha256_after": ledger_sha_after,
        "authority": _patch107_authority(commit_authority=True),
    }
    json_path = ENGINE_REVIEW_BATCH_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_BATCH_COMMIT_PREFIX}.json"
    md_path = ENGINE_REVIEW_BATCH_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_BATCH_COMMIT_PREFIX}.md"
    _patch107_write_json(json_path, receipt)
    _patch107_write_receipt_md(receipt, md_path)
    _patch107_write_json(ENGINE_REVIEW_BATCH_COMMIT_DIR / f"latest_{ENGINE_REVIEW_BATCH_COMMIT_PREFIX}.json", receipt)
    (ENGINE_REVIEW_BATCH_COMMIT_DIR / f"latest_{ENGINE_REVIEW_BATCH_COMMIT_PREFIX}.md").write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")
    return receipt, json_path, md_path


def _patch107_write_receipt_md(receipt: dict, md_path: Path) -> None:
    lines = [
        "# Patch 107 Evidence-Based Batch Commit Receipt",
        "",
        f"Status: `{receipt.get('status')}`",
        f"Applied: `{receipt.get('applied_count')}`",
        f"Skipped: `{receipt.get('skipped_count')}`",
        f"Ledger before: `{receipt.get('ledger_sha256_before')}`",
        f"Ledger after: `{receipt.get('ledger_sha256_after')}`",
        "",
        "Applied rows:",
        "",
    ]
    for r in receipt.get("applied_rows", []):
        lines.append(f"- `{r.get('engine_family')}` → `{r.get('target_review_status')}` eligible=`{r.get('future_lockfile_eligible')}`")
    for b in receipt.get("blockers") or []:
        lines.append(f"- BLOCKER: {b}")
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")


def _patch107_print_receipt(receipt: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    print()
    print("── Engine Review Batch Commit Receipt — Patch 107 ───")
    print("  Status :", receipt.get("status"))
    print("  Applied:", receipt.get("applied_count"))
    print("  Skipped:", receipt.get("skipped_count"))
    print("  Blockers:", len(receipt.get("blockers") or []))
    print("  Warnings:", len(receipt.get("warnings") or []))
    if json_path:
        print("  JSON   :", json_path)
    if md_path:
        print("  Markdown:", md_path)
    print("  Ledger :", receipt.get("ledger_path"))
    print("  Authority: ledger write only; NO engine files, NO final lockfile")
    print("──────────────────────────────────────────────────────")
    for r in receipt.get("applied_rows") or []:
        print(f"  - {r.get('engine_family')} → {r.get('target_review_status')} | future_lockfile_eligible={r.get('future_lockfile_eligible')}")
    print()


def cmd_engine_review_batch_commit_apply(arg: str, session_id: str) -> None:
    """Apply latest Patch 107 batch commit plan only with explicit confirm token."""
    from agents.forge.memory import write_audit_entry
    token = (arg or "").strip()
    if token != ENGINE_REVIEW_BATCH_COMMIT_CONFIRM_TOKEN:
        print()
        print("── Engine Review Batch Commit Apply — Patch 107 ─────")
        print("  Status : REFUSED_CONFIRM_TOKEN_REQUIRED")
        print("  Needed :", ENGINE_REVIEW_BATCH_COMMIT_CONFIRM_TOKEN)
        print("  Result : no ledger mutation")
        print("──────────────────────────────────────────────────────")
        print()
        write_audit_entry(session_id, "ENGINE_REVIEW_BATCH_COMMIT_APPLY_REFUSED", "-", "missing_confirm_token", "no_ledger_mutation")
        return
    plan, plan_json, _plan_md = _patch107_build_plan()
    ok, problems, warnings = _patch107_validate_plan(plan)
    if not ok:
        print()
        print("── Engine Review Batch Commit Apply — Patch 107 ─────")
        print("  Status : REFUSED_PLAN_NOT_VALID")
        print("  Problems:", len(problems))
        for p in problems[:20]:
            print("    -", p)
        print("  Result : no ledger mutation")
        print("──────────────────────────────────────────────────────")
        print()
        write_audit_entry(session_id, "ENGINE_REVIEW_BATCH_COMMIT_APPLY_REFUSED", str(plan_json), f"problems={len(problems)}", "no_ledger_mutation")
        return
    receipt, json_path, md_path = _patch107_apply_to_ledger(plan)
    _patch107_print_receipt(receipt, json_path, md_path)
    write_audit_entry(session_id, "ENGINE_REVIEW_BATCH_COMMIT_APPLIED", str(json_path), f"applied={receipt.get('applied_count')}", receipt.get("status", "unknown"))


def cmd_engine_review_batch_commit_export(session_id: str) -> None:
    """Export Patch 107 batch commit plans and receipts."""
    from agents.forge.memory import write_audit_entry
    ENGINE_REVIEW_BATCH_COMMIT_DIR.mkdir(parents=True, exist_ok=True)
    reports = []
    for p in sorted(ENGINE_REVIEW_BATCH_COMMIT_DIR.glob("*.json")):
        if p.name.startswith("latest_"):
            continue
        try:
            d = _patch107_read_json(p)
            reports.append({"path": str(p), "sha256": _patch107_sha256(p), "report_type": d.get("report_type"), "status": d.get("status"), "counts": d.get("counts"), "applied_count": d.get("applied_count")})
        except Exception:
            continue
    now = _patch107_now()
    export = {"schema_version": ENGINE_REVIEW_BATCH_COMMIT_SCHEMA_VERSION, "report_type": "ENGINE_REVIEW_BATCH_COMMIT_EXPORT_V1_PATCH107", "created_at": now, "counts": {"reports": len(reports)}, "reports": reports, "authority": _patch107_authority(commit_authority=False)}
    json_path = ENGINE_REVIEW_BATCH_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_BATCH_COMMIT_EXPORT_PREFIX}.json"
    md_path = ENGINE_REVIEW_BATCH_COMMIT_DIR / f"{now}_{ENGINE_REVIEW_BATCH_COMMIT_EXPORT_PREFIX}.md"
    _patch107_write_json(json_path, export)
    md_path.write_text("# Patch 107 Batch Commit Export\n\n" + "\n".join([f"- `{r.get('report_type')}` `{r.get('status')}` — `{r.get('path')}`" for r in reports]) + "\n", encoding="utf-8")
    print()
    print("── Engine Review Batch Commit Export — Patch 107 ────")
    print("  JSON    :", json_path)
    print("  Markdown:", md_path)
    print("  Reports :", len(reports))
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_BATCH_COMMIT_EXPORT_WRITTEN", str(json_path), f"reports={len(reports)}", "no_ledger_mutation")


# ─── PATCH 108: ENGINE REVIEW PROGRESS DASHBOARD / REMAINING QUEUE MAP ───────

def _patch108_root() -> "Path":
    from pathlib import Path
    return Path.home() / "forge"


def _patch108_now() -> str:
    from datetime import datetime
    return datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch108_read_json(path):
    import json
    from pathlib import Path
    p = Path(path)
    return json.loads(p.read_text(encoding="utf-8"))


def _patch108_write_json(path, data):
    import json
    from pathlib import Path
    p = Path(path)
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, indent=2, sort_keys=True), encoding="utf-8")


def _patch108_sha256(path):
    import hashlib
    from pathlib import Path
    p = Path(path)
    h = hashlib.sha256()
    with p.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def _patch108_safe_read(path):
    try:
        return _patch108_read_json(path)
    except Exception:
        return None


def _patch108_review_dir():
    return _patch108_root() / "memory" / "engine_review_progress_v1"


def _patch108_latest_json(directory, pattern):
    from pathlib import Path
    d = Path(directory)
    if not d.exists():
        return None
    matches = sorted([p for p in d.glob(pattern) if p.is_file()])
    return matches[-1] if matches else None


def _patch108_engine_from_latest_name(path, suffix):
    name = path.name
    if name.startswith("latest_"):
        name = name[len("latest_"):]
    if name.endswith(suffix):
        name = name[:-len(suffix)]
    return name


def _patch108_authority():
    return {
        "patch": "108",
        "mode": "ENGINE_REVIEW_PROGRESS_DASHBOARD_READ_ONLY",
        "writes": [str(_patch108_review_dir())],
        "human_review_ledger_write_authority": False,
        "engine_file_write_authority": False,
        "project_file_write_authority": False,
        "final_lockfile_authority": False,
        "canonical_decision_authority": False,
        "llm_autonomous_decision_authority": False,
        "chroma_write_authority": False,
        "ingestion_write_authority": False,
        "shell_execution_authority": False,
        "rule": "Patch 108 only summarizes engine review progress, queue state, evidence coverage, and remaining work. It does not approve, defer, commit, edit engines, or create lockfile authority.",
    }


def _patch108_collect():
    from collections import Counter
    from pathlib import Path
    forge = _patch108_root()
    memory = forge / "memory"
    code_manifests = memory / "code_library_v1" / "manifests"
    ledger_path = code_manifests / "engine_review_ledger_v1.json"
    ledger = _patch108_safe_read(ledger_path) or {}
    entries = ledger.get("entries", []) if isinstance(ledger, dict) else []
    engine_names = [e.get("engine_base") or e.get("engine_family") or e.get("name") for e in entries]
    engine_names = [e for e in engine_names if e]
    status_counter = Counter((e.get("review_status") or "UNKNOWN") for e in entries)
    eligible = [e.get("engine_base") for e in entries if e.get("future_lockfile_eligible")]
    approved = [e.get("engine_base") for e in entries if e.get("review_status") == "APPROVED"]
    deferred = [e.get("engine_base") for e in entries if e.get("review_status") == "DEFERRED"]
    rejected = [e.get("engine_base") for e in entries if e.get("review_status") == "REJECTED"]
    pending = [e.get("engine_base") for e in entries if e.get("review_status") == "PENDING_REVIEW"]

    def latest_set(dir_name, suffix):
        d = memory / dir_name
        out = set()
        if d.exists():
            for p in d.glob("latest_*" + suffix):
                if p.is_file():
                    out.add(_patch108_engine_from_latest_name(p, suffix))
        return out

    binder_set = latest_set("engine_evidence_binders_v1", "_engine_evidence_binder.json")
    draft_set = latest_set("llm_engine_review_drafts_v1", "_llm_engine_review_draft.json")
    crosscheck_set = latest_set("engine_review_evidence_crosschecks_v1", "_engine_review_evidence_crosscheck_v1.json")
    approval_helper_set = latest_set("engine_review_approval_helpers_v1", "_engine_review_approval_helper_v1.json")

    # Queue state from latest report and decision receipts.
    queue_dir = memory / "engine_review_queue_v1"
    latest_queue_path = queue_dir / "latest_engine_review_queue_v1.json"
    latest_queue = _patch108_safe_read(latest_queue_path) or {}
    queue_items = latest_queue.get("items", []) if isinstance(latest_queue, dict) else []
    queue_counts = latest_queue.get("counts", {}) if isinstance(latest_queue, dict) else {}
    decision_receipts = []
    if queue_dir.exists():
        for p in sorted(queue_dir.glob("*_engine_review_queue_decision_v1.json")):
            d = _patch108_safe_read(p)
            if isinstance(d, dict):
                decision_receipts.append({
                    "engine": d.get("engine") or d.get("engine_family") or d.get("engine_base"),
                    "decision": d.get("decision") or d.get("queue_decision") or d.get("status"),
                    "path": str(p),
                    "sha256": _patch108_sha256(p),
                })

    # Latest commit receipts.
    p100_dir = memory / "engine_review_commits_v1"
    p104_dir = memory / "engine_review_evidence_commits_v1"
    p107_dir = memory / "engine_review_batch_commits_v1"
    latest_batch_commit_path = p107_dir / "latest_engine_review_batch_commit_v1.json"
    latest_batch_commit = _patch108_safe_read(latest_batch_commit_path) or {}
    latest_evidence_commit_path = p104_dir / "latest_engine_review_evidence_commit_v1.json"
    latest_evidence_commit = _patch108_safe_read(latest_evidence_commit_path) or {}

    # Latest workflow / batch run receipts.
    latest_workflow = _patch108_safe_read((memory / "engine_review_workflows_v1" / "latest_engine_review_workflow_v1.json")) or {}
    latest_batch_run = _patch108_safe_read((memory / "llm_engine_review_batch_runs_v1" / "latest_llm_engine_review_batch_run_v1.json")) or {}

    engine_set = set(engine_names)
    pending_set = set([x for x in pending if x])
    approved_set = set([x for x in approved if x])
    deferred_set = set([x for x in deferred if x])
    rejected_set = set([x for x in rejected if x])

    gaps = {
        "pending_without_evidence_binder": sorted(pending_set - binder_set),
        "pending_with_binder_no_llm_draft": sorted((pending_set & binder_set) - draft_set),
        "drafted_without_crosscheck": sorted((draft_set & engine_set) - crosscheck_set - approved_set - deferred_set - rejected_set),
        "crosschecked_not_decided": sorted((crosscheck_set & engine_set) - approved_set - deferred_set - rejected_set - set([d.get("engine") for d in decision_receipts if d.get("decision") in ("APPROVED_FOR_FUTURE_COMMIT", "DEFERRED_FOR_MORE_REVIEW", "REJECTED_FROM_CANONICAL_REVIEW")])),
        "queue_decided_not_committed_approx": [],
    }
    # approximate queue decisions not reflected in ledger yet
    by_status = {e.get("engine_base"): e.get("review_status") for e in entries}
    undecided_decisions = []
    for d in decision_receipts:
        eng = d.get("engine")
        dec = d.get("decision")
        if not eng:
            continue
        if dec == "APPROVED_FOR_FUTURE_COMMIT" and by_status.get(eng) != "APPROVED":
            undecided_decisions.append(eng)
        elif dec == "DEFERRED_FOR_MORE_REVIEW" and by_status.get(eng) != "DEFERRED":
            undecided_decisions.append(eng)
        elif dec == "REJECTED_FROM_CANONICAL_REVIEW" and by_status.get(eng) != "REJECTED":
            undecided_decisions.append(eng)
    gaps["queue_decided_not_committed_approx"] = sorted(set(undecided_decisions))

    counts = {
        "ledger_total_entries": len(entries),
        "ledger_approved": status_counter.get("APPROVED", 0),
        "ledger_deferred": status_counter.get("DEFERRED", 0),
        "ledger_rejected": status_counter.get("REJECTED", 0),
        "ledger_pending": status_counter.get("PENDING_REVIEW", 0),
        "future_lockfile_eligible": len([e for e in entries if e.get("future_lockfile_eligible")]),
        "latest_evidence_binders": len(binder_set),
        "latest_llm_drafts": len(draft_set),
        "latest_evidence_crosschecks": len(crosscheck_set),
        "latest_approval_helpers": len(approval_helper_set),
        "queue_items_latest_report": len(queue_items),
        "queue_decision_receipts": len(decision_receipts),
        "remaining_pending_without_draft": len(gaps["pending_with_binder_no_llm_draft"]),
        "drafted_without_crosscheck": len(gaps["drafted_without_crosscheck"]),
        "crosschecked_not_decided": len(gaps["crosschecked_not_decided"]),
        "queue_decided_not_committed_approx": len(gaps["queue_decided_not_committed_approx"]),
    }
    status = "ENGINE_REVIEW_PROGRESS_READY"
    next_step = "Continue controlled review batches. Use engine-review-workflow-run, engine-review-evidence-show, batch approval, then batch commit. Do not approve from summary alone."
    if gaps["queue_decided_not_committed_approx"]:
        next_step = "Run an evidence-based commit gate for queue decisions not yet reflected in the ledger."
    elif gaps["crosschecked_not_decided"]:
        next_step = "Review crosschecked engines and approve/defer/reject with evidence visible."
    elif gaps["drafted_without_crosscheck"]:
        next_step = "Run evidence cross-checks for drafted engines before approval."
    elif gaps["pending_with_binder_no_llm_draft"]:
        next_step = "Run engine-review-workflow-run in small batches to create LLM drafts and cross-checks."

    return {
        "schema_version": "engine_review_progress_v1_patch108",
        "report_type": "ENGINE_REVIEW_PROGRESS_REPORT_V1_PATCH108",
        "created_at": _patch108_now(),
        "status": status,
        "authority": _patch108_authority(),
        "ledger_path": str(ledger_path),
        "ledger_sha256": _patch108_sha256(ledger_path) if ledger_path.exists() else None,
        "counts": counts,
        "ledger_status_counts": dict(status_counter),
        "queue_counts_latest_report": queue_counts,
        "approved_engines": sorted([x for x in approved if x]),
        "deferred_engines": sorted([x for x in deferred if x]),
        "rejected_engines": sorted([x for x in rejected if x]),
        "future_lockfile_eligible_engines": sorted([x for x in eligible if x]),
        "evidence_coverage": {
            "binder_engines": sorted(binder_set),
            "draft_engines": sorted(draft_set),
            "crosschecked_engines": sorted(crosscheck_set),
            "approval_helper_engines": sorted(approval_helper_set),
        },
        "latest_reports": {
            "queue": str(latest_queue_path) if latest_queue_path.exists() else None,
            "workflow": latest_workflow.get("created_at"),
            "batch_run": latest_batch_run.get("created_at"),
            "patch104_evidence_commit": latest_evidence_commit.get("created_at"),
            "patch107_batch_commit": latest_batch_commit.get("created_at"),
        },
        "gaps": gaps,
        "next_step": next_step,
        "manual_rule": "Do not approve from a summary. Always inspect engine-review-evidence-show <engine> before approve/defer/reject.",
    }


def _patch108_write_report(report):
    d = _patch108_review_dir()
    d.mkdir(parents=True, exist_ok=True)
    now = report.get("created_at") or _patch108_now()
    json_path = d / f"{now}_engine_review_progress_report_v1.json"
    md_path = d / f"{now}_engine_review_progress_report_v1.md"
    _patch108_write_json(json_path, report)
    _patch108_write_json(d / "latest_engine_review_progress_report_v1.json", report)
    md_lines = [
        "# Patch 108 Engine Review Progress Report",
        "",
        f"Status: `{report.get('status')}`",
        f"Created: `{report.get('created_at')}`",
        "",
        "## Counts",
    ]
    for k, v in report.get("counts", {}).items():
        md_lines.append(f"- {k}: `{v}`")
    md_lines += ["", "## Next Step", report.get("next_step", ""), "", "## Manual Rule", report.get("manual_rule", "")]
    md_lines += ["", "## Gaps"]
    for k, vals in report.get("gaps", {}).items():
        md_lines.append(f"- {k}: `{len(vals) if isinstance(vals, list) else vals}`")
        if isinstance(vals, list):
            for item in vals[:25]:
                md_lines.append(f"  - `{item}`")
            if len(vals) > 25:
                md_lines.append(f"  - ... {len(vals)-25} more")
    md_path.write_text("\n".join(md_lines) + "\n", encoding="utf-8")
    latest_md = d / "latest_engine_review_progress_report_v1.md"
    latest_md.write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")
    return json_path, md_path


def _patch108_resolve_report(arg="latest"):
    from pathlib import Path
    d = _patch108_review_dir()
    if arg in (None, "", "latest"):
        p = d / "latest_engine_review_progress_report_v1.json"
        return p if p.exists() else None
    p = Path(arg)
    if p.exists():
        return p
    matches = sorted(d.glob(f"*{arg}*progress_report*.json")) if d.exists() else []
    return matches[-1] if matches else None


def _patch108_print_summary(report, json_path=None):
    print()
    print("── Engine Review Progress Dashboard — Patch 108 ─────")
    if json_path:
        print("  Report   :", json_path)
    print("  Status   :", report.get("status"))
    c = report.get("counts", {})
    print("  Ledger   : total={total} approved={approved} deferred={deferred} rejected={rejected} pending={pending}".format(
        total=c.get("ledger_total_entries", 0), approved=c.get("ledger_approved", 0), deferred=c.get("ledger_deferred", 0), rejected=c.get("ledger_rejected", 0), pending=c.get("ledger_pending", 0)))
    print("  Evidence : binders={b} drafts={d} crosschecks={x} approvals={a}".format(
        b=c.get("latest_evidence_binders", 0), d=c.get("latest_llm_drafts", 0), x=c.get("latest_evidence_crosschecks", 0), a=c.get("latest_approval_helpers", 0)))
    print("  Queue    : latest_items={qi} decision_receipts={dr}".format(qi=c.get("queue_items_latest_report", 0), dr=c.get("queue_decision_receipts", 0)))
    print("  Eligible :", c.get("future_lockfile_eligible", 0))
    print("  Next     :", report.get("next_step"))
    print("  Rule     :", report.get("manual_rule"))
    print("──────────────────────────────────────────────────────")
    print()


