def cmd_engine_review_progress_export(session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    d = _patch108_review_dir()
    d.mkdir(parents=True, exist_ok=True)
    reports = []
    for p in sorted(d.glob("*_engine_review_progress_report_v1.json")):
        if p.name.startswith("latest_"):
            continue
        r = _patch108_safe_read(p)
        if isinstance(r, dict):
            reports.append({"path": str(p), "sha256": _patch108_sha256(p), "created_at": r.get("created_at"), "status": r.get("status"), "counts": r.get("counts", {})})
    now = _patch108_now()
    export = {"schema_version": "engine_review_progress_export_v1_patch108", "report_type": "ENGINE_REVIEW_PROGRESS_EXPORT_V1_PATCH108", "created_at": now, "counts": {"reports": len(reports)}, "reports": reports, "authority": _patch108_authority()}
