def cmd_engine_review_triage_show(arg: str, session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    arg = (arg or "latest").strip()
    if arg.lower() in {"latest", "last", "plan"}:
        path = _patch109_latest_plan_path()
        if not path.exists():
            plan = _patch109_build_plan()
            path, _ = _patch109_write_plan(plan)
        else:
            plan = _patch109_read_json(path)
        _patch109_print_plan(plan)
        write_audit_entry(session_id, "ENGINE_REVIEW_TRIAGE_SHOW", str(path), "latest", "no_mutation")
        return
    engine = _patch109_slug(arg.split()[0])
    row, plan = _patch109_row_for_engine(engine)
    if not row:
        print()
        print("── Engine Review Triage Show ────────────────────────")
        print("  Status: ENGINE_NOT_FOUND_IN_TRIAGE_PLAN")
        print("  Engine:", engine)
        print("  Run   : engine-review-triage-plan")
        print("──────────────────────────────────────────────────────")
        print()
        return
    # Show full evidence first when available.
    try:
        if "cmd_engine_review_evidence_show" in globals():
            cmd_engine_review_evidence_show(engine, session_id)
    except Exception as exc:
        print("[forge] Warning: evidence display failed:", repr(exc))
    print()
    print("── Triage Decision Panel ─────────────────────────────")
    print("  Engine       :", row.get("engine_family"))
    print("  Ready        :", row.get("ready_for_triage_decision"))
    print("  Ledger       :", row.get("ledger_status"))
    print("  Queue        :", row.get("queue_decision"))
    print("  LLM status   :", row.get("llm_status"))
    print("  Evidence ID  :", row.get("evidence_id"))
    print("  Candidate    :", row.get("candidate_path"))
    print("  Recommendation:", row.get("recommendation_draft"))
    if row.get("blockers"):
        print("  Blockers:")
        for b in row.get("blockers"):
            print("    -", b)
    if row.get("warnings"):
        print("  Warnings:")
        for w in row.get("warnings"):
            print("    -", w)
    print("  Approve:", f"engine-review-triage-approve {engine}")
    print("  Defer  :", f"engine-review-triage-defer {engine}")
    print("  Reject :", f"engine-review-triage-reject {engine}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_TRIAGE_SHOW", row.get("crosscheck_path") or "-", engine, "evidence_visible")


def _patch109_write_decision_receipt(receipt: dict) -> tuple[Path, Path]:
    ENGINE_REVIEW_TRIAGE_DIR.mkdir(parents=True, exist_ok=True)
    now = receipt.get("created_at") or _patch109_now()
    engine_part = _patch109_slug("_".join(receipt.get("engines") or ["none"]))[:80] or "none"
    json_path = ENGINE_REVIEW_TRIAGE_DIR / f"{now}_{engine_part}_{ENGINE_REVIEW_TRIAGE_DECISION_PREFIX}.json"
    md_path = ENGINE_REVIEW_TRIAGE_DIR / f"{now}_{engine_part}_{ENGINE_REVIEW_TRIAGE_DECISION_PREFIX}.md"
    _patch109_write_json(json_path, receipt)
    lines = [
        "# Patch 109 Engine Review Triage Decision Receipt",
        "",
        f"Status: `{receipt.get('status')}`",
        f"Decision: `{receipt.get('decision_value')}`",
        f"Recorded: `{receipt.get('counts', {}).get('recorded')}`",
        f"Refused: `{receipt.get('counts', {}).get('refused')}`",
        "",
    ]
    for r in receipt.get("rows") or []:
        lines.append(f"- `{r.get('engine_family')}` — `{r.get('status')}` — queue_receipt=`{r.get('queue_receipt_status')}`")
        for b in r.get("blockers") or []:
            lines.append(f"  - blocker: {b}")
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    _patch109_write_json(ENGINE_REVIEW_TRIAGE_DIR / f"latest_{ENGINE_REVIEW_TRIAGE_DECISION_PREFIX}.json", receipt)
    (ENGINE_REVIEW_TRIAGE_DIR / f"latest_{ENGINE_REVIEW_TRIAGE_DECISION_PREFIX}.md").write_text(md_path.read_text(encoding="utf-8"), encoding="utf-8")
    return json_path, md_path


def cmd_engine_review_triage_decision(arg: str, decision_value: str, session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    engines = _patch109_parse_engine_args(arg)
    now = _patch109_now()
    rows = []
    blockers = []
    if not engines:
        blockers.append("No engines supplied. Example: engine-review-triage-approve agents_stack")
    recordable = []
    for engine in engines:
        row, _ = _patch109_row_for_engine(engine)
        out = {"engine_family": engine, "decision_value": decision_value, "status": "PENDING", "blockers": [], "warnings": [], "queue_receipt_status": None}
        if not row:
            out["blockers"].append("engine_not_found_in_triage_plan")
        else:
            out["crosscheck_path"] = row.get("crosscheck_path")
            out["crosscheck_sha256"] = row.get("crosscheck_sha256")
            out["evidence_id"] = row.get("evidence_id")
            out["candidate_path"] = row.get("candidate_path")
            if row.get("blockers"):
                out["blockers"].extend(row.get("blockers"))
            if row.get("ledger_status") != "PENDING_REVIEW":
                out["blockers"].append(f"ledger_status_is_{row.get('ledger_status')}")
            if row.get("queue_decision") != "UNDECIDED":
                out["blockers"].append(f"queue_decision_already_{row.get('queue_decision')}")
        if out["blockers"]:
            out["status"] = "TRIAGE_DECISION_REFUSED"
            blockers.extend([f"{engine}:{b}" for b in out["blockers"]])
        else:
            out["status"] = "TRIAGE_DECISION_READY_TO_RECORD_QUEUE_INTENT"
            recordable.append(engine)
        rows.append(out)
    queue_status = None
    if recordable:
        if "cmd_engine_review_batch_approval_decision" in globals():
            # Existing Patch106 path writes Patch99-compatible queue decision receipts and keeps ledger authority off.
            cmd_engine_review_batch_approval_decision(" ".join(recordable), decision_value, session_id)
            queue_status = "PATCH106_QUEUE_DECISION_WRITTEN"
            for r in rows:
                if r.get("engine_family") in recordable:
                    r["status"] = "TRIAGE_QUEUE_DECISION_RECORDED_NO_LEDGER_MUTATION"
                    r["queue_receipt_status"] = queue_status
        else:
            blockers.append("patch106_batch_approval_helper_missing")
            for r in rows:
                if r.get("engine_family") in recordable:
                    r["status"] = "TRIAGE_DECISION_REFUSED_PATCH106_MISSING"
                    r.setdefault("blockers", []).append("patch106_batch_approval_helper_missing")
    receipt = {
        "schema_version": ENGINE_REVIEW_TRIAGE_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_TRIAGE_DECISION_V1_PATCH109",
        "created_at": now,
        "status": "ENGINE_REVIEW_TRIAGE_DECISION_RECORDED_NO_LEDGER_MUTATION" if recordable and not blockers else "ENGINE_REVIEW_TRIAGE_DECISION_COMPLETED_WITH_REFUSALS",
        "decision_value": decision_value,
        "engines": engines,
        "counts": {"requested": len(engines), "recorded": len(recordable), "refused": len([r for r in rows if r.get("status", "").startswith("TRIAGE_DECISION_REFUSED")])},
        "rows": rows,
        "authority": _patch109_authority(decision_write_authority=bool(recordable)),
        "next_step": "Run engine-review-queue-export, then use the commit gate only after reviewing decisions.",
    }
    json_path, md_path = _patch109_write_decision_receipt(receipt)
    print()
    print("── Engine Review Triage Decision ────────────────────")
    print("  Status  :", receipt.get("status"))
    print("  Decision:", decision_value)
    print("  Recorded:", receipt.get("counts", {}).get("recorded"))
    print("  Refused :", receipt.get("counts", {}).get("refused"))
    print("  JSON    :", json_path)
    print("  Markdown:", md_path)
    print("  Authority: NO ledger mutation; Patch107/commit gate still required")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_TRIAGE_DECISION_WRITTEN", str(json_path), f"recorded={receipt.get('counts', {}).get('recorded')}", receipt.get("status"))


def cmd_engine_review_triage_export(session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    ENGINE_REVIEW_TRIAGE_DIR.mkdir(parents=True, exist_ok=True)
    reports = []
    for p in sorted(ENGINE_REVIEW_TRIAGE_DIR.glob("*.json")):
        if p.name.startswith("latest_"):
            continue
        try:
            d = _patch109_read_json(p)
            reports.append({
                "path": str(p),
                "sha256": _patch109_sha256(p),
                "report_type": d.get("report_type"),
                "status": d.get("status"),
                "counts": d.get("counts"),
                "engines": d.get("engines") or [r.get("engine_family") for r in d.get("rows") or [] if r.get("engine_family")],
            })
        except Exception:
            continue
    now = _patch109_now()
    export = {
        "schema_version": ENGINE_REVIEW_TRIAGE_SCHEMA_VERSION,
        "report_type": "ENGINE_REVIEW_TRIAGE_EXPORT_V1_PATCH109",
        "created_at": now,
        "counts": {"reports": len(reports)},
        "reports": reports,
        "authority": _patch109_authority(decision_write_authority=False),
    }
    json_path = ENGINE_REVIEW_TRIAGE_DIR / f"{now}_{ENGINE_REVIEW_TRIAGE_EXPORT_PREFIX}.json"
    md_path = ENGINE_REVIEW_TRIAGE_DIR / f"{now}_{ENGINE_REVIEW_TRIAGE_EXPORT_PREFIX}.md"
    _patch109_write_json(json_path, export)
    lines = ["# Patch 109 Engine Review Triage Export", "", f"Reports: `{len(reports)}`", ""]
    for r in reports:
        lines.append(f"- `{r.get('report_type')}` — `{r.get('status')}` — `{r.get('path')}`")
    md_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    print()
    print("── Engine Review Triage Export ──────────────────────")
    print("  JSON    :", json_path)
    print("  Markdown:", md_path)
    print("  Reports :", len(reports))
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_TRIAGE_EXPORT_WRITTEN", str(json_path), f"reports={len(reports)}", "no_ledger_mutation")



# ─── PATCH 110: ENGINE REVIEW CYCLE PLANNER ──────────────────────────────────
# Purpose:
#   Read-only/Forge-memory-only dashboard for the next engine review cycle.
#   It summarizes ledger state, evidence coverage, queue state, and exact next commands.
# Authority:
#   Writes only reports under ~/forge/memory/engine_review_cycle_v1.
#   No ledger mutation. No engine files. No lockfile. No Chroma. No shell.

PATCH110_CYCLE_ROOT = Path.home() / "forge" / "memory" / "engine_review_cycle_v1"

def _patch110_timestamp() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")

def _patch110_load_json(path: Path, default=None):
    try:
        if path and path.exists():
            return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        pass
    return {} if default is None else default

def _patch110_sha256(path: Path) -> str | None:
    try:
        h = hashlib.sha256()
        with path.open("rb") as f:
            for block in iter(lambda: f.read(1024 * 1024), b""):
                h.update(block)
        return h.hexdigest()
    except Exception:
        return None

def _patch110_latest_file(folder: Path, pattern: str) -> Path | None:
    try:
        files = [p for p in folder.glob(pattern) if p.is_file()]
        if not files:
            return None
        return max(files, key=lambda p: p.stat().st_mtime)
    except Exception:
        return None

def _patch110_engine_from_latest_filename(name: str, suffix: str) -> str | None:
    # Expected forms:
    # latest_<engine>_llm_engine_review_draft.json
    # latest_<engine>_engine_review_evidence_crosscheck_v1.json
    # latest_<engine>_engine_evidence_binder.json
    if not name.startswith("latest_") or not name.endswith(suffix):
        return None
    middle = name[len("latest_"):-len(suffix)]
    return middle.strip("_") or None

def _patch110_scan_latest_engines(folder: Path, suffix: str) -> set[str]:
    engines: set[str] = set()
    try:
        if folder.exists():
            for p in folder.glob(f"latest_*{suffix}"):
                engine = _patch110_engine_from_latest_filename(p.name, suffix)
                if engine:
                    engines.add(engine)
    except Exception:
        pass
    return engines

def _patch110_load_ledger() -> tuple[list[dict], Path | None, str | None]:
    ledger_path = Path.home() / "forge" / "memory" / "code_library_v1" / "manifests" / "engine_review_ledger_v1.json"
    data = _patch110_load_json(ledger_path, {})
    entries = data.get("entries") or []
    if not isinstance(entries, list):
        entries = []
    return entries, ledger_path if ledger_path.exists() else None, _patch110_sha256(ledger_path) if ledger_path.exists() else None

def _patch110_queue_decisions() -> dict[str, str]:
    qdir = Path.home() / "forge" / "memory" / "engine_review_queue_v1"
    latest = qdir / "latest_engine_review_queue_v1.json"
    data = _patch110_load_json(latest, {})
    decisions: dict[str, str] = {}
    for item in data.get("items", []) if isinstance(data.get("items"), list) else []:
        engine = item.get("engine_family")
        decision = item.get("human_queue_decision")
        if engine and decision:
            decisions[engine] = decision
    # Also scan individual decision receipts because some queue reports lag behind receipts.
    try:
        for p in qdir.glob("*_engine_review_queue_decision_v1.json"):
            d = _patch110_load_json(p, {})
            engine = d.get("engine_family") or d.get("engine")
            decision = d.get("decision") or d.get("human_queue_decision")
            if engine and decision:
                decisions[engine] = decision
    except Exception:
        pass
    return decisions

def _patch110_triage_decisions() -> dict[str, str]:
    tdir = Path.home() / "forge" / "memory" / "engine_review_triage_v1"
    decisions: dict[str, str] = {}
    try:
        for p in tdir.glob("*_engine_review_triage_decision_v1.json"):
            d = _patch110_load_json(p, {})
            engine = d.get("engine_family") or d.get("engine")
            decision = d.get("decision") or d.get("human_queue_decision")
            if engine and decision:
                decisions[engine] = decision
    except Exception:
        pass
    return decisions

def _patch110_build_report() -> tuple[dict, Path, Path]:
    PATCH110_CYCLE_ROOT.mkdir(parents=True, exist_ok=True)
    ts = _patch110_timestamp()

    entries, ledger_path, ledger_sha = _patch110_load_ledger()
    ledger_by_engine = {e.get("engine_base"): e for e in entries if e.get("engine_base")}

    approved = sorted([k for k, e in ledger_by_engine.items() if str(e.get("review_status", "")).upper() == "APPROVED"])
    deferred = sorted([k for k, e in ledger_by_engine.items() if str(e.get("review_status", "")).upper() == "DEFERRED"])
    rejected = sorted([k for k, e in ledger_by_engine.items() if str(e.get("review_status", "")).upper() == "REJECTED"])
    pending = sorted([k for k, e in ledger_by_engine.items() if str(e.get("review_status", "")).upper() in ("PENDING_REVIEW", "PENDING", "")])
    eligible = sorted([k for k, e in ledger_by_engine.items() if bool(e.get("future_lockfile_eligible"))])

    base = Path.home() / "forge" / "memory"
    binders = _patch110_scan_latest_engines(base / "engine_evidence_binders_v1", "_engine_evidence_binder.json")
    drafts = _patch110_scan_latest_engines(base / "llm_engine_review_drafts_v1", "_llm_engine_review_draft.json")
    crosschecks = _patch110_scan_latest_engines(base / "engine_review_evidence_crosschecks_v1", "_engine_review_evidence_crosscheck_v1.json")
    approval_helpers = _patch110_scan_latest_engines(base / "engine_review_approval_helpers_v1", "_engine_review_approval_helper_v1.json")
    queue_decisions = _patch110_queue_decisions()
    triage_decisions = _patch110_triage_decisions()
    all_decisions = dict(queue_decisions)
    all_decisions.update(triage_decisions)

    ledger_committed = set(approved) | set(deferred) | set(rejected)
    pending_set = set(pending)

    crosschecked_pending_undecided = sorted([e for e in crosschecks if e in pending_set and e not in all_decisions])
    decided_not_committed = sorted([e for e, d in all_decisions.items() if e in pending_set])
    drafted_without_crosscheck = sorted([e for e in drafts if e in pending_set and e not in crosschecks])
    binder_without_draft = sorted([e for e in binders if e in pending_set and e not in drafts])

    # PATCH 114 — Engine review completion route fix
    # If the ledger has no pending rows, the review cycle is complete.
    # Do not route back into workflow drafting with an empty next_engines list.
    # The next lawful step is a non-authoritative approved-lockfile candidate.
    if decided_not_committed:
        next_route = "COMMIT_DECIDED_QUEUE_ITEMS"
        next_commands = [
            "engine-review-batch-commit-plan",
            "engine-review-batch-commit-show latest",
            "engine-review-batch-commit-verify latest",
            "engine-review-batch-commit-apply",
            "engine-review-batch-commit-apply CONFIRM_COMMIT_EVIDENCE_BATCH_QUEUE",
            "engine-review-batch-commit-export",
        ]
        next_engines = decided_not_committed[:5]
    elif crosschecked_pending_undecided:
        next_route = "TRIAGE_CROSSCHECKED_UNDECIDED"
        e = crosschecked_pending_undecided[0]
        next_commands = [
            "engine-review-triage-plan",
            f"engine-review-triage-show {e}",
            f"engine-review-triage-defer {e}   # or approve/reject after reading evidence",
            "engine-review-triage-export",
        ]
        next_engines = crosschecked_pending_undecided[:5]
    elif drafted_without_crosscheck:
        next_route = "CROSSCHECK_DRAFTED_ENGINES"
        e = drafted_without_crosscheck[0]
        next_commands = [
            f"engine-review-evidence-check {e}",
            f"engine-review-evidence-show {e}",
            "engine-review-evidence-export",
        ]
        next_engines = drafted_without_crosscheck[:5]
    elif pending:
        if binder_without_draft:
            next_route = "RUN_NEXT_EVIDENCE_REVIEW_WORKFLOW_BATCH"
            next_commands = [
                "engine-review-workflow-plan",
                "engine-review-workflow-run all",
                "engine-review-workflow-show latest",
                "engine-review-queue-build",
                "engine-review-queue-show latest",
            ]
            next_engines = binder_without_draft[:5]
        else:
            next_route = "INSPECT_ENGINE_REVIEW_PROGRESS_GAPS"
            next_commands = [
                "engine-review-progress-report",
                "engine-review-progress-gaps",
                "engine-review-cycle-report",
                "engine-review-cycle-show latest",
            ]
            next_engines = pending[:5]
    else:
        # Patch 116: if the final canonical engine lockfile already exists, the
        # engine review phase is complete. Do not route back to the approved
        # candidate stage after Patch 115 has written canonical authority.
        final_state = _patch116_final_lockfile_state() if "_patch116_final_lockfile_state" in globals() else {"exists": False}
        if final_state.get("exists") and final_state.get("canonical_authority") is True:
            next_route = "ENGINE_REVIEW_COMPLETE"
            next_commands = [
                "engine-review-completion-status",
                "forge-next",
                "forge-roadmap-status",
                "engine-review-cycle-export",
            ]
        else:
            next_route = "READY_FOR_APPROVED_LOCKFILE_CANDIDATE"
            next_commands = [
                "engine-approved-lockfile-policy",
                "engine-approved-lockfile-candidate",
                "engine-approved-lockfile-validate",
                "engine-approved-lockfile-export",
                "engine-review-cycle-export",
            ]
        next_engines = []

    report = {
        "report_type": "ENGINE_REVIEW_CYCLE_REPORT_V1_PATCH110",
        "created_at": ts,
        "authority": {
            "patch": "110",
            "mode": "ENGINE_REVIEW_CYCLE_PLANNER_READ_ONLY",
            "rule": "Patch 110 summarizes the engine review cycle and suggests exact next commands. It does not approve, commit, mutate ledgers, edit engine files, write Chroma, or create lockfile authority.",
            "writes": [str(PATCH110_CYCLE_ROOT)],
            "human_review_ledger_write_authority": False,
            "engine_file_write_authority": False,
            "final_lockfile_authority": False,
            "chroma_write_authority": False,
            "shell_execution_authority": False,
            "llm_autonomous_decision_authority": False,
        },
        "ledger": {
            "path": str(ledger_path) if ledger_path else None,
            "sha256": ledger_sha,
            "total": len(entries),
            "approved": len(approved),
            "deferred": len(deferred),
            "rejected": len(rejected),
            "pending": len(pending),
            "future_lockfile_eligible": len(eligible),
        },
        "coverage": {
            "evidence_binders": len(binders),
            "llm_drafts": len(drafts),
            "evidence_crosschecks": len(crosschecks),
            "approval_helpers": len(approval_helpers),
            "queue_or_triage_decisions": len(all_decisions),
            "crosschecked_pending_undecided": len(crosschecked_pending_undecided),
            "decided_not_committed": len(decided_not_committed),
            "drafted_without_crosscheck": len(drafted_without_crosscheck),
            "pending_without_draft": len(binder_without_draft),
        },
        "sets": {
            "approved": approved,
            "deferred": deferred,
            "pending": pending,
            "eligible": eligible,
            "crosschecked_pending_undecided": crosschecked_pending_undecided,
            "decided_not_committed": decided_not_committed,
            "drafted_without_crosscheck": drafted_without_crosscheck,
            "pending_without_draft": binder_without_draft,
        },
        "next_route": next_route,
        "next_engines": next_engines,
        "next_commands": next_commands,
    }

    json_path = PATCH110_CYCLE_ROOT / f"{ts}_engine_review_cycle_report_v1.json"
    md_path = PATCH110_CYCLE_ROOT / f"{ts}_engine_review_cycle_report_v1.md"
    latest_json = PATCH110_CYCLE_ROOT / "latest_engine_review_cycle_report_v1.json"
    latest_md = PATCH110_CYCLE_ROOT / "latest_engine_review_cycle_report_v1.md"

    json_text = json.dumps(report, indent=2, ensure_ascii=False)
    json_path.write_text(json_text, encoding="utf-8")
    latest_json.write_text(json_text, encoding="utf-8")

    md_lines = [
        "# Engine Review Cycle Report — Patch 110",
        "",
        f"Created: `{ts}`",
        "",
        "## Ledger",
        "",
        f"- Total: {len(entries)}",
        f"- Approved: {len(approved)}",
        f"- Deferred: {len(deferred)}",
        f"- Rejected: {len(rejected)}",
        f"- Pending: {len(pending)}",
        f"- Future lockfile eligible: {len(eligible)}",
        "",
        "## Coverage",
        "",
        f"- Evidence binders: {len(binders)}",
        f"- LLM drafts: {len(drafts)}",
        f"- Evidence cross-checks: {len(crosschecks)}",
        f"- Approval helpers: {len(approval_helpers)}",
        f"- Queue/triage decisions: {len(all_decisions)}",
        f"- Cross-checked pending undecided: {len(crosschecked_pending_undecided)}",
        f"- Decided but not committed: {len(decided_not_committed)}",
        f"- Drafted without cross-check: {len(drafted_without_crosscheck)}",
        f"- Pending without draft: {len(binder_without_draft)}",
        "",
        "## Recommended Next Route",
        "",
        f"`{next_route}`",
        "",
        "## Next Engines",
        "",
    ]
    md_lines += [f"- {e}" for e in next_engines] or ["- none"]
    md_lines += ["", "## Exact Next Commands", ""]
    md_lines += [f"```text\n{cmd}\n```" for cmd in next_commands]
    md_lines += ["", "## Authority", "", "Read-only planning report. No approvals, no commits, no engine writes, no lockfile authority."]
    md_text = "\n".join(md_lines) + "\n"
    md_path.write_text(md_text, encoding="utf-8")
    latest_md.write_text(md_text, encoding="utf-8")
    return report, json_path, md_path

def _patch110_print_report(report: dict) -> None:
    print()
    print("── Engine Review Cycle Report ─────────────────────")
    ledger = report.get("ledger", {})
    cov = report.get("coverage", {})
    print(f"  Ledger total       : {ledger.get('total')}")
    print(f"  Approved           : {ledger.get('approved')}")
    print(f"  Deferred           : {ledger.get('deferred')}")
    print(f"  Pending            : {ledger.get('pending')}")
    print(f"  Lockfile eligible  : {ledger.get('future_lockfile_eligible')}")
    print()
    print(f"  Evidence binders   : {cov.get('evidence_binders')}")
    print(f"  LLM drafts         : {cov.get('llm_drafts')}")
    print(f"  Cross-checks       : {cov.get('evidence_crosschecks')}")
    print(f"  Decisions          : {cov.get('queue_or_triage_decisions')}")
    print(f"  Decided uncommitted: {cov.get('decided_not_committed')}")
    print(f"  Crosschecked open  : {cov.get('crosschecked_pending_undecided')}")
    print(f"  Pending no draft   : {cov.get('pending_without_draft')}")
    print()
    print(f"  Next route         : {report.get('next_route')}")
    engines = report.get("next_engines") or []
    if engines:
        print("  Next engines       : " + ", ".join(engines[:8]))
    print("  Next commands:")
    for cmd in report.get("next_commands") or []:
        print(f"    {cmd}")
    print("────────────────────────────────────────────────────")
    print()

