# ─── PATCH 113 — LEDGER-AWARE ENGINE REVIEW WORKFLOW SELECTOR ────────────────
#
# Purpose:
#   Stop Patch 105/101 workflow drafting from repeatedly selecting engines that
#   are already committed in engine_review_ledger_v1.json.
#
# Authority:
#   This patch changes only Forge's selector logic. It does not approve reviews,
#   commit ledger decisions, write engine files, write Chroma, run shell commands,
#   or create a canonical lockfile.
#
# Operational rule:
#   The ledger is the source of truth for whether an engine still needs review.
#   Workflow drafting should target only engines whose ledger review_status is
#   PENDING_REVIEW and which do not already have a ready evidence cross-check.

try:
    ENGINE_REVIEW_WORKFLOW_MAX_LIMIT = max(int(ENGINE_REVIEW_WORKFLOW_MAX_LIMIT), 25)
except Exception:
    ENGINE_REVIEW_WORKFLOW_MAX_LIMIT = 25


def _patch113_now() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch113_path_obj(value):
    try:
        return _Patch105Path(value)
    except Exception:
        return Path(value)


def _patch113_slug(value: str) -> str:
    try:
        return _patch105_slug(value)
    except Exception:
        return re.sub(r"[^a-zA-Z0-9_\-]+", "_", (value or "").strip()).strip("_").lower()


def _patch113_read_json(path):
    p = _patch113_path_obj(path)
    return json.loads(p.read_text(encoding="utf-8"))


def _patch113_engine_review_ledger_path():
    candidates = []
    try:
        candidates.append(MEMORY_DIR / "code_library_v1" / "manifests" / "engine_review_ledger_v1.json")
    except Exception:
        pass
    try:
        candidates.append(Path.home() / "forge" / "memory" / "code_library_v1" / "manifests" / "engine_review_ledger_v1.json")
    except Exception:
        pass
    for p in candidates:
        try:
            if p.exists():
                return p
        except Exception:
            continue
    return candidates[0] if candidates else None


def _patch113_ledger_status_map() -> dict:
    """Return engine_family -> ledger row, using engine_review_ledger_v1 as source of truth."""
    path = _patch113_engine_review_ledger_path()
    if not path:
        return {}
    try:
        data = _patch113_read_json(path)
    except Exception:
        return {}
    status = {}
    for entry in data.get("entries") or []:
        fam = _patch113_slug(entry.get("engine_base") or entry.get("engine_family") or "")
        if not fam:
            continue
        status[fam] = {
            "engine_family": fam,
            "review_status": entry.get("review_status"),
            "future_lockfile_eligible": entry.get("future_lockfile_eligible"),
            "is_hold_family": entry.get("is_hold_family"),
            "ledger_entry": entry,
        }
    return status


def _patch113_pending_families() -> set:
    rows = _patch113_ledger_status_map()
    pending = set()
    for fam, row in rows.items():
        if str(row.get("review_status") or "").upper() == "PENDING_REVIEW":
            pending.add(fam)
    return pending


def _patch113_existing_crosscheck_for_family(engine_family: str) -> bool:
    fam = _patch113_slug(engine_family)
    try:
        return _patch105_existing_crosscheck(fam)
    except Exception:
        pass
    try:
        if "ENGINE_REVIEW_EVIDENCE_DIR" in globals() and "ENGINE_REVIEW_EVIDENCE_PREFIX" in globals():
            return (ENGINE_REVIEW_EVIDENCE_DIR / f"latest_{fam}_{ENGINE_REVIEW_EVIDENCE_PREFIX}.json").exists()
    except Exception:
        pass
    return False


def _patch113_ledger_aware_candidate_rows() -> list:
    """Build workflow candidates from evidence binders, but gate readiness by ledger status."""
    gateway_ok, gateway_msg = _patch98_gateway_ready()
    source_ok, source_report, source_blockers = _patch98_source_law_ready()
    ledger_rows = _patch113_ledger_status_map()
    rows = []

    try:
        binders = _patch98_all_latest_evidence_binders()
    except Exception as exc:
        return [{
            "engine_family": "_error",
            "ready_for_batch_draft": False,
            "ready_for_workflow": False,
            "skipped_reason": "binder_loader_failed",
            "blockers": [f"Evidence binder loader failed: {exc}"],
        }]

    for binder in binders:
        fam = _patch113_slug(binder.get("engine_family") or binder.get("engine_base") or "")
        if not fam:
            continue

        ledger_row = ledger_rows.get(fam) or {}
        ledger_status = str(ledger_row.get("review_status") or "UNKNOWN").upper()
        blockers = []
        skipped_reason = None

        if not gateway_ok:
            blockers.append(gateway_msg)
        if not source_ok:
            blockers.extend(source_blockers)
        if not binder.get("ready_for_llm_brief"):
            blockers.append("Evidence binder is not marked ready_for_llm_brief.")

        if ledger_status != "PENDING_REVIEW":
            skipped_reason = f"ledger_status_{ledger_status}"
        elif _patch113_existing_crosscheck_for_family(fam):
            skipped_reason = "pending_already_crosschecked_needs_human_decision_or_commit"

        ready = bool(not blockers and skipped_reason is None)
        rows.append({
            "engine_family": fam,
            "evidence_id": binder.get("evidence_id"),
            "candidate_path": binder.get("candidate_path") or binder.get("candidate_path_resolved"),
            "candidate_path_resolved": binder.get("candidate_path_resolved") or binder.get("candidate_path"),
            "review_status": ledger_status,
            "ledger_review_status": ledger_status,
            "future_lockfile_eligible": ledger_row.get("future_lockfile_eligible"),
            "is_hold_family": ledger_row.get("is_hold_family"),
            "ready_for_batch_draft": ready,
            "ready_for_workflow": ready,
            "crosscheck_exists": _patch113_existing_crosscheck_for_family(fam),
            "skipped_reason": skipped_reason,
            "blockers": blockers,
            "selector_patch": "patch113_ledger_aware",
        })

    rows.sort(key=lambda r: (
        not r.get("ready_for_workflow"),
        r.get("engine_family") or ""
    ))
    return rows


# Preserve previous selectors for forensic access, then override the active selectors.
try:
    _patch113_original_patch101_candidate_rows = _patch101_candidate_rows
except Exception:
    _patch113_original_patch101_candidate_rows = None

try:
    _patch113_original_patch105_candidate_rows = _patch105_candidate_rows
except Exception:
    _patch113_original_patch105_candidate_rows = None


def _patch101_candidate_rows() -> list:
    return _patch113_ledger_aware_candidate_rows()


def _patch105_candidate_rows() -> list:
    return _patch113_ledger_aware_candidate_rows()


def _patch105_parse_limit(arg: str) -> int:
    """Patch 113: support `all` while keeping a hard ceiling for runaway local LLM calls."""
    raw = (arg or "").strip().lower()
    if raw in {"all", "max", "pending", "remaining"}:
        return ENGINE_REVIEW_WORKFLOW_MAX_LIMIT
    if not raw:
        return ENGINE_REVIEW_WORKFLOW_DEFAULT_LIMIT
    try:
        n = int(raw.split()[0])
    except Exception:
        return ENGINE_REVIEW_WORKFLOW_DEFAULT_LIMIT
    return max(1, min(ENGINE_REVIEW_WORKFLOW_MAX_LIMIT, n))




# ─── PATCH 117: DEFERRED / EXCLUDED ENGINE DISPOSITION REPORT ────────────────

_PATCH117_ROOT = MEMORY_DIR / "engine_disposition_v1"
_PATCH117_REPORT_PREFIX = "engine_disposition_report_v1"
_PATCH117_EXPORT_PREFIX = "engine_disposition_export_v1"
_PATCH117_SCHEMA_VERSION = "engine_disposition_report_v1_patch117"


def _patch117_latest_report_path() -> Path:
    return _PATCH117_ROOT / f"latest_{_PATCH117_REPORT_PREFIX}.json"


def _patch117_load_json(path: Path) -> dict:
    try:
        if path.exists():
            return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        pass
    return {}


def _patch117_final_lockfile() -> tuple[dict, Path, str | None]:
    path = CODE_MANIFESTS_DIR / "engine_canonical_lockfile_v1.json"
    data = _patch117_load_json(path)
    sha = _patch116_sha256(path) if "_patch116_sha256" in globals() else None
    return data, path, sha


def _patch117_ledger_by_engine() -> tuple[dict, str | None, str | None]:
    try:
        entries, ledger_path, ledger_sha = _patch110_load_ledger()
    except Exception:
        entries, ledger_path, ledger_sha = [], None, None
    return {str(e.get("engine_base") or ""): e for e in entries}, str(ledger_path) if ledger_path else None, ledger_sha


def _patch117_bucket(row: dict, ledger_row: dict) -> tuple[str, str, str]:
    name = str(row.get("engine_base") or "")
    path = str(row.get("recommended_keep_path") or "")
    status = str(row.get("review_status") or "").upper()
    draft = str(row.get("draft_decision") or ledger_row.get("draft_decision") or "")
    is_hold = bool(row.get("is_hold_family") or ledger_row.get("is_hold_family"))

    if status == "APPROVED" and is_hold:
        return (
            "approved_hold_family_excluded",
            "Approved by review, but intentionally excluded because the family is marked hold.",
            "Manual architect review before future lockfile eligibility; do not delete or quarantine automatically.",
        )
    if is_hold:
        return (
            "deferred_hold_family",
            "Deferred and marked hold-family, usually because the candidate/family needs manual architectural comparison.",
            "Keep as held evidence. Compare family variants before any future promotion.",
        )
    if name in {"gilligan", "neo", "neo_engine", "athena", "athena_engine"} or path.startswith("agents/"):
        return (
            "agent_identity_deferred",
            "Agent identity/runtime layer deferred; this should not be finalized only from engine evidence.",
            "Review agent role, memory boundaries, safety scope, and runtime responsibilities before promotion.",
        )
    if "runtime_wrappers" in path or name.endswith("_stack") or "stack" in name:
        return (
            "runtime_wrapper_or_stack_deferred",
            "Wrapper/stack layer deferred because it may depend on multiple engines, imports, or runtime ordering.",
            "Map dependencies and test wrapper startup before any future promotion.",
        )
    if name in {"admin_override_console", "external_feed_listener", "goal_injection_engine"}:
        return (
            "authority_or_external_control_deferred",
            "Authority, external input, or goal-injection surface deferred because misuse could affect system behavior.",
            "Require stricter permission, trust-guard, and input-boundary review before future promotion.",
        )
    if any(token in name for token in ["memory", "archive", "fluid", "dream"]):
        return (
            "memory_archive_or_state_deferred",
            "Memory/archive/state layer deferred because persistence and data durability need stronger testing.",
            "Run persistence, corruption, backup, and recovery tests before future promotion.",
        )
    if "HOLD" in draft:
        return (
            "deferred_hold_by_draft_decision",
            "Draft decision indicates hold/review even though no stronger bucket matched.",
            "Inspect draft, evidence binder, and candidate family before future promotion.",
        )
    return (
        "general_deferred_review",
        "Deferred by human review and excluded from the final canonical lockfile.",
        "Keep for later evidence review; do not delete or quarantine automatically.",
    )


def _patch117_build_report() -> dict:
    lockfile, lockfile_path, lockfile_sha = _patch117_final_lockfile()
    ledger_by_engine, ledger_path, ledger_sha = _patch117_ledger_by_engine()
    excluded = list(lockfile.get("excluded_entries") or [])
    rows = []
    buckets = {}
    statuses = {}

    for idx, row in enumerate(excluded, start=1):
        name = str(row.get("engine_base") or "")
        ledger_row = ledger_by_engine.get(name, {})
        bucket, bucket_reason, next_action = _patch117_bucket(row, ledger_row)
        statuses[row.get("review_status") or "UNKNOWN"] = statuses.get(row.get("review_status") or "UNKNOWN", 0) + 1
        buckets[bucket] = buckets.get(bucket, 0) + 1
        review_note = str(ledger_row.get("review_note") or row.get("reason") or "")
        rows.append({
            "index": idx,
            "engine_base": name,
            "recommended_keep_path": row.get("recommended_keep_path"),
            "review_status": row.get("review_status"),
            "is_hold_family": bool(row.get("is_hold_family") or ledger_row.get("is_hold_family")),
            "future_lockfile_eligible": bool(row.get("future_lockfile_eligible")),
            "future_lockfile_block_reason": ledger_row.get("future_lockfile_block_reason"),
            "draft_decision": row.get("draft_decision") or ledger_row.get("draft_decision"),
            "exclusion_reason": row.get("reason"),
            "disposition_bucket": bucket,
            "bucket_reason": bucket_reason,
            "recommended_next_action": next_action,
            "decision_confidence": ledger_row.get("decision_confidence"),
            "variant_count": ledger_row.get("variant_count"),
            "required_human_checks": ledger_row.get("required_human_checks") or [],
            "cautions": ledger_row.get("cautions") or [],
            "review_note_summary": review_note[:500],
            "safe_current_action": "read-only disposition only; no delete, no quarantine, no promotion, no engine writes",
        })

    report = {
        "schema_version": _PATCH117_SCHEMA_VERSION,
        "report_type": "ENGINE_DISPOSITION_REPORT_V1",
        "created_at": _patch116_iso_now() if "_patch116_iso_now" in globals() else datetime.datetime.now().isoformat(timespec="seconds"),
        "status": "ENGINE_DISPOSITION_REPORT_READY",
        "purpose": "Classify final-lockfile excluded/deferred engines after canonical engine review closure.",
        "authority": {
            "mode": "READ_ONLY_DISPOSITION_REPORT_ONLY",
            "writes": [str(_PATCH117_ROOT)],
            "engine_file_write_authority": False,
            "human_review_ledger_write_authority": False,
            "final_lockfile_write_authority": False,
            "quarantine_authority": False,
            "delete_authority": False,
            "chroma_write_authority": False,
            "shell_execution_authority": False,
            "llm_autonomous_decision_authority": False,
        },
        "source_final_lockfile": {
            "path": str(lockfile_path),
            "sha256": lockfile_sha,
            "canonical_authority": lockfile.get("canonical_authority"),
            "actual_lockfile_written": lockfile.get("actual_lockfile_written"),
            "included_count": lockfile.get("included_count"),
            "excluded_count": lockfile.get("excluded_count"),
        },
        "source_ledger": {
            "path": ledger_path,
            "sha256": ledger_sha,
            "entries": len(ledger_by_engine),
        },
        "counts": {
            "excluded_total": len(rows),
            "by_bucket": buckets,
            "by_review_status": statuses,
            "approved_hold_excluded": len([r for r in rows if r.get("review_status") == "APPROVED" and r.get("is_hold_family")]),
            "deferred_total": len([r for r in rows if r.get("review_status") == "DEFERRED"]),
            "safe_to_delete_now": 0,
            "safe_to_quarantine_now": 0,
            "safe_to_promote_now": 0,
        },
        "next_phase": "FORGE_MASTER_STATUS_REPORT",
        "recommended_next_patch": "Patch 118 — Forge Master Status Report",
        "next_commands": [
            "engine-disposition-show latest",
            "engine-disposition-export",
            "forge-next",
            "Install Patch 118 when ready",
        ],
        "rows": rows,
    }
    return report


def _patch117_write_report(report: dict, prefix: str) -> tuple[Path, Path]:
    _PATCH117_ROOT.mkdir(parents=True, exist_ok=True)
    ts = _patch116_now() if "_patch116_now" in globals() else datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")
    json_path = _PATCH117_ROOT / f"{ts}_{prefix}.json"
    md_path = _PATCH117_ROOT / f"{ts}_{prefix}.md"
    latest_json = _PATCH117_ROOT / f"latest_{prefix}.json"
    latest_md = _PATCH117_ROOT / f"latest_{prefix}.md"
    text = json.dumps(report, indent=2, ensure_ascii=False)
    json_path.write_text(text, encoding="utf-8")
    latest_json.write_text(text, encoding="utf-8")
    lines = [
        "# Engine Disposition Report — Patch 117",
        "",
        f"Created: `{report.get('created_at')}`",
        f"Status: `{report.get('status')}`",
        f"Excluded total: `{(report.get('counts') or {}).get('excluded_total')}`",
        f"Recommended next patch: `{report.get('recommended_next_patch')}`",
        "",
        "## Bucket Counts",
        "",
    ]
    for bucket, count in sorted(((report.get("counts") or {}).get("by_bucket") or {}).items()):
        lines.append(f"- `{bucket}`: `{count}`")
    lines += ["", "## Engines", ""]
    for row in report.get("rows") or []:
        lines.append(f"- `{row.get('engine_base')}` → `{row.get('disposition_bucket')}` | `{row.get('review_status')}` | `{row.get('recommended_keep_path')}`")
    lines += ["", "## Authority", "", "Read-only disposition report. No engine writes, no ledger mutation, no quarantine, no delete."]
    md_text = "\n".join(lines) + "\n"
    md_path.write_text(md_text, encoding="utf-8")
    latest_md.write_text(md_text, encoding="utf-8")
    return json_path, md_path


def _patch117_print_summary(report: dict) -> None:
    counts = report.get("counts") or {}
    print()
    print("── Deferred / Excluded Engine Disposition — Patch 117 ─")
    print(f"  Status        : {report.get('status')}")
    print(f"  Excluded total: {counts.get('excluded_total')}")
    print(f"  Approved hold : {counts.get('approved_hold_excluded')}")
    print(f"  Deferred total: {counts.get('deferred_total')}")
    print(f"  Safe delete   : {counts.get('safe_to_delete_now')}")
    print(f"  Safe quarantine: {counts.get('safe_to_quarantine_now')}")
    print(f"  Safe promote  : {counts.get('safe_to_promote_now')}")
    print()
    print("  Buckets:")
    for bucket, count in sorted((counts.get("by_bucket") or {}).items()):
        print(f"    {bucket}: {count}")
    print()
    print(f"  Next patch    : {report.get('recommended_next_patch')}")
    print("  Authority     : read-only report only; no engine writes, no quarantine, no delete")
    print("──────────────────────────────────────────────────────")
    print()


