    report = _patch117_load_latest_report()
    arg = (arg or "latest").strip()
    rows = report.get("rows") or []
    print()
    print("── Engine Disposition Show — Patch 117 ───────────────")
    if arg in {"latest", "summary", ""}:
        _patch117_print_summary(report)
    elif arg == "all":
        for row in rows:
            print(f"  - {row.get('engine_base')} :: {row.get('disposition_bucket')} :: {row.get('review_status')} :: {row.get('recommended_keep_path')}")
