        matches = [r for r in rows if r.get("engine_base") == arg or r.get("disposition_bucket") == arg]
        if not matches:
            print(f"  No disposition row or bucket matched: {arg}")
        for row in matches:
            print(f"  Engine      : {row.get('engine_base')}")
            print(f"  Path        : {row.get('recommended_keep_path')}")
