# ─── PATCH 118 — FORGE MASTER STATUS REPORT ─────────────────────────────────
#
# Purpose:
#   Consolidate Forge's current truth into one read-only status surface so Nic
#   and future LLM planning layers do not have to manually reconcile engine
#   review state, final lockfile state, disposition state, tool registry state,
#   command surface state, audit continuity, scope, context, snapshots, tests,
#   and next-roadmap routing from many separate commands.
#
# Authority:
#   Forge-owned reports only under /home/nic/forge/memory/forge_master_status_v1.
#   No engine writes, no ledger mutation, no lockfile mutation, no quarantine,
#   no delete, no Chroma writes, no shell execution, no autonomous LLM authority.

_PATCH118_SCHEMA_VERSION = "forge_master_status_v1_patch118"
_PATCH118_ROOT = MEMORY_DIR / "forge_master_status_v1"
_PATCH118_REPORT_PREFIX = "forge_master_status_report_v1"
_PATCH118_EXPORT_PREFIX = "forge_master_status_export_v1"


def _patch118_now() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch118_iso_now() -> str:
    return datetime.datetime.now().isoformat(timespec="seconds")


def _patch118_sha256(path) -> str | None:
    try:
        p = Path(path)
        if not p.exists() or not p.is_file():
            return None
        h = hashlib.sha256()
        with p.open("rb") as f:
            for chunk in iter(lambda: f.read(1024 * 1024), b""):
                h.update(chunk)
        return h.hexdigest()
    except Exception:
        return None


def _patch118_load_json(path, default=None):
    try:
        p = Path(path)
        if p.exists():
            return json.loads(p.read_text(encoding="utf-8"))
    except Exception:
        pass
    return {} if default is None else default


def _patch118_latest(root: Path, pattern: str):
    try:
        candidates = sorted(root.glob(pattern), key=lambda p: p.stat().st_mtime, reverse=True)
        return candidates[0] if candidates else None
    except Exception:
        return None


def _patch118_count_files(path: Path, pattern: str = "*") -> int:
    try:
        if path.exists():
            return len(list(path.glob(pattern)))
    except Exception:
        pass
    return 0


def _patch118_command_surface_summary() -> dict:
    try:
        source = Path(__file__).read_text(encoding="utf-8")
    except Exception:
        try:
            source = (FORGE_ROOT / "main.py").read_text(encoding="utf-8")
        except Exception as exc:
            return {"expected": len(FORGE_EXPECTED_COMMANDS), "found": 0, "missing": list(FORGE_EXPECTED_COMMANDS), "status": "ERROR", "error": str(exc)}
    found = []
    missing = []
    for cmd in FORGE_EXPECTED_COMMANDS:
        if f'"{cmd}"' in source or f"'{cmd}'" in source:
            found.append(cmd)
        else:
            missing.append(cmd)
    return {
        "expected": len(FORGE_EXPECTED_COMMANDS),
        "found": len(found),
        "missing_count": len(missing),
        "missing": missing,
        "status": "PASS" if not missing else "FAIL",
    }


def _patch118_tool_registry_summary() -> dict:
    path = FORGE_ROOT / "config" / "tool_registry.json"
    data = _patch118_load_json(path, {})
    tools = data.get("tools") or {}
    return {
        "path": str(path),
        "exists": path.exists(),
        "sha256": _patch118_sha256(path),
        "trust_level": data.get("current_trust_level"),
        "tool_count": len(tools) if isinstance(tools, dict) else 0,
    }


def _patch118_audit_summary(max_scan: int = 20000) -> dict:
    path = FORGE_ROOT / "logs" / "forge_audit.log"
    summary = {
        "path": str(path),
        "exists": path.exists(),
        "entries_checked": 0,
        "chain_breaks": 0,
        "first_checked_entry_hash": None,
        "last_entry_hash": None,
        "status": "MISSING",
    }
    if not path.exists():
        return summary
    try:
        lines = path.read_text(encoding="utf-8", errors="ignore").splitlines()[-max_scan:]
        entries = []
        for line in lines:
            m = re.search(r"PREV_HASH: ([0-9a-f]+) \| ENTRY_HASH: ([0-9a-f]+)", line)
            if m:
                entries.append((m.group(1), m.group(2)))
        breaks = 0
        for i in range(1, len(entries)):
            if entries[i][0] != entries[i - 1][1]:
                breaks += 1
        summary.update({
            "entries_checked": len(entries),
            "chain_breaks": breaks,
            "first_checked_entry_hash": entries[0][1] if entries else None,
            "last_entry_hash": entries[-1][1] if entries else None,
            "status": "PASS" if entries and breaks == 0 else "FAIL",
        })
        return summary
    except Exception as exc:
        summary["status"] = "ERROR"
        summary["error"] = str(exc)
        return summary


def _patch118_scope_summary() -> dict:
    approved_path = FORGE_ROOT / "config" / "approved_paths.json"
    session_scope_path = FORGE_ROOT / "config" / "session_scope.json"
    approved = _patch118_load_json(approved_path, {})
    session_scope = _patch118_load_json(session_scope_path, {})
    return {
        "approved_paths_path": str(approved_path),
        "approved_paths_exists": approved_path.exists(),
        "approved_paths_sha256": _patch118_sha256(approved_path),
        "approved_paths": approved,
        "session_scope_path": str(session_scope_path),
        "session_scope_exists": session_scope_path.exists(),
        "session_scope_sha256": _patch118_sha256(session_scope_path),
        "session_scope": session_scope,
    }


def _patch118_engine_review_summary() -> dict:
    ledger_path = MEMORY_DIR / "code_library_v1" / "manifests" / "engine_review_ledger_v1.json"
    final_path = MEMORY_DIR / "code_library_v1" / "manifests" / "engine_canonical_lockfile_v1.json"
    completion_path = MEMORY_DIR / "engine_review_completion_v1" / "latest_engine_review_completion_status_v1.json"
    disposition_path = MEMORY_DIR / "engine_disposition_v1" / "latest_engine_disposition_report_v1.json"
    ledger = _patch118_load_json(ledger_path, {})
    final = _patch118_load_json(final_path, {})
    completion = _patch118_load_json(completion_path, {})
    disposition = _patch118_load_json(disposition_path, {})
    entries = ledger.get("entries") or []
    counts = {
        "total": len(entries),
        "approved": len([e for e in entries if str(e.get("review_status") or "").upper() == "APPROVED"]),
        "deferred": len([e for e in entries if str(e.get("review_status") or "").upper() == "DEFERRED"]),
        "rejected": len([e for e in entries if str(e.get("review_status") or "").upper() == "REJECTED"]),
        "pending": len([e for e in entries if str(e.get("review_status") or "").upper() == "PENDING_REVIEW"]),
        "future_lockfile_eligible": len([e for e in entries if e.get("future_lockfile_eligible") is True]),
    }
    return {
        "ledger": {"path": str(ledger_path), "exists": ledger_path.exists(), "sha256": _patch118_sha256(ledger_path), "counts": counts},
        "final_lockfile": {
            "path": str(final_path),
            "exists": final_path.exists(),
            "sha256": _patch118_sha256(final_path),
            "canonical_authority": final.get("canonical_authority"),
            "actual_lockfile_written": final.get("actual_lockfile_written"),
            "included_count": final.get("included_count"),
            "excluded_count": final.get("excluded_count"),
        },
        "completion_status": {
            "path": str(completion_path),
            "exists": completion_path.exists(),
            "status": completion.get("status"),
            "recommended_next_patch": completion.get("recommended_next_patch"),
        },
        "disposition": {
            "path": str(disposition_path),
            "exists": disposition_path.exists(),
            "sha256": _patch118_sha256(disposition_path),
            "excluded_total": ((disposition.get("counts") or {}).get("excluded_total")),
            "by_bucket": ((disposition.get("counts") or {}).get("by_bucket")) or {},
            "safe_to_delete_now": ((disposition.get("counts") or {}).get("safe_to_delete_now")),
            "safe_to_quarantine_now": ((disposition.get("counts") or {}).get("safe_to_quarantine_now")),
            "safe_to_promote_now": ((disposition.get("counts") or {}).get("safe_to_promote_now")),
        },
    }


def _patch118_context_summary() -> dict:
    context_root = MEMORY_DIR / "context_library_v1"
    code_root = MEMORY_DIR / "code_library_v1"
    snapshot_root = MEMORY_DIR / "snapshot_plans_v1"
    restore_root = MEMORY_DIR / "live_restore_backups_v1"
    return {
        "context_library": {
            "path": str(context_root),
            "exists": context_root.exists(),
            "manifests": _patch118_count_files(context_root / "manifests"),
            "receipts": _patch118_count_files(context_root / "receipts", "*.json"),
            "indexes": _patch118_count_files(context_root / "indexes"),
            "symbolic_maps": _patch118_count_files(context_root / "symbolic_maps", "*.json"),
            "chroma_db_exists": (context_root / "chroma_db").exists(),
        },
        "code_library": {
            "path": str(code_root),
            "exists": code_root.exists(),
            "manifests": _patch118_count_files(code_root / "manifests"),
            "has_final_engine_lockfile": (code_root / "manifests" / "engine_canonical_lockfile_v1.json").exists(),
        },
        "snapshot_plans": {"path": str(snapshot_root), "exists": snapshot_root.exists(), "file_count": _patch118_count_files(snapshot_root, "**/*")},
        "live_restore_backups": {"path": str(restore_root), "exists": restore_root.exists(), "file_count": _patch118_count_files(restore_root, "**/*")},
    }


def _patch118_capability_summary() -> dict:
    cmds = set(FORGE_EXPECTED_COMMANDS)
    def has_all(names):
        return all(n in cmds for n in names)
    return {
        "patch_lifecycle": has_all(["patch-propose", "patch-review", "patch-preflight", "patch-apply", "patch-verify"]),
        "sandbox": has_all(["patch-sandbox-plan", "patch-sandbox-apply", "patch-sandbox-report"]),
        "safe_tests": has_all(["test-inventory", "test-run-safe", "test-run-report"]),
        "snapshot": has_all(["snapshot-create", "snapshot-create-verify", "snapshot-diff"]),
        "engine_review_complete": has_all(["engine-review-completion-status", "engine-final-lockfile-apply"]),
        "engine_disposition": has_all(["engine-disposition-report", "engine-disposition-show"]),
        "llm_gateway": has_all(["llm-engine-review-gateway-init", "llm-engine-review-draft"]),
        "relationship_intelligence": has_all(["code-related-files", "code-risk-neighbors"]),
        "master_status": has_all(["forge-master-status", "forge-master-status-show"]),
    }


def _patch118_build_report() -> dict:
    command_surface = _patch118_command_surface_summary()
    tools = _patch118_tool_registry_summary()
    audit = _patch118_audit_summary()
    engine_review = _patch118_engine_review_summary()
    final_lockfile = engine_review.get("final_lockfile") or {}
    ledger_counts = ((engine_review.get("ledger") or {}).get("counts") or {})
    status = "FORGE_MASTER_STATUS_READY"
    blockers = []
    if command_surface.get("status") != "PASS":
        blockers.append("command_surface_missing_commands")
    if audit.get("status") != "PASS":
        blockers.append("audit_chain_not_verified")
    if not final_lockfile.get("exists") or final_lockfile.get("canonical_authority") is not True:
        blockers.append("final_canonical_engine_lockfile_missing_or_not_authoritative")
    if ledger_counts.get("pending", 0) != 0:
        blockers.append("engine_review_pending_not_zero")
    if blockers:
        status = "FORGE_MASTER_STATUS_READY_WITH_BLOCKERS"
    return {
        "schema_version": _PATCH118_SCHEMA_VERSION,
        "report_type": "FORGE_MASTER_STATUS_REPORT_V1",
        "created_at": _patch118_iso_now(),
        "status": status,
        "blockers": blockers,
        "authority": {
            "mode": "READ_ONLY_MASTER_STATUS_ONLY",
            "writes": [str(_PATCH118_ROOT)],
            "engine_file_write_authority": False,
            "project_file_write_authority": False,
            "ledger_mutation_authority": False,
            "final_lockfile_write_authority": False,
            "quarantine_authority": False,
            "delete_authority": False,
            "chroma_write_authority": False,
            "shell_execution_authority": False,
            "llm_autonomous_decision_authority": False,
        },
        "forge": {
            "root": str(FORGE_ROOT),
            "memory_root": str(MEMORY_DIR),
            "tool_registry": tools,
            "command_surface": command_surface,
            "audit": audit,
            "scope": _patch118_scope_summary(),
        },
        "engine_review": engine_review,
        "libraries": _patch118_context_summary(),
        "capabilities": _patch118_capability_summary(),
        "next_phase": "LLM_PLANNING_PACKET_SCHEMA",
        "recommended_next_patch": "Patch 119 — LLM Planning Packet Schema",
        "next_commands": [
            "forge-master-status-show latest",
            "forge-master-status-export",
            "Install Patch 119 when ready",
        ],
        "plain_english": "Forge now has one consolidated read-only system status surface. The next safe move is to define the structured LLM planning packet format before giving the LLM more planning responsibility.",
    }


def _patch118_write_report(payload: dict, prefix: str) -> tuple[Path, Path]:
    _PATCH118_ROOT.mkdir(parents=True, exist_ok=True)
    ts = _patch118_now()
    json_path = _PATCH118_ROOT / f"{ts}_{prefix}.json"
    md_path = _PATCH118_ROOT / f"{ts}_{prefix}.md"
    latest_json = _PATCH118_ROOT / f"latest_{prefix}.json"
    latest_md = _PATCH118_ROOT / f"latest_{prefix}.md"
    text = json.dumps(payload, indent=2, ensure_ascii=False)
    json_path.write_text(text, encoding="utf-8")
    latest_json.write_text(text, encoding="utf-8")
    md_lines = [
        "# Forge Master Status Report — Patch 118",
        "",
        f"Created: `{payload.get('created_at')}`",
        f"Status: `{payload.get('status')}`",
        f"Recommended next patch: `{payload.get('recommended_next_patch')}`",
        "",
        "## Core State",
        f"- Tools: `{((payload.get('forge') or {}).get('tool_registry') or {}).get('tool_count')}`",
        f"- Trust: `{((payload.get('forge') or {}).get('tool_registry') or {}).get('trust_level')}`",
        f"- Command surface: `{((payload.get('forge') or {}).get('command_surface') or {}).get('found')}/{((payload.get('forge') or {}).get('command_surface') or {}).get('expected')}`",
        f"- Audit: `{((payload.get('forge') or {}).get('audit') or {}).get('status')}` with `{((payload.get('forge') or {}).get('audit') or {}).get('chain_breaks')}` breaks",
        "",
        "## Engine Review",
    ]
    er = payload.get("engine_review") or {}
    ledger = (er.get("ledger") or {}).get("counts") or {}
    final = er.get("final_lockfile") or {}
    md_lines += [
        f"- Ledger total: `{ledger.get('total')}`",
        f"- Approved: `{ledger.get('approved')}`",
        f"- Deferred: `{ledger.get('deferred')}`",
        f"- Pending: `{ledger.get('pending')}`",
        f"- Canonical lockfile exists: `{final.get('exists')}`",
        f"- Canonical lockfile SHA: `{final.get('sha256')}`",
        f"- Included engines: `{final.get('included_count')}`",
        f"- Excluded engines: `{final.get('excluded_count')}`",
        "",
        "## Authority",
        "Read-only master status report. No engine writes, no ledger mutation, no lockfile mutation, no quarantine, no delete.",
    ]
    md_text = "\n".join(md_lines) + "\n"
    md_path.write_text(md_text, encoding="utf-8")
    latest_md.write_text(md_text, encoding="utf-8")
    return json_path, md_path


def _patch118_latest_report_path() -> Path:
    return _PATCH118_ROOT / f"latest_{_PATCH118_REPORT_PREFIX}.json"


def _patch118_load_latest_report() -> dict:
    p = _patch118_latest_report_path()
    if p.exists():
        return _patch118_load_json(p, {})
    return _patch118_build_report()


def _patch118_print_summary(report: dict) -> None:
    forge = report.get("forge") or {}
    tools = forge.get("tool_registry") or {}
    surface = forge.get("command_surface") or {}
    audit = forge.get("audit") or {}
    er = report.get("engine_review") or {}
    ledger = (er.get("ledger") or {}).get("counts") or {}
    final = er.get("final_lockfile") or {}
    disposition = er.get("disposition") or {}
    print()
    print("── Forge Master Status — Patch 118 ──────────────────")
    print(f"  Status       : {report.get('status')}")
    print(f"  Tools        : {tools.get('tool_count')}")
    print(f"  Trust        : {tools.get('trust_level')}")
    print(f"  Commands     : {surface.get('found')}/{surface.get('expected')} ({surface.get('status')})")
    print(f"  Audit        : {audit.get('status')} | breaks={audit.get('chain_breaks')} | checked={audit.get('entries_checked')}")
    print()
    print("  Engine Review:")
    print(f"    Total      : {ledger.get('total')}")
    print(f"    Approved   : {ledger.get('approved')}")
    print(f"    Deferred   : {ledger.get('deferred')}")
    print(f"    Pending    : {ledger.get('pending')}")
    print(f"    Final lock : {final.get('exists')} | included={final.get('included_count')} excluded={final.get('excluded_count')}")
    print(f"    Lock SHA   : {final.get('sha256')}")
    print()
    print("  Disposition:")
    print(f"    Exists     : {disposition.get('exists')} | excluded_total={disposition.get('excluded_total')}")
    print(f"    Safe delete: {disposition.get('safe_to_delete_now')} | safe quarantine={disposition.get('safe_to_quarantine_now')} | safe promote={disposition.get('safe_to_promote_now')}")
    print()
    print(f"  Next patch   : {report.get('recommended_next_patch')}")
    print("  Authority    : read-only status only; no project writes")
    print("──────────────────────────────────────────────────────")
    print()


