# ─── PATCH 119: LLM PLANNING PACKET SCHEMA ───────────────────────────────────
#
# Purpose:
#   Define the safe structure for future LLM-generated build/patch plans.
#   This patch does not allow the LLM to apply patches, mutate ledgers, edit
#   project files, run shell commands, or make autonomous decisions.
#
# Principle:
#   LLM may draft the reasoning packet. Forge must validate every field before
#   later patch gates can even consider sandbox/test/apply authority.

_PATCH119_ROOT = MEMORY_DIR / "llm_plans_v1"
_PATCH119_TEMPLATE_PREFIX = "llm_plan_template_v1"
_PATCH119_VALIDATION_PREFIX = "llm_plan_validation_v1"
_PATCH119_EXPORT_PREFIX = "llm_plan_export_v1"
_PATCH119_SCHEMA_VERSION = "llm_plan_packet_schema_v1_patch119"
_PATCH119_REQUIRED_FIELDS = [
    "goal",
    "target_files",
    "source_evidence",
    "runtime_roles",
    "risk_level",
    "expected_changes",
    "test_plan",
    "rollback_plan",
    "requires_human_approval",
]
_PATCH119_ALLOWED_RISK_LEVELS = ["LOW", "MEDIUM", "HIGH"]


def _patch119_now() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch119_iso_now() -> str:
    return datetime.datetime.now().isoformat(timespec="seconds")


def _patch119_sha256(path: Path) -> str | None:
    try:
        if not path.exists():
            return None
        return hashlib.sha256(path.read_bytes()).hexdigest()
    except Exception:
        return None


def _patch119_write_json_and_md(payload: dict, prefix: str) -> tuple[Path, Path]:
    _PATCH119_ROOT.mkdir(parents=True, exist_ok=True)
    stamp = _patch119_now()
    json_path = _PATCH119_ROOT / f"{stamp}_{prefix}.json"
    md_path = _PATCH119_ROOT / f"{stamp}_{prefix}.md"
    latest_json = _PATCH119_ROOT / f"latest_{prefix}.json"
    latest_md = _PATCH119_ROOT / f"latest_{prefix}.md"
    text = json.dumps(payload, indent=2, ensure_ascii=False)
    json_path.write_text(text + "\n", encoding="utf-8")
    latest_json.write_text(text + "\n", encoding="utf-8")
    md = _patch119_to_markdown(payload)
    md_path.write_text(md, encoding="utf-8")
    latest_md.write_text(md, encoding="utf-8")
    return json_path, md_path


def _patch119_to_markdown(payload: dict) -> str:
    lines = []
    lines.append(f"# {payload.get('report_type', 'LLM_PLAN_PACKET')}\n")
    lines.append(f"- **Created:** {payload.get('created_at')}\n")
    lines.append(f"- **Status:** {payload.get('status')}\n")
    if payload.get("recommended_next_patch"):
        lines.append(f"- **Recommended next patch:** {payload.get('recommended_next_patch')}\n")
    if payload.get("plain_english"):
        lines.append("\n## Plain English\n")
        lines.append(str(payload.get("plain_english")) + "\n")
    if payload.get("required_fields"):
        lines.append("\n## Required Fields\n")
        for field in payload.get("required_fields") or []:
            lines.append(f"- `{field}`")
        lines.append("")
    if payload.get("validation"):
        lines.append("\n## Validation\n")
        lines.append("```json")
        lines.append(json.dumps(payload.get("validation"), indent=2, ensure_ascii=False))
        lines.append("```\n")
    if payload.get("template"):
        lines.append("\n## Template\n")
        lines.append("```json")
        lines.append(json.dumps(payload.get("template"), indent=2, ensure_ascii=False))
        lines.append("```\n")
    if payload.get("authority"):
        lines.append("\n## Authority\n")
        lines.append("```json")
        lines.append(json.dumps(payload.get("authority"), indent=2, ensure_ascii=False))
        lines.append("```\n")
    if payload.get("next_commands"):
        lines.append("\n## Next Commands\n")
        for cmd in payload.get("next_commands") or []:
            lines.append(f"```text\n{cmd}\n```")
    return "\n".join(lines).rstrip() + "\n"


def _patch119_latest_template_path() -> Path:
    return _PATCH119_ROOT / f"latest_{_PATCH119_TEMPLATE_PREFIX}.json"


def _patch119_latest_validation_path() -> Path:
    return _PATCH119_ROOT / f"latest_{_PATCH119_VALIDATION_PREFIX}.json"


def _patch119_load_json(path: Path) -> dict:
    try:
        if path.exists():
            return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        pass
    return {}


def _patch119_template_object() -> dict:
    return {
        "schema_version": _PATCH119_SCHEMA_VERSION,
        "packet_type": "LLM_PLANNING_PACKET",
        "goal": "",
        "target_files": [],
        "source_evidence": [],
        "runtime_roles": [],
        "risk_level": "MEDIUM",
        "expected_changes": [],
        "test_plan": [],
        "rollback_plan": [],
        "requires_human_approval": True,
        "llm_notes": "",
        "forge_validation_notes": [],
        "authority": {
            "llm_may_draft": True,
            "forge_must_validate": True,
            "human_approval_required": True,
            "project_file_write_authority": False,
            "forge_self_write_authority": False,
            "patch_apply_authority": False,
            "shell_execution_authority": False,
            "chroma_write_authority": False,
            "ledger_mutation_authority": False,
        },
        "validation_requirements": {
            "target_files_must_exist": True,
            "target_files_must_be_in_scope": True,
            "source_evidence_must_exist": True,
            "runtime_roles_must_be_known": True,
            "current_sha_must_match_before_apply": True,
            "snapshot_required_before_write": True,
            "sandbox_required_before_write": True,
            "safe_tests_required_before_write_when_available": True,
            "rollback_plan_required_before_write": True,
        },
    }


def _patch119_validate_packet(packet: dict) -> dict:
    problems = []
    warnings = []
    required = list(_PATCH119_REQUIRED_FIELDS)
    missing = [field for field in required if field not in packet]
    if missing:
        problems.append(f"missing_required_fields: {', '.join(missing)}")

    list_fields = ["target_files", "source_evidence", "runtime_roles", "expected_changes", "test_plan", "rollback_plan"]
    for field in list_fields:
        if field in packet and not isinstance(packet.get(field), list):
            problems.append(f"{field}_must_be_list")

    if "goal" in packet and not isinstance(packet.get("goal"), str):
        problems.append("goal_must_be_string")

    risk = str(packet.get("risk_level") or "").upper()
    if risk not in _PATCH119_ALLOWED_RISK_LEVELS:
        problems.append(f"risk_level_must_be_one_of_{'_'.join(_PATCH119_ALLOWED_RISK_LEVELS)}")

    if packet.get("requires_human_approval") is not True:
        problems.append("requires_human_approval_must_be_true")

    # This patch only validates the schema. Later patches validate actual file existence,
    # evidence receipts, runtime roles, snapshots, sandbox reports, tests, and rollback.
    if not packet.get("target_files"):
        warnings.append("target_files_empty_template_or_non_executable_plan")
    if not packet.get("source_evidence"):
        warnings.append("source_evidence_empty_template_or_non_executable_plan")
    if not packet.get("test_plan"):
        warnings.append("test_plan_empty_template_or_non_executable_plan")
    if not packet.get("rollback_plan"):
        warnings.append("rollback_plan_empty_template_or_non_executable_plan")

    schema_valid = not problems
    concrete_plan = bool(packet.get("target_files") and packet.get("source_evidence") and packet.get("rollback_plan"))
    return {
        "schema_valid": schema_valid,
        "status": "LLM_PLAN_SCHEMA_VALID" if schema_valid else "LLM_PLAN_SCHEMA_INVALID",
        "problems": problems,
        "warnings": warnings,
        "required_fields": required,
        "allowed_risk_levels": list(_PATCH119_ALLOWED_RISK_LEVELS),
        "concrete_plan": concrete_plan,
        "live_apply_eligible": False,
        "live_apply_reason": "Patch 119 validates schema only. Later gates must validate files, evidence, roles, SHA, snapshot, sandbox, tests, rollback, and human approval.",
    }


def _patch119_read_latest_template_or_make() -> dict:
    path = _patch119_latest_template_path()
    data = _patch119_load_json(path)
    if data.get("template"):
        return data.get("template") or {}
    if data.get("packet_type") == "LLM_PLANNING_PACKET":
        return data
    return _patch119_template_object()


