    print()
    print("── LLM Planning Packet Policy — Patch 119 ───────────")
    print("  Purpose   : define safe structure for future LLM-generated build/patch plans")
    print("  Authority : schema/template/validation only")
    print("  Writes    : Forge-owned reports under memory/llm_plans_v1 only")
