    print("  Rule      : LLM may draft; Forge must validate; Nic must approve before any write path")
    print("  Next      : llm-plan-template")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "LLM_PLAN_POLICY_SHOWN", str(_PATCH119_ROOT), "read-only", "patch119")


