# ─── PATCH 120: FORGE SELF-UPDATE PROPOSAL GATE ─────────────────────────────
# Purpose:
#   Create a proposal-only lane for Forge self-updates.
#   This patch grants NO write authority to main.py, tool_registry.json, project files,
#   engine files, Chroma, audit log, or final manifests.
#   It only writes Forge-owned proposal/verification/export reports under memory.

_PATCH120_SCHEMA_VERSION = "forge_self_update_proposal_v1_patch120"
_PATCH120_ROOT = FORGE_ROOT / "memory" / "forge_self_updates_v1"
_PATCH120_PROPOSAL_PREFIX = "forge_self_update_proposal_v1"
_PATCH120_VERIFY_PREFIX = "forge_self_update_verification_v1"
_PATCH120_EXPORT_PREFIX = "forge_self_update_export_v1"

_PATCH120_ALLOWED_TARGETS = {
    str(FORGE_ROOT / "main.py"),
    str(FORGE_ROOT / "config" / "tool_registry.json"),
}

_PATCH120_FORBIDDEN_TOKENS = (
    "/.ssh/",
    "/secrets/",
    "/credentials/",
    ".env",
    "forge_audit.log",
    "chroma_db",
    "/memory/context_library_v1/chroma_db",
)


def _patch120_now_id() -> str:
    import datetime
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _patch120_iso_now() -> str:
    import datetime
    return datetime.datetime.now().isoformat(timespec="seconds")


def _patch120_ensure_root() -> None:
    _PATCH120_ROOT.mkdir(parents=True, exist_ok=True)


def _patch120_sha256_file(path: Path) -> str:
    import hashlib
    h = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def _patch120_write_json_and_md(payload: dict, prefix: str) -> tuple[Path, Path]:
    import json
    _patch120_ensure_root()
    stamp = _patch120_now_id()
    json_path = _PATCH120_ROOT / f"{stamp}_{prefix}.json"
    md_path = _PATCH120_ROOT / f"{stamp}_{prefix}.md"
    latest_json = _PATCH120_ROOT / f"latest_{prefix}.json"
    latest_md = _PATCH120_ROOT / f"latest_{prefix}.md"

    text = json.dumps(payload, indent=2, sort_keys=True)
    json_path.write_text(text + "\n", encoding="utf-8")
    latest_json.write_text(text + "\n", encoding="utf-8")

    lines = [
        f"# {payload.get('report_type', prefix)}",
        "",
        f"- Status: `{payload.get('status')}`",
        f"- Created: `{payload.get('created_at')}`",
        f"- Authority: `{(payload.get('authority') or {}).get('mode', 'NO_WRITE_AUTHORITY')}`",
        "",
    ]
    if payload.get("plain_english"):
        lines.extend(["## Plain English", "", str(payload.get("plain_english")), ""])
    if payload.get("target_files"):
        lines.extend(["## Target Files", ""])
        for row in payload.get("target_files") or []:
            if isinstance(row, dict):
                lines.append(f"- `{row.get('path')}` — allowed={row.get('allowed')} exists={row.get('exists')}")
            else:
                lines.append(f"- `{row}`")
        lines.append("")
    if payload.get("problems"):
        lines.extend(["## Problems", ""])
        for problem in payload.get("problems") or []:
            lines.append(f"- {problem}")
        lines.append("")
    if payload.get("warnings"):
        lines.extend(["## Warnings", ""])
        for warning in payload.get("warnings") or []:
            lines.append(f"- {warning}")
        lines.append("")
    if payload.get("next_commands"):
        lines.extend(["## Next Commands", ""])
        for cmd in payload.get("next_commands") or []:
            lines.append(f"- `{cmd}`")
        lines.append("")
    md_text = "\n".join(lines)
    md_path.write_text(md_text, encoding="utf-8")
    latest_md.write_text(md_text, encoding="utf-8")
    return json_path, md_path


def _patch120_load_json(path: Path) -> dict:
    import json
    if not path.exists():
        return {}
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {}


def _patch120_latest_proposal_path() -> Path:
    return _PATCH120_ROOT / f"latest_{_PATCH120_PROPOSAL_PREFIX}.json"


def _patch120_latest_verify_path() -> Path:
    return _PATCH120_ROOT / f"latest_{_PATCH120_VERIFY_PREFIX}.json"


def _patch120_normalize_target(raw: str) -> str:
    raw = (raw or "").strip()
    if not raw:
        return ""
    p = Path(raw).expanduser()
    if not p.is_absolute():
        p = FORGE_ROOT / p
    try:
        return str(p.resolve())
    except Exception:
        return str(p.absolute())


def _patch120_target_row(raw_path: str) -> dict:
    normalized = _patch120_normalize_target(raw_path)
    exists = Path(normalized).exists() if normalized else False
    allowed = normalized in _PATCH120_ALLOWED_TARGETS
    forbidden_reasons = []
    lowered = normalized.lower()
    for token in _PATCH120_FORBIDDEN_TOKENS:
        if token.lower() in lowered:
            forbidden_reasons.append(f"forbidden_token:{token}")
    sha = None
    if exists and Path(normalized).is_file():
        try:
            sha = _patch120_sha256_file(Path(normalized))
        except Exception as exc:
            forbidden_reasons.append(f"sha_read_failed:{exc}")
    return {
        "path": normalized,
        "exists": exists,
        "is_file": Path(normalized).is_file() if normalized else False,
        "allowed": allowed,
        "sha256": sha,
        "forbidden_reasons": forbidden_reasons,
    }


def _patch120_default_target_rows() -> list[dict]:
    return [_patch120_target_row(p) for p in sorted(_PATCH120_ALLOWED_TARGETS)]


def cmd_forge_self_update_policy(session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    _patch120_ensure_root()
    print()
    print("── Forge Self-Update Policy — Patch 120 ─────────────")
    print("  Purpose   : create a proposal-only lane for Forge self-updates")
    print("  Allowed   : main.py and config/tool_registry.json as proposal targets only")
    print("  Writes    : Forge-owned proposal reports under memory/forge_self_updates_v1")
    print("  Forbidden : live self-write, patch apply, shell execution, Chroma writes, audit overwrite")
    print("  Rule      : proposal → snapshot → sandbox → tests → human approval → later apply gate")
    print("  Authority : NO live write authority")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "FORGE_SELF_UPDATE_POLICY_SHOWN", str(_PATCH120_ROOT), "read-only", "patch120")


def cmd_forge_self_update_propose(arg: str, session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    tokens = [x.strip() for x in (arg or "").split() if x.strip()]
    if not tokens:
        target_rows = _patch120_default_target_rows()
        goal = "Create a proposal shell for a future Forge self-update. No live file changes are authorized."
    else:
        target_rows = [_patch120_target_row(x) for x in tokens]
        goal = "Create a proposal shell for the specified Forge self-update target(s). No live file changes are authorized."

    problems = []
    warnings = []
    for row in target_rows:
        if not row.get("path"):
            problems.append("empty_target_path")
        if not row.get("exists"):
            problems.append(f"target_missing:{row.get('path')}")
        if not row.get("allowed"):
            problems.append(f"target_not_allowed_for_self_update:{row.get('path')}")
        if row.get("forbidden_reasons"):
            problems.append(f"forbidden_target:{row.get('path')}:{','.join(row.get('forbidden_reasons') or [])}")
    if not problems:
        warnings.append("proposal_only_no_diff_attached")
        warnings.append("not_live_apply_eligible_until_snapshot_sandbox_tests_and_human_approval_exist")

    payload = {
        "schema_version": _PATCH120_SCHEMA_VERSION,
        "report_type": "FORGE_SELF_UPDATE_PROPOSAL_V1",
        "created_at": _patch120_iso_now(),
        "status": "FORGE_SELF_UPDATE_PROPOSAL_READY_NO_WRITE_AUTHORITY" if not problems else "FORGE_SELF_UPDATE_PROPOSAL_BLOCKED",
        "goal": goal,
        "target_files": target_rows,
        "source_evidence": [
            "Patch 119 LLM planning packet schema",
            "Forge final canonical engine lockfile",
            "Forge master status report",
        ],
        "risk_level": "HIGH",
        "expected_changes": [],
        "test_plan": [
            "python3 -m py_compile main.py",
            "forge-command-surface",
            "tool registry JSON parse",
            "audit chain verification",
        ],
        "rollback_plan": [
            "restore main.py from preinstall backup",
            "restore config/tool_registry.json from preinstall backup",
            "verify py_compile and forge-command-surface",
        ],
        "requires_human_approval": True,
        "problems": problems,
        "warnings": warnings,
        "authority": {
            "mode": "PROPOSAL_ONLY",
            "llm_may_draft": True,
            "forge_must_validate": True,
            "human_approval_required": True,
            "live_self_write_authority": False,
            "project_file_write_authority": False,
            "patch_apply_authority": False,
            "shell_execution_authority": False,
            "chroma_write_authority": False,
            "audit_overwrite_authority": False,
        },
        "validation_requirements": {
            "fresh_self_snapshot_required": True,
            "self_update_sandbox_required": True,
            "safe_tests_required": True,
            "human_confirmation_required": True,
            "current_sha_must_match_before_apply": True,
            "rollback_ready_required": True,
        },
        "plain_english": "This proposal records what Forge may later update in itself. It does not change main.py or tool_registry.json.",
        "next_commands": [
            "forge-self-update-show latest",
            "forge-self-update-verify latest",
            "forge-self-update-export",
            "forge-next",
        ],
    }
    json_path, md_path = _patch120_write_json_and_md(payload, _PATCH120_PROPOSAL_PREFIX)
    print()
    print("── Forge Self-Update Proposal — Patch 120 ───────────")
    print(f"  Status  : {payload.get('status')}")
    print(f"  Targets : {len(target_rows)}")
    print(f"  Problems: {len(problems)}")
    print(f"  Warnings: {len(warnings)}")
    print("  Authority: proposal only; NO live Forge self-write")
    print(f"  JSON    : {json_path}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "FORGE_SELF_UPDATE_PROPOSAL_WRITTEN", str(json_path), f"targets={len(target_rows)}", payload.get("status"))


def cmd_forge_self_update_show(arg: str, session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    arg = (arg or "latest").strip().lower()
    if arg in {"latest", "proposal", ""}:
        path = _patch120_latest_proposal_path()
    elif arg in {"verify", "verification", "validation"}:
        path = _patch120_latest_verify_path()
    else:
        candidate = _PATCH120_ROOT / arg
        path = candidate if candidate.exists() else _patch120_latest_proposal_path()
    payload = _patch120_load_json(path)
    print()
    print("── Forge Self-Update Show — Patch 120 ───────────────")
    if not payload:
        print("  Status : NOT_FOUND")
        print(f"  Path   : {path}")
    else:
        print(f"  Status : {payload.get('status')}")
        print(f"  Type   : {payload.get('report_type')}")
        print(f"  Path   : {path}")
        if payload.get("target_files"):
            print("  Targets:")
            for row in payload.get("target_files") or []:
                print(f"    - {row.get('path')} | allowed={row.get('allowed')} exists={row.get('exists')}")
        if payload.get("problems"):
            print("  Problems:")
            for p in payload.get("problems") or []:
                print(f"    - {p}")
        if payload.get("warnings"):
            print("  Warnings:")
            for w in payload.get("warnings") or []:
                print(f"    - {w}")
        print("  Authority: NO live self-write")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "FORGE_SELF_UPDATE_SHOW", str(path), "read-only", f"arg={arg}")


def cmd_forge_self_update_verify(arg: str, session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    arg = (arg or "latest").strip().lower()
    proposal_path = _patch120_latest_proposal_path() if arg in {"latest", "proposal", ""} else (_PATCH120_ROOT / arg)
    proposal = _patch120_load_json(proposal_path)

    problems = []
    warnings = []
    target_rows = []
    if not proposal:
        problems.append(f"proposal_not_found:{proposal_path}")
    else:
        for row in proposal.get("target_files") or []:
            checked = _patch120_target_row(row.get("path", ""))
            target_rows.append(checked)
            if not checked.get("exists"):
                problems.append(f"target_missing:{checked.get('path')}")
            if not checked.get("allowed"):
                problems.append(f"target_not_allowed:{checked.get('path')}")
            if checked.get("forbidden_reasons"):
                problems.append(f"forbidden_target:{checked.get('path')}:{','.join(checked.get('forbidden_reasons') or [])}")
            old_sha = row.get("sha256")
            new_sha = checked.get("sha256")
            if old_sha and new_sha and old_sha != new_sha:
                warnings.append(f"target_sha_changed_since_proposal:{checked.get('path')}")
        if not target_rows:
            problems.append("proposal_has_no_target_files")

    status = "FORGE_SELF_UPDATE_PROPOSAL_VERIFIED_NO_WRITE_AUTHORITY" if not problems else "FORGE_SELF_UPDATE_PROPOSAL_VERIFY_BLOCKED"
    payload = {
        "schema_version": _PATCH120_SCHEMA_VERSION,
        "report_type": "FORGE_SELF_UPDATE_VERIFICATION_V1",
        "created_at": _patch120_iso_now(),
        "status": status,
        "proposal_path": str(proposal_path),
        "proposal_sha256": _patch120_sha256_file(proposal_path) if proposal_path.exists() else None,
        "target_files": target_rows,
        "problems": problems,
        "warnings": warnings,
        "live_apply_eligible": False,
        "live_apply_reason": "Patch 120 is proposal/verification only. Later patches must require fresh self-snapshot, sandbox, safe tests, rollback readiness, and explicit confirmation.",
        "authority": {
            "mode": "VERIFY_ONLY",
            "live_self_write_authority": False,
            "project_file_write_authority": False,
            "patch_apply_authority": False,
            "shell_execution_authority": False,
            "audit_overwrite_authority": False,
        },
        "plain_english": "Forge checked the self-update proposal targets. This still does not allow a live write.",
        "next_commands": ["forge-self-update-show verification", "forge-self-update-export", "forge-next"],
    }
    json_path, md_path = _patch120_write_json_and_md(payload, _PATCH120_VERIFY_PREFIX)
    print()
    print("── Forge Self-Update Verify — Patch 120 ─────────────")
    print(f"  Status  : {status}")
    print(f"  Problems: {len(problems)}")
    print(f"  Warnings: {len(warnings)}")
    print("  Eligible: false — proposal lane only")
    print(f"  JSON    : {json_path}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "FORGE_SELF_UPDATE_VERIFY_WRITTEN", str(json_path), f"status={status}", "no_write_authority")


def cmd_forge_self_update_export(session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
